window.HADITH_CACHE["ahmad_0"] = {"1":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ أَخْبَرَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ قَيْسٍ قَالَقَامَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تَقْرَءُونَ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لَا يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ }وَإِنَّا سَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ النَّاسَ إِذَا رَأَوْا الْمُنْكَرَ فَلَمْ يُنْكِرُوهُ أَوْشَكَ أَنْ يَعُمَّهُمْ اللَّهُ بِعِقَابِهِ","id":"Telah menceritakan kepada kami [Abdullah Bin Numair] dia berkata; telah mengabarkan kepada kami [Isma'il] dari [Qais] dia berkata; [Abu Bakar] berdiri lalu memuji Allah dan mensucikan-Nya kemudian berkata; wahai manusia sesungguhnya kalian membaca ayat ini: \"Hai orang-orang yang beriman, jagalah dirimu; tiadalah orang yang sesat itu akan memberi mudharat kepadamu apabila kamu telah mendapat petunjuk.\" (QS Al Maidah ayat 105). Dan sesungguhnya kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"sesungguhnya jika manusia melihat kemungkaran kemudian mereka tidak mengingkarinya, maka hampir saja Allah akan menimpakan siksa kepada mereka semua.\""},"2":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ أَبُو سَعِيدٍ يَعْنِي الْعَنْقَزِيَّ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنِ الْبَرَاءِ بْنِ عَازِبٍ قَالَاشْتَرَى أَبُو بَكْرٍ مِنْ عَازِبٍ سَرْجًا بِثَلَاثَةَ عَشَرَ دِرْهَمًا قَالَ فَقَالَ أَبُو بَكْرٍ لِعَازِبٍ مُرْ الْبَرَاءَ فَلْيَحْمِلْهُ إِلَى مَنْزِلِي فَقَالَ لَا حَتَّى تُحَدِّثَنَا كَيْفَ صَنَعْتَ حِينَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتَ مَعَهُ قَالَ فَقَالَ أَبُو بَكْرٍ خَرَجْنَا فَأَدْلَجْنَا فَأَحْثَثْنَا يَوْمَنَا وَلَيْلَتَنَا حَتَّى أَظْهَرْنَا وَقَامَ قَائِمُ الظَّهِيرَةِ فَضَرَبْتُ بِبَصَرِي هَلْ أَرَى ظِلًّا نَأْوِي إِلَيْهِ فَإِذَا أَنَا بِصَخْرَةٍ فَأَهْوَيْتُ إِلَيْهَا فَإِذَا بَقِيَّةُ ظِلِّهَا فَسَوَّيْتُهُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَرَشْتُ لَهُ فَرْوَةً وَقُلْتُ اضْطَجِعْ يَا رَسُولَ اللَّهِ فَاضْطَجَعَ ثُمَّ خَرَجْتُ أَنْظُرُ هَلْ أَرَى أَحَدًا مِنْ الطَّلَبِ فَإِذَا أَنَا بِرَاعِي غَنَمٍ فَقُلْتُ لِمَنْ أَنْتَ يَا غُلَامُ فَقَالَ لِرَجُلٍ مِنْ قُرَيْشٍ فَسَمَّاهُ فَعَرَفْتُهُ فَقُلْتُ هَلْ فِي غَنَمِكَ مِنْ لَبَنٍ قَالَ نَعَمْ قَالَ قُلْتُ هَلْ أَنْتَ حَالِبٌ لِي قَالَ نَعَمْ قَالَ فَأَمَرْتُهُ فَاعْتَقَلَ شَاةً مِنْهَا ثُمَّ أَمَرْتُهُ فَنَفَضَ ضَرْعَهَا مِنْ الْغُبَارِ ثُمَّ أَمَرْتُهُ فَنَفَضَ كَفَّيْهِ مِنْ الْغُبَارِ وَمَعِي إِدَاوَةٌ عَلَى فَمِهَا خِرْقَةٌ فَحَلَبَ لِي كُثْبَةً مِنْ اللَّبَنِ فَصَبَبْتُ يَعْنِي الْمَاءَ عَلَى الْقَدَحِ حَتَّى بَرَدَ أَسْفَلُهُ ثُمَّ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَافَيْتُهُ وَقَدْ اسْتَيْقَظَ فَقُلْتُ اشْرَبْ يَا رَسُولَ اللَّهِ فَشَرِبَ حَتَّى رَضِيتُ ثُمَّ قُلْتُ هَلْ أَنَى الرَّحِيلُ قَالَ فَارْتَحَلْنَا وَالْقَوْمُ يَطْلُبُونَا فَلَمْ يُدْرِكْنَا أَحَدٌ مِنْهُمْ إِلَّا سُرَاقَةُ بْنُ مَالِكِ بْنِ جُعْشُمٍ عَلَى فَرَسٍ لَهُ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا الطَّلَبُ قَدْ لَحِقَنَا فَقَالَ لَا تَحْزَنْ إِنَّ اللَّهَ مَعَنَا حَتَّى إِذَا دَنَا مِنَّا فَكَانَ بَيْنَنَا وَبَيْنَهُ قَدْرُ رُمْحٍ أَوْ رُمْحَيْنِ أَوْ ثَلَاثَةٍ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ هَذَا الطَّلَبُ قَدْ لَحِقَنَا وَبَكَيْتُ قَالَ لِمَ تَبْكِي قَالَ قُلْتُ أَمَا وَاللَّهِ مَا عَلَى نَفْسِي أَبْكِي وَلَكِنْ أَبْكِي عَلَيْكَ قَالَ فَدَعَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اللَّهُمَّ اكْفِنَاهُ بِمَا شِئْتَ فَسَاخَتْ قَوَائِمُ فَرَسِهِ إِلَى بَطْنِهَا فِي أَرْضٍ صَلْدٍ وَوَثَبَ عَنْهَا وَقَالَ يَا مُحَمَّدُ قَدْ عَلِمْتُ أَنَّ هَذَا عَمَلُكَ فَادْعُ اللَّهَ أَنْ يُنْجِيَنِي مِمَّا أَنَا فِيهِ فَوَاللَّهِ لَأُعَمِّيَنَّ عَلَى مَنْ وَرَائِي مِنْ الطَّلَبِ وَهَذِهِ كِنَانَتِي فَخُذْ مِنْهَا سَهْمًا فَإِنَّكَ سَتَمُرُّ بِإِبِلِي وَغَنَمِي فِي مَوْضِعِ كَذَا وَكَذَا فَخُذْ مِنْهَا حَاجَتَكَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَاجَةَ لِي فِيهَا قَالَ وَدَعَا لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُطْلِقَ فَرَجَعَ إِلَى أَصْحَابِهِ وَمَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ حَتَّى قَدِمْنَا الْمَدِينَةَ فَتَلَقَّاهُ النَّاسُ فَخَرَجُوا فِي الطَّرِيقِ وَعَلَى الْأَجَاجِيرِ فَاشْتَدَّ الْخَدَمُ وَالصِّبْيَانُ فِي الطَّرِيقِ يَقُولُونَ اللَّهُ أَكْبَرُ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ مُحَمَّدٌ قَالَ وَتَنَازَعَ الْقَوْمُ أَيُّهُمْ يَنْزِلُ عَلَيْهِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْزِلُ اللَّيْلَةَ عَلَى بَنِي النَّجَّارِ أَخْوَالِ عَبْدِ الْمُطَّلِبِ لِأُكْرِمَهُمْ بِذَلِكَ فَلَمَّا أَصْبَحَ غَدَا حَيْثُ أُمِرَ قَالَ الْبَرَاءُ بْنُ عَازِبٍ أَوَّلُ مَنْ كَانَ قَدِمَ عَلَيْنَا مِنْ الْمُهَاجِرِينَ مُصْعَبُ بْنُ عُمَيْرٍ أَخُو بَنِي عَبْدِ الدَّارِ ثُمَّ قَدِمَ عَلَيْنَا ابْنُ أُمِّ مَكْتُومٍ الْأَعْمَى أَخُو بَنِي فِهْرٍ ثُمَّ قَدِمَ عَلَيْنَا عُمَرُ بْنُ الْخَطَّابِ فِي عِشْرِينَ رَاكِبًا فَقُلْنَا مَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هُوَ عَلَى أَثَرِي ثُمَّ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ مَعَهُ قَالَ الْبَرَاءُ وَلَمْ يَقْدَمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى حَفِظْتُ سُوَرًا مِنْ الْمُفَصَّلِقَالَ إِسْرَائِيلُ وَكَانَ الْبَرَاءُ مِنْ الْأَنْصَارِ مِنْ بَنِي حَارِثَةَ","id":"Telah menceritakan kepada kami ['Amru Bin Muhammad Abu Sa'id yaitu Al 'Anqazi] dia berkata; Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Barra' Bin 'Azib], dia berkata; Abu bakar membeli sebuah pelana dari 'Azib seharga tiga belas dirham, Al Barra' berkata; kemudian Abu Bakar berkata kepada Azib; \"suruhlah Al Barro' membawanya ke rumahku.\" Maka 'Azib menjawab; \"tidak, kecuali jika kamu mau menceritakan kepada kami, tentang apa yang kamu lakukan ketika Rasulullah shallallahu 'alaihi wasallam keluar bersamamu.\" dia berkata; maka [Abu Bakar] berkata; \"kami keluar berjalan di malam hari dan mempercepat jalan diwaktu siang dan malam yang kami lalui, ketika kami tiba di waktu dzuhur dan matahari tepat berada di atas, aku memperhatikan sekitar kami apakah ada tempat berteduh untuk kami, sesaat kemudian aku melihat sebuah batu besar dan aku pun mendekatinya dan ternyata ada sedikit rongga (menjorok kedalam) yang tertutupi bayangan batu tersebut, maka aku rapikan tempat itu dan membentangkan jubah dari kulit untuk Rasulullah shallallahu 'alaihi wasallam, kemudian aku berkata; \"berbaringlah wahai Rasulullah\" lalu beliau berbaring, kemudian aku keluar melihat lihat apakah ada orang yang mencari, tiba tiba aku melihat seorang penggembala kambing, aku bertanya; \"milik siapa kamu wahai pemuda?\" dia menjawab; \"milik seorang lelaki dari Quraisy, \" lalu dia menyebutkan namanya dan akupun mengenalnya, aku bertanya lagi; \"apakah kambingmu mengeluarkan air susu? 'dia menjawab; 'ya 'aku bertanya lagi; 'apakah kamu mau memerahkan susu untukku? ' dia menjawab; \"ya\" maka aku perintahkan kepadanya untuk memegang salah satu dari kambingnya dan membersihkan susu kambing tersebut serta kedua telapak tangannya dari debu, aku membawa geriba dari kulit yang di bagian mulutnya ada penutup dari kain, kemudian dia memerahkan sedikit susu untukku dan aku siramkan air ke geriba supaya bawahnya tidak terlalu panas, kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam untuk memberinya minum, dan ternyata beliau sudah terjaga dari tidurnya, aku berkata; \"wahai Rasulullah minumlah\" Beliaupun meminumnya hingga aku merasa lega, kemudian aku berkata; \"apakah sudah saatnya kita berangkat?\" maka kami berangkat sementara orang-orang mencari dan tidak ada seorangpun dari mereka yang dapat menemukan kami kecuali Suraqah Bin Malik Bin Ju'syum dengan berkuda, aku berkata; \"wahai Rasulullah orang yang memburu (kita ini) akan menyusul kita\" maka Nabi menjawab: \"jangan bersedih sesungguhnya Allah bersama kita\" sampai ketika Suraqah telah dekat dengan kami kira kira jarak satu tombak atau dua tombak atau tiga tombak aku berkata; \"wahai Rasulullah orang yang memburu (kita ini) akan menyusul kita\" dan aku (saat itu) menangis, Nabi bertanya: \"kenapa kamu menangis?\" aku menjawab; \"demi Allah, aku bukan menangis karena khawatir terhadap diriku akan tetapi aku menangis karena khawatir kepada tuan\" kemudian Rasulullah shallallahu 'alaihi wasallam berdoa: \"kami serahkan dia (Suraqah) kepada kehendakMu \"maka kaki sampai perut kuda Suraqah tergelincir masuk ke tanah yang keras dan dia melompat darinya dan berkata; \"wahai Muhammad aku sudah tahu ini adalah perbuatanmu maka doakanlah kepada Allah agar menyelamatkanku dari apa yang menimpaku, demi Allah aku akan rahasiakan beritamu kepada orang-orang yang mencarimu yang ada di belakangku, dan ini wadah panah dari kulit milikku ambillah sebagian anak panahnya, sesungguhnya kamu akan melalui unta dan kambing milikku di tempat ini dan ini maka ambillah darinya untuk keperluanmu.\" Abu Bakar melanjutkan, maka Rasulullah shallallahu 'alaihi wasallam menjawab; \"aku tidak membutuhkannya\" kemudian Rasulullah shallallahu 'alaihi wasallam mendoakannya maka lepaslah Suraqah (dari bencana yang menimpanya) dan kembali kepada teman temannya, Rasulullah shallallahu 'alaihi wasallam melanjutkan perjalanannya bersamaku, sesampainya kami tiba di Madinah, orang-orang menyambut dan keluar ke jalan-jalan dan di atas atap rumah, para pelayan dan anak anak keluar bersegera sambil berkata; \"Allah maha besar, Rasulullah shallallahu 'alaihi wasallam telah datang, Muhammad telah datang.\" Orang-orang berselisih, siapakah diantara mereka yang berhak untuk ditempati rumahnya oleh beliau, maka Rasulullah shallallahu 'alaihi wasallam berkata: \"malam ini aku akan menginap di rumah Bani Najar paman Abdul MuThalib untuk menghormati mereka, \" maka ketika pagi esok harinya beliau berangkat sebagaimana yang diperintahkan. Barra' Bin Azib berkata; \"orang muhajirin pertama yang datang kepada kami adalah Mush'ab Bin Umair saudara Bani Abdud Dar kemudian Ibnu Ummi Maktum yang buta saudara Bani Fihri, kemudian Umar Bin Al Khaththab bersama dua puluh orang berkendaraan, maka kami bertanya; \"apa yang dilakukan oleh Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab; \"beliau berada di belakangku\", kemudian Rasulullah shallallahu 'alaihi wasallam tiba bersama Abu Bakar, Barro' berkata; \"tidaklah Rasulullah shallallahu 'alaihi wasallam tiba (di Madinah) kecuali pada saat itu aku telah hafal beberapa surat dari Al Mufashal.\" Israil berkata; \" Barro' adalah sahabat Anshar dari Bani Haritsah.\""},"3":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ قَالَ إِسْرَائِيلُ قَالَ أَبُو إِسْحَاقَ عَنْ زَيْدِ بْنِ يُثَيْعٍ عَنْ أَبِي بَكْرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ بِبَرَاءَةٌ لِأَهْلِ مَكَّةَ لَا يَحُجُّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفُ بِالْبَيْتِ عُرْيَانٌ وَلَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسٌ مُسْلِمَةٌ مَنْ كَانَ بَيْنَهُ وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُدَّةٌ فَأَجَلُهُ إِلَى مُدَّتِهِ وَاللَّهُ بَرِيءٌ مِنْ الْمُشْرِكِينَ وَرَسُولُهُ قَالَ فَسَارَ بِهَا ثَلَاثًا ثُمَّ قَالَ لِعَلِيٍّ رَضِيَ اللَّهُ تَعَالَى عَنْهُ الْحَقْهُ فَرُدَّ عَلَيَّ أَبَا بَكْرٍ وَبَلِّغْهَا أَنْتَ قَالَ فَفَعَلَ قَالَ فَلَمَّا قَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو بَكْرٍ بَكَى قَالَ يَا رَسُولَ اللَّهِ حَدَثَ فِيَّ شَيْءٌ قَالَ مَا حَدَثَ فِيكَ إِلَّا خَيْرٌ وَلَكِنْ أُمِرْتُ أَنْ لَا يُبَلِّغَهُ إِلَّا أَنَا أَوْ رَجُلٌ مِنِّي","id":"Telah menceritakan kepada kami [Waki'] dia berkata; telah berkata [Israil]; telah berkata [Abu Ishaq]; dari [Zaid Bin Yutsai'] dari [Abu Bakar] bahwasannya Nabi shallallahu 'alaihi wasallam mengutusnya dengan pernyataan berlepas diri dari penduduk Makkah; \"agar tidak seorang musyrik pun pergi menunaikan haji setelah tahun ini, tidak ada yang melakukan thawaf dalam keadaan telanjang dan tidak akan masuk syurga kecuali orang muslim, barangsiapa diantara dirinya dan Rasulullah ada perjanjian maka batasnya sampai sekesai perjanjian tersebut, dan Allah beserta Rasul-Nya berlepas diri dari orang-orang musyrik.\" YAzid berkata; maka ia berangkat dengan tiga orang. Kemudian Beliau berkata kepada Ali; \"susul dia dan kembalikan Abu Bakar padaku dan sampaikan pernyataan itu olehmu.\" maka diapun melakukannya, dia berkata; ketika Abu Bakar datang kepada Nabi shallallahu 'alaihi wasallam, ia menangis dan bertanya; \"wahai Rasulullah apakah telah terjadi sesuatu pada diriku?\" beliau menjawab; \"tidak ada yang terjadi padamu kecuali kebaikan, akan tetapi aku diperintahkan agar perkara itu tidak disampaikan kecuali olehku atau salah seorang dariku\". "},"4":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيْرٍ عَنْ سُلَيْمِ بْنِ عَامِرٍ عَنْ أَوْسَطَ قَالَخَطَبَنَا أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَامِي هَذَا عَامَ الْأَوَّلِ وَبَكَى أَبُو بَكْرٍ فَقَالَ أَبُو بَكْرٍ سَلُوا اللَّهَ الْمُعَافَاةَ أَوْ قَالَ الْعَافِيَةَ فَلَمْ يُؤْتَ أَحَدٌ قَطُّ بَعْدَ الْيَقِينِ أَفْضَلَ مِنْ الْعَافِيَةِ أَوْ الْمُعَافَاةِ عَلَيْكُمْ بِالصِّدْقِ فَإِنَّهُ مَعَ الْبِرِّ وَهُمَا فِي الْجَنَّةِ وَإِيَّاكُمْ وَالْكَذِبَ فَإِنَّهُ مَعَ الْفُجُورِ وَهُمَا فِي النَّارِ وَلَا تَحَاسَدُوا وَلَا تَبَاغَضُوا وَلَا تَقَاطَعُوا وَلَا تَدَابَرُوا وَكُونُوا إِخْوَانًا كَمَا أَمَرَكُمْ اللَّهُ تَعَالَى","id":"Telah menceritakan kepada kami [Muhammad Bin Ja'far] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Yazid Bin Khumair] dari [Sulaim Bin 'Amir] dari [Ausath], dia berkata; [Abu Bakar] berkhutbah kepada kami dan berkata; Rasullah shallallahu 'alaihi wasallam berdiri ditempatku ini pada tahun pertama. Lalu Abu Bakar menangis, kemudian berkata; mohonlah kepada Allah Al mu'Aafaat (ampunan) atau ia berkata Al 'Aa'fiyah (keselamatan), karena tidaklah seseorang diberi sesuatu yang lebih utama dari Al 'Aa'fiyah atau Al mu'Aafaat setelah keyakinan, berlaku jujurlah kalian karena kejujuran bersama kebajikan dan keduanya berada di surga, dan jauhilah dusta karena dusta bersama kejahatan dan keduanya berada di neraka, dan janganlah kalian saling dengki, bermusuhan, dan jangan pula saling memutus tali silaturrahim dan saling berpaling, akan tetapi jadilah kalian bersaudara sebagaimana yang Allah Ta'ala perintahkan.\" "},"5":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ قَالَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنِ ابْنِ أَبِي عَتِيقٍ عَنْ أَبِيهِ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السِّوَاكُ مَطْهَرَةٌ لِلْفَمِ مَرْضَاةٌ لِلرَّبِّ","id":"Telah menceritakan kepada kami [Abu Kamil], dia berkata; Telah menceritakan kepada kami [Hammad yaitu Ibnu Salamah] dari [Ibnu Abu 'Atiq] dari [bapaknya] dari [Abu Bakar], bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Siwak adalah pembersih mulut dan diRidhai oleh Allah\"."},"6":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِي بَكْرٍ الصِّدِّيقِأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمْنِي دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي قَالَ قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُو قَالَ يُونُسُ كَبِيرًا حَدَّثَنَاه حَسَنٌ الْأَشْيَبُ عَنْ ابْنِ لَهِيعَةَ قَالَ قَالَ كَبِيرًا","id":"Telah menceritakan kepada kami [Hasyim Bin Al Qasim] dia berkata; Telah menceritakan kepada kami [Al Laits] dia berkata; Telah menceritakan kepadaku [Yazid Bin Abu Habib] dari [Abul Khair] dari [Abdullah Bin 'Amru] dari [Abu Bakar Ash Shiddiq] bahwasanya dia berkata kepada Rasulllah; \"ajarilah aku Do'a yang dengannya aku berdoa didalam shalatku, \" Beliau menjawab: \"bacalah, Allahumma Innii Zhalamtu Nafsii Zhulman Katsiiro, Walaa Yaghfirudz Dzunuuba Illaa Anta, Faghfirlii maghfiratan Min 'Indika Warhamnii Innaka Antal Ghofuurur Rahiim \"(Ya Allah aku telah banyak menzhalimi diriku sendiri, dan tidak ada yang dapat mengampuni dosa kecuali Engkau maka ampunilah dosaku dengan ampunan dari sisimu dan rahmatilah aku, sesungguhnya engkau maha pengampun lagi maha penyayang).\" [Yunus] berkata; \"kabiiraa (besar), \" telah menceritakannya kepada kami [Hasan Al Asy yab] dari [Ibnu Lahi'ah] dia berkata; beliau bersabda: \"kabiiraa (besar).\""},"7":{"ar":"حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ قَالَ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ قَالَ سَمِعْتُ عَبْدَ الْمَلِكِ بْنَ الْحَارِثِ يَقُولُ إِنَّ أَبَا هُرَيْرَةَ قَالَ سَمِعْتُ أَبَا بَكْرٍ الصِّدِّيقَ رَضِيَ اللَّهُ عَنْهُ عَلَى هَذَا الْمِنْبَرِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْيَوْمِ مِنْ عَامِ الْأَوَّلِ ثُمَّ اسْتَعْبَرَ أَبُو بَكْرٍ وَبَكَى ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَمْ تُؤْتَوْا شَيْئًا بَعْدَ كَلِمَةِ الْإِخْلَاصِ مِثْلَ الْعَافِيَةِ فَاسْأَلُوا اللَّهَ الْعَافِيَةَ","id":"Telah menceritakan kepada kami [Abu Abdurrahman Al Muqri'] dia berkata; Telah menceritakan kepada kami [Haiwah Bin Syuraih] dia berkata; aku mendengar [Abdul Malik Bin Al Harits] berkata; Sesungguhnya [Abu Hurairah] berkata; aku mendengar [Abu Bakar Ash Shiddiq] berkata diatas mimbar ini; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada hari ini ditahun pertama, kemudian Abu Bakar hanyut dalam nasehat sehingga menangis kemudian berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"tidaklah kalian diberi sesuatu (yang kedudukannya lebih tinggi) setelah kalimat ikhlas seperti Al Afiyah (keselamatan), maka mohonlah Al Afiyah kepada Allah\"."},"8":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا هَمَّامٌ قَالَ أَخْبَرَنَا ثَابِتٌ عَنْ أَنَسٍ أَنَّ أَبَا بَكْرٍ حَدَّثَهُ قَالَقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْغَارِ وَقَالَ مَرَّةً وَنَحْنُ فِي الْغَارِ لَوْ أَنَّ أَحَدَهُمْ نَظَرَ إِلَى قَدَمَيْهِ لَأَبْصَرَنَا تَحْتَ قَدَمَيْهِ قَالَ فَقَالَ يَا أَبَا بَكْرٍ مَا ظَنُّكَ بِاثْنَيْنِ اللَّهُ ثَالِثُهُمَا","id":"Telah menceritakan kepada kami ['Affan] dia berkata; Telah menceritakan kepada kami [Hammam], dia berkata; telah mengabarkan kepada kami [Tsabit] dari [Anas] bahwasannya [Abu Bakar] telah bercerita kepadanya, dia (Abu Bakar) berkata; aku berkata kepada Nabi shallallahu 'alaihi wasallam ketika berada di dalam goa, -dalam riwayat lain ia berkata; \"dan kami berada didalam goa, - dan seandainya salah seorang dari mereka melihat kedua kaki beliau, pasti mereka akan melihat kami dari bawah kedua kakinya\", maka Beliau berkata: \"wahai Abu Bakar, apa persangkaanmu terhadap dua orang, bukankah Allah adalah yang ketiga dari keduanya.\""},"9":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ حَدَّثَنَا ابْنُ أَبِي عَرُوبَةَ عَنْ أَبِي التَّيَّاحِ عَنِ الْمُغِيرَةِ بْنِ سُبَيْعٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الدَّجَّالَ يَخْرُجُ مِنْ أَرْضٍ بِالْمَشْرِقِ يُقَالُ لَهَا خُرَاسَانُ يَتَّبِعُهُ أَقْوَامٌ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ","id":"Telah menceritakan kepada kami [Rauh] dia berkata; Telah menceritakan kepada kami [Ibnu Abi 'Arubah] dari [Abu At Taiyyah] dari [Al Mughirah Bin Subai'] dari ['Amru Bin Huraits] dari [Abu Bakar Ash Shiddiq], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bercerita kepada kami bahwasannya Dajjal akan keluar dari bumi bagian timur yang disebut Khurasan, banyak orang yang mengikutinya, seakan akan wajah mereka seperti tameng yang dipalu.\""},"10":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ مِنْ عَبْدِ اللَّهِ بْنِ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنِ الْوَلِيدِ بْنِ جُمَيْعٍ عَنْ أَبِي الطُّفَيْلِ قَالَلَمَّا قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَتْ فَاطِمَةُ إِلَى أَبِي بَكْرٍ أَنْتَ وَرِثْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْ أَهْلُهُ قَالَ فَقَالَ لَا بَلْ أَهْلُهُ قَالَتْ فَأَيْنَ سَهْمُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ أَبُو بَكْرٍ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ إِذَا أَطْعَمَ نَبِيًّا طُعْمَةً ثُمَّ قَبَضَهُ جَعَلَهُ لِلَّذِي يَقُومُ مِنْ بَعْدِهِ فَرَأَيْتُ أَنْ أَرُدَّهُ عَلَى الْمُسْلِمِينَ فَقَالَتْ فَأَنْتَ وَمَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْلَمُ","id":"Telah menceritakan kepada kami [Abdullah Bin Muhammad Bin Abu Syaibah]. Abdullah berkata; dan aku telah mendengarnya dari Abdullah Bin Abu Syaibah, dia berkata; Telah menceritakan kepada kami [Muhammad Bin Fudlail] dari [Al Walid Bin Jumai'] dari [Abu Ath Thufail] dia berkata; ketika Rasulullah wafat, Fathimah menulis surat kepada Abu Bakar yang berisi; \"Apakah kamu atau keluarganya yang mewarisi Rasulullah shallallahu 'alaihi wasallam?\" Dia menjawab; \"Aku tidak mewarisinya, tetapi keluarganyalah yang mewarisinya, \" Fathimah berkata; \"Lalu dimanakah saham Rasulullah shallallahu 'alaihi wasallam?\" Maka [Abu Bakar] berkata; \"Sesungguhnya aku mendengar Rasulullah bersabda; \"Sesungguhnya apabila Allah memberi makan seorang Nabi, kemudian mewafatkannya, maka Dia (Allah) menjadikannya untuk orang yang datang setelahnya\", maka aku berniat mengembalikannya kepada kaum Muslimin.\" kemudian Fathimah berkata; \"Kalau demikian, kamu lebih tahu atas apa yang telah kamu dengar dari Rasulullah.\""},"11":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَاقَ عَنْ حَارِثَةَ قَالَجَاءَ نَاسٌ مِنْ أَهْلِ الشَّامِ إِلَى عُمَرَ رَضِيَ اللَّهُ عَنْهُ فَقَالُوا إِنَّا قَدْ أَصَبْنَا أَمْوَالًا وَخَيْلًا وَرَقِيقًا نُحِبُّ أَنْ يَكُونَ لَنَا فِيهَا زَكَاةٌ وَطَهُورٌ قَالَ مَا فَعَلَهُ صَاحِبَايَ قَبْلِي فَأَفْعَلَهُ وَاسْتَشَارَ أَصْحَابَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِيهِمْ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَقَالَ عَلِيٌّ هُوَ حَسَنٌ إِنْ لَمْ يَكُنْ جِزْيَةً رَاتِبَةً يُؤْخَذُونَ بِهَا مِنْ بَعْدِكَ","id":"Telah menceritakan kepada kami [Abdurrahman Bin Mahdi] dari [Sufyan] dari [Abu Ishaq] dari [Haritsah] dia berkata; sekelompok orang dari syam datang kepada Umar, kemudian mereka berkata; \"Sesungguhnya kami mempunyai harta, kuda dan budak, dan kami ingin mengeluarkan zakat dan pensucinya.\" [Umar] menjawab; \"Sebagaimana yang dilakukan oleh kedua sahabatku sebelumku maka aku akan melakukan seperti yang dilakukan mereka berdua.\" Kemudian dia bermusyawarah dengan para sahabat Nabi Muhammad shallallahu 'alaihi wasallam dan diantara mereka ada Ali, maka Ali berkata; \"Itu adalah baik jika itu bukan pajak rutin yang diambil dari mereka setelah kamu.\""},"12":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَمْرَو بْنَ مَيْمُونٍ قَالَصَلَّى بِنَا عُمَرُ بِجَمْعٍ الصُّبْحَ ثُمَّ وَقَفَ وَقَالَ إِنَّ الْمُشْرِكِينَ كَانُوا لَا يُفِيضُونَ حَتَّى تَطْلُعَ الشَّمْسُ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالَفَهُمْ ثُمَّ أَفَاضَ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar ['Amru Bin Maimun] berkata; [Umar] shalat shubuh bersama kami di Muzdalifah kemudian berdiri dan berkata; \"Sesungguhnya orang-orang musyrik tidak meninggalkan Muzdalifah sampai matahari terbit dan sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah menyelisihi mereka, sehingga beliau meninggalkan Muzdalifah sebelum matahari terbit.\""},"13":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ قَالَ قَالَ أَبِي فَحَدَّثَنَا بِهِ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاقَالَ وَمَا أَعْجَبَكَ مِنْ ذَلِكَ كَانَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ إِذَا دَعَا الْأَشْيَاخَ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَانِي مَعَهُمْ فَقَالَ لَا تَتَكَلَّمْ حَتَّى يَتَكَلَّمُوا قَالَ فَدَعَانَا ذَاتَ يَوْمٍ أَوْ ذَاتَ لَيْلَةٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي لَيْلَةِ الْقَدْرِ مَا قَدْ عَلِمْتُمْ فَالْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ وِتْرًا فَفِي أَيِّ الْوِتْرِ تَرَوْنَهَا","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Abdul Wahid Bin Ziyad] dia berkata; Telah menceritakan kepada kami ['Ashim Bin Kulaib] dia berkata; [bapakku] telah berkata; telah menceritakan kepada kami dengan hadits itu [Ibnu Abbas] dia berkata; \"Sesuatu yang akan sangat mengherankan kalian adalalah, bahwa [Umar] apabila mengundang tetua-tetua dari kalangan sahabat Muhammad shallallahu 'alaihi wasallam, dia juga mengundangku bersama mereka, dan berkata; \"Kamu jangan berkata sehingga mereka telah mereka berkata.\" Maka pada suatu hari atau malam dia mengundang kami dan berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda tentang lailatul Qadar sebagaimana kalian telah mengetahuinya, maka intailah dia pada malam malam sepuluh hari terakhir yang ganjil dan di waktu waktu yang kamu anggap ganjil.\""},"14":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَاصِمَ بْنَ عَمْرٍو الْبَجَلِيَّ يُحَدِّثُ عَنْ رَجُلٍ مِنْ الْقَوْمِ الَّذِينَ سَأَلُوا عُمَرَ بْنَ الْخَطَّابِفَقَالُوا لَهُ إِنَّمَا أَتَيْنَاكَ نَسْأَلُكَ عَنْ ثَلَاثٍ عَنْ صَلَاةِ الرَّجُلِ فِي بَيْتِهِ تَطَوُّعًا وَعَنْ الْغُسْلِ مِنْ الْجَنَابَةِ وَعَنْ الرَّجُلِ مَا يَصْلُحُ لَهُ مِنْ امْرَأَتِهِ إِذَا كَانَتْ حَائِضًا فَقَالَ أَسُحَّارٌ أَنْتُمْ لَقَدْ سَأَلْتُمُونِي عَنْ شَيْءٍ مَا سَأَلَنِي عَنْهُ أَحَدٌ مُنْذُ سَأَلْتُ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلَاةُ الرَّجُلِ فِي بَيْتِهِ تَطَوُّعًا نُورٌ فَمَنْ شَاءَ نَوَّرَ بَيْتَهُ وَقَالَ فِي الْغُسْلِ مِنْ الْجَنَابَةِ يَغْسِلُ فَرْجَهُ ثُمَّ يَتَوَضَّأُ ثُمَّ يُفِيضُ عَلَى رَأْسِهِ ثَلَاثًا وَقَالَ فِي الْحَائِضِ لَهُ مَا فَوْقَ الْإِزَارِ","id":"Telah menceritakan kepada kami [Muhammad Bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar ['Ashim Bin 'Amru Al Bajali] bercerita dari [seorang lelaki] di antara sekelompok kaum yang bertanya kepada [Umar Bin Al Khaththab]; \"Kami datang kepadamu hanya untuk menanyakan kepadamu tentang tiga hal; tentang shalat sunnahnya seorang lelaki di rumah, tentang mandi dari junub dan tentang apa yang diperbolehkan bagi laki-laki dari istrinya yang sedang haid.\" Maka Umar menjawab; \"Apakah kalian tukang sihir, kalian telah menanyakan kepadaku sesuatu yang tidak pernah ditanyakan oleh seorangpun sejak aku menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam?\" Daka dia berkata; \"Shalat sunnahnya seorang lelaki di rumahnya adalah cahaya, maka barang siapa yang berkehendak terangilah rumahnya.\" Dan dia menerangkan tentang mandi dari junub; \"Hendaknya mencuci kemaluannya kemudian berwudlu kemudian menyiram ke kepalanya sebanyak tiga kali\" dan dia menerangkan tentang istri yang sedang haid; \"Baginya adalah apa yang ada di atas kain (selain farji).\""},"15":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَسَحَ عَلَى الْخُفَّيْنِ وَأَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ سَأَلَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ عَنْ ذَلِكَ فَقَالَ نَعَمْ إِذَا حَدَّثَكَ سَعْدٌ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا فَلَا تَسْأَلْ عَنْهُ غَيْرَهُ","id":"Telah menceritakan kepada kami [Harun Bin Ma'ruf] dia berkata; Telah menceritakan kepada kami [Ibnu Wahab] dari ['Amru Bin Al Harits] dari [Abu An Nadlar] dari [Abu Salamah Bin Abdurrahman] dari [Abdullah Bin Umar] dari [Sa'd Bin Abi Waqqas] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau mengusap kedua khuf, dan Abdullah Bin Umar bertanya kepada [Umar] tentang hal itu kemudian dia menjawab; \"Ya, jika Sa'd menceritakan sesuatu dari Rasulullah shallallahu 'alaihi wasallam kepadamu maka jangan bertanya hal itu kepada selainnya.\""},"16":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى قَالَ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ الْغَطَفَانِيِّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمَرِيِّأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَامَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ ذَكَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ ثُمَّ قَالَ رَأَيْتُ رُؤْيَا لَا أُرَاهَا إِلَّا لِحُضُورِ أَجَلِي رَأَيْتُ كَأَنَّ دِيكًا نَقَرَنِي نَقْرَتَيْنِ قَالَ وَذَكَرَ لِي أَنَّهُ دِيكٌ أَحْمَرُ فَقَصَصْتُهَا عَلَى أَسْمَاءَ بِنْتِ عُمَيْسٍ امْرَأَةِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَتْ يَقْتُلُكَ رَجُلٌ مِنْ الْعَجَ��ِ قَالَ وَإِنَّ النَّاسَ يَأْمُرُونَنِي أَنْ أَسْتَخْلِفَ وَإِنَّ اللَّهَ لَمْ يَكُنْ لِيُضَيِّعَ دِينَهُ وَخِلَافَتَهُ الَّتِي بَعَثَ بِهَا نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ يَعْجَلْ بِي أَمْرٌ فَإِنَّ الشُّورَى فِي هَؤُلَاءِ السِّتَّةِ الَّذِينَ مَاتَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَنْهُمْ رَاضٍ فَمَنْ بَايَعْتُمْ مِنْهُمْ فَاسْمَعُوا لَهُ وَأَطِيعُوا وَإِنِّي أَعْلَمُ أَنَّ أُنَاسًا سَيَطْعَنُونَ فِي هَذَا الْأَمْرِ أَنَا قَاتَلْتُهُمْ بِيَدِي هَذِهِ عَلَى الْإِسْلَامِ أُولَئِكَ أَعْدَاءُ اللَّهِ الْكُفَّارُ الضُّلَّالُ وَايْمُ اللَّهِ مَا أَتْرُكُ فِيمَا عَهِدَ إِلَيَّ رَبِّي فَاسْتَخْلَفَنِي شَيْئًا أَهَمَّ إِلَيَّ مِنْ الْكَلَالَةِ وَايْمُ اللَّهِ مَا أَغْلَظَ لِي نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ مُنْذُ صَحِبْتُهُ أَشَدَّ مَا أَغْلَظَ لِي فِي شَأْنِ الْكَلَالَةِ حَتَّى طَعَنَ بِإِصْبَعِهِ فِي صَدْرِي وَقَالَ تَكْفِيكَ آيَةُ الصَّيْفِ الَّتِي نَزَلَتْ فِي آخِرِ سُورَةِ النِّسَاءِ وَإِنِّي إِنْ أَعِشْ فَسَأَقْضِي فِيهَا بِقَضَاءٍ يَعْلَمُهُ مَنْ يَقْرَأُ وَمَنْ لَا يَقْرَأُ وَإِنِّي أُشْهِدُ اللَّهَ عَلَى أُمَرَاءِ الْأَمْصَارِ إِنِّي إِنَّمَا بَعَثْتُهُمْ لِيُعَلِّمُوا النَّاسَ دِينَهُمْ وَيُبَيِّنُوا لَهُمْ سُنَّةَ نَبِيِّهِمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَرْفَعُوا إِلَيَّ مَا عُمِّيَ عَلَيْهِمْ ثُمَّ إِنَّكُمْ أَيُّهَا النَّاسُ تَأْكُلُونَ مِنْ شَجَرَتَيْنِ لَا أُرَاهُمَا إِلَّا خَبِيثَتَيْنِ هَذَا الثُّومُ وَالْبَصَلُ وَايْمُ اللَّهِ لَقَدْ كُنْتُ أَرَى نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجِدُ رِيحَهُمَا مِنْ الرَّجُلِ فَيَأْمُرُ بِهِ فَيُؤْخَذُ بِيَدِهِ فَيُخْرَجُ بِهِ مِنْ الْمَسْجِدِ حَتَّى يُؤْتَى بِهِ الْبَقِيعَ فَمَنْ أَكَلَهُمَا لَا بُدَّ فَلْيُمِتْهُمَا طَبْخًا قَالَ فَخَطَبَ النَّاسَ يَوْمَ الْجُمُعَةِ وَأُصِيبَ يَوْمَ الْأَرْبِعَاءِ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammam Bin Yahya] dia berkata; Telah menceritakan kepada kami [Qatadah] dari [Salim Bin Abul Ja'd Al Ghatafani] dari [Ma'dan Bin Abu Thalhah Al Ya'mari] bahwa [Umar Bin Al Khaththab] berdiri di atas mimbar pada hari Jum'at, kemudian memuji dan mengagungkan Allah lalu menyebutkan Rasulullah shallallahu 'alaihi wasallam dan Abu bakar, kemudian berkata; \"Aku bermimpi dan aku menganggapnya itu adalah pertanda akan tibanya ajalku, aku bermimpi seakan akan seekor ayam jantan mematukku dua kali.\" Ma'dan berkata; dia (Umar) menyebutkan bahwa ayamnya berwarna merah, kemudian aku ceritakan kepada Asma' Binti Umais istri Abu Bakar, maka dia berkata; \"Seorang lelaki asing/selain arab akan membunuhmu.\" Umar berkata; \"Sesungguhnya orang-orang menyuruhku untuk mengangkat seorang pengganti, dan sesungguhnya Allah tidak akan menyia-nyiakan agama dan kekhilafahanNya, yang telah mengutus Nabi-Nya shallallahu 'alaihi wasallam dengan mengusungnya, dan jika ajal menjemputku maka urusan ini diserahkan didalam Syuraa (musyawarah) diantara enam orang yang ketika Nabiyullah shallallahu 'alaihi wasallam meninggal beliau ridla kepada mereka, maka siapa saja diantara mereka yang kalian bai'at hendaklah kalian dengar dan taati, dan sesungguhnya aku mengetahui akan ada orang-orang yang akan mengacaukan urusan ini, dan aku adalah yang akan memerangi mereka dengan tanganku atas dasar Islam, mereka itulah musuh musuh Allah, orang-orang kafir lagi sesat, demi Allah, aku tidak akan meninggalkan dari apa-apa yang telah Rabbku janjikan kepadaku kemudian menggantikanku dengan sesuatu yang lebih penting bagiku ketimbang Al Kalalah (seseorang yang meninggal dan tidak meninggalkan bapak serta anak), dan demi Allah, tidak pernah Nabiyullah shallallahu 'alaihi wasallam menegaskan sesuatu kepadaku tentang sesuatu sejak aku menemani beliau melebihi ketegasannya kepadaku dalam masalah kalalah sampai beliau menusukkan jarinya ke dadaku dan berkata: \"Cukup bagimu ayat tentang shaif yang ada di akhir surat An Nisa', sesungguhnya jika aku hidup maka aku akan putuskan masalah itu dengan keputusan yang dapat diketahui oleh orang yang membaca dan orang yang tidak membaca, dan aku bersaksi kepada Allah atas pemimpin pemimpin negri, bahwasannya aku mengutus mereka supaya mereka mengajarkan kepada manusia perihal urusan agama mereka dan agar supaya mereka menjelaskan tentang sunnah Nabi mereka shallallahu 'alaihi wasallam dan mengadukan kepadaku apa yang tidak mereka tidak ketahui, kemudian sesungguhnya kalian wahai manusia, kalian memakan dua pohon yang tidak aku anggap kecuali keduanya adalah menjijikan, yaitu bawang putih dan bawang merah ini, demi Allah aku telah melihat Nabiyullah shallallahu 'alaihi wasallam ketika mencium bau keduanya dari seorang lelaki, beliau menyuruhnya sambil memegang tangannya untuk keluar dari masjid sehingga diletakkan di Baqi', maka barangsiapa memakan keduanya hendaklah memasaknya hingga tidak ada baunya.\" Ma'dan berkata; \"Umar berkhutbah di hadapan manusia pada hari jum'at dan terbunuh pada hari Rabu.\""},"17":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى وَحُسَيْنُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ بَيْنَا هُوَ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ جَاءَ رَجُلٌ فَقَالَ عُمَرُ لِمَ تَحْتَبِسُونَ عَنْ الصَّلَاةِ فَقَالَ الرَّجُلُ مَا هُوَ إِلَّا أَنْ سَمِعْتُ النِّدَاءَ فَتَوَضَّأْتُ فَقَالَ أَيْضًا أَوَلَمْ تَسْمَعُوا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا رَاحَ أَحَدُكُمْ إِلَى الْجُمُعَةِ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Hasan Bin Musa] dan [Husain Bin Muhammad] keduanya berkata; Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] bahwa ketika Umar Bin Al Khaththab sedang berkhutbah pada hari Jum'at, tiba tiba datang seorang lelaki, maka Umar bertanya; \"Kenapa kalian menunda-nunda dari shalat?\" maka laki-laki tersebut menjawab; \"Tidak lain kecuali ketika aku mendangar adzan maka aku langsung berwudlu.\" [Umar] bertanya lagi; \"Bukankah kalian telah mengengar bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Jika kalian berangkat untuk shalat Jum'at maka mandilah.\""},"18":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي عُثْمَانَ قَالَجَاءَنَا كِتَابُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ وَنَحْنُ بِأَذْرَبِيجَانَ يَا عُتْبَةَ بْنَ فَرْقَدٍ وَإِيَّاكُمْ وَالتَّنَعُّمَ وَزِيَّ أَهْلِ الشِّرْكِ وَلَبُوسَ الْحَرِيرِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا عَنْ لَبُوسِ الْحَرِيرِ وَقَالَ إِلَّا هَكَذَا وَرَفَعَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِصْبَعَيْهِ","id":"Telah menceritakan kepada kami [Hasan Bin Musa] dia berkata; Telah menceritakan kepada kami [Zuhair] dia berkata; Telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abu Utsman] dia berkata; telah datang kepada kami surat dari [Umar], dan kami pada saat itu berada di Azerbaijan, yang isinya; \"Wahai Utbah Bin Farqad, janganlah kalian bersenang-senang dan mengenakan perhiasan orang-orang musyrik, serta memakai pakaian sutra, karena sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kami memakai sutra, kemudian beliau bersabda: \"Kecuali begini \"dan Rasulullah shallallahu 'alaihi wasallam mengangkat kedua jarinya kepada kami.\""},"19":{"ar":"حَدَّثَنَا حَسَنٌ قَالَ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الْأَسْوَدِ أَنَّهُ سَمِعَ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ ابْنِ لَبِيبَةَ يُحَدِّثُ عَنْ أَبِي سِنَانٍ الدُّؤَلِيِّأَنَّهُ دَخَلَ عَلَى عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ وَعِنْدَهُ نَفَرٌ مِنْ الْمُهَاجِرِينَ الْأَوَّلِينَ فَأَرْسَلَ عُمَرُ إِلَى سَفَطٍ أُتِيَ بِهِ مِنْ قَلْعَةٍ مِنْ الْعِرَاقِ فَكَانَ فِيهِ خَاتَمٌ فَأَخَذَهُ بَعْضُ بَنِيهِ فَأَدْخَلَهُ فِي فِيهِ فَانْتَزَعَهُ عُمَرُ مِنْهُ ثُمَّ بَكَى عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَقَالَ لَهُ مَنْ عِنْدَهُ لِمَ تَبْكِي وَقَدْ فَتَحَ اللَّهُ لَكَ وَأَظْهَرَكَ عَلَى عَدُوِّكَ وَأَقَرَّ عَيْنَكَ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُفْتَحُ الدُّنْيَا عَلَى أَحَدٍ إِلَّا أَلْقَى اللَّهُ عَزَّ وَجَلَّ بَيْنَهُمْ الْعَدَاوَةَ وَالْبَغْضَاءَ إِلَى يَوْمِ الْقِيَامَةِ وَأَنَا أُشْفِقُ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Hasan] dia berkata; Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Abu Al Aswad] bahwa dia mendengar [Muhammad Bin Abdurrahman Bin Labibah] bercerita dari [Abu Sinan Ad Dauli], bahwa dia datang menemui [Umar Bin Al Khaththab], dan di sisinya ada orang-orang muhajirin pendahulu, kemudian Umar mengeluarkan keranjang yang didatangkan dari sebuah benteng di Irak yang di dalamnya ada cincin, kemudian cincin itu diambil oleh salah seorang anaknya dan dimasukkan ke dalam mulutnya, maka Umar mengeluarkan dari mulutnya kemudian Umar menangis, orang-orang yang ada di sampingnya bertanya; \"Kenapa kamu menangis, bukankah Allah telah menaklukkan bagimu dan memenangkanmu dari musuh musuhmu serta membuat tentram pandanganmu?\" Umar menjawab; \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah dunia dibukakan kepada seorang hamba, kecuali Allah akan menjadikan kebencian dan permusuhan diantara mereka pada hari Kiamat.\" dan saya takut yang demikian itu.\" "},"20":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا تُوُفِّيَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ دُعِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلصَّلَاةِ عَلَيْهِ فَقَامَ إِلَيْهِ فَلَمَّا وَقَفَ عَلَيْهِ يُرِيدُ الصَّلَاةَ تَحَوَّلْتُ حَتَّى قُمْتُ فِي صَدْرِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعَلَى عَدُوِّ اللَّهِ عَبْدِ اللَّهِ بْنِ أُبَيٍّ الْقَائِلِ يَوْمَ كَذَا كَذَا وَكَذَا يُعَدِّدُ أَيَّامَهُ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَبَسَّمُ حَتَّى إِذَا أَكْثَرْتُ عَلَيْهِ قَالَ أَخِّرْ عَنِّي يَا عُمَرُ إِنِّي خُيِّرْتُ فَاخْتَرْتُ وَقَدْ قِيلَ{ اسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِنْ تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَنْ يَغْفِرَ اللَّهُ لَهُمْ }لَوْ أَعْلَمُ أَنِّي إِنْ زِدْتُ عَلَى السَّبْعِينَ غُفِرَ لَهُ لَزِدْتُ قَالَ ثُمَّ صَلَّى عَلَيْهِ وَمَشَى مَعَهُ فَقَامَ عَلَى قَبْرِهِ حَتَّى فُرِغَ مِنْهُ قَالَ فَعَجَبٌ لِي وَجَرَاءَتِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَوَاللَّهِ مَا كَانَ إِلَّا يَسِيرًا حَتَّى نَزَلَتْ هَاتَانِ الْآيَتَانِ{ وَلَا تُصَلِّ عَلَى أَحَدٍ مِنْهُمْ مَاتَ أَبَدًا وَلَا تَقُمْ عَلَى قَبْرِهِ إِنَّهُمْ كَفَرُوا بِاللَّهِ وَرَسُولِهِ وَمَاتُوا وَهُمْ فَاسِقُونَ }فَمَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَهُ عَلَى مُنَافِقٍ وَلَا قَامَ عَلَى قَبْرِهِ حَتَّى قَبَضَهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] Telah menceritakan kepadaku [Az Zuhri] dari [Ubaidullah Bin Abdullah Bin 'Utbah Bin Mas'ud] dari [Abdullah bin Abbas], dia berkata; aku mendengar [Umar Bin Khattab] berkata; ketika Abdullah Bin Ubai meninggal, Rasulullah shallallahu 'alaihi wasallam dipanggil untuk menshalatinya, maka beliau bergegas mendatanginya, tatkala beliau berdiri dihadapannya untuk menshalatinya aku menghalanginya sehingga aku berdiri dihadapan beliau dan berkata; \"Wahai Rasulullah, Abdullah Bin Ubai adalah dedengkot musuh Allah yang mengatakan pada hari ini dan ini, \" dia menyebutkan nama nama harinya, kemudian Umar melanjutkan; akan tetapi Rasulullah shallallahu 'alaihi wasallam hanya tersenyum sampai ketika aku mengulang-ngulang perkataanku beliau berkata: \"Minggirlah dariku wahai Umar, sesungguhnya aku di beri pilihan maka aku memilih, dan sudah di sebutkan: \"Kamu memohonkan ampun bagi mereka atau tidak kamu mohonkan ampun bagi mereka (adalah sama saja). kendatipun kamu memohonkan ampun bagi mereka tujuh puluh kali, namun Allah sekali-kali tidak akan memberi ampunan kepada mereka.'\" (QS Al Anfal ayat 80) seandainya aku tahu apabila aku menambah permohonanku sampai tujuh puluh kali dia akan mendapat ampunan niscaya aku akan tambah\" Umar berkata; kemudian beliau menshalatinya dan mengantarkan jenazahnya lalu berdiri di atas kuburannya sampai selesai dimakamkan, \" Umar berkata; \"aku heran dengan diriku atas lancangnya diriku kepada Rasulullah shallallahu 'alaihi wasallam, padahal Allah dan Rasul-Nya lebih tahu\" Umar berkata lagi; \"maka demi Allah tidak lama kemudian turunlah dua ayat ini (QS At Taubah ayat 80, 84).\"Dan janganlah kamu sekali-kali menyembahyangkan (jenazah) seorang yang mati di antara mereka, dan janganlah kamu berdiri (mendoakan) di kuburnya. Sesungguhnya mereka Telah kafir kepada Allah dan rasul-Nya dan mereka mati dalam keadaan fasik\". Kemudian Rasulullah shallallahu 'alaihi wasallam setelah itu tidak pernah lagi menshalati orang munafiq dan tidak juga berdiri di atas quburannya."},"21":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ أَخْبَرَنِي أَبِي أَنَّ حُمْرَانَ أَخْبَرَهُ قَالَتَوَضَّأَ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ عَلَى الْبَلَاطِ ثُمَّ قَالَ لَأُحَدِّثَنَّكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا آيَةٌ فِي كِتَابِ اللَّهِ مَا حَدَّثْتُكُمُوهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ دَخَلَ فَصَلَّى غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الصَّلَاةِ الْأُخْرَى حَتَّى يُصَلِّيَهَا","id":"Telah menceritakan kepada kami [Yahya Bin Sa'id] dari [Hisyam Bin 'Urwah] telah mengabarkan kepadaku [bapakku] bahwa [Humran] telah mengabarkan kepadanya, dia berkata; ['Utsman] berwudlu di atas lantai kemudian dia berkata; \"Sungguh aku akan ceritakan kepada kalian sebuah hadits yang telah aku dengar dari Rasulullah shallallahu 'alaihi wasallam, seandainya bukan karena sebuah ayat dalam Kitabullah, tentu aku tidak akan menceritakannya kepada kalian, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu dan membaguskan wudlunya kemudian dia masuk masjid dan melaksanakan shalat, niscaya akan diampuni dosanya antara wudlunya dengan shalat yang lain yang dia laksanakan.\""},"22":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مَالِكٍ حَدَّثَنِي نَافِعٌ عَنْ نُبَيْهِ بْنِ وَهْبٍ عَنْ أَبَانَ بْنِ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُحْرِمُ لَا يَنْكِحُ وَلَا يُنْكِحُ وَلَا يَخْطُبُ","id":"Telah menceritakan kepada kami [Yahya Bin Sa'id] dari [Malik] Telah menceritakan kepadaku [Nafi'] dari [Nubaih Bin Wahab] dari [Aban Bin Utsman] dari [bapaknya], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang sedang melaksanakan ihram tidak boleh menikah, tidak boleh menikahkan dan tidak boleh mengkhitbah.\""},"23":{"ar":"حَدَّثَنَا يَحْيَى عَنِ ابْنِ حَرْمَلَةَ قَالَ سَمِعْتُ سَعِيدًا يَعْنِي ابْنَ الْمُسَيَّبِ قَالَخَرَجَ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ حَاجًّا حَتَّى إِذَا كَانَ بِبَعْضِ الطَّرِيقِ قِيلَ لِعَلِيٍّ رِضْوَانُ اللَّهِ عَلَيْهِمَا إِنَّهُ قَدْ نَهَى عَنْ التَّمَتُّعِ بِالْعُمْرَةِ إِلَى الْحَجِّ فَقَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ لِأَصْحَابِهِ إِذَا ارْتَحَلَ فَارْتَحِلُوا فَأَهَلَّ عَلِيٌّ وَأَصْحَابُهُ بِعُمْرَةٍ فَلَمْ يُكَلِّمْهُ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ فِي ذَلِكَ فَقَالَ لَهُ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ أَلَمْ أُخْبَرْ أَنَّكَ نَهَيْتَ عَنْ التَّمَتُّعِ بِالْعُمْرَةِ قَالَ فَقَالَ بَلَى قَالَ فَلَمْ تَسْمَعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمَتَّعَ قَالَ بَلَى","id":"Telah menceritakan kepada kami [Yahya] dari [Ibnu Harmalah] dia berkata; aku mendengar [Sa'id yaitu Ibnul Musayyib] berkata; \" [Utsman Bin Affan] keluar untuk melaksanakan haji dan ketika sampai di tengah perjalanan, dikatakan kepada Ali bahwa dia (Utsman) telah melarang dari tamattu' dalam Umrah sampai haji, maka [Ali] berkata kepada para sahabatnya; \"Jika dia berjalan maka berjalanlah kalian.\" Kemudian Ali dan para sahabatnya memulai niat Umrah, dan Utsman tidak menyampaikan kepadanya, maka Ali berkata kepadanya; \"Aku tidak diberitahu bahwa kamu telah melarang dari Tamattu' dalam Umrah\" -Said Bin Al Musayyib berkata- maka Utsman menjawab; \"Ya.\" Ali berkata; \"Tidakkah kamu mendengar bahwa Rasulullah shallallahu 'alaihi wasallam melakukan tamattu'?\" Utsman menjawab; \"Ya.\""},"24":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي النَّضْرِ عَنْ أَبُو أَنَسٍأَنَّ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ تَوَضَّأَ بِالْمَقَاعِدِ ثَلَاثًا ثَلَاثًا وَعِنْدَهُ رِجَالٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَيْسَ هَكَذَا رَأَيْتُمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ قَالُوا نَعَمْ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Abu An Nadlar] dari [Abu Anas] bahwa [Utsman] berwudlu sambil duduk dibangku tiga kali tiga kali, sementara di sampingnya [para sahabat] Rasulullah shallallahu 'alaihi wasallam, dia (Utsman) bertanya; \"Bukankah kalian melihat Rasulullah berwudlu seperti ini?\" Para sahabat menjawab; \"ya.\""},"25":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ وَعَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dan [Abdurrahman] dari [Sufyan] dari ['Alqamah Bin Martsad] dari [Abu Abdurrahman] dari [Utsman], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang paling utama diantara kalian adalah yang belajar Al Qur'an dan mengajarkannya.\""},"26":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ قَالَ قَالَ قَيْسٌ فَحَدَّثَنِي أَبُو سَهْلَةَ أَنَّ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُقَالَ يَوْمَ الدَّارِ حِينَ حُصِرَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهِدَ إِلَيَّ عَهْدًا فَأَنَا صَابِرٌ عَلَيْهِقَالَ قَيْسٌ فَكَانُوا يَرَوْنَهُ ذَلِكَ الْيَوْمَ","id":"Telah menceritakan kepada kami [Waki'] dari [Isma'il Bin Abu Khalid] dia berkata; [Qais] berkata; Telah menceritakan kepada kami [Abu Sahlah] bahwa [Utsman] berkata pada saat dikepung di rumahnya; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah mewasiatkan kepadaku sebuah wasiat maka aku bersabar dengannya.\" Qais berkata; \"Kemudian mereka melihatnya hari itu.\""},"27":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ وَعَبْدُ الرَّزَّاقِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ حَكِيمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ عُثْمَانَ بْنِ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ قَالَ عَبْدُ الرَّزَّاقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ مَنْ صَلَّى صَلَاةَ الْعِشَاءِ وَالصُّبْحِ فِي جَمَاعَةٍ فَهُوَ كَقِيَامِ لَيْلَةٍ وَقَالَ عَبْدُ الرَّحْمَنِ مَنْ صَلَّى الْعِشَاءَ فِي جَمَاعَةٍ فَهُوَ كَقِيَامِ نِصْفِ لَيْلَةٍ وَمَنْ صَلَّى الصُّبْحَ فِي جَمَاعَةٍ فَهُوَ كَقِيَامِ لَيْلَةٍ","id":"Telah menceritakan kepada kami [Abdurrahman] Telah menceritakan kepada kami [Sufyan] dan [Abdurrazzaq] keduanya berkata; Telah menceritakan kepada kami [Sufyan] dari [Utsman Bin Hakim] dari [Abdurrahman Bin Abu 'Amrah] dari [Utsman Bin Affan] dia berkata; -Abdurrazzaq berkata; \"Utsman berkata dari Nabi shallallahu 'alaihi wasallam, - bahwa beliau bersabda: \"Barangsiapa melaksanakan shalat Isya dan shubuh dengan berjama'ah maka baginya seperti shalat malam.\" -Dan Abdurrahman berkata; - \"Barangsiapa shalat Isya dengan berjamaah maka baginya seperti shalat separuh malam, dan barangsiapa shalat shubuh dengan berjama'ah maka baginya seperti shalat satu malam.\""},"28":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عُثْمَانَ بْنِ عَفَّانَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى الْعِشَاءَ فِي جَمَاعَةٍ فَهُوَ كَمَنْ قَامَ نِصْفَ اللَّيْلِ وَمَنْ صَلَّى الصُّبْحَ فِي جَمَاعَةٍ فَهُوَ كَمَنْ قَامَ اللَّيْلَ كُلَّهُ","id":"Telah menceritakan kepada kami [Abdul Malik Bin 'Amru] Telah menceritakan kepada kami ['Ali Bin Al Mubarak] dari [Yahya yaitu Ibnu Abi Katsir] dari [Muhammad Bin Ibrahim] dari [Utsman Bin Affan], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melaksanakan shalat Isya berjama'ah, maka pahalanya sebagaimana dia melaksanakan shalat separuh malam, dan barangsiapa melaksanakan shalat Shubuh berjama'ah, maka pahalanya sebagaimana dia melaksanakan shalat sepanjang malam.\""},"29":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَكُنْتُ مَعَ ابْنِ مَسْعُودٍ وَهُوَ عِنْدَ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ لَهُ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ مَا بَقِيَ لِلنِّسَاءِ مِنْكَ قَالَ فَلَمَّا ذُكِرَتْ النِّسَاءُ قَالَ ابْنُ مَسْعُودٍ ادْنُ يَا عَلْقَمَةُ قَالَ وَأَنَا رَجُلٌ شَابٌّ فَقَالَ لَهُ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فِتْيَةٍ مِنْ الْمُهَاجِرِينَ فَقَالَ مَنْ كَانَ مِنْكُمْ ذَا طَوْلٍ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلطَّرْفِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَا فَإِنَّ الصَّوْمَ لَهُ وِجَاءٌ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Yunus Bin 'Ubaid] dari [Abu Ma'syar] dari [Ibrahim] dari ['Alqamah] dia berkata; aku bersama Ibnu Mas'ud di sisi Utsman, kemudian Utsman bertanya kepadanya; \"apa yang kamu sisakan untuk istrimu?\" 'Alqamah berkata; maka ketika disebut istri, Ibnu Mas'ud berkata; \"Mendekatlah wahai 'Alqamah\" dia berkata; dan saya ketika itu masih bujang. maka [Utsman] berkata kepadanya; \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam keluar menemui sekelompok pemuda muhajirin dan berkata: \"Barangsiapa diantara kalian memiliki kemampuan maka menikahlah, karena dengan menikah dapat lebih menjaga pandangan dan dapat lebih menjaga kemaluan (menahan gejolak syahwat), dan barangsiapa belum mampu maka puasa adalah sebagai benteng baginya.\" "},"30":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَبَهْزٌ وَحَجَّاجٌ قَالُوا حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَلْقَمَةَ بْنَ مَرْثَدٍ يُحَدِّثُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عُثْمَانَ بْنِ عَفَّانَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ خَيْرَكُمْ مَنْ عَلَّمَ الْقُرْآنَ أَوْ تَعَلَّمَهُقَالَ مُحَمَّدُ بْنُ جَعْفَرٍ وَحَجَّاجٌ فَقَالَ أَبُو عَبْدِ الرَّحْمَنِ فَذَاكَ الَّذِي أَقْعَدَنِي هَذَا الْمَقْعَدَ قَالَ حَجَّاجٌ قَالَ شُعْبَةُ وَلَمْ يَسْمَعْ أَبُو عَبْدِ الرَّحْمَنِ مِنْ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ وَلَا مِنْ عَبْدِ اللَّهِ وَلَكِنْ قَدْ سَمِعَ مِنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ أَبِي وَقَالَ بَهْزٌ عَنْ شُعْبَةَ قَالَ عَلْقَمَةُ بْنُ مَرْثَدٍ أَخْبَرَنِي وَقَالَ خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَلْقَمَةُ بْنُ مَرْثَدٍ وَقَالَ فِيهِ مَنْ تَعَلَّمَ الْقُرْآنَ أَوْ عَلَّمَهُ","id":"Telah menceritakan kepada kami [Muhammad Bin Ja'far], [Bahz] dan [Hajjaj] mereka berkata; Telah menceritakan kepada kami [Syu'bah], dia berkata; aku mendengar ['Alqamah Bin Martsad] bercerita dari [Sa'd Bin 'Ubaidah] dari [Abu Abdurrahman As Sulami] dari [Utsman Bin Affan], dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Sesungguhnya sebaik baik kalian adalah orang yang mengajarkan Al Qur'an atau mempelajarinya.\" Muhammad Bin Ja'far dan Hajjaj Berkata; Abu Abdurrahman berkata; \"Itulah yang membuat aku duduk ditempat duduk ini.\" Hajjaj berkata; Syu'bah berkata; \"Abu Abdurrahman tidak mendengar dari Utsman dan juga tidak dari Abdullah, akan tetapi dia mendengar dari Ali.\" Bapakku berkata; dan Bahz berkata, dari Syu'bah, dia berkata; 'Alqamah Bin Martsad telah mengabarkan kepadaku; Dan beliau bersabda berkata: \"sebaik-baik kalian adalah orang yang belajar Al Qur`an dan mengajarkannya.\" Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami ['Alqamah Bin Martsad] dan dihadits ini, dia berkata; \"Orang yang belajar Al Qur`an atau mengajarkannya.\""},"31":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ عَيَّاشِ بْنِ أَبِي رَبِيعَةَ عَنْ زَيْدِ بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَوَقَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَقَالَ هَذَا الْمَوْقِفُ وَعَرَفَةُ كُلُّهَا مَوْقِفٌ وَأَفَاضَ حِينَ غَابَتْ الشَّمْسُ ثُمَّ أَرْدَفَ أُسَامَةَ فَجَعَلَ يُعْنِقُ عَلَى بَعِيرِهِ وَالنَّاسُ يَضْرِبُونَ يَمِينًا وَشِمَالًا يَلْتَفِتُ إِلَيْهِمْ وَيَقُولُ السَّكِينَةَ أَيُّهَا النَّاسُ ثُمَّ أَتَى جَمْعًا فَصَلَّى بِهِمْ الصَّلَاتَيْنِ الْمَغْرِبَ وَالْعِشَاءَ ثُمَّ بَاتَ حَتَّى أَصْبَحَ ثُمَّ أَتَى قُزَحَ فَوَقَفَ عَلَى قُزَحَ فَقَالَ هَذَا الْمَوْقِفُ وَجَمْعٌ كُلُّهَا مَوْقِفٌ ثُمَّ سَارَ حَتَّى أَتَى مُحَسِّرًا فَوَقَفَ عَلَيْهِ فَقَرَعَ نَاقَتَهُ فَخَبَّتْ حَتَّى جَازَ الْوَادِيَ ثُمَّ حَبَسَهَا ثُمَّ أَرْدَفَ الْفَضْلَ وَسَارَ حَتَّى أَتَى الْجَمْرَةَ فَرَمَاهَا ثُمَّ أَتَى الْمَنْحَرَ فَقَالَ هَذَا الْمَنْحَرُ وَمِنًى كُلُّهَا مَنْحَرٌ قَالَ وَاسْتَفْتَتْهُ جَارِيَةٌ شَابَّةٌ مِنْ خَثْعَمَ فَقَالَتْ إِنَّ أَبِي شَيْخٌ كَبِيرٌ قَدْ أَفْنَدَ وَقَدْ أَدْرَكَتْهُ فَرِيضَةُ اللَّهِ فِي الْحَجِّ فَهَلْ يُجْزِئُ عَنْهُ أَنْ أُؤَدِّيَ عَنْهُ قَالَ نَعَمْ فَأَدِّي عَنْ أَبِيكِ قَالَ وَقَدْ لَوَى عُنُقَ الْفَضْلِ فَقَالَ لَهُ الْعَبَّاسُ يَا رَسُولَ اللَّهِ لِمَ لَوَيْتَ عُنُقَ ابْنِ عَمِّكَ قَالَ رَأَيْتُ شَابًّا وَشَابَّةً فَلَمْ آمَنْ الشَّيْطَانَ عَلَيْهِمَا قَالَ ثُمَّ جَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ حَلَقْتُ قَبْلَ أَنْ أَنْحَرَ قَالَ انْحَرْ وَلَا حَرَجَ ثُمَّ أَتَاهُ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَفَضْتُ قَبْلَ أَنْ أَحْلِقَ قَالَ احْلِقْ أَوْ قَصِّرْ وَلَا حَرَجَ ثُمَّ أَتَى الْبَيْتَ فَطَافَ بِهِ ثُمَّ أَتَى زَمْزَمَ فَقَالَ يَا بَنِي عَبْدِ الْمُطَّلِبِ سِقَايَتَكُمْ وَلَوْلَا أَنْ يَغْلِبَكُمْ النَّاسُ عَلَيْهَا لَنَزَعْتُ بِهَا","id":"Telah menceritakan kepada kami [Abu Ahmad Muhammad Bin Abdullah Bin Az Zubair] Telah menceritakan kepada kami [Sufyan] dari [Abdurrahman Bin Al Harits Bin 'Ayyasy Bin Abu Rabi'ah] dari [Zaid Bin Ali] dari [bapaknya] dari [Ubaidullah Bin Abu Rafi'] dari [Ali Bin Abu Thalib], dia berkata; Rasulullah shallallahu 'alaihi wasallam melaksanakan wuquf di Arafah lalu bersabda: \"Ini adalah tempat wuquf, dan semua Arafah adalah tempat wuquf.\" Lalu beliau bertolak (meninggalkan Arafah) ketika matahari terbenam, kemudian beliau membonceng Usamah dan menjalankan untanya dengan perlahan sementara orang-orang berdesak desakan ke kanan dan ke kiri, lalu beliau menoleh ke arah orang-orang seraya bersabda: \"Wahai orang-orang, tenanglah, \" kemudian beliau tiba di jam'un (Muzdalifah) dan melaksanakan dua Shalat bersama mereka yaitu Maghrib dan Isya, lalu beliau bermalam hingga shubuh, kemudian beliau pergi ke arah Quzah dan berdiri di atasnya seraya bersabda: \"Ini adalah tempat berhenti dan semua muzdalifah adalah tempat berhenti.\" Lalu beliau melanjutkan perjalanannya hingga sampai di lembah Muhassir dan berhenti di sana, kemudian beliau menarik (tali kekang untanya) secara perlahan dan untanyapun menurut hingga melewati lembah lalu beliau mengikatnya, kemudian beliau membonceng Al Fadlal dan berjalan hingga sampai di jamarat (lokasi lempar jumrah), kemudian beliau melempar. Lalu beliau pergi ke manhar (tempat penyembelihan hewan) dan beliau bersabda: \"Ini adalah manhar (tempat penyembelihan hewan) dan mina semuanya adalah manhar.\" Ali berkata kemudian ada seorang gadis dari Khats'am datang meminta fatwa kepada beliau dan bekata; \"Sesungguhnya bapakku sudah lanjut usia sementara kewajiban dari Allah berupa haji telah wajib baginya, maka apakah sah baginya jika aku yang menggantikan hajinya?\" Beliau menjawab: \"Ya, maka kerjakanlah untuk bapakmu.\" Ali berkata; dan beliau memalingkan leher Al Fadlal, sehingga Al Abbas berkata kepada beliau; \"Wahai Rasulullah, engkau telah palingkan leher anak pamanmu.\" Beliau menjawab: \"Karena aku melihat ada pemuda dan pemudi, maka keduanya tidak akan selamat dari Setan.\" Ali berkata; kemudian datanglah seorang lelaki dan bertanya; \"Wahai Rasulullah sesungguhnya aku telah mencukur sebelum menyembelih hewan?\" Beliau menjawab: \"Sembelihlah dan tidak mengapa.\" Kemudian datang yang lain dan bertanya; \"Wahai Rasulullah sesungguhnya aku melakukan Thawaf Ifadlah sebelum mencukur?\" Beliau menjawab; \"Cukurlah atau pendekkanlah dan tidak mengapa.\" Kemudian beliau menuju Ka'bah dan melaksanakan thawaf, lalu menuju air Zamzam kemudian beliau bersabda: \"Wahai Bani Abdul MuThalib, kalaulah bukan karena aku khawatir orang-orang akan mengalahkan kalian (berebut untuk memberikan minum dengan air zamzam), niscaya aku akan mengambilnya (sendiri).\" "},"32":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَبِي حَرْبِ بْنِ أَبِي الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَوْلُ الْغُلَامِ يُنْضَحُ عَلَيْهِ وَبَوْلُ الْجَارِيَةِ يُغْسَلُقَالَ قَتَادَةُ هَذَا مَا لَمْ يَطْعَمَا فَإِذَا طَعِمَا غُسِلَ بَوْلُهُمَا","id":"Telah menceritakan kepada kami [Abdush Shamad Bin Abdul Warits] Telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Abu Harb Bin Abul Aswad] dari [bapaknya] dari [Ali], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Air kencing bayi laki-laki (cara membersihkannya) cukup diperciki air, sedangkan air kencing bayi perempuan di cuci.\" Qatadah berkata; \"Cara seperti ini apabila keduanya (bayi laki-laki dan perempuan) belum makan makanan (selain Asi), akan tetapi apabila telah makan, maka air kencing keduanya harus dicuci.\" "},"33":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَاقَ عَنِ الْحَارِثِ عَنْ عَلِيٍّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَوَّذَ مَرِيضًا قَالَ أَذْهِبْ الْبَاسَ رَبَّ النَّاسِ اشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا","id":"Telah menceritakan kepada kami [Abu Sa'id] mantan budak Bani Hasyim, Telah menceritakan kepada kami [Israil] Telah menceritakan kepada kami [Abu Ishaq] dari [Al Harits] dari [Ali], dia berkata; apabila Rasulullah shallallahu 'alaihi wasallam memohonkan perlindungan untuk orang yang sedang sakit, beliau membaca: \"ADZHIBIL BA'SA RABBAN NAAS, ISYFI ANTASY SYAAFI LAA SYIFAA'A ILLAA SYIFAA`UKA SYIFAA`AN LAA YUGHAADIRU SAQAMAA (hilangkanlah rasa sakit wahai Rabb manusia, sembuhkanlah, Engkau maha menyembuhkan, tidak ada kesembuhan kecuali kesembuhan dari-Mu, yaitu kesembuhan yang tidak menyisakan sakit.\" "},"34":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَاقَ عَنِ الْحَارِثِ عَنْ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ مُؤَمِّرًا أَحَدًا دُونَ مَشُورَةِ الْمُؤْمِنِينَ لَأَمَّرْتُ ابْنَ أُمِّ عَبْدٍ","id":"Telah menceritakan kepada kami [Abu Sa'id] Telah menceritakan kepada kami [Israil] Telah menceritakan kepada kami [Abu Ishaq] dari [Al Harits] dari [Ali], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya aku mengangkat seseorang tanpa musyawarah dari kaum mukminin, niscaya aku telah mengangkat Ibnu Ummi 'Abd.\" "},"35":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا سَعِيدُ بْنُ سَلَمَةَ بْنِ أَبِي الْحُسَامِ مَدَنِيٌّ مَوْلًى لِآلِ عُمَرَ حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أُمِّهِ قَالَتْبَيْنَمَا نَحْنُ بِمِنًى إِذَا عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ هَذِهِ أَيَّامُ أَكْلٍ وَشُرْبٍ فَلَا يَصُومُهَا أَحَدٌ وَاتَّبَعَ النَّاسَ عَلَى جَمَلِهِ يَصْرُخُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Abu Sa'id] Telah menceritakan kepada kami [Sa'id Bin Salamah Bin Abu Al Husam] seorang penduduk Madinah mantan budak keluarga Umar, Telah menceritakan kepada kami [Yazid Bin Abdullah] dari [Abdullah Bin Abu Salamah] dari ['Amru Bin Sulaim] dari [ibunya] dia berkata; ketika kami sedang berada di Mina, tiba tiba [Ali Bin Abu Thalib] berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada saat ini adalah hari-hari makan dan minum, maka tidak boleh seorangpun berpuasa.\" Kemudian dia mengikuti orang-orang dengan menunggang untanya sambil mengucapkan hal tersebut. "},"36":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ وَحُسَيْنُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنِ الْحَارِثِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي رَكْعَتَيْ الْفَجْرِ عِنْدَ الْإِقَامَةِ","id":"Telah menceritakan kepada kami [Abu Sa'id] dan [Husain Bin Muhammad] keduanya berkata; Telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Al Harits] dari [Ali], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam melaksanakan Shalat sunnah dua rakaat fajar ketika Iqamah (hendak dikumandangkan).\""},"37":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ الثَّقَفِيُّ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ عَنِ الْحَارِثِ بْنِ يَزِيدَ الْعُكْلِيِّ عَنْ أَبِي زُرْعَةَ عَنْ عَبْدِ اللَّهِ بْنِ نُجَيٍّ قَالَقَالَ عَلِيٌّ كَانَتْ لِي سَاعَةٌ مِنْ السَّحَرِ أَدْخُلُ فِيهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنْ كَانَ قَائِمًا يُصَلِّي سَبَّحَ بِي فَكَانَ ذَاكَ إِذْنُهُ لِي وَإِنْ لَمْ يَكُنْ يُصَلِّي أَذِنَ لِي","id":"Telah menceritakan kepada kami [Abu Sa'id] Telah menceritakan kepada kami [Abdul Wahid Bin Ziyad Ats Tsaqafi] Telah menceritakan kepada kami [Umarah Bin Al Qa'qa'] dari [Al Harits Bin Yazid Al 'Ukli] dari [Abu Zur'ah] dari [Abdullah Bin Nujai] dia berkata; [Ali] berkata; \"Aku mempunyai waktu pada saat sahur untuk menemui Rasulullah shallallahu 'alaihi wasallam, apabila beliau sedang berdiri melakukan Shalat beliau bertasbih (membaca Subanallah) kepadaku, maka itu pertanda beliau mengizinkanku, dan apabila tidak sedang Shalat beliau langsung mengizinkanku.\""},"38":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَاقَ عَنِ الْحَارِثِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ يَغْتَسِلُونَ مِنْ إِنَاءٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Abu Sa'id] Telah menceritakan kepada kami [Israil] Telah menceritakan kepada kami [Abu Ishaq] dari [Al Harits] dari [Ali] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mandi dengan istrinya dalam satu bejana.\" "},"39":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا سِمَاكٌ عَنْ حَنَشٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَانْتَهَيْنَا إِلَى قَوْمٍ قَدْ بَنَوْا زُبْيَةً لِلْأَسَدِ فَبَيْنَا هُمْ كَذَلِكَ يَتَدَافَعُونَ إِذْ سَقَطَ رَجُلٌ فَتَعَلَّقَ بِآخَرَ ثُمَّ تَعَلَّقَ رَجُلٌ بِآخَرَ حَتَّى صَارُوا فِيهَا أَرْبَعَةً فَجَرَحَهُمْ الْأَسَدُ فَانْتَدَبَ لَهُ رَجُلٌ بِحَرْبَةٍ فَقَتَلَهُ وَمَاتُوا مِنْ جِرَاحَتِهِمْ كُلُّهُمْ فَقَامُوا أَوْلِيَاءُ الْأَوَّلِ إِلَى أَوْلِيَاءِ الْآخِرِ فَأَخْرَجُوا السِّلَاحَ لِيَقْتَتِلُوا فَأَتَاهُ��ْ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ عَلَى تَفِيئَةِ ذَلِكَ فَقَالَ تُرِيدُونَ أَنْ تَقَاتَلُوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيٌّ إِنِّي أَقْضِي بَيْنَكُمْ قَضَاءً إِنْ رَضِيتُمْ فَهُوَ الْقَضَاءُ وَإِلَّا حَجَزَ بَعْضُكُمْ عَنْ بَعْضٍ حَتَّى تَأْتُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَكُونَ هُوَ الَّذِي يَقْضِي بَيْنَكُمْ فَمَنْ عَدَا بَعْدَ ذَلِكَ فَلَا حَقَّ لَهُ اجْمَعُوا مِنْ قَبَائِلِ الَّذِينَ حَفَرُوا الْبِئْرَ رُبُعَ الدِّيَةِ وَثُلُثَ الدِّيَةِ وَنِصْفَ الدِّيَةِ وَالدِّيَةَ كَامِلَةً فَلِلْأَوَّلِ الرُّبُعُ لِأَنَّهُ هَلَكَ مَنْ فَوْقَهُ وَلِلثَّانِي ثُلُثُ الدِّيَةِ وَلِلثَّالِثِ نِصْفُ الدِّيَةِ فَأَبَوْا أَنْ يَرْضَوْا فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عِنْدَ مَقَامِ إِبْرَاهِيمَ فَقَصُّوا عَلَيْهِ الْقِصَّةَ فَقَالَ أَنَا أَقْضِي بَيْنَكُمْ وَاحْتَبَى فَقَالَ رَجُلٌ مِنْ الْقَوْمِ إِنَّ عَلِيًّا قَضَى فِينَا فَقَصُّوا عَلَيْهِ الْقِصَّةَ فَأَجَازَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادٌ أَنْبَأَنَا سِمَاكٌ عَنْ حَنَشٍ أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ قَالَ وَلِلرَّابِعِ الدِّيَةُ كَامِلَةً","id":"Telah menceritakan kepada kami [Abu Sa'id] Telah menceritakan kepada kami [Israil] Telah menceritakan kepada kami [Simak] dari [Hanasy] dari [Ali], dia berkata; Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman, setelah kami sampai pada suatu kaum yang sedang membuat lubang perlindung dari singa, ketika sedang demikian mereka saling mendorong, maka terjatuhlah salah seorang dan menggantung kepada yang lain dan yang lain menggantung kepada yang lainnya juga, hingga mereka menjadi empat yang bergelantungan, dan singa melukai mereka, kemudian seorang melempar singa dengan tombaknya hingga mati, sedangkan empat orang itu meninggal semuanya karena terluka, kemudian wali orang pertama datang kepada wali yang lain dan mengeluarkan senjata untuk saling bunuh, maka pada waktu itu datanglah Ali kepada mereka dan berkata; \"Apakah kalian akan berperang sementara Rasulullah shallallahu 'alaihi wasallam masih hidup? Sesungguhnya aku akan memutuskan perkara diantara kalian jika kalian ridla, dan itu merupakan sebaik baik keputusan, dan jika tidak maka persiapkanlah oleh sebagian kalian dengan sebagian yang lain, lalu datang kepada Nabi shallallahu 'alaihi wasallam dan dia yang akan memutuskan perkara kalian, dan barangsiapa melampau batas setelah itu maka tidak ada hak baginya, kumpulkanlah seperempat diyat, sepertiga diyat, setengah diyat dan diyat penuh dari kabilah kabilah orang yang menggali lubang.\" Maka orang pertama mendapatkan bagian seperempat diyat karena dia yang menyebabkan binasanya orang yang ada di atasnya, orang kedua mendapatkan bagian sepertiga diyat, dan orang ketiga mendapatkan bagian setengah diyat, namun mereka menolak tidak ridla, dan mendatangi Nabi shallallahu 'alaihi wasallam sementara beliau berada di Maqam Ibrahim, kemudian mereka menceritakan kepadanya, dan Rasulullah shallallahu 'alaihi wasallam menjawab: \"Aku akan memutuskan perkaranya diantara kalian.\" Dan beliau duduk mendekap lututnya, maka salah seorang dari mereka berkata; \"Sesungguhnya Ali telah memutuskan perkara kami, \" dan dia menceritakan kisahnya dan Rasulullah shallallahu 'alaihi wasallam menyetujuinya.Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad] telah mencertikan kepada kami [simak] dari [Hanasy] bahwa [Ali] berkata; \"Dan untuk orang keempat mendapatkan bagian diyah penuh.\" "},"40":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ كَتَبَ إِلَيَّ قُتَيْبَةُ بْنُ سَعِيدٍ كَتَبْتُ إِلَيْكَ بِخَطِّي وَخَتَمْتُ الْكِتَابَ بِخَاتَمِي يَذْكُرُ أَنَّ اللَّيْثَ بْنَ سَعْدٍ حَدَّثَهُمْ عَنْ عُقَيْلٍ عَنِ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ أَنَّ الْحُسَيْنَ بْنَ عَلِيٍّ حَدَّثَهُ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَقَهُ وَفَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَ أَلَا تُصَلُّونَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا أَنْفُسُنَا بِيَدِ اللَّهِ فَإِذَا شَاءَ أَنْ يَبْعَثَنَا بَعَثَنَا وَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قُلْتُ لَهُ ذَلِكَ ثُمَّ سَمِعْتُهُ وَهُوَ مُدْبِرٌ يَضْرِبُ فَخِذَهُ وَيَقُولُ{ وَكَانَ الْإِنْسَانُ أَكْثَرَ شَيْءٍ جَدَلًا }","id":"Telah menceritakan kepada kami Abdullah, dia berkata; [Qutaibah Bin Sa'id] menulis surat kepadaku yang berisi; aku tulis surat kepadamu dengan tulisanku sendiri, dan aku setempel suratnya dengan setempelku sendiri. Dia menyebutkan bahwa [Laits Bin Sa'd] telah bercerita kepada mereka dari [Uqail] dari [Az Zuhri] dari [Ali Bin Al Husain] bahwa [Al Husain Bin Ali] bercerita kepadanya dari [Ali Bin Abu Thalib], bahwa Nabi shallallahu 'alaihi wasallam mengetuk pintu (membangunkan) dia dan Fatimah radliallahu 'anhuma, kemudian beliau bersabda: \"Tidakkah kalian Shalat?\" Maka aku menjawab; \"Wahai Rasulullah hanyasannya jiwa kami berada di tangan Allah, jika Dia menghehendaki membangunkan kami pasti akan membangunkan kami.\" Kemudian Rasulullah shallallahu 'alaihi wasallam pergi ketika aku katakan demikian kepada beliau, namun aku mendengar beliau memukul pahanya ketika berlalu sambil membaca: (Dan manusia adalah makhluk yang paling banyak membantah.) (QS Al Kahfi: 54) "},"41":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ وَعَبْدُ الْجَبَّارِ بْنُ وَرْدٍ عَنِ ابْنِ أَبِي مُلَيْكَةَ قَالَ قَالَ طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ رَضِيَ اللَّهُ تَعَالَى عَنْهُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نِعْمَ أَهْلُ الْبَيْتِ عَبْدُ اللَّهِ وَأَبُو عَبْدِ اللَّهِ وَأُمُّ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Nafi' bin 'Amru] dan [Abdul Jabbar bin Al Ward] dari [Ibnu Abu Mulaikah] berkata; [Thalhah bin Ubaidullah radliallahu 'anhu] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik Ahlul Bait adalah Abdullah, Abu Abdullah dan Ummu Abdullah.\""},"42":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ مُعَاذِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّ عَنْ أَبِيهِ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ قَالَكُنَّا مَعَ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ وَنَحْنُ حُرُمٌ فَأُهْدِيَ لَهُ طَيْرٌ وَطَلْحَةُ رَاقِدٌ فَمِنَّا مَنْ أَكَلَ وَمِنَّا مَنْ تَوَرَّعَ فَلَمْ يَأْكُلْ فَلَمَّا اسْتَيْقَظَ طَلْحَةُ وَفَّقَ مَنْ أَكَلَهُ وَقَالَ أَكَلْنَاهُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Bakar] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Muhammad bin Al Munkadir] dari [Mu'adz bin Abdurrahman bin Utsman At Taimi] dari [bapaknya, Abdurrahman bin Utsman] berkata; kami bersama [Thalhah bin Ubaidullah] radliallahu 'anhu dalam keadaan berihram, kemudian dihadiahkan kepadanya daging burung. Saat itu dia sedang tidur. Maka di antara kami ada yang memakan dan ada yang menolak memakannya. Ketika Thalhah terjaga, dia sepakat dengan orang-orang yang memakannya dan berkata; \"Kami pernah memakannya bersama Rasulullah shallallahu 'alaihi wasallam.\""},"43":{"ar":"حَدَّثَنَا أَسْبَاطٌ حَدَّثَنَا مُطَرِّفٌ عَنْ عَامِرٍ عَنْ يَحْيَى بْنِ طَلْحَةَ عَنْ أَبِيهِ قَالَرَأَى عُمَرُ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ ثَقِيلًا فَقَالَ مَا لَكَ يَا أَبَا فُلَانٍ لَعَلَّكَ سَاءَتْكَ إِمْرَةُ ابْنِ عَمِّكَ يَا أَبَا فُلَانٍ قَالَ لَا إِلَّا أَنِّي سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا مَا مَنَعَنِي أَنْ أَسْأَلَهُ عَنْهُ إِلَّا الْقُدْرَةُ عَلَيْهِ حَتَّى مَاتَ سَمِعْتُهُ يَقُولُ إِنِّي لَأَعْلَمُ كَلِمَةً لَا يَقُولُهَا عَبْدٌ عِنْدَ مَوْتِهِ إِلَّا أَشْرَقَ لَهَا لَوْنُهُ وَنَفَّسَ اللَّهُ عَنْهُ كُرْبَتَهُ قَالَ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ إِنِّي لَأَعْلَمُ مَا هِيَ قَالَ وَمَا هِيَ قَالَ تَعْلَمُ كَلِمَةً أَعْظَمَ مِنْ كَلِمَةٍ أَمَرَ بِهَا عَمَّهُ عِنْدَ الْمَوْتِ لَا إِلَهَ إِلَّا اللَّهُ قَالَ طَلْحَةُ صَدَقْتَ هِيَ وَاللَّهِ هِيَ","id":"Telah menceritakan kepada kami [Asbath] telah menceritakan kepada kami [Mutharrif] dari ['Amir] dari [Yahya bin Thalhah] dari [bapaknya] berkata; Umar melihat Thalhah bin Ubaidullah merasa risau dan murung, maka dia bertanya; \"ada apa denganmu Wahai Abu fulan! sepertinya kepemimpinan anak pamanmu tidak menyenangkanmu Wahai Abu Fulan.\" Dia menjawab; \"Tidak, tapi aku mendengar sebuah hadits Rasulullah shallallahu 'alaihi wasallam, tidak ada yang menghalangiku untuk menanyakannya kecuali taqdir sehingga beliau meninggal, aku mendengar beliau bersabda: \"Sesungguhnya aku mengetahui satu kalimat yang tidaklah dibaca oleh seorang hamba ketika menjelang ajalnya kecuali dia akan memancarkan warna yang cerah dan Allah akan menghilangkan kesusahan darinya.\" Umar radliallahu 'anhu berkata; \"Aku tahu kalimat itu.\" Thalhah bertanya; \"Apa itu?\" Umar menjawab; \"Kamu tahu sebuah kalimat yang lebih agung dari kalimat yang beliau perintahkan kepada pamannya ketika menjelang meninggal dunia: \"LA ILAHA ILLA ALLAH (tidak ada Ilah yang berhak disembah selain Allah).\" Thalhah berkata; \"Benar kamu, itu yang dimaksud. Demi Allah itu dia.\""},"44":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَاعِيلَ قَالَ قَالَ قَيْسٌرَأَيْتُ طَلْحَةَ يَدُهُ شَلَّاءُ وَقَى بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Waki'] dari [Isma'il] berkata; [Qais] berkata; \"Aku melihat tangan [Thalhah] lumpuh, karena menjaga Rasulullah shallallahu 'alaihi wasallam pada Perang Uhud.\""},"45":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ مَعْنٍ الْغِفَارِيُّ أَخْبَرَنِي دَاوُدُ بْنُ خَالِدِ بْنِ دِينَارٍ أَنَّهُ مَرَّ هُوَ وَرَجُلٌ يُقَالُ لَهُ أَبُو يُوسُفَ مِنْ بَنِي تَيْمٍ عَلَى رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ رَضِيَ اللَّهُ عَنْهُ قَالَ قَالَ لَهُ أَبُو يُوسُفَ إِنَّا لَنَجِدُ عِنْدَ غَيْرِكَ مِنْ الْحَدِيثِ مَا لَا نَجِدُهُ عِنْدَكَ فَقَالَ أَمَا إِنَّ عِنْدِي حَدِيثًا كَثِيرًا وَلَكِنَّ رَبِيعَةَ بْنَ الْهُدَيْرِ قَالَ وَكَانَ يَلْزَمُ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ إِنَّهُ لَمْ يَسْمَعْ طَلْحَةَ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا قَطُّ غَيْرَ حَدِيثٍ وَاحِدٍ قَالَ رَبِيعَةُ بْنُ أَبِي عَبْدِ الرَّحْمَنِ قُلْتُ لَهُ وَمَا هُوَ قَالَ قَالَ لِي طَلْحَةُخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَشْرَفْنَا عَلَى حَرَّةِ وَاقِمٍ قَالَ فَدَنَوْنَا مِنْهَا فَإِذَا قُبُورٌ بِمَحْنِيَّةٍ فَقُلْنَا يَا رَسُولَ اللَّهِ قُبُورُ إِخْوَانِنَا هَذِهِ قَالَ قُبُورُ أَصْحَابِنَا ثُمَّ خَرَجْنَا حَتَّى إِذَا جِئْنَا قُبُورَ الشُّهَدَاءِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ قُبُورُ إِخْوَانِنَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepadaku [Muhammad bin Ma'n Al Ghifari] telah menghabarkan kepadaku [Daud bin Khalid bin Dinar] bahwa dia dan seorang lelaki yang bernama Abu Yusuf dari Bani Taim lewat di depan Rabi'ah bin Abu Abdurrahman. Abu Yusuf berkata kepada Rabi'ah bin Abu Abdurrahman; \"Sesungguhnya kami mendapatkan beberapa hadits dari selainmu yang tidak kami dapatkan pada dirimu\" Maka dia menjawab; \"Sebetulnya hadits yang ada padaku banyak, tetapi [Rabi'ah bin Al Hudair] berkata dan dia selalu menemani Thalhah bin Ubaidullah; bahwasanya dia tidak pernah mendengar Thalhah menyampaikan sebuah hadits dari Rasulullah shallallahu 'alaihi wasallam kecuali satu hadits saja.\" [Rabi'ah bin Abu Abdurrahman] berkata; aku bertanya kepadanya; \"Hadits apa itu?\" dia menjawab; [Thalhah] berkata kepadaku; Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dan ketika kami hampir sampai di Harrah Waqim, -Thalhah melanjutkan; - Kamipun semakin mendekati tempat itu, dan ternyata tempat itu adalah kuburan di daerah Mahniyyah. Kami bertanya; \"Wahai Rasulullah! apakah ini kuburan saudara-saudara kita?\" beliau menjawab; \"Ini kuburan sahabat-sahabat kita.\" kemudian kami keluar, dan ketika sudah dekat dengan kuburan para syuhada, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini adalah kuburan saudara-saudara kita.\""},"46":{"ar":"حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِ قَالَكُنَّا نُصَلِّي وَالدَّوَابُّ تَمُرُّ بَيْنَ أَيْدِينَا فَذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مِثْلُ مُؤْخِرَةِ الرَّحْلِ تَكُونُ بَيْنَ يَدَيْ أَحَدِكُمْ ثُمَّ لَا يَضُرُّهُ مَا مَرَّ عَلَيْهِ وَقَالَ عُمَرُ مَرَّةً بَيْنَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Umar bin 'Ubaid] dari [Simak bin Harb] dari [Musa bin Thalhah] dari [bapaknya] berkata; \"Ketika Kami sedang shalat, binatang tunggangan lewat di hadapan kami, maka kami sampaikan hal itu kepada Nabi shallallahu 'alaihi wasallam. Beliau bersabda: \"Seperti kayu sandaran penunggang unta yang diletakkan di hadapan salah seorang dari kalian, hal itu tidak akan berbahaya terhadap apa yang lewat di depannya.\" Umar berkata dalam riwayat lain; \"Di hadapannya.\""},"47":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مَالِكٌ عَنْ عَمِّهِ عَنْ أَبِيهِ أَنَّهُ سَمِعَ طَلْحَةَ بْنَ عُبَيْدِ اللَّهِ يَقُولُجَاءَ أَعْرَابِيٌّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَا الْإِسْلَامُ قَالَ خَمْسُ صَلَوَاتٍ فِي يَوْمٍ وَلَيْلَةٍ قَالَ هَلْ عَلَيَّ غَيْرُهُنَّ قَالَ لَا وَسَأَلَهُ عَنْ الصَّوْمِ فَقَالَ صِيَامُ رَمَضَانَ قَالَ هَلْ عَلَيَّ غَيْرُهُ قَالَ لَا قَالَ وَذَكَرَ الزَّكَاةَ قَالَ هَلْ عَلَيَّ غَيْرُهَا قَالَ لَا قَالَ وَاللَّهِ لَا أَزِيدُ عَلَيْهِنَّ وَلَا أَنْقُصُ مِنْهُنَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَفْلَحَ إِنْ صَدَقَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Malik] dari [pamannya] dari [Bapaknya] bahwa dia mendengar [Thalhah bin Ubaidullah] berkata; Seorang Badui menemui Rasulullah shallallahu 'alaihi wasallam dan bertanya; \"Wahai Rasulullah apa itu Islam?\" beliau menjawab; \"Shalat lima waktu sehari semalam.\" Dia bertanya lagi; \"Apakah ada kewajiban yang lainnya bagiku?\" beliau menjawab; \"Tidak ada.\" Lalu dia bertanya tentang puasa, maka Nabi menjawab; \"Puasa di bulan Ramadlan.\" Dia bertanya lagi; \"Apakah ada kewajiban yang lainnya bagiku?\" beliau menjawab; \"Tidak ada.\" Thalhah berkata; kemudian dia menyebutkan zakat; \"Apakah ada kewajiban yang lainnya bagiku?\" beliau menjawab; \"Tidak ada.\" dia berkata; \"Demi Allah, saya tidak menambah atau menguranginya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia akan beruntung jika dia benar-benar jujur.\""},"48":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنِ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسٍسَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَقُولُ لِعَبْدِ الرَّحْمَنِ وَطَلْحَةَ وَالزُّبَيْرِ وَسَعْدٍ نَشَدْتُكُمْ بِاللَّهِ الَّذِي تَقُومُ بِهِ السَّمَاءُ وَالْأَرْضُ وَقَالَ سُفْيَانُ مَرَّةً الَّذِي بِإِذْنِهِ تَقُومُ أَعَلِمْتُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالُوا اللَّهُمَّ نَعَمْ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Az Zuhri] dari [Malik bin Aus] saya mendengar [Umar radliallahu 'anhu] berkata kepada [Abdurrahman], [Thalhah], [Az Zubair], dan [Sa'd]; \"aku menyumpah kalian dengan nama Allah yang dengannya langit dan bumi tegak.\"-dalam kesempatan lain [Sufyan] berkata; \"yang dengan izin-Nya (langit dan bumi) tegak- Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kami tidak diwarisi. Apa yang kami tinggalkan adalah sedekah.'\" Mereka menjawab; \"Ya.\""},"49":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ جُرَيْجٍ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ مُعَاذِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّ عَنْ أَبِيهِ قَالَكُنَّا مَعَ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ وَنَحْنُ حُرُمٌ فَأُهْدِيَ لَهُ طَيْرٌ وَطَلْحَةُ رَاقِدٌ فَمِنَّا مَنْ أَكَلَ وَمِنَّا مَنْ تَوَرَّعَ فَلَمَّا اسْتَيْقَظَ طَلْحَةُ وَفَّقَ مَنْ أَكَلَهُ وَقَالَ أَكَلْنَاهُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] telah menceritakan kepadaku [Muhammad bin Al Munkadir] dari [Mu'adz bin Abdurrahman bin 'Utsman At Taimi] dari [Bapaknya] berkata; ketika kami sedang bersama [Thalhah bin 'Ubaidullah] dalam keadaan ihram, dihadiahkan kepadanya daging burung. Saat itu dia sedang tidur. Maka di antara kami ada yang memakan dan ada yang menolak memakannya. Ketika Thalhah terjaga, dia sepakat dengan orang-orang yang memakannya dan berkata; \"Kami pernah memakannya bersama Rasulullah shallallahu 'alaihi wasallam.\""},"50":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سِمَاكٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَوْمٍ فِي رُءُوسِ النَّخْلِ فَقَالَ مَا يَصْنَعُ هَؤُلَاءِ قَالُوا يُلَقِّحُونَهُ يَجْعَلُونَ الذَّكَرَ فِي الْأُنْثَى قَالَ مَا أَظُنُّ ذَلِكَ يُغْنِي شَيْئًا فَأُخْبِرُوا بِذَلِكَ فَتَرَكُوهُ فَأُخْبِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كَانَ يَنْفَعُهُمْ فَلْيَصْنَعُوهُ فَإِنِّي إِنَّمَا ظَنَنْتُ ظَنًّا فَلَا تُؤَاخِذُونِي بِالظَّنِّ وَلَكِنْ إِذَا أَخْبَرْتُكُمْ عَنْ اللَّهِ عَزَّ وَجَلَّ بِشَيْءٍ فَخُذُوهُ فَإِنِّي لَنْ أَكْذِبَ عَلَى اللَّهِ شَيْئًا","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Simak] dari [Musa bin Thalhah] dari [bapaknya] berkata; Rasulullah shallallahu 'alaihi wasallam melewati suatu kaum yang sedang berada diatas pohon kurma, kemudian beliau bertanya; \"Apa yang sedang mereka lakukan?\" mereka menjawab; \"Mereka sedang mengawinkan kurma jantan dengan kurma betina.\" Beliau berkata; \"Aku mengira hal itu tidak bermanfaat\" kemudian mereka diberitahu ucapan Nabi tersebut dan mereka pun meninggalkannya. Kemudian Rasulullah shallallahu 'alaihi wasallam mendapat berita (tentang kegagalan panen mereka karena tidak dikawinkan), maka beliau berkata; \"Jika hal itu memberi manfaat, maka lakukanlah! hanyasannya aku cuma mengira dengan perkiraan, maka jangan kalian salahkan aku karena perkiraan ini, namun jika aku beritakan sesuatu yang datang dari Allah 'azza wajalla, maka ambillah! Karena aku sekali-kali tidak mungkin sedikitpun berdusta kepada Allah.\""},"51":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنِ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسٍسَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ يَقُولُ لِعَبْدِ الرَّحْمَنِ وَطَلْحَةَ وَالزُّبَيْرِ وَسَعْدٍ نَشَدْتُكُمْ بِاللَّهِ الَّذِي تَقُومُ بِهِ السَّمَاءُ وَالْأَرْضُ وَقَالَ سُفْيَانُ مَرَّةً الَّذِي بِإِذْنِهِ تَقُومُ أَعَلِمْتُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالَ قَالُوا اللَّهُمَّ نَعَمْ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Az Zuhri] dari [Malik bin Aus] saya mendengar [Umar radliallahu 'anhu] berkata kepada [Abdurrahman], [Thalhah], [Az Zuhair], dan [Sa'd]; \"aku menyumpah kalian dengan nama Allah yang dengan-Nya langit dan bumi tegak.\"-dalam kesempatan lain Sufyan berkata; \"yang dengan izin-Nya (langit dan bumi) tegak- Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kami tidak diwarisi. Apa yang kami tinggalkan adalah sedekah.'\" Mereka menjawab; \"Ya.\""},"52":{"ar":"حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنِ الزُّبَيْرِ بْنِ الْعَوَّامِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَحْمِلَ الرَّجُلُ حَبْلًا فَيَحْتَطِبَ بِهِ ثُمَّ يَجِيءَ فَيَضَعَهُ فِي السُّوقِ فَيَبِيعَهُ ثُمَّ يَسْتَغْنِيَ بِهِ فَيُنْفِقَهُ عَلَى نَفْسِهِ خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ النَّاسَ أَعْطَوْهُ أَوْ مَنَعُوهُ","id":"Telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hisyam] dari [Bapaknya] dari [Zubair bin Al Awwam] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang lelaki yang membawa seutas tali kemudian dia mencari kayu bakar dan membawa ke pasar untuk menjualnya sehingga dia merasa cukup untuk menafkahi dirinya adalah lebih baik baginya daripada meminta-minta kepada manusia baik mereka memberi atau menolaknya.\""},"53":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنِ الزُّبَيْرِ قَالَجَمَعَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَوَيْهِ يَوْمَ أُحُدٍ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Hisyam] dari [Bapaknya] dari [Abdullah bin Zubair] dari [Zubair] berkata; \"Rasulullah shallallahu 'alaihi wasallam menyebutkan nama kedua orang tuanya (ketika meminta sesuatu kepadaku) pada Perang Uhud.\""},"54":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا سُلَيْمَانُ يَعْنِي التَّيْمِيَّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرٍ عَنِ الزُّبَيْرِ بْنِ الْعَوَّامِأَنَّ رَجُلًا حَمَلَ عَلَى فَرَسٍ يُقَالُ لَهَا غَمْرَةُ أَوْ غَمْرَاءُ وَقَالَ فَوَجَدَ فَرَسًا أَوْ مُهْرًا يُبَاعُ فَنُسِبَتْ إِلَى تِلْكَ الْفَرَسِ فَنُهِيَ عَنْهَا","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Sulaiman] yaitu At Taimi, dari [Abu 'Utsman] dari [Abdullah bin 'Amru] dari [Az Zubair bin Al Awwam] bahwa seorang lelaki mensedekahkan seekor kuda yang dinamakan ghamrah atau ghamra`. Zubair berkata; Kemudian dia mendapatkan kuda atau anak kuda yang dijual, lalu dinisbatkan kepada kudanya, maka hal itu dilarang."},"55":{"ar":"حَدَّثَنَا يَزِيدُ أَنْبَأَنَا ابْنُ أَبِي ذِئْبٍ عَنْ مُسْلِمِ بْنِ جُنْدُبٍ عَنِ الزُّبَيْرِ بْنِ الْعَوَّامِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَنْصَرِفُ فَنَبْتَدِرُ الْآجَامَ فَلَا نَجِدُ إِلَّا قَدْرَ مَوْضِعِ أَقْدَامِنَاقَالَ يَزِيدُ الْآجَامُ هِيَ الْآطَامُ","id":"Telah menceritakan kepada kami [Yazid] telah memberitakan kepada kami [Ibnu Abu Dzi`b] dari [Muslim bin Jundub] dari [Zubair bin Awwam radliallahu 'anhu] berkata; kami shalat Jum'at bersama Rasulullah shallallahu 'alaihi wasallam kemudian kami meninggalkan beliau dan berlomba menuju Al Ajam (tembok tinggi), ternyata kami tidak mendapatkan tempat kecuali tempat yang cukup untuk telapak kaki kami saja.\" Yazid berkata; \"Al Ajam yaitu tembok tinggi seperti benteng.\""},"56":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَقُلْتُ لِلزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُ مَا لِي لَا أَسْمَعُكَ تُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا أَسْمَعُ ابْنَ مَسْعُودٍ وَفُلَانًا وَفُلَانًا قَالَ أَمَا إِنِّي لَمْ أُفَارِقْهُ مُنْذُ أَسْلَمْتُ وَلَكِنِّي سَمِعْتُ مِنْهُ كَلِمَةً مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Jami' bin Syaddad] dari [Amir bin Abdullah bin Zubair] dari [bapaknya] berkata; Aku bertanya kepada [Zubair]; \"Kenapa aku tidak mendengarmu meriwayatkan hadits dari Rasulullah shallallahu 'alaihi wasallam seperti aku mendengar dari Ibnu Mas'ud, dari fulan dan fulan?\" dia menjawab; \"Aku belum pernah berpisah darinya sejak aku masuk Islam, tetapi aku mendengar dari beliau satu kalimat: \"Barangsiapa sengaja berdusta atas namaku maka hendaklah mempersiapkan tempat duduknya di Neraka.\""},"57":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا شَدَّادٌ يَعْنِي ابْنَ سَعِيدٍ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ مُطَرِّفٍ قَالَقُلْنَا لِلزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُ يَا أَبَا عَبْدِ اللَّهِ مَا جَاءَ بِكُمْ ضَيَّعْتُمْ الْخَلِيفَةَ حَتَّى قُتِلَ ثُمَّ جِئْتُمْ تَطْلُبُونَ بِدَمِهِ قَالَ الزُّبَيْرُ رَضِيَ اللَّهُ عَنْهُ إِنَّا قَرَأْنَاهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ رَضِيَ اللَّهُ عَنْهُمْ{ وَاتَّقُوا فِتْنَةً لَا تُصِيبَنَّ الَّذِينَ ظَلَمُوا مِنْكُمْ خَاصَّةً }لَمْ نَكُنْ نَحْسَبُ أَنَّا أَهْلُهَا حَتَّى وَقَعَتْ مِنَّا حَيْثُ وَقَعَتْ","id":"Telah menceritakan kepada kami [Abu Sa'id] mantan budak Bani Hasyim, telah menceritakan kepada kami [Syaddad] yaitu Ibnu Sa'id telah menceritakan kepada kami [Ghailan bin Jarir] dari [Mutharrif] berkata; kami bertanya kepada Zubair radliallahu 'anhu \"Wahai Abu Abdullah, apa yang kamu terima, padahal kamu telah menyia-nyiakan khalifah sehingga dia terbunuh, kemudian kalian datang menuntut darahnya?\" [Zubair] radliallahu 'anhu menjawab; \"Sesungguhnya kami telah membacanya pada masa Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman: (Dan peliharalah dirimu dari pada siksaan yang tidak khusus menimpa orang-orang yang zalim saja di antara kamu.) sebelumnya kami tidak menyangka bahwa kamilah orang yang tertimpa siksaan itu sehingga siksaan itu benar-benar terjadi kami."},"58":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كُنَاسَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُثْمَانَ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنِ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا الشَّيْبَ وَلَا تَشَبَّهُوا بِالْيَهُودِ","id":"Telah menceritakan kepada kami [Muhammad bin Kunasah] telah menceritakan kepada kami [Hisyam bin Urwah] dari ['Utsman bin 'Urwah] dari [Bapaknya] dari [Zubair radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rubahlah uban dan jangan kalian menyerupai orang-orang Yahudi!\""},"59":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي يَحْيَى بْنُ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنِ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَئِذٍ أَوْجَبَ طَلْحَةُ حِينَ صَنَعَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا صَنَعَ يَعْنِي حِينَ بَرَكَ لَهُ طَلْحَةُ فَصَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ظَهْرِهِ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Bapakku] telah menceritakan kepada kami [Ibnu Ishaq] telah menceritakan kepadaku [Yahya bin 'Abbad bin Abdullah bin Zubair] dari [Bapaknya] dari [Abdullah bin Zubair] dari [Zubair radliallahu 'anhu] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam berkata pada Perang Uhud: \"Telah wajib bagi Thalhah\", ketika dia melakukan tindakan untuk Rasulullah shallallahu 'alaihi wasallam, yaitu dia merunduk kemudian Rasulullah shallallahu 'alaihi wasallam naik di atas punggungnya.\""},"60":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ أَبِي الزِّنَادِ عَنْ هِشَامٍ عَنْ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي الزُّبَيْرُ رَضِيَ اللَّهُ عَنْهُ أَنَّهُلَمَّا كَانَ يَوْمُ أُحُدٍ أَقْبَلَتْ امْرَأَةٌ تَسْعَى حَتَّى إِذَا كَادَتْ أَنْ تُشْرِفَ عَلَى الْقَتْلَى قَالَ فَكَرِهَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَرَاهُمْ فَقَالَ الْمَرْأَةَ الْمَرْأَةَ قَالَ الزُّبَيْرُ رَضِيَ اللَّهُ عَنْهُ فَتَوَسَّمْتُ أَنَّهَا أُمِّي صَفِيَّةُ قَالَ فَخَرَجْتُ أَسْعَى إِلَيْهَا فَأَدْرَكْتُهَا قَبْلَ أَنْ تَنْتَهِيَ إِلَى الْقَتْلَى قَالَ فَلَدَمَتْ فِي صَدْرِي وَكَانَتْ امْرَأَةً جَلْدَةً قَالَتْ إِلَيْكَ لَا أَرْضَ لَكَ قَالَ فَقُلْتُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَزَمَ عَلَيْكِ قَالَ فَوَقَفَتْ وَأَخْرَجَتْ ثَوْبَيْنِ مَعَهَا فَقَالَتْ هَذَانِ ثَوْبَانِ جِئْتُ بِهِمَا لِأَخِي حَمْزَةَ فَقَدْ بَلَغَنِي مَقْتَلُهُ فَكَفِّنُوهُ فِيهِمَا قَالَ فَجِئْنَا بِالثَّوْبَيْنِ لِنُكَفِّنَ فِيهِمَا حَمْزَةَ فَإِذَا إِلَى جَنْبِهِ رَجُلٌ مِنْ الْأَنْصَارِ قَتِيلٌ قَدْ فُعِلَ بِهِ كَمَا فُعِلَ بِحَمْزَةَ قَالَ فَوَجَدْنَا غَضَاضَةً وَحَيَاءً أَنْ نُكَفِّنَ حَمْزَةَ فِي ثَوْبَيْنِ وَالْأَنْصَارِيُّ لَا كَفَنَ لَهُ فَقُلْنَا لِحَمْزَةَ ثَوْبٌ وَلِلْأَنْصَارِيِّ ثَوْبٌ فَقَدَرْنَاهُمَا فَكَانَ أَحَدُهُمَا أَكْبَرَ مِنْ الْآخَرِ فَأَقْرَعْنَا بَيْنَهُمَا فَكَفَّنَّا كُلَّ وَاحِدٍ مِنْهُمَا فِي الثَّوْبِ الَّذِي صَارَ لَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Hasyimi] telah memberitakan kepada kami [Abdurrahman] yaitu Ibnu Abu Ziyad, dari [Hisyam] dari dari ['Urwah] berkata; telah mengabarkan kepadaku [bapakku, Zubair radliallahu 'anhu] ketika perang Uhud telah usai seorang wanita datang sambil berjalan, sehingga ketika dia hampir mendekat kepada para korban, Nabi shallallahu 'alaihi wasallam tidak suka jika wanita itu sampai melihat mereka, maka beliau berkata; \"Hentikan wanita itu, hentikan wanita itu!\" Zubair radliallahu 'anhu berkata; \"Maka aku menjelaskan bahwa itu adalah ibuku, Shafiyyah. Aku pergi berlari ke arahnya, dan aku dapat menemuinya sebelum dia mendekati kepada para korban yang gugur. Tetapi dia mendorong dan memukul dadaku, dan memang dia adalah seorang wanita yang kuat lagi penyabar, kemudian dia berkata; \"Menjauhlah kamu, Aku tidak rela kepadamu.\" Saya katakan kepadanya; \"Rasulullah shallallahu 'alaihi wasallam bersikeras untuk melarangmu\" Maka ibuku pun berhenti dan mengeluarkan dua kain yang dibawanya, kemudian berkata; \"Dua kain ini aku bawa untuk saudaraku Hamzah, karena telah sampai kepadaku berita kegugurannya, maka kafanilah dia dengan dua kain ini.\" Maka kami membawa dua kain itu untuk mengafani Hamzah, tetapi di samping Hamzah ada seorang lelaki Anshar yang terbunuh juga, yang telah diperlakukan sebagaimana yang diperlakukan kepada Hamzah. Kami merasa tidak pantas dan malu jika mengafani Hamzah dengan dua kain sementara tidak ada kafan untuk lelaki Anshar. Maka Kami katakan: \"Satu kain untuk Hamzah dan satu lagi untuk lelaki Anshar, \" kemudian kami mengukur keduanya, ternyata salah satunya lebih besar dari yang lain sehingga kami lakukan undian diantara keduanya dan masing masing kami kafani dengan kain yang menjadi bagiannya.\""},"61":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا ابْنُ أَبِي نَجِي��ٍ قَالَ سَأَلْتُ طَاوُسًا عَنْ رَجُلٍ رَمَى الْجَمْرَةَ بِسِتِّ حَصَيَاتٍ فَقَالَ لِيُطْعِمْ قَبْضَةً مِنْ طَعَامٍ قَالَ فَلَقِيتُ مُجَاهِدًا فَسَأَلْتُهُ وَذَكَرْتُ لَهُ قَوْلَ طَاوُسٍ فَقَالَ رَحِمَ اللَّهُ أَبَا عَبْدِ الرَّحْمَنِ أَمَا بَلَغَهُ قَوْلُ سَعْدِ بْنِ مَالِكٍ قَالَرَمَيْنَا الْجِمَارَ أَوْ الْجَمْرَةَ فِي حَجَّتِنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ جَلَسْنَا نَتَذَاكَرُ فَمِنَّا مَنْ قَالَ رَمَيْتُ بِسِتٍّ وَمِنَّا مَنْ قَالَ رَمَيْتُ بِسَبْعٍ وَمِنَّا مَنْ قَالَ رَمَيْتُ بِثَمَانٍ وَمِنَّا مَنْ قَالَ رَمَيْتُ بِتِسْعٍ فَلَمْ يَرَوْا بِذَلِكَ بَأْسًا","id":"Telah menceritakan kepada kami ['Affan] telah menceritkan kepada kami [Abdul Warits] telah menceritakan kepada kami [Ibnu Abu Najih] berkata; saya bertanya kepada Thawus tentang seorang lelaki yang melempar jumrah dengan enam kerikil. Dia menjawab; \"Hendaknya dia memberi makan dengan segenggam makanan.\" Ibnu Abu Najih berkata; Kemudian aku bertemu [Mujahid], maka aku pun menanyakan kepadanya dan menyebutkan pendapat Thawus, maka dia menjawab; \"Semoga Allah memberikan rahmat kepada Abu Abdurrahman, tidakkah sampai kepadanya perkataan [Sa'd bin Malik] bahwa dia berkata; Kami melempar beberapa jumrah atau satu jumrah dalam ritual haji kami (yang kami jalani) bersama Rasulullah shallallahu 'alaihi wasallam, kemudian kami duduk saling berdiskusi, di antara kami ada yang berkata; 'Aku telah melempar enam kerikil, ' diantara kami ada yang berkata; 'Aku melempar tujuh kerikil, ' diantara kami ada yang berkata; 'Aku telah melempar delapan kerikil, ' dan diantara kami ada yang berkata; 'Aku melempar sembilan kerikil, ' dan mereka tidak menganggap bahwa hal itu merupakan satu kesalahan.\""},"62":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ عَبْدُ الْكَبِيرِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا بُكَيْرُ بْنُ مِسْمَارٍ عَنْ عَامِرِ بْنِ سَعْدٍأَنَّ أَخَاهُ عُمَرَ انْطَلَقَ إِلَى سَعْدٍ فِي غَنَمٍ لَهُ خَارِجًا مِنْ الْمَدِينَةِ فَلَمَّا رَآهُ سَعْدٌ قَالَ أَعُوذُ بِاللَّهِ مِنْ شَرِّ هَذَا الرَّاكِبِ فَلَمَّا أَتَاهُ قَالَ يَا أَبَتِ أَرَضِيتَ أَنْ تَكُونَ أَعْرَابِيًّا فِي غَنَمِكَ وَالنَّاسُ يَتَنَازَعُونَ فِي الْمُلْكِ بِالْمَدِينَةِ فَضَرَبَ سَعْدٌ صَدْرَ عُمَرَ وَقَالَ اسْكُتْ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُحِبُّ الْعَبْدَ التَّقِيَّ الْغَنِيَّ الْخَفِيَّ","id":"Telah menceritakan kepada kami [Abu Bakar bin Al Hanafi, Abdul Kabir bin Abdul Majid] telah menceritakan kepada kami [Bukair bin Mismar] dari ['Amir bin Sa'd], mengatakan bahwa saudaranya, Umar berangkat menemui Sa'd di tempat penggembalaan kambingnya di luar Madinah. Ketika Sa'd melihatnya, dia berkata; \"Aku berlindung kepada Allah dari keburukan pengendara ini\" dan ketika Umar menemuinya, dia berkata; \"Wahai bapakku, apakah engkau rela menjadi seorang badui yang mengurusi kambingmu sementara orang-orang berselisih dalam masalah kepemimpinan di Madinah?\" maka [Sa'd] memukul dada Umar dan berkata; \"Diam kamu, saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah mencintai hambaNya yang bertaqwa, berkecukupan dan sembunyi-sembunyi (mengeluarkan sedekahnya).\""},"63":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحٌ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ يَعْنِي ابْنَ مَعْمَرٍ قَالَ حَدَّثَ عَامِرُ بْنُ سَعْدٍ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ وَهُوَ أَمِيرٌ عَلَى الْمَدِينَةِ أَنَّ سَعْدًا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ سَبْعَ تَمَرَاتِ عَجْوَةٍ مِنْ بَيْنَ لَابَتَيْ الْمَدِينَةِ عَلَى الرِّيقِ لَمْ يَضُرَّهُ يَوْمَهُ ذَلِكَ شَيْءٌ حَتَّى يُمْسِيَقَالَ فُلَيْحٌ وَأَظُنُّهُ قَالَ وَإِنْ أَكَلَهَا حِينَ يُمْسِي لَمْ يَضُرَّهُ شَيْءٌ حَتَّى يُصْبِحَ فَقَالَ عُمَرُ انْظُرْ يَا عَامِرُ مَا تُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَشْهَدُ مَا كَذَبْتُ عَلَى سَعْدٍ وَمَا كَذَبَ سَعْدٌ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Fulaih] dari [Abdullah bin Abdurrahman] yaitu Ibnu Ma'mar, dia berkata; bahwa [Amir bin Sa'd] menceritakan kepada Umar bin Abdul Aziz ketika dia sedang menjabat Gubernur kota Madinah, bahwa [Sa'd] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan tujuh biji kurma 'Ajwah dari antara dua sisi Madinah sebelum sarapan pagi maka tidak akan ada sesuatu yang membahayakannya pada hari itu sampai sore harinya.\" Fulaih berkata; Aku mengiranya beliau bersabda: \"Dan jika memakannya pada waktu sore hari maka tidak ada sesuatu yang membahayakannya sampai pagi hari.\" Maka Umar berkata; \"perhatikanlah Wahai 'Amir apa yang kamu ceritakan dari Rasulullah shallallahu 'alaihi wasallam?\" maka 'Amir menjawab; \"Aku bersaksi, dan aku tidak berbohong atas nama Sa'd dan Sa'd tidak berbohong atas nama Rasulullah shallallahu 'alaihi wasallam.\" "},"64":{"ar":"حَدَّثَنَا رَوْحٌ أَمْلَاهُ عَلَيْنَا بِبَغْدَادَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حُمَيْدٍ عَنْ إِسْمَاعِيلَ بْنِ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ عَنْ جَدِّهِ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَعَادَةِ ابْنِ آدَمَ اسْتِخَارَتُهُ اللَّهَ وَمِنْ سَعَادَةِ ابْنِ آدَمَ رِضَاهُ بِمَا قَضَاهُ اللَّهُ وَمِنْ شِقْوَةِ ابْنِ آدَمَ تَرْكُهُ اسْتِخَارَةَ اللَّهِ وَمِنْ شِقْوَةِ ابْنِ آدَمَ سَخَطُهُ بِمَا قَضَى اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Rauh] -dia mendekte kepada kami ketika di Baghdad, - telah menceritakan kepada kami [Muhammad bin Abu Humaid] dari [Isma'il bin Muhammad bin Sa'd bin Abu Waqqash] dari [bapaknya] dari [kakeknya, Sa'd bin Abu Waqqash] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di antara kebahagiaan anak Adam adalah istikharahnya (memohon pilihan dengan meminta petunjuk kepada Allah) kepada Allah, dan diantara kebahagiaan anak Adam adalah kerelaannya kepada ketetapan Allah, sedangkan diantara kesengsaraan anak Adam adalah dia meninggalkan istikharah kepada Allah, dan diantara kesengsaraan anak Adam adalah kemurkaannya terhadap ketetapan Allah.\""},"65":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حُمَيْدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ مُحَمَّدِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَعَادَةِ ابْنِ آدَمَ ثَلَاثَةٌ وَمِنْ شِقْوَةِ ابْنِ آدَمَ ثَلَاثَةٌ مِنْ سَعَادَةِ ابْنِ آدَمَ الْمَرْأَةُ الصَّالِحَةُ وَالْمَسْكَنُ الصَّالِحُ وَالْمَرْكَبُ الصَّالِحُ وَمِنْ شِقْوَةِ ابْنِ آدَمَ الْمَرْأَةُ السُّوءُ وَالْمَسْكَنُ السُّوءُ وَالْمَرْكَبُ السُّوءُ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Muhammad bin Abu Humaid] telah menceritakan kepada kami [Isma'il bin Muhammad bin Sa'd bin Abu Waqqash] dari [bapaknya] dari [kakeknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga indikasi kebahagiaan anak Adam, dan tiga indikasi kesengsaraan anak Adam; indikasi kebahagiaan anak cucu adam adalah istri yang shalehah, tempat tinggal yang baik dan kendaraan yang baik. Sedangkan indikasi kesengsaraan anak Adam adalah istri yang berakhlak buruk, tempat tinggal yang buruk dan kendaraan yang buruk.\""},"66":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ لَهِيعَةَ حَدَّثَنَا بُكَيْرُ بْنُ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ أَنَّهُ سَمِعَ حُسَيْنَ بْنَ عَبْدِ الرَحَّمَنِ يُحَدِّثُ أَنَّهُ سَمِعَ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَتَكُونُ فِتْنَةٌ الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ الْمَاشِي وَيَكُونُ الْمَاشِي فِيهَا خَيْرًا مِنْ السَّاعِي قَالَ وَأُرَاهُ قَالَ وَالْمُضْطَجِعُ فِيهَا خَيْرٌ مِنْ الْقَاعِدِ","id":"Telah menceritakan kepada kami [Abu Sa'id] mantan budak Bani Hasyim, telah menceritakan kepada kami [Abdullah bin Lahi'ah] telah menceritakan kepada kami [Bukair bin Abdullah bin Al Asyaj] bahwa dia mendengar [Husain bin Abdurrahman] menceritakan, bahwa dia mendengar [Sa'd bin Abu Waqqash] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi suatu fitnah, dimana orang yang duduk ketika itu lebih baik dari orang yang berdiri, dan orang yang berdiri ketika itu lebih baik dari orang yang berjalan, dan orang yang berjalan ketika itu lebih baik dari orang yang berlari.\" Husain bin Abdurrahman berkata; Aku mengira Sa'd juga berkata: \"Dan orang yang berbaring ketika itu lebih baik dari orang yang duduk.\""},"67":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ دَاوُدَ بْنِ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ مَا يُقِلُّ ظُفُرٌ مِمَّا فِي الْجَنَّةِ بَدَا لَتَزَخْرَفَتْ لَهُ مَا بَيْنَ خَوَافِقِ السَّمَوَاتِ وَالْأَرْضِ وَلَوْ أَنَّ رَجُلًا مِنْ أَهْلِ الْجَنَّةِ اطَّلَعَ فَبَدَا سِوَارُهُ لَطَمَسَ ضَوْءُهُ ضَوْءَ الشَّمْسِ كَمَا تَطْمِسُ الشَّمْسُ ضَوْءَ النُّجُومِ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Daud bin 'Amir bin Sa'd bin Abu Waqqash] dari [bapaknya] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seandainya secuil kuku saja dari keindahan yang ada di Syurga muncul, niscaya akan menghiasi ruang yang ada antara langit dan bumi. Seandainya seorang lelaki dari ahli syurga muncul kemudian tampak gelangnya, niscaya cahayanya akan menghapus cahaya matahari sebagaimana cahaya matahari menghapus cahaya bintang.\" "},"68":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ إِسْمَاعِيلَ بْنِ مُحَمَّدٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَالْحَدُوا لِي لَحْدًا وَانْصِبُوا عَلَيَّ اللَّبِنَ نَصْبًا كَمَا صُنِعَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ إِسْمَاعِيلَ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ سَعْدٍ فَذَكَرَ مِثْلَهُ وَوَافَقَهُ أَبُو سَعِيدٍ عَلَى عَامِرِ بْنِ سَعْدٍ كَمَا قَالَ الْخُزَاعِيُّ","id":"Telah menceritakan kepada kami [Abu Salamah Al Khuza'i] telah mengabarkan kepada kami [Abdullah bin Ja'far] dari [Isma'il bin Muhammad] dari ['Amir bin Sa'd] dari [Sa'd] berkata; \"Buatkanlah liang lahat untukku dan letakkanlah batu bata sebagaimana telah dibuatkan untuk Rasulullah shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Ibnu Mahdi] telah menceritakan kepada kami [Abdullah bin Ja'far] dari [Isma'il bin Muhammad] dari [bapaknya] dari [Sa'd] kemudian dia menyebutkan hadits yang serupa dengannya, dan [Abu Sa'id] menyepakati [Amir bin Sa'd] dalam hal ini, sebagaimana yang dikatakan oleh Al Khuza'i.\""},"69":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى حَدَّثَنِي مَالِكٌ يَعْنِي ابْنَ أَنَسٍ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَ سَمِعْتُ أَبِي يَقُولُمَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِحَيٍّ مِنْ النَّاسِ يَمْشِي إِنَّهُ فِي الْجَنَّةِ إِلَّا لِعَبْدِ اللَّهِ بْنِ سَلَامٍ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] telah menceritakan kepadaku [Malik] yaitu Ibnu Anas, dari [Salim Abu Nadhr] dari ['Amir bin Sa'd bin Abu Waqqash] berkata; Aku mendengar [bapakku] berkata; \"Saya tidak pernah mendengar Rasulullah shallallahu 'alaihi wasallam berkata kepada manusia yang masih hidup lagi masih berjalan bahwa dia berada di syurga kecuali kepada Abdullah bin Salam.\""},"70":{"ar":"حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا خَالِدٌ عَنْ أَبِي عُثْمَانَ قَالَ لَمَّا ادُّعِيَ زِيَادٌ لَقِيتُ أَبَا بَكْرَةَ قَالَ فَقُلْتُ مَا هَذَا الَّذِي صَنَعْتُمْ إِنِّي سَمِعْتُ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُسَمِعَ أُذُنِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَ��ُولُ مَنْ ادَّعَى أَبًا فِي الْإِسْلَامِ غَيْرَ أَبِيهِ وَهُوَ يَعْلَمُ أَنَّهُ غَيْرُ أَبِيهِ فَالْجَنَّةُ عَلَيْهِ حَرَامٌفَقَالَ أَبُو بَكْرَةَ وَأَنَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Husyaim] telah memberitakan kepada kami [Khalid] dari [Abu 'Utsman] berkata; Ketika Ziyad diaku (sebagai ayah oleh orang yang bukan anaknya), maka aku bertemu Abu Bakrah dan berkata; \"Apa yang kalian lakukan ini? sesungguhnya aku mendengar [Sa'd bin Abu Waqqash] berkata; telingaku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengaku seorang bapak dalam Islam padahal bukan bapaknya dan dia tahu bahwa dia bukan bapaknya maka Syurga haram baginya.\" Kemudian [Abu Bakrah] berkata; \"Aku juga telah mendengar dari Rasulullah shallallahu 'alaihi wasallam.\""},"71":{"ar":"حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ عَبْدَ الْمَلِكِ بْنَ عُمَيْرٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ","id":"Telah menceritakan kepada kami [Mu'tamir bin Sulaiman] berkata; saya mendengar [Abdul Malik bin 'Umair] dari ['Amru bin Huraits] dari [Sa'id bin Zaid bin 'Amru bin Nufail] bahwa Nabiyullah shallallahu 'alaihi wasallam bersabda: \"Cendawan berasal al Manna, dan airnya merupakan obat untuk mata.\""},"72":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنِي أَبِي حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَ حَدَّثَنِي أَبِيعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَمْأَةُ مِنْ السَّلْوَى وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ","id":"Telah menceritakan kepada kami [Abdushshamad] telah menceritakan kepadaku [bapakku] telah menceritakan kepada kami ['Atho` bin As Sa`ib] dari ['Amru bin Huraits] berkata; telah menceritakan kepadaku [bapakku] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Cendawan berasal Salwa, dan airnya merupakan obat untuk mata.\""},"73":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ هَذَا حَفِظْنَاهُ عَنِ الزُّهْرِيِّ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ سَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ وَمَنْ ظَلَمَ مِنْ الْأَرْضِ شِبْرًا طُوِّقَهُ مِنْ سَبْعِ أَرَضِينَ","id":"Telah menceritakan kepada kami [Sufyan] berkata; hadits ini kami hafal dari [Az Zuhri] dari [Thalhah bin Abdullah bin 'Auf] dari [Sa'id bin Zaid bin 'Amru bin Nufail] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa terbunuh karena membela hartanya maka dia (mati) syahid. Barangsiapa berbuat aniaya (dengan mengambil) sejengkal tanah niscaya kelak akan dikalungkan kepadanya tujuh lapis bumi.\""},"74":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ حُصَيْنٍ وَمَنْصُورٍ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ سَعِيدِ بْنِ زَيْدٍ قَالَ وَكِيعٌ مَرَّةً قَالَ مَنْصُورٌ عَنْ سَعِيدِ بْنِ زَيْدٍ وَقَالَ مَرَّةً حُصَيْنٌ عَنِ ابْنِ ظَالِمٍ عَنْ سَعِيدِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْكُنْ حِرَاءُ فَلَيْسَ عَلَيْكَ إِلَّا نَبِيٌّ أَوْ صِدِّيقٌ أَوْ شَهِيدٌ قَالَ وَعَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ وَعَلِيٌّ وَطَلْحَةُ وَالزُّبَيْرُ وَسَعْدٌ وَعَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ وَسَعِيدُ بْنُ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Hushain bin Manshur] dari [Hilal bin Yisaf] dari [Sa'id bin Zaid], di kesempatan lain [Waki'] berkata: [Manshur] berkata; dari [Sa'id bin Zaid], dan di kesempatan yang lainnya berkata; [Hushain] dari [Ibnu Zhalim] dari [Sa'id bin Zaid] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tenanglah Wahai Hira`, yang sedang berada di atasmu adalah seorang Nabi atau orang yang shiddiq atau orang yang syahid!\" Sa'id menerangkan; \"Di atasnya adalah Nabi shallallahu 'alaihi wasallam, Abu Bakar, Umar, 'Utsman, Ali, Thalhah, Zubair, Sa'd, Abdurrahman bin 'Auf dan Sa'id bin Zaid radliallahu 'anhum.\""},"75":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنِ الْحُرِّ بْنِ الصَّيَّاحِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَخْنَسِ قَالَخَطَبَنَا الْمُغِيرَةُ بْنُ شُعْبَةَ فَنَالَ مِنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ فَقَامَ سَعِيدُ بْنُ زَيْدٍ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ النَّبِيُّ فِي الْجَنَّةِ وَأَبُو بَكْرٍ فِي الْجَنَّةِ وَعُمَرُ فِي الْجَنَّةِ وَعُثْمَانُ فِي الْجَنَّةِ وَعَلِيٌّ فِي الْجَنَّةِ وَطَلْحَةُ فِي الْجَنَّةِ وَالزُّبَيْرُ فِي الْجَنَّةِ وَعَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فِي الْجَنَّةِ وَسَعْدٌ فِي الْجَنَّةِ وَلَوْ شِئْتُ أَنْ أُسَمِّيَ الْعَاشِرَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Syu'bah] dari [Al Hur bin Asy Shayyah] dari [Abdurrahman bin Al Akhnas] berkata; Al Mughirah bin Syu'bah berkhutbah di hadapan kami, kemudian dia mencela Ali radliallahu 'anhu, maka [Sa'id bin Zaid] bangun dan berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nabi di Syurga, Abu Bakar di Syurga, Umar di Syurga, Utsman di Syurga, Ali di Syurga, Thalhah di Syurga, Zubair di Syurga, Abdurrahman bin 'Auf di Syurga dan Sa'd di Syurga.\" Jika saya mau saya akan sebutkan yang kesepuluh.\" "},"76":{"ar":"حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ","id":"Telah menceritakan kepada kami [Umar bin 'Ubaid] dari [Abdul Malik bin 'Umair] dari ['Amru bin Huraits] dari [Sa'id bin Zaid] berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Cendawan berasal Manna, dan airnya merupakan obat untuk mata.\" "},"77":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدٍ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي يَدِهِ كَمْأَةٌ فَقَالَ تَدْرُونَ مَا هَذَا هَذَا مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ","id":"Telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin 'Umair] dari ['Amru bin Huraits] dari [Sa'id bin Zaid] berkata; Rasulullah shallallahu 'alaihi wasallam menemui kami dan beliau membawa cendawan di tangannya dan bersabda: \"Apakah kalian tahu apa ini? ini berasal al Manna, dan airnya merupakan obat untuk mata.\" "},"78":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ عَمْرَو بْنَ حُرَيْثٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ زَيْدٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِحَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي الْحَكَمُ بْنُ عُتَيْبَةَ عَنِ الْحَسَنِ الْعُرَنِيِّ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شُعْبَةُ لَمَّا حَدَّثَنِي بِهِ الْحَكَمُ لَمْ أُنْكِرْهُ مِنْ حَدِيثِ عَبْدِ الْمَلِكِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin 'Umair] berkata; saya mendengar ['Amru bin Huraits] berkata; saya mendengar [Sa'id bin Zaid] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Cendawan berasal Manna, dan airnya merupakan obat untuk mata.\" Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Al Hakam bin 'Utaibah] dari [Hasan Al 'Arani] dari ['Amru bin Huraits] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam. Syu'bah berkata; \"Tatkala Al Hakam menceritakannya kepadaku, saya tidak mengingkari bahwa ini adalah hadits Abdul Malik.\" "},"79":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ عَبْدِ اللَّهِ بْنِ ظَالِمٍ قَالَخَطَبَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَنَالَ مِنْ عَلِيٍّ فَخَرَجَ سَعِيدُ بْنُ زَيْدٍ فَقَالَ أَلَا تَعْجَبُ مِنْ هَذَا يَسُبُّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ أَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّا كُنَّا عَلَى حِرَاءٍ أَوْ أُحُدٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْبُتْ حِرَاءُ أَوْ أُحُدُ فَإِنَّمَا عَلَيْكَ صِدِّيقٌ أَوْ شَهِيدٌ فَسَمَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَشَرَةَ فَسَمَّى أَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ وَعَلِيًّا وَطَلْحَةَ وَالزُّبَيْرَ وَسَعْدًا وَعَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ وَسَمَّى نَفْسَهُ سَعِيدًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Hushain] dari [Hilal bin Yisaf] dari [Abdullah bin Zhalim] berkata; Al Mughirah bin Syu'bah berkhutbah dan mencela Ali radliallahu 'anhu, maka [Sa'id bin Zaid] berdiri dan berkata; Tidak kamu heran terhadap orang ini? dia mencela Ali Radhiallah 'anhu padahal saya menyaksikan Rasulullah shallallahu 'alaihi wasallam ketika kami berada di Hira` atau Uhud. Nabi shallallahu 'alaihi wasallam bersabda: \"Tenanglah Wahai Hira` atau Uhud, yang sedang berada di atasmu adalah seorang yang shiddiq atau orang yang syahid!\" lalu Nabi shallallahu 'alaihi wasallam menyebutkan sepuluh orang.\" Kemudian Sa'id menyebutkan: Abu Bakar, Umar, 'Utsman, Ali, Thalhah, Zubair, Sa'd, Abdurrahman bin 'Auf, dan dia menyebutkan dirinya sendiri Sa'id."},"80":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَوْفٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَهْلٍ عَنْ سَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَرَقَ مِنْ الْأَرْضِ شِبْرًا طُوِّقَهُ مِنْ سَبْعِ أَرَضِينَقَالَ مَعْمَرٌ وَبَلَغَنِي عَنِ الزُّهْرِيِّ وَلَمْ أَسْمَعْهُ مِنْهُ زَادَ فِي هَذَا الْحَدِيثِ وَمَنْ قُتِلَ دُونَ مَالِهِ فَهُوَ شَهِيدٌ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Thalhah bin Abdullah bin 'Auf] dari [Abdurrahman bin Sahl] dari [Sa'id bin Zaid bin 'Amru bin Nufail] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mencuri sejengkal tanah niscaya kelak akan dikalungkan kepadanya dari tujuh lapis bumi.\" Ma'mar berkata; telah sampai kepadaku dari Az Zuhri, namun saya tidak mendengar dia memberikan tambahan dalam hadits ini lafazh: \"Barangsiapa terbunuh karena membela hartanya maka dia adalah syahid.\" "},"81":{"ar":"حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَاقَ عَنِ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَهِدْتُ حِلْفَ الْمُطَيَّبِينَ مَعَ عُمُومَتِي وَأَنَا غُلَامٌ فَمَا أُحِبُّ أَنَّ لِي حُمْرَ النَّعَمِ وَأَنِّي أَنْكُثُهُقَالَ الزُّهْرِيُّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُصِبْ الْإِسْلَامُ حِلْفًا إِلَّا زَادَهُ شِدَّةً وَلَا حِلْفَ فِي الْإِسْلَامِ وَقَدْ أَلَّفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ قُرَيْشٍ وَالْأَنْصَارِ","id":"Telah menceritakan kepada kami [Bisyr bin Muhammad] dari [Abdurrahman bin Ishaq] dari [Az Zuhri] dari [Muhammad bin jubair bin Muth'im] dari [Bapaknya] dari [Abdurrahman bin Auf] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Saya menyaksikan peristiwa perjanjian Mutthayyabin bersama paman-pamanku ketika saya masih kecil. Saya tidak suka walaupun saya mendapat unta merah, jika saya harus membatalkan perjanjian tersebut.\" Az Zuhri menambahkan; Rasulullah bersabda: \"Tidaklah Islam menjumpai satu perjanjian kecuali Islam akan menguatkannya, namun tidak ada lagi perjanjian (yang seperti itu) dalam Islam (karena Islam telah menghapusnya).\" dan sungguh Rasulullah shallallahu 'alaihi wasallam telah menyatukan antara orang-orang Quraisy dengan Anshar.\""},"82":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنِي مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مَكْحُولٍ عَنْ كُرَيْبٍ عَنِ ابْنِ عَبَّاسٍأَنَّهُ قَالَ لَهُ عُمَرُ يَا غُلَامُ هَلْ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ مِنْ أَحَدٍ مِنْ أَصْحَابِهِ إِذَا شَكَّ الرَّجُلُ فِي صَلَاتِهِ مَاذَا يَصْنَعُ قَالَ فَبَيْنَا هُوَ كَذَلِكَ إِذْ أَقْبَلَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فَقَالَ فِيمَ أَنْتُمَا فَقَالَ عُمَرُ سَأَلْتُ هَذَا الْغُلَامَ هَلْ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أَحَدٍ مِنْ أَصْحَابِهِ إِذَا شَكَّ الرَّجُلُ فِي صَلَاتِهِ مَاذَا يَصْنَعُ فَقَالَ عَبْدُ الرَّحْمَنِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلَمْ يَدْرِ أَوَاحِدَةً صَلَّى أَمْ ثِنْتَيْنِ فَلْيَجْعَلْهَا وَاحِدَةً وَإِذَا لَمْ يَدْرِ ثِنْتَيْنِ صَلَّى أَمْ ثَلَاثًا فَلْيَجْعَلْهَا ثِنْتَيْنِ وَإِذَا لَمْ يَدْرِ أَثَلَاثًا صَلَّى أَمْ أَرْبَعًا فَلْيَجْعَلْهَا ثَلَاثًا ثُمَّ يَسْجُدْ إِذَا فَرَغَ مِنْ صَلَاتِهِ وَهُوَ جَالِسٌ قَبْلَ أَنْ يُسَلِّمَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepadaku [Muhammad bin Ishaq] dari [Makhul] dari [Kuraib] dari [Ibnu Abbas] bahwa Umar bertanya kepadanya; \"Wahai anak muda! apakah kamu mendengar dari Rasulullah shallallahu 'alaihi wasallam atau dari salah seorang sahabat beliau, bahwa jika salah seorang ragu dalam shalatnya, apa yang harus dia lakukan?\" Kuraib berkata; Ketika itu datang Abdurrahman bin Auf dan bertanya; \"apa yang sedang kalian bicarakan?\" Umar menjawab; \"Saya bertanya kepada anak muda ini, apakah dia mendengar Rasulullah shallallahu 'alaihi wasallam atau salah seorang dari sahabat beliau, mengenai seseorang yang ragu dalam shalatnya, apa yang harus dia lakukan?\" [Abdurrahman] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian ragu dalam shalatnya dan dia tidak tahu apakah sudah shalat satu raka'at atau dua raka'at maka anggaplah shalat satu raka'at. Jika tidak tahu apakah dia sudah shalat dua raka'at atau tiga raka'at maka anggaplah dia shalat dua raka'at. Jika tidak tahu apakah dia sudah shalat tiga raka'at atau empat raka'at maka anggaplah tiga raka'at, kemudian sujud dua kali jika selesai shalat ketika masih duduk sebelum salam.\" "},"83":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنِ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسٍ سَمِعْتُ عُمَرَ يَقُولُ لِعَبْدِ الرَّحْمَنِ وَطَلْحَةَ وَالزُّبَيْرِ وَسَعْدٍنَشَدْتُكُمْ بِاللَّهِ الَّذِي تَقُومُ بِهِ السَّمَاءُ وَالْأَرْضُ وَقَالَ مَرَّةً الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ أَعَلِمْتُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالُوا اللَّهُمَّ نَعَمْ","id":"Telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Az Zuhri] dari [Malik bin Aus] saya mendengar [Umar radliallahu 'anhu] berkata kepada [Abdurrahman], [Thalhah], [Az Zuhair], dan [Sa'd]; \"Demi Allah, yang dengan-Nya langit dan bumi tegak.-Sufyan berkata; \"Demi yang dengan izinnya (langit dan bumi) tegak\"- Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kami tidak diwarisi. Apa yang kami tinggalkan adalah sedekah.\" Mereka menjawab; \"Ya.\""},"84":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ قَارِظٍ أَنَّ أَبَاهُ حَدَّثَهُأَنَّهُ دَخَلَ عَلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَهُوَ مَرِيضٌ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ وَصَلَتْكَ رَحِمٌ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ عَزَّ وَجَلَّ أَنَا الرَّحْمَنُ خَلَقْتُ الرَّحِمَ وَشَقَقْتُ لَهَا مِنْ اسْمِي فَمَنْ يَصِلْهَا أَصِلْهُ وَمَنْ يَقْطَعْهَا أَقْطَعْهُ فَأَبُتَّهُ أَوْ قَالَ مَنْ يَبُتَّهَا أَبُتَّهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Hisyam Ad Dastuwa`i] dari [Yahya bin Abu Katsir] dari [Ibrahim bin Abdullah bin Farizh] bahwa [bapaknya] telah menceritakan kepadanya, bahwa dia menemui [Abdurrahman bin Auf] ketika sedang sakit. Abdurrahman berkata kepadanya; \"ar rahim telah menyambungmu, Nabi shallallahu 'alaihi wasallam bersabda: \"Allah 'azza wajalla berfirman: 'Aku adalah Ar Rahman yang telah menciptakan rahim dan Aku jadikan kata itu pecahan dari namaKu, barangsiapa yang menyambungnya maka Aku akan menyambungnya, dan barangsiapa yang memutusnya maka Aku akan memutusnya dan memotongnya.\" atau dalam riwayat lain Allah berfirman: \"Barangsiapa memotongnya maka aku akan memotongnya.\""},"85":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ أَنَّ ابْنَ قَارِظٍ أَخْبَرَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّتْ الْمَرْأَةُ خَمْسَهَا وَصَامَتْ شَهْرَهَا وَحَفِظَتْ فَرْجَهَا وَأَطَاعَتْ زَوْجَهَا قِيلَ لَهَا ادْخُلِي الْجَنَّةَ مِنْ أَيِّ أَبْوَابِ الْجَنَّةِ شِئْتِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah menceritakan kepada kami [Ibnu Lahi'ah] dari ['Ubaidullah bin Abu Ja'far] bahwa [Ibnu Qarizh] mengabarinya dari [Abdurrahman bin Auf] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang istri melaksanakan shalat lima waktu, berpuasa di bulan Ramadhan, menjaga kemaluannya dan ta'at kepada suaminya, niscaya akan dikatakan kepadanya; 'Masuklah kamu ke dalam syurga dari pintu mana saja yang kamu inginkan'.\""},"86":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ مَنْصُورُ بْنُ سَلَمَةَ الْخُزَاعِيُّ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ أَبِي الْحُوَيْرِثِ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاتَّبَعْتُهُ حَتَّى دَخَلَ نَخْلًا فَسَجَدَ فَأَطَالَ السُّجُودَ حَتَّى خِفْتُ أَوْ خَشِيتُ أَنْ يَكُونَ اللَّهُ قَدْ تَوَفَّاهُ أَوْ قَبَضَهُ قَالَ فَجِئْتُ أَنْظُرُ فَرَفَعَ رَأْسَهُ فَقَالَ مَا لَكَ يَا عَبْدَ الرَّحْمَنِ قَالَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام قَالَ لِي أَلَا أُبَشِّرُكَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَقُولُ لَكَ مَنْ صَلَّى عَلَيْكَ صَلَّيْتُ عَلَيْهِ وَمَنْ سَلَّمَ عَلَيْكَ سَلَّمْتُ عَلَيْهِحَدَّثَنَا يُونُسُ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ عَنْ عَمْرٍو عَنْ عَبْدِ الرَّحْمَنِ أَبِي الْحُوَيْرِثِ عَنْ مُحَمَّدِ بْنِ جُبَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَ دَخَلْتُ الْمَسْجِدَ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَارِجًا مِنْ الْمَسْجِدِ فَاتَّبَعْتُهُ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abu Salamah Manshur bin Salamah Al Khuza'i] telah menceritakan kepada kami [Laits] dari [Yazid bin Al Had] dari ['Amru bin Abu 'Amru] dari [Abu Al Huwairits] dari [Muhammad bin Jubair bin Muth'im] dari [Abdurrahman bin Auf] berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam keluar kemudian aku mengikuti beliau, ketika beliau masuk ke kebun kurma, beliau bersujud dengan memanjangkannya sehingga membuatku takut atau khawatir jika Allah mewafatkan atau mencabut ruhnya. Maka aku mendekati beliau dan memperhatikannya, tiba-tiba beliau mengangkat kepalanya, lalu bertanya: \"ada apa denganmu wahai Abdurrahman?\" saya pun menerangkan hal itu kepada beliau, dan beliau menjawab; \"Jibril 'Alaihiis salam berkata kepadaku: 'Apakah kamu mau aku sampaikan kabar gembira kepadamu, sesungguhnya Allah 'azza wajalla berfirman kepadamu: 'Barangsiapa bershalawat kepadamu, niscaya Aku akan bershalawat kepadanya, dan barangsiapa yang mengucapkan salam kepadamu niscaya aku akan mengucapkan salam kepadanya.\" Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Laits] dari [Yazid] dari ['Amru] dari [Abdurrahman Abu Al Huwairits] dari [Muhammad bin Jubair] dari [Abdurrahman bin Auf] berkata; \"Aku masuk masjid dan melihat Rasulullah shallallahu 'alaihi wasallam keluar dari masjid, kemudian aku mengikutinya.., \" kemudian dia menyebutkan hadits secara lengkap. "},"87":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنَا عَمْرُو بْنُ أَبِي عَمْرٍو عَنْ عَبْدِ الْوَاحِدِ بْنِ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَوَجَّهَ نَحْوَ صَدَقَتِهِ فَدَخَلَ فَاسْتَقْبَلَ الْقِبْلَةَ فَخَرَّ سَاجِدًا فَأَطَالَ السُّجُودَ حَتَّى ظَنَنْتُ أَنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ قَبَضَ نَفْسَهُ فِيهَا فَدَنَوْتُ مِنْهُ فَجَلَسْتُ فَرَفَعَ رَأْسَهُ فَقَالَ مَنْ هَذَا قُلْتُ عَبْدُ الرَّحْمَنِ قَالَ مَا شَأْنُكَ قُلْتُ يَا رَسُولَ اللَّهِ سَجَدْتَ سَجْدَةً خَشِيتُ أَنْ يَكُونَ اللَّهُ عَزَّ وَجَلَّ قَدْ قَبَضَ نَفْسَكَ فِيهَا فَقَالَ إِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام أَتَانِي فَبَشَّرَنِي فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَقُولُ مَنْ صَلَّى عَلَيْكَ صَلَّيْتُ عَلَيْهِ وَمَنْ سَلَّمَ عَلَيْكَ سَلَّمْتُ عَلَيْهِ فَسَجَدْتُ لِلَّهِ عَزَّ وَجَلَّ شُكْرًا","id":"Telah menceritakan kepada kami [Abu Sa'id] mantan budak Bani Hasyim, telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepada kami ['Amru bin Abu 'Amru] dari [Abdul Wahid bin Muhammad bin Abdurrahman bin Auf] dari [Abdurrahman bin Auf] berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam keluar menuju ke arah tempat shalatnya, setelah beliau masuk, beliau menghadap kiblat dan tersungkur sujud. Beliau memanjangkan sujudnya sampai saya mengira bahwa Allah Azza Wa Jalla telah mencabut nyawa beliau pada saat itu. Maka aku pun mendekati beliau dan duduk, tiba-tiba beliau mengangkat kepalanya dan bertanya: \"Siapa kamu?\" aku menjawab; \"Abdurrahman bin Auf.\" Beliau bertanya; \"Ada apa?\" aku menjawab; \"Wahai Rasulullah, anda melakukan sujud yang saya khawatir bahwa Allah telah mencabut nyawa anda pada saat itu.\" Beliau bersabda: \"Jibril 'Alaihis salam mendatangiku dan menyampaikan kabar gembira kepadaku, dia berkata bahwa Allah telah berfirman; 'Barangsiapa bershalawat kepadamu niscaya Aku akan bershalawat kepadanya, dan barangsiapa yang mengucapkan salam kepadamu niscaya aku akan mengucapkan salam kepadanya.' Maka saya bersujud kepada Allah Azza Wa Jalla.\""},"88":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَانَ الْوَبَاءُ بِأَرْضٍ وَلَسْتَ بِهَا فَلَا تَدْخُلْهَا وَإِذَا كَانَ بِأَرْضٍ وَأَنْتَ بِهَا فَلَا تَخْرُجْ مِنْهَا","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Muhammad bin Abu Hafshah] telah menceritakan kepada kami [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata; saya mendengar [Abdurrahman bin Auf] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila wabah penyakit sedang menyebar di suatu tempat dan kamu tidak berada di dalamnya, janganlah kalian memasukinya, dan jika kamu di dalamnya maka janganlah kamu keluar darinya.\""},"89":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍأَنَّ قَوْمًا مِنْ الْعَرَبِ أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَأَسْلَمُوا وَأَصَابَهُمْ وَبَاءُ الْمَدِينَةِ حُمَّاهَا فَأُرْكِسُوا فَخَرَجُوا مِنْ الْمَدِينَةِ فَاسْتَقْبَلَهُمْ نَفَرٌ مِنْ أَصْحَابِهِ يَعْنِي أَصْحَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا لَهُمْ مَا لَكُمْ رَجَعْتُمْ قَالُوا أَصَابَنَا وَبَاءُ الْمَدِينَةِ فَاجْتَوَيْنَا الْمَدِينَةَ فَقَالُوا أَمَا لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ فَقَالَ بَعْضُهُمْ نَافَقُوا وَقَالَ بَعْضُهُمْ لَمْ يُنَافِقُوا هُمْ مُسْلِمُونَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ وَاللَّهُ أَرْكَسَهُمْ بِمَا كَسَبُوا }الْآيَةَ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Salamah] dari [Yazid bin Abdullah bin Qusaith] dari [Abu Salamah bin Abdurrahman bin Auf] dari [Abddurrahman bin Auf]; bahwa Suatu kaum dari bangsa Arab menemui Rasulullah shallallahu 'alaihi wasallam di Madinah dan masuk Islam, kemudian mereka tertimpa wabah penyakit di Madinah berupa sakit panas. Lalu mereka berbalik murtad dan keluar dari Madinah, maka sekelompok orang dari sahabat beliau, yaitu sahabat Nabi shallallahu 'alaihi wasallam menyusul mereka dan bertanya; \"Kenapa kalian kembali menjadi murtad?\" mereka menjawab; \"Kami terkena wabah penyakit Madinah, Madinah tidak cocok bagi kami.\" Para sahabat berkata; \"Bukankah sudah ada contoh dari Rasulullah bagi kalian?\" maka sebagian sahabat berpendapat bahwa mereka munafiq, dan sebagian yang lain berpendapat bahwa mereka bukan munafiq tetapi mereka adalah orang-orang muslim. maka turunlah firman Allah 'azza wajalla: (Maka Mengapa kamu (terpecah) menjadi dua golongan dalam (menghadapi) orang-orang munafik, padahal Allah Telah membalikkan mereka kepada kekafiran)."},"90":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ قَالَأَقْطَعَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعُمَرَ بْنَ الْخَطَّابِ أَرْضَ كَذَا وَكَذَا فَذَهَبَ الزُّبَيْرُ إِلَى آلِ عُمَرَ فَاشْتَرَى نَصِيبَهُ مِنْهُمْ فَأَتَى عُثْمَانَ بْنَ عَفَّانَ فَقَالَ إِنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ زَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْطَعَهُ وَعُمَرَ بْنَ الْخَطَّابِ أَرْضَ كَذَا وَكَذَا وَإِنِّي اشْتَرَيْتُ نَصِيبَ آلِ عُمَرَ فَقَالَ عُثْمَانُ عَبْدُ الرَّحْمَنِ جَائِزُ الشَّهَادَةِ لَهُ وَعَلَيْهِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari ['Urwah] bahwa [Abdurrahman bin Auf] berkata; Rasulullah shallallahu 'alaihi wasallam menetapkan bagian untukku dan untuk Umar bin Khaththab tanah ini dan ini, maka Zubair pergi kepada keluarga Umar dan membeli bagian Umar dari mereka. Setelah itu dia pergi kepada Utsman bin Affan dan berkata; \"Abdurrahman bin Auf mengaku bahwa Rasulullah shallallahu 'alaihi wasallam telah memutuskan untuknya dan untuk Umar bin Khaththab bagian tanah ini dan ini, dan aku membeli bagian keluarga Umar.\" Maka Utsman berkata; \"Abdurrahman boleh memberikan persaksiannya yang menguntungkan dirinya ataupun merugikannya.\""},"91":{"ar":"حَدَّثَنَا زِيَادُ بْنُ الرَّبِيعِ أَبُو خِدَاشٍ حَدَّثَنَا وَاصِلٌ مَوْلَى أَبِي عُيَيْنَةَ عَنْ بَشَّارِ بْنِ أَبِي سَيْفٍ الْجَرْمِيِّ عَنْ عِيَاضِ بْنِ غُطَيْفٍ قَ��لَدَخَلْنَا عَلَى أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ نَعُودُهُ مِنْ شَكْوًى أَصَابَهُ وَامْرَأَتُهُ تُحَيْفَةُ قَاعِدَةٌ عِنْدَ رَأْسِهِ قُلْتُ كَيْفَ بَاتَ أَبُو عُبَيْدَةَ قَالَتْ وَاللَّهِ لَقَدْ بَاتَ بِأَجْرٍ فَقَالَ أَبُو عُبَيْدَةَ مَا بِتُّ بِأَجْرٍ وَكَانَ مُقْبِلًا بِوَجْهِهِ عَلَى الْحَائِطِ فَأَقْبَلَ عَلَى الْقَوْمِ بِوَجْهِهِ فَقَالَ أَلَا تَسْأَلُونَنِي عَمَّا قُلْتُ قَالُوا مَا أَعْجَبَنَا مَا قُلْتَ فَنَسْأَلُكَ عَنْهُ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَنْفَقَ نَفَقَةً فَاضِلَةً فِي سَبِيلِ اللَّهِ فَبِسَبْعِ مِائَةٍ وَمَنْ أَنْفَقَ عَلَى نَفْسِهِ وَأَهْلِهِ أَوْ عَادَ مَرِيضًا أَوْ مَازَ أَذًى فَالْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا وَالصَّوْمُ جُنَّةٌ مَا لَمْ يَخْرِقْهَا وَمَنْ ابْتَلَاهُ اللَّهُ بِبَلَاءٍ فِي جَسَدِهِ فَهُوَ لَهُ حِطَّةٌ","id":"Telah menceritakan kepada kami [Ziyad bin Ar Rabi' Abu Khidasy] telah menceritakan kepada kami [Washil] mantan budak Abu 'Uyainah, dari [Basysyar bin Saif Al Jarmi] dari ['Iyadh bin Ghuthaif] berkata; Kami menemui [Abu Ubaidah bin Al Jarrah] untuk menjenguknya karena sakit yang menimpanya, sedangkan istrinya Tuhaifah duduk di dekat kepalanya. Aku bertanya; \"Bagaimana kondisi Abu Ubaidah tadi malam?\" istrinya menjawab; \"Demi Allah! dia melewati malamnya dengan mendapatkan pahala.\" Abu Ubaidah berkata; \"Aku melewati malam dengan tidak mendapatkan pahala.\" sebelumnya dia menghadapkan wajahnya ke tembok, lalu menghadap kepada orang-orang. Dia berkata lagi; \"Tidakkah kalian menanyakan tentang apa yang baru aku katakan?\" Mereka menjawab; \"sungguh sangat menggelitik kami perkataanmu tadi sehingga kami harus menanyakannya kepadamu.\" Dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menginfaqkan hartanya yang utama di jalan Allah, maka baginya tujuh ratus pahala, dan barangsiapa memberikan nafkah untuk dirinya dan keluarganya atau menjenguk orang yang sakit atau menyingkirkan duri maka satu kebaikan baginya dilipatkan menjadi sepuluh kali lipat yang semisalnya. Puasa adalah benteng selama tidak merusaknya (dengan maksiat), dan barangsiapa yang diuji oleh Allah dengan suatu ujian di tubuhnya maka baginya dihapuskan dosanya\".\" "},"92":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَيْمُونٍ حَدَّثَنَا سَعْدُ بْنُ سَمُرَةَ بْنِ جُنْدُبٍ عَنْ أَبِيهِ عَنْ أَبِي عُبَيْدَةَ قَالَآخِرُ مَا تَكَلَّمَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْرِجُوا يَهُودَ أَهْلِ الْحِجَازِ وَأَهْلِ نَجْرَانَ مِنْ جَزِيرَةِ الْعَرَبِ وَاعْلَمُوا أَنَّ شِرَارَ النَّاسِ الَّذِينَ اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Ibrahim bin Maimun] telah menceritakan kepada kami [Sa'd bin Samurah bin Jundub] dari [Bapaknya] dari [Abu 'Ubaidah] berkata; Akhir perkataan yang diucapkan Nabi shallallahu 'alaihi wasallam adalah: \"Keluarkan orang Yahudi Hijaz dan Najran dari Jazirah Arab, dan ketahuilah bahwa orang yang paling buruk diantara manusia adalah mereka yang menjadikan kuburan Nabi-Nabi mereka sebagai masjid.\" "},"93":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذَكَرَ الدَّجَّالَ فَحَلَّاهُ بِحِلْيَةٍ لَا أَحْفَظُهَا قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ قُلُوبُنَا يَوْمَئِذٍ كَالْيَوْمِ فَقَالَ أَوْ خَيْرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abdullah bin Syaqiq] dari [Abdullah bin Suraqah] dari [Abu Ubaidah bin Al Jarrah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau menyebutkan tentang Dajjal, lalu beliau merincikan dengan ciri cirinya yang aku tidak dapat mengingatnya.\" Para sahabat bertanya; \"Wahai Rasulullah bagaimana hati kami ketika itu, apakah seperti hari ini?\" beliau menjawab; \"Atau (bisa jadi) lebih baik.\""},"94":{"ar":"حَدَّثَنَا عَفَّانُ وَعَبْدُ الصَّمَدِ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَنْبَأَنَا خَالِدٌ الْحَذَّاءُ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ سُرَاقَةَ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ لَمْ يَكُنْ نَبِيٌّ بَعْدَ نُوحٍ إِلَّا وَقَدْ أَنْذَرَ الدَّجَّالَ قَوْمَهُ وَإِنِّي أُنْذِرُكُمُوهُ قَالَ فَوَصَفَهُ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَلَعَلَّهُ يُدْرِكُهُ بَعْضُ مَنْ رَآنِي أَوْ سَمِعَ كَلَامِي قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ قُلُوبُنَا يَوْمَئِذٍ أَمِثْلُهَا الْيَوْمَ قَالَ أَوْ خَيْرٌ","id":"Telah menceritakan kepada kami ['Affan] dan [Abdushshamad] berkata; telah menceritakan kepada kami [Hammad bin Salamah] telah memberitakan kepada kami [Khalid Al Hadza`] dari [Abdullah bin Syaqiq] dari [Abdullah bin Suraqah] dari [Abu Ubaidah bin Al Jarrah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya tidak ada seorang Nabi pun setelah Nabi Nuh kecuali dia memperingatkan tentang Dajjal kepada umatnya, dan aku pasti memperingatkannya kepada kalian.\" Abu Ubaidah berkata; \"Lalu Rasulullah shallallahu 'alaihi wasallam menyebutkan ciri-cirinya dan berkata; \"Barangkali ada sebagian orang yang sempat melihatku atau mendengar perkataanku akan menemuinya.\" para shahabat bertanya; \"Apakah kondisi hati kami pada saat itu sebagaimana keadaan hati sekarang ini?\" beliau menjawab; \"Bisa jadi lebih baik.\""},"95":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَيْمُونٍ عَنْ سَعْدِ بْنِ سَمُرَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ قَالَكَانَ آخِرُ مَا تَكَلَّمَ بِهِ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَخْرِجُوا يَهُودَ الْحِجَازِ مِنْ جَزِيرَةِ الْعَرَبِ وَاعْلَمُوا أَنَّ شِرَارَ النَّاسِ الَّذِينَ يَتَّخِذُونَ الْقُبُورَ مَسَاجِدَ","id":"Telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Ibrahim bin Maimun] dari [Sa'd bin Samurah] dari [Samurah bin Jundub] dari [Abu 'Ubaidah bin Al Jarrah] berkata; Akhir perkataan yang diucapkan Nabiyullah shallallahu 'alaihi wasallam adalah: \"Keluarkan orang Yahudi Hijaz di jazirah Arab, dan ketahuilah bahwa orang yang paling buruk diantara manusia adalah mereka yang menjadikan kuburan Nabi-Nabi mereka sebagai masjid.\" "},"96":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عُمَرَ حَدَّثَنَا إِسْرَائِيلُ عَنِ الْحَجَّاجِ بْنِ أَرْطَاةَ عَنِ الْوَلِيدِ بْنِ أَبِي مَالِكٍ عَنِ الْقَاسِمِ عَنْ أَبِي أُمَامَةَ قَالَأَجَارَ رَجُلٌ مِنْ الْمُسْلِمِينَ رَجُلًا وَعَلَى الْجَيْشِ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ فَقَالَ خَالِدُ بْنُ الْوَلِيدِ وَعَمْرُو بْنُ الْعَاصِ لَا نُجِيرُهُ وَقَالَ أَبُو عُبَيْدَةَ نُجِيرُهُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُجِيرُ عَلَى الْمُسْلِمِينَ أَحَدُهُمْ","id":"Telah menceritakan kepada kami [Isma'il bin Umar] telah menceritakan kepada kami [Abu Israil] dari [Al Hajjaj bin Arthah] dari [Al Walid bin Abu Malik] dari [Al Qasim] dari [Abu Umamah] berkata; Seorang Muslim melindungi seseorang, ketika itu komandan pasukan adalah [Abu Ubaidah bin Jarrah]. Kemudian Khalid bin Al Walid dan 'Amru bin Ash berkata; \"Kami tidak melindunginya.\" Maka Abu Ubaidah berkata; Kami melindunginya, karena saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang dari kaum muslim memiliki hak perlindungan.\" "},"97":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو حِسْبَةَ مُسْلِمُ بْنُ أُكَيْسٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عَامِرٍ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ قَالَ ذَكَرَ مَنْ دَخَلَ عَلَيْهِ فَوَجَدَهُ يَبْكِي فَقَالَ مَا يُبْكِيكَ يَا أَبَا عُبَيْدَةَ فَقَالَنَبْكِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ يَوْمًا مَا يَفْتَحُ اللَّهُ عَلَى الْمُسْلِمِينَ وَيُفِيءُ عَلَيْهِمْ حَتَّى ذَكَرَ الشَّامَ فَقَالَ إِنْ يُنْسَأْ فِي أَجَلِكَ يَا أَبَا عُبَيْدَةَ فَحَسْبُكَ مِنْ الْخَدَمِ ثَلَاثَةٌ خَادِمٌ يَخْدُمُكَ وَخَادِمٌ يُسَافِرُ مَعَكَ وَخَادِمٌ يَخْدُمُ أَهْلَكَ وَيَرُدُّ عَلَيْهِمْ وَحَسْبُكَ مِنْ الدَّوَابِّ ثَلَاثَةٌ دَابَّةٌ لِرَحْلِكَ وَدَابَّةٌ لِثَقَلِكَ وَدَابَّةٌ لِغُلَامِكَ ثُمَّ هَذَا أَنَا أَنْظُرُ إِلَى بَيْتِي قَدْ امْتَلَأَ رَقِيقًا وَأَنْظُرُ إِلَى مِرْبَطِي قَدْ امْتَلَأَ دَوَابَّ وَخَيْلًا فَكَيْفَ أَلْقَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هَذَا وَقَدْ أَوْصَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَبَّكُمْ إِلَيَّ وَأَقْرَبَكُمْ مِنِّي مَنْ لَقِيَنِي عَلَى مِثْلِ الْحَالِ الَّذِي فَارَقَنِي عَلَيْهَا","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Shafwan bin 'Amru] telah menceritakan kepada kami [Abu Hisbah, Muslim bin Ukais] mantan budak Abdullah bin 'Amir, dari Abu Ubaidah bin Jarrah, Abu Hisbah berkata; telah menceritakan [orang] yang menemuinya ketika dia sedang menangis. Orang itu bertanya; \"Apa yang menyebabkanmu menangis wahai [Abu Ubaidah]?\" Dia menjawab; \"Kami menangis karena pada suatu hari Rasulullah shallallahu 'alaihi wasallam menyebutkan, bahwa Allah akan memenangkan kaum muslimin dan memberi mereka rampasan Perang sampai beliau menyebut negeri Syam. Beliau bersabda: \"Jika ajalmu di akhirkan wahai Abu Ubaidah, maka cukuplah bagimu tiga pelayan; satu pelayan melayanimu, satu pelayan lagi yang melayani perjalananmu dan terakhir yang melayani keluargamu dan membantu mereka. Cukuplah bagimu tiga kendaraan; satu kendaraan untuk kamu naiki, satunya untuk membawa barang-barangmu dan satunya lagi untuk budakmu.\" kemudian saya melihat ke rumahku, ternyata telah penuh dengan budak laki-laki dan aku melihat ke kandang untaku, telah penuh dengan kendaraan unta dan kuda, bagaimana aku bertemu Rasulullah shallallahu 'alaihi wasallam setelah ini, padahal Rasulullah shallallahu 'alaihi wasallam telah berwasiat kepada kami: \"Orang yang paling aku cintai dan paling dekat kepadaku diantara kalian adalah orang yang berjumpa denganku dalam kondisi sebagaimana ketika dia berpisah denganku.\""},"98":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي أَبَانُ بْنُ صَالِحٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ الْأَشْعَرِيِّ عَنْ رَابِّهِ رَجُلٍ مِنْ قَوْمِهِ كَانَ خَلَفَ عَلَى أُمِّهِ بَعْدَ أَبِيهِ كَانَ شَهِدَ طَاعُونَ عَمَوَاسَ قَالَلَمَّا اشْتَعَلَ الْوَجَعُ قَامَ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ فِي النَّاسِ خَطِيبًا فَقَالَ أَيُّهَا النَّاسُ إِنَّ هَذَا الْوَجَعَ رَحْمَةُ رَبِّكُمْ وَدَعْوَةُ نَبِيِّكُمْ وَمَوْتُ الصَّالِحِينَ قَبْلَكُمْ وَإِنَّ أَبَا عُبَيْدَةَ يَسْأَلُ اللَّهَ أَنْ يَقْسِمَ لَهُ مِنْهُ حَظَّهُ قَالَ فَطُعِنَ فَمَاتَ رَحِمَهُ اللَّهُوَاسْتُخْلِفَ عَلَى النَّاسِ مُعَاذُ بْنُ جَبَلٍ فَقَامَ خَطِيبًا بَعْدَهُ فَقَالَ أَيُّهَا النَّاسُ إِنَّ هَذَا الْوَجَعَ رَحْمَةُ رَبِّكُمْ وَدَعْوَةُ نَبِيِّكُمْ وَمَوْتُ الصَّالِحِينَ قَبْلَكُمْ وَإِنَّ مُعَاذًا يَسْأَلُ اللَّهَ أَنْ يَقْسِمَ لِآلِ مُعَاذٍ مِنْهُ حَظَّهُ قَالَ فَطُعِنَ ابْنُهُ عَبْدُ الرَّحْمَنِ بْنُ مُعَاذٍ فَمَاتَ ثُمَّ قَامَ فَدَعَا رَبَّهُ لِنَفْسِهِ فَطُعِنَ فِي رَاحَتِهِ فَلَقَدْ رَأَيْتُهُ يَنْظُرُ إِلَيْهَا ثُمَّ يُقَبِّلُ ظَهْرَ كَفِّهِ ثُمَّ يَقُولُ مَا أُحِبُّ أَنَّ لِي بِمَا فِيكِ شَيْئًا مِنْ الدُّنْيَا فَلَمَّا مَاتَ اسْتُخْلِفَ عَلَى النَّاسِ عَمْرُو بْنُ الْعَاصِ فَقَامَ فِينَا خَطِيبًا فَقَالَ أَيُّهَا النَّاسُ إِنَّ هَذَا الْوَجَعَ إِذَا وَقَعَ فَإِنَّمَا يَشْتَعِلُ اشْتِعَالَ النَّارِ فَتَجَبَّلُوا مِنْهُ فِي الْجِبَالِ قَالَ فَقَالَ لَهُ أَبُو وَاثِلَةَ الْهُذَلِيُّ كَذَبْتَ وَاللَّهِ لَقَدْ صَحِبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتَ شَرٌّ مِنْ حِمَارِي هَذَا قَالَ وَاللَّهِ مَا أَرُدُّ عَلَيْكَ مَا تَقُولُ وَايْمُ اللَّهِ لَا نُقِيمُ عَلَيْهِ ثُمَّ خَرَجَ وَخَرَجَ النَّاسُ فَتَفَرَّقُوا عَنْهُ وَدَفَعَهُ اللَّهُ عَنْهُمْ قَالَ فَبَلَغَ ذَلِكَ عُمَرَ بْنَ الْخَطَّابِ مِنْ رَأْيِ عَمْرٍو فَوَاللَّهِ مَا كَرِهَهُ قَالَ أَبُو عَبْد الرَّحْمَنِ عَبْد اللَّهِ بْن أَحْمَد بْن حَنْبَلٍ أَبَانُ بْنُ صَالِحٍ جَدُّ أَبِي عَبْ��ِ الرَّحْمَنِ مُشْكُدَانَةَ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Aban bin Shalih] dari [Syahr bin Hausyab Al Asy'ari] dari [suami ibunya], seorang lelaki dari kaumnya yang menikahi ibunya setelah ayahnya meninggal, dia termasuk yang menyaksikan peristiwa menjangkitnya penyakit lepra yang merajalela, dia berkata; Ketika wabah merajalela, berdirilah [Abu Ubaidah bin Jarrah] berkhutbah di hadapan orang-orang dan berkata; \"Wahai manusia! sesungguhnya penyakit ini merupakan rahmat dari Rabb kalian, doa para Nabi kalian, dan sebab kematian orang-orang shalih sebelum kalian. Dan sesungguhnya Abu Ubaidah memohon kepada Allah untuk mendapat bagian dari rahmat tersebut.\" Lalu dia terjangkit penyakit lepra tersebut sehingga meninggal dunia -semoga Allah memberikan rahmat kepadanya.- kemudian [Mu'adz bin Jabal] menggantikan dia untuk memimpin orang-orang, kemudian dia dia berdiri menyampaikan khutbah setelah wafatnya Abu Ubaidah; \"Wahai manusia, penyakit ini merupakan rahmat dari Rabb kalian, doanya para Nabi kalian dan sebab kematiannya para orang-orang shalih sebelum kalian. Dan sesungguhnya Mu'adz memohon kepada Allah agar keluarga Mu'adz mendapat bagian dari rahmat tersebut.\" Kemudian Abdurrahman bin Mu'adz, anaknya terjangkit penyakit lepra sampai meninggal. Dia pun bangkit memohon kepada Rabbnya untuk dirinya, dan akhirnya dia juga terjangkit lepra di telapak tangannya. Sungguh saya melihatnya memperhatikan penyakit lepra tersebut kemudian mencium bagian atas tangannya sambil berkata; \"Aku tidak senang mempunyaimu dan (aku pergunakan untuk meletakkan perhiasan) dunia ada padamu.\" Ketika dia wafat, 'Amru bin Al Ash menggantikan kedudukannya untuk memimpin orang-orang. Kemudian dia berdiri menyampaikan khutbah di hadapan kami; \"Wahai manusia! sesungguhnya jika wabah ini menjangkiti (di suatu negri) maka dia akan melahap sebagaimana menyalanya api, maka menghindarlah kalian ke gunung-gunung.\" Tetapi Abu Watsilah Al Hudzali berkata kepadanya; \"Demi Allah, kamu telah berdusta, saya pernah menyertai Rasulullah shallallahu 'alaihi wasallam dan kamu lebih buruk daripada keledaiku ini.\" 'Amru berkata; \"Demi Allah aku tidak akan membalas perkataanmu, demi Allah saya tidak akan memperkarakan perkataanmu itu.\" dia pun keluar dan orang-orangpun keluar berpencar darinya, kemudian Allah melenyapkan wabah tersebut dari mereka. Ketika pendapat 'Amru tersebut sampai kepada Umar bin Khaththab, demi Allah dia tidak membencinya.\" Abu Abdullah, Abdurrahman bin Ahmad bin Hanbal berkata; \"Aban bin Shalih adalah kakek Abdurrahman Musykudanah.\""},"99":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ دَاوُدَ عَنْ عَامِرٍ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَيْشَ ذَاتِ السُّلَاسِلِ فَاسْتَعْمَلَ أَبَا عُبَيْدَةَ عَلَى الْمُهَاجِرِينَ وَاسْتَعْمَلَ عَمْرَو بْنَ الْعَاصِ عَلَى الْأَعْرَابِ فَقَالَ لَهُمَا تَطَاوَعَا قَالَ وَكَانُوا يُؤْمَرُونَ أَنْ يُغِيرُوا عَلَى بَكْرٍ فَانْطَلَقَ عَمْرٌو فَأَغَارَ عَلَى قُضَاعَةَ لِأَنَّ بَكْرًا أَخْوَالُهُ فَانْطَلَقَ الْمُغِيرَةُ بْنُ شُعْبَةَ إِلَى أَبِي عُبَيْدَةَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَكَ عَلَيْنَا وَإِنَّ ابْنَ فُلَانٍ قَدْ ارْتَبَعَ أَمْرَ الْقَوْمِ وَلَيْسَ لَكَ مَعَهُ أَمْرٌ فَقَالَ أَبُو عُبَيْدَةَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَنَا أَنْ نَتَطَاوَعَ فَأَنَا أُطِيعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ عَصَاهُ عَمْرٌو","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Daud] dari ['Amir] berkata; \"Rasulullah shallallahu 'alaihi wasallam mengutus sekelompok pasukan ke Dzatu Salasil. Beliau menjadikan Abu Ubaidah sebagai komandan bagi kaum Muhajirin dan Amru bin al Ash sebagai komandan bagi orang-orang Badui. Beliau berpesan kepada mereka berdua: \"Lakukanlah dengan sukarela!\" ketika itu mereka mendapat misi untuk menyerang Bani Bakr, tetapi 'Amru berangkat dan menyerang Bani Qudlz'ah karena Bani Bakr adalah paman dari Bani Qudla'ah. Maka Al Mughirah bin Syu'bah berangkat menemui Abu 'Ubaidah. Dia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah mengangkat anda untuk menjadi pemimpin kami, sedangkan anak fulan telah berangkat memimpin kaumnya, sehingga kamu sudah tidak ada lagi wewenang untuk mereka.\" Abu 'Ubaidah berkata; Rasulullah shallallahu 'alaihi wasallam menyuruh kami agar kami melakukannya dengan sukarela sedangkan saya akan mentaati Rasulullah shallallahu 'alaihi wasallam walau 'Amru membantahnya.\""},"100":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا هِشَامٌ عَنْ وَاصِلٍ عَنِ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عِيَاضِ بْنِ غُطَيْفٍ قَالَدَخَلْنَا عَلَى أَبِي عُبَيْدَةَ نَعُودُهُ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَنْفَقَ نَفَقَةً فَاضِلَةً فِي سَبِيلِ اللَّهِ فَبِسَبْعِ مِائَةٍ وَمَنْ أَنْفَقَ عَلَى نَفْسِهِ أَوْ عَلَى أَهْلِهِ أَوْ عَادَ مَرِيضًا أَوْ مَازَ أَذًى عَنْ طَرِيقٍ فَهِيَ حَسَنَةٌ بِعَشْرِ أَمْثَالِهَا وَالصَّوْمُ جُنَّةٌ مَا لَمْ يَخْرِقْهَا وَمَنْ ابْتَلَاهُ اللَّهُ بَلَاءً فِي جَسَدِهِ فَهُوَ لَهُ حِطَّةٌحَدَّثَنَا يَزِيدُ أَنْبَأَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا بَشَّارُ بْنُ أَبِي سَيْفٍ عَنِ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عِيَاضِ بْنِ غُطَيْفٍ قَالَ دَخَلْنَا عَلَى أَبِي عُبَيْدَةَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah memberitakan kepada kami [Hisyam] dari [Washil] dari [Al Walid bin Abdurrahman] dari ['Iyadh bin Ghuthaif] berkata; Kami menemui [Abu 'Ubaidah] untuk menjenguknya. Dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berinfak harta yang utamanya di jalan Allah maka dia akan mendapatkan tujuh ratus kali lipat. Barangsiapa berifak untuk dirinya, atau untuk keluarganya, atau menjenguk orang sakit, atau menyingkirkan duri di jalanan maka setiap kebaikan itu akan dibalas sepuluh kali lipatnya. Puasa adalah tameng selama dia tidak merusaknya. Barangsiapa diuji Allah dengan suatu ujian pada tubuhnya maka itu menjadi penghapus (dsa) baginya.\" Telah menceritakan kepada kami [Yazid] telah memberitakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Basyar bin Abu Saif] dari [Al Walid bin Abdurrahman] dari ['Iyadh bin Ghuthaif] berkata; \"Kami menemui [Abu 'Ubaidah]..\" lalu menyebutkan hadits secara lengkap. "},"101":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ يَعْنِي التَّيْمِيَّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ قَالَجَاءَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بِضَيْفٍ لَهُ أَوْ بِأَضْيَافٍ لَهُ قَالَ فَأَمْسَى عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا أَمْسَى قَالَتْ لَهُ أُمِّي احْتَبَسْتَ عَنْ ضَيْفِكَ أَوْ أَضْيَافِكَ مُنْذُ اللَّيْلَةِ قَالَ أَمَا عَشَّيْتِهِمْ قَالَتْ لَا قَالَتْ قَدْ عَرَضْتُ ذَاكَ عَلَيْهِ أَوْ عَلَيْهِمْ فَأَبَوْا أَوْ فَأَبَى قَالَ فَغَضِبَ أَبُو بَكْرٍ وَحَلَفَ أَنْ لَا يَطْعَمَهُ وَحَلَفَ الضَّيْفُ أَوْ الْأَضْيَافُ أَنْ لَا يَطْعَمُوهُ حَتَّى يَطْعَمَهُ فَقَالَ أَبُو بَكْرٍ إِنْ كَانَتْ هَذِهِ مِنْ الشَّيْطَانِ قَالَ فَدَعَا بِالطَّعَامِ فَأَكَلَ وَأَكَلُوا قَالَ فَجَعَلُوا لَا يَرْفَعُونَ لُقْمَةً إِلَّا رَبَتْ مِنْ أَسْفَلِهَا أَكْثَرَ مِنْهَا فَقَالَ يَا أُخْتَ بَنِي فِرَاسٍ مَا هَذَا قَالَ فَقَالَتْ قُرَّةُ عَيْنِي إِنَّهَا الْآنَ لَأَكْثَرُ مِنْهَا قَبْلَ أَنْ نَأْكُلَ قَالَ فَأَكَلُوا وَبَعَثَ بِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَنَّهُ أَكَلَ مِنْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Sulaiman] yaitu At Taimi, dari [Abu 'Utsman] dari [Abdurrahman bin Abu Bakar] berkata; Abu Bakar datang bersama seseorang atau beberapa orang tamunya. Kemudian Abu Bakar menghabiskan waktu sore di sisi Nabi shallallahu 'alaihi wasallam. Saat pulang, ibuku berkata kepadanya; \"Kamu terlambat untuk menjamu tamu atau para tamumu pada malam ini.\" dia bertanya; \"Apakah kamu telah memberi makan malam kepada mereka?\" ibuku menjawab; \"Belum.\" Ibuku berkata lagi; \"Saya sudah tawarkan kepadanya atau kepada mereka, namun mereka menolaknya.\" Abu Bakar marah dan bersumpah untuk tidak memakannya, dan tamu tersebut atau para tamu tersebut juga bersumpah untuk tidak memakannya sampai Abu Bakar memakannya. Kemudian Abu Bakar berkata; \"perbuatan ini dari syetan.\" Lalu dia meminta makanan tersebut dan memakannya dan mereka juga memakannya, setiap kali mereka mengangkat suapan muncul dari bawahnya makanan yang lebih banyak, maka dia pun bertanya; \"Wahai saudari Bani Firasy, apa ini?\" Ibuku menjawab; \"Wahai penyejuk hatiku, sekarang makanan ini malah lebih banyak daripada sebelum kita makan.\" Kemudian mereka menyantapnya dan mengirimkannya kepada Nabi shallallahu 'alaihi wasallam. Abdurrahman menceritakan bahwa beliau juga memakannya. "},"102":{"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ أَنَّهُقَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثِينَ وَمِائَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ مَعَ أَحَدٍ مِنْكُمْ طَعَامٌ فَإِذَا مَعَ رَجُلٍ صَاعٌ مِنْ طَعَامٍ أَوْ نَحْوُهُ فَعُجِنَ ثُمَّ جَاءَ رَجُلٌ مُشْرِكٌ مُشْعَانٌّ طَوِيلٌ بِغَنَمٍ يَسُوقُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَيْعًا أَمْ عَطِيَّةً أَوْ قَالَ أَمْ هَدِيَّةً قَالَ لَا بَلْ بَيْعٌ فَاشْتَرَى مِنْهُ شَاةً فَصُنِعَتْ وَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَوَادِ الْبَطْنِ أَنْ يُشْوَى قَالَ وَايْمُ اللَّهِ مَا مِنْ الثَّلَاثِينَ وَالْمِائَةِ إِلَّا قَدْ حَزَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُزَّةً مِنْ سَوَادِ بَطْنِهَا إِنْ كَانَ شَاهِدًا أَعْطَاهَا إِيَّاهُ وَإِنْ كَانَ غَائِبًا خَبَأَ لَهُ قَالَ وَجَعَلَ مِنْهَا قَصْعَتَيْنِ قَالَ فَأَكَلْنَا أَجْمَعُونَ وَشَبِعْنَا وَفَضَلَ فِي الْقَصْعَتَيْنِ فَجَعَلْنَاهُ عَلَى الْبَعِيرِ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami ['Arim] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Abu 'Utsman] dari [Abdurrahman bin Abu Bakar] bahwa dia berkata; Kami pernah menyertai Nabi shallallahu 'alaihi wasallam dan jumlah kami saat itu seratus tiga puluh orang. Nabi shallallahu 'alaihi wasallam bertanya pada kami; \"Apakah diantara kalian ada yang membawa makanan?\" ternyata seorang laki-laki mempunyai satu sha' makanan atau yang semisalnya, kemudian makanan tersebut dibuat adonan. Lalu datang seorang musyrik berambut kusut dan berperawakan jangkung membawa beberapa ekor kambing. Maka Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah ini dagangan atau pemberian?\" Atau beliau berkata: \"Atau hadiah?\" Laki-laki itu menjawab; \"Bukan, ini adalah dagangan.\" lalu beliau membeli seekor kambing dan kambing tersebut dimasak. Nabi shallallahu 'alaihi wasallam memerintahkan agar jantung kambing itu dipanggang. Abdurrahman berkata; Demi Allah! tidak seorangpun dari seratus tiga puluh orang itu kecuali beliau beri satu potongan dari jantung kambing tersebut. Bagi yang hadir beliau berikan kepadanya, dan jika tidak hadir maka beliau simpankan baginya, lalu beliau letakkan potongan-potongan jantung dan adonan tersebut kedalam dua nampan, kami semua makan hingga kenyang bahkan masih tersisa. Kemudian sisa makanan itu kami taruh diatas tunggangan kami.\" Atau dengan lafazh yang semisalnya. "},"103":{"ar":"حَدَّثَنَا عَارِمٌ وَعَفَّانُ قَالَا حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ عَفَّانُ فِي حَدِيثِهِ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا أَبُو عُثْمَانَ أَنَّهُ حَدَّثَهُ عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍأَنَّ أَصْحَابَ الصُّفَّةِ كَانُوا أُنَاسًا فُقَرَاءَ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَرَّةً مَنْ كَانَ عِنْدَهُ طَعَامُ اثْنَيْنِ فَلْيَذْهَبْ بِثَالِثٍ وَقَالَ عَفَّانُ بِثَلَاثَةٍ وَمَنْ كَانَ عِنْدَهُ طَعَامُ أَرْبَعَةٍ فَلْيَذْهَبْ بِخَامِسٍ سَادِسٍ أَوْ كَمَا قَالَ وَأَنَّ أَبَا بَكْرٍ جَاءَ بِثَلَاثَةٍ وَانْطَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَشَرَةٍ وَأَبُو بَكْرٍ بِثَلَاثَةٍ قَالَ عَفَّانُ بِسَادِسٍ","id":"Telah menceritakan kepada kami ['Arim] dan ['Affan] keduanya berkata; telah menceritakan kepada kami [Mu'tamir bin Sulaiman], sedang ['Affan] berkata dalam haditsnya; Mu'tamir berkata; saya mendengar [bapakku] berkata; telah menceritakan kepada kami [Abu 'Utsman], bahwa [Abdurrahman bin Abu Bakar] menceritakan kepadanya, bahwa para ahli Shuffah adalah orang-orang fakir, dan suatu ketika Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki makanan yang cukup untuk dua orang maka ajaklah orang ketiga.\" -'Affan berkata; \"Untuk tiga orang\"- Barangsiapa memiliki makanan yang cukup untuk empat orang maka ajaklah orang kelima, atau keenam.\" Atau sebagaimana yang beliau sabdakan, Abu Bakar datang bersama tiga orang, dan Nabi shallallahu 'alaihi wasallam bersama dengan sepuluh orang sedang Abu Bakar dengan tiga orang.-'Affan berkata; dengan enam orang.-"},"104":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ أَخْبَرَهُ عَمْرُو بْنُ أَوْسٍ الثَّقَفِيُّ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُرْدِفَ عَائِشَةَ إِلَى التَّنْعِيمِ فَأُعْمِرَهَا","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru] yaitu Ibnu Dinar, bahwa ['Amru bin Aus Ats Tsaqafi] mengabarinya, bahwa [Abdurrahman bin Abu Bakar] telah menceritakan kepadaku, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menyuruhku untuk menemani Aisyah ke at Tan'im dalam rangka umrah.\""},"105":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ السَّهْمِيُّ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنِ الْقَاسِمِ بْنِ مِهْرَانَ عَنْ مُوسَى بْنِ عُبَيْدٍ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ رَبِّي أَعْطَانِي سَبْعِينَ أَلْفًا مِنْ أُمَّتِي يَدْخُلُونَ الْجَنَّةَ بِغَيْرِ حِسَابٍ فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ فَهَلَّا اسْتَزَدْتَهُ قَالَ قَدْ اسْتَزَدْتُهُ فَأَعْطَانِي مَعَ كُلِّ رَجُلٍ سَبْعِينَ أَلْفًا قَالَ عُمَرُ فَهَلَّا اسْتَزَدْتَهُ قَالَ قَدْ اسْتَزَدْتُهُ فَأَعْطَانِي هَكَذَا وَفَرَّجَ عَبْدُ اللَّهِ بْنُ بَكْرٍ بَيْنَ يَدَيْهِ وَقَالَ عَبْدُ اللَّهِ وَبَسَطَ بَاعَيْهِ وَحَثَا عَبْدُ اللَّهِو قَالَ هِشَامٌ وَهَذَا مِنْ اللَّهِ لَا يُدْرَى مَا عَدَدُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Bakar As Sahmi] telah menceritakan kepada kami [Hisyam] dari [Al Qasim bin Mihran] dari [Musa bin 'Ubaid] dari [Maimun bin Mihran] dari [Abdurrahman bin Abu Bakar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabbku memberikan padaku tujuhpuluh ribu orang dari umatku yang masuk syurga tanpa hisab.\" Lalu Umar bertanya; \"Wahai Rasulullah, apakah anda tidak meminta tambahan?\" Beliau berkata: \"Aku meminta agar ditambah, lalu Dia memberiku setiap satu orang dari itu membawa tujuh puluh ribu orang.\" Umar bertanya lagi: \"Apakah anda tidak meminta tambahan lagi?\" beliau menjawab: \"Aku telah meminta-Nya, dan Dia memberiku sama seperti itu juga.\" Abdullah bin Bakar membentangkan kedua tangannya, kemudian berkata; \"Beliau membentangkan kedua tangannya\" dan Abdullah mempraktekannya. Dan Hisyam berkata; \"Ini merupakan karunia dari Allah yang tidak diketahui berapa jumlahnya.\""},"106":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا صَدَقَةُ حَدَّثَنَا أَبُو عِمْرَانَ حَدَّثَنِي قَيْسُ بْنُ زَيْدٍ عَنْ قَاضِي الْمِصْرَيْنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدْعُو اللَّهُ بِصَاحِبِ الدَّيْنِ يَوْمَ الْقِيَامَةِ حَتَّى يُوقَفَ بَيْنَ يَدَيْهِ فَيُقَالُ يَا ابْنَ آدَمَ فِيمَ أَخَذْتَ هَذَا الدَّيْنَ وَفِيمَ ضَيَّعْتَ حُقُوقَ النَّاسِ فَيَقُولُ يَا رَبِّ إِنَّكَ تَعْلَمُ أَنِّي أَخَذْتُهُ فَلَمْ آكُلْ وَلَمْ أَشْرَبْ وَلَمْ أَلْبَسْ وَلَمْ أُضَيِّعْ وَلَكِنْ أَتَى عَلَى يَدَيَّ إِمَّا حَرَقٌ وَإِمَّا سَرَقٌ وَإِمَّا وَضِيعَةٌ فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ صَدَقَ عَبْدِي أَنَا أَحَقُّ مَنْ قَضَى عَنْكَ الْيَوْمَ فَيَدْعُو اللَّهُ بِشَيْءٍ فَيَضَعُهُ فِي كِفَّةِ مِيزَانِهِ فَتَرْجَحُ حَسَنَاتُهُ عَلَى سَيِّئَاتِهِ فَيَدْخُلُ الْجَنَّةَ بِفَضْلِ رَحْمَتِهِ","id":"Telah menceritakan kepada kami [Abdushshamad] telah menceritakan kepada kami [Shadaqah] telah menceritakan kepada kami [Abu 'Imran] telah menceritakan kepadaku [Qais bin Zaid] dari [seorang hakim di dua kota] dari [Abdurrahman bin Abu Bakar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah akan memanggil orang yang berhutang pada Hari Kiamat, sehingga dia menempatkannya di depanNya. Lalu ditanyakan: 'Wahai Ibnu Adam, untuk apa hutang kamu ini, dan kenapa kamu menghilangkan hak orang lain? ' Hamba itu menjawab; 'Wahai Rabbku, sungguh Engkau telah mengetahui bahwasannya aku mengambilnya namun saya tidak memakan dan tidak meminumnya bahkan tidak memakainya, namun yang ada di hadapanku ada yang terbakar, ada yang dicuri dan ada yang hilang.' Lalu Allah Azza Wa Jalla berkata; 'HambaKu benar, dan Aku yang paling berhak untuk menunaikannya untukmu saat ini.' Maka Allah 'azza wajalla memanggil seuatu (hutang rang tersebut). Kemudian meletakkannya di timbangan, dan ternyata amal kebaikannya lebih berat daripada kejelekannya dan dia masuk syurga karena rahmatNya.\""},"107":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَنْبَأَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ أَنْبَأَنَا زَكَرِيَّا بْنُ إِسْحَاقَ عَنِ ابْنِ أَبِي نَجِيحٍ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ أَخْبَرَهُ مَنْ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْحَلْ هَذِهِ النَّاقَةَ ثُمَّ أَرْدِفْ أُخْتَكَ فَإِذَا هَبَطْتُمَا مِنْ أَكَمَةِ التَّنْعِيمِ فَأَهِلَّا وَأَقْبِلَا وَذَلِكَ لَيْلَةُ الصَّدَرِ","id":"Telah menceritakan kepada kami [Ali bin Ishaq] telah memberitakan kepada kami [Abdullah] yaitu Ibnu Mubarak, telah memberitakan kepada kami [Zakaria bin Ishaq] dari [Ibnu Abu Nujaih] bahwa [Bapaknya] menceritakannya, [seseorang] yang mendengar [Abdurrahman bin Abu Bakar] mengabarinya, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Naiklah pada unta ini dan boncengkan saudarimu. Jika kalian telah sampai pada bukit Tan'im maka berihramlah dan berjalanlah menuju Makkah.\" Dan saat itu adalah pada lailatus shadar."},"108":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ مِهْرَانَ الدَّبَّاغُ حَدَّثَنَا دَاوُدُ يَعْنِي الْعَطَّارَ عَنِ ابْنِ خُثَيْمٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَفْصَةَ ابْنَةِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ أَبِيهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَبْدِ الرَّحْمَنِ أَرْدِفْ أُخْتَكَ يَعْنِي عَائِشَةَ فَأَعْمِرْهَا مِنْ التَّنْعِيمِ فَإِذَا هَبَطْتَ بِهَا مِنْ الْأَكَمَةِ فَمُرْهَا فَلْتُحْرِمْ فَإِنَّهَا عُمْرَةٌ مُتَقَبَّلَةٌ","id":"Telah menceritakan kepada kami [Daud bin Mihran Ad Dabbagh] telah menceritakan kepada kami [Daud] yaitu Al 'Athar, dari [Ibnu Khutsaim] dari [Yusuf bin Mahik] dari [Hafshah binti Abdurrahman bin Abu Bakar] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abdurrahman: \"Boncengkan saudarimu. Yaitu Aisyah, dan bantulah dia dalam melaksanakan umrah dari Tan'im. Jika kamu telah sampai di bukitnya maka lewatilah dan berihramlah, karena itu merupakan ihram yang akan diterima.\" "},"109":{"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ حَدَّثَنَا أَبُو عُثْمَانَ أَنَّهُ حَدَّثَهُ عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍأَنَّ أَصْحَابَ الصُّفَّةِ كَانُوا أُنَاسًا فُقَرَاءَ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَرَّةً مَنْ كَانَ عِنْدَهُ طَعَامُ اثْنَيْنِ فَلْيَذْهَبْ بِثَالِثٍ مَنْ كَانَ عِنْدَهُ طَعَامُ أَرْبَعَةٍ فَلْيَذْهَبْ بِخَامِسٍ بِسَادِسٍ أَوْ كَمَا قَالَ وَأَنَّ أَبَا بَكْرٍ جَاءَ بِثَلَاثَةٍ فَانْطَلَقَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَشَرَةٍ وَأَبُو بَكْرٍ بِثَلَاثَةٍ قَالَ فَهُوَ أَنَا وَأَبِي وَأُمِّي وَ��َا أَدْرِي هَلْ قَالَ وَامْرَأَتِي وَخَادِمٌ بَيْنَ بَيْتِنَا وَبَيْتِ أَبِي بَكْرٍ وَإِنَّ أَبَا بَكْرٍ تَعَشَّى عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ لَبِثَ حَتَّى صَلَّيْتُ الْعِشَاءَ ثُمَّ رَجَعَ فَلَبِثَ حَتَّى نَعَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ بَعْدَمَا مَضَى مِنْ اللَّيْلِ مَا شَاءَ اللَّهُ قَالَتْ لَهُ امْرَأَتُهُ مَا حَبَسَكَ عَنْ أَضْيَافِكَ أَوْ قَالَتْ ضَيْفِكَ قَالَ أَوَمَا عَشَّيْتِهِمْ قَالَتْ أَبَوْا حَتَّى تَجِيءَ قَدْ عَرَضُوا عَلَيْهِمْ فَغَلَبُوهُمْ قَالَ فَذَهَبْتُ أَنَا فَاخْتَبَأْتُ قَالَ يَا غُنْثَرُ أَوْ يَا عَنْتَرُ فَجَدَّعَ وَسَبَّ وَقَالَ كُلُوا لَا هَنِيًّا وَقَالَ وَاللَّهِ لَا أَطْعَمُهُ أَبَدًا قَالَ وَحَلَفَ الضَّيْفُ أَنْ لَا يَطْعَمَهُ حَتَّى يَطْعَمَهُ أَبُو بَكْرٍ قَالَ فَقَالَ أَبُو بَكْرٍ هَذِهِ مِنْ الشَّيْطَانِ قَالَ فَدَعَا بِالطَّعَامِ فَأَكَلَ قَالَ فَايْمُ اللَّهِ مَا كُنَّا نَأْخُذُ مِنْ لُقْمَةٍ إِلَّا رَبَا مِنْ أَسْفَلِهَا أَكْثَرَ مِنْهَا قَالَ حَتَّى شَبِعُوا وَصَارَتْ أَكْثَرَ مِمَّا كَانَتْ قَبْلَ ذَلِكَ فَنَظَرَ إِلَيْهَا أَبُو بَكْرٍ فَإِذَا هِيَ كَمَا هِيَ أَوْ أَكْثَرُ فَقَالَ لِامْرَأَتِهِ يَا أُخْتَ بَنِي فِرَاسٍ مَا هَذَا قَالَتْ لَا وَقُرَّةِ عَيْنِي لَهِيَ الْآنَ أَكْثَرُ مِنْهَا قَبْلَ ذَلِكَ بِثَلَاثِ مِرَارٍ فَأَكَلَ مِنْهَا أَبُو بَكْرٍ وَقَالَ إِنَّمَا كَانَ ذَلِكَ مِنْ الشَّيْطَانِ يَعْنِي يَمِينَهُ ثُمَّ أَكَلَ لُقْمَةً ثُمَّ حَمَلَهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَصْبَحَتْ عِنْدَهُ قَالَ وَكَانَ بَيْنَنَا وَبَيْنَ قَوْمٍ عَقْدٌ فَمَضَى الْأَجَلُ فَعَرَّفْنَا اثْنَيْ عَشَرَ رَجُلًا مَعَ كُلِّ رَجُلٍ أُنَاسٌ اللَّهُ أَعْلَمُ كَمْ مَعَ كُلِّ رَجُلٍ غَيْرَ أَنَّهُ بَعَثَ مَعَهُمْ فَأَكَلُوا مِنْهَا أَجْمَعُونَ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami ['Arim] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [bapaknya] telah menceritakan kepada kami [Abu 'Utsman] bahwa [Abdurrahman bin Abu Bakar] menceritakannya, bahwa para ahli Shuffah adalah orang-orang fakir. Rasulullah shallallahu 'alaihi wasallam suatu kali bersabda: \"Barangsiapa memiliki makanan yang cukup untuk dua orang maka ajaklah orang ketiga (untuk ikut serta makan). Barangsiapa memiliki makanan yang cukup untuk empat orang maka ajaklah orang kelima, atau keenam.\" Abu Bakar datang bersama tiga orang dan Nabi shallallahu 'alaihi wasallam bersama dengan sepuluh orang, dan Abu Bakar dengan tiga orang, yaitu saya bapakku dan ibuku. -Abu 'Utsman berkata; Saya tidak tahu apakah Abdurrahman mengatakan; Istriku, pelayan yang berada di rumah kami dan rumah Abu Bakar. Abu Bakar makan malam bersama Rasulullah shallallahu 'alaihi wasallam kemudian tetap di sana sampai saya selesai melaksanakan shalat isya', kemudian dia kembali lagi ke tempat tersebut sehingga Rasulullah shallallahu 'alaihi wasallam mengantuk. Setelah berlalu waktu mendekati perengahan malam dia datang, dan istrinya bertanya; \"Apa yang menyebabkan kamu terlambat untuk melayani para tamumu, atau seorang tamumu?\" Abu Bakar berkata; \"Apakah kamu telah memberi makan malam kepada mereka?\" dia menjawab; \"Mereka menolaknya sampai kamu datang, padahal sudah saya tawarkan kepada mereka.\" Kemudian saya pergi bersembunyi mengawasi. Abu Bakar berkata; \"Wahai Ghuntsar atau 'Antar (kata hinaan kepada mereka)!\" Abu Bakar merendahkannya dan mencelanya, lalu dia berkata; \"Makanlah kalian seadanya. Demi Allah! Saya tidak akan makan selamanya.\" Abdurrahman berkata; Tamu tersebut juga bersumpah, bahwa dia tidak akan memakannya sampai Abu Bakar memakannya. Abu Bakar berkata; \"Perbuatan ini dari syetan.\" Lalu dia meminta makanan tersebut dan memakannya dan mereka juga memakannya. Maka tidaklah kami mengangkat satu suapan kecuali muncul dari bawahnya makanan yang lebih banyak. Sampai akhirnya mereka kenyang dan jumlahnya semakin bertambah banyak dari sebelumnya. Kemudian Abu Bakar melihat makanan itu, dan rupanya makanan tersebut seperti semula atau bahkan lebih banyak. Lalu Abu Bakar bertanya kepada istrinya; \"Wahai saudari Bani Firasy, apa ini?\" Dia menjawab; \"Wahai penyejuk hatiku, sekarang makanan ini malah lebih banyak daripada sebelum kita makan.\" (dia ucapkan) tiga kali. Kemudian Abu Bakar menyantapnya dan berkata; \"sesungguhnya hal itu (sumpahnya) dari syetan, \" setelah memakan satu suapan dia membawanya kepada Rasulullah shallallahu 'alaihi wasallam dan akhirnya makanan tersebut berada di tempat beliau. Ketika itu antara kami dan suatu kaum ada sebuah perjanjian yang masa berlakunya telah selesai. Kemudian kami mengangkat dua belas orang sebagai pemimpin dan setiap orang memimpin beberapa orang. Allah yang tahu berapa jumlah mereka yang bersama setiap pemimpin, dan Abu Bakar mengirim makanan tersebut kepada mereka dan mereka semuanya memakan makanan tersebut."},"110":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبِي يَقُولُ حَدَّثَنَا أَبُو عُثْمَانَ أَنَّهُ حَدَّثَهُ عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍأَنَّ أَصْحَابَ الصُّفَّةِ كَانُوا أُنَاسًا فُقَرَاءَ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ عِنْدَهُ طَعَامُ اثْنَيْنِ فَلْيَذْهَبْ بِثَلَاثَةٍ وَمَنْ كَانَ عِنْدَهُ طَعَامُ أَرْبَعَةٍ فَلْيَذْهَبْ بِخَامِسٍ بِسَادِسٍ أَوْ كَمَا قَالَ وَأَنَّ أَبَا بَكْرٍ جَاءَ بِثَلَاثَةٍ وَانْطَلَقَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَشَرَةٍ قَالَ فَهُوَ وَأَنَا وَأَبِي وَأُمِّي وَلَا أَدْرِي هَلْ قَالَ امْرَأَتِي وَخَادِمٌ بَيْنَ بَيْتِنَا وَبَيْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] berkata; saya mendengar [Bapakku] berkata; telah menceritakan kepada kami [Abu 'Utsman] bahwa [Abdurrahman bin Abu Bakar] menceritakan kepadanya, bahwa para ahli Shuffah, adalah orang-orang fakir. Rasulullah shallallahu 'alaihi wasallam suatu ketika bersabda: \"Barangsiapa memiliki makanan yang cukup untuk dua orang maka ajaklah orang ketiga (untuk diajak makan bersama). Barangsiapa memiliki makanan yang cukup untuk empat orang maka ajaklah orang kelima dan keenam.\" Abu Bakar datang bersama tiga orang dan Nabiyullah shallallahu 'alaihi wasallam bersama dengan sepuluh orang. Abdurrahman berkata; \"Yaitu saya, bapakku dan ibuku.\" Abu 'Utsman berkata; Saya tidak tahu apakah dia mengatakan: \"Dan istriku serta seorang pelayan di rumah kami dan rumah Abu Bakar RAdhi Allahu 'anhu.\" "},"111":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ حَدَّثَنَا خَالِدُ بْنُ سَلَمَةَ أَنْ عَبْدَ الْحَمِيدِ بْنَ عَبْدِ الرَّحْمَنِ دَعَا مُوسَى بْنَ طَلْحَةَ حِينَ عَرَّسَ عَلَى ابْنِهِ فَقَالَ يَا أَبَا عِيسَى كَيْفَ بَلَغَكَ فِي الصَّلَاةِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُوسَى سَأَلْتُ زَيْدَ بْنَ خَارِجَةَ عَنْ الصَّلَاةِ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ زَيْدٌإِنِّي سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَفْسِي فَقُلْتُ كَيْفَ الصَّلَاةُ عَلَيْكَ قَالَ صَلُّوا وَاجْتَهِدُوا ثُمَّ قُولُوا اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Ali bin Bahr] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami ['Utsman bin Hakim] telah menceritakan kepada kami [Khalid bin Salamah] bahwa Abdul Hamid bin Abdurrahman mengundang [Musa bin Thalhah] ketika sedang mengadakan walimah putranya. Dia berkata; \"Wahai Abu Isa, apa yang engkau ketahui tentang shalawat kepada Nabi shallallahu 'alaihi wasallam?\" Maka Musa menjawab; Aku bertanya pada Zaid bin Kharijah tentang shalawat pada Nabi shallallahu 'alaihi wasallam, maka [Zaid] menjawab: Saya bertanya sendiri kepada Rasulullah shallallahu 'alaihi wasallam; \"Bagaimanakah cara shalawat kepada anda?\" Beliau menjawab: \"Shalatlah kalian dan bersungguh-sungguhlah, kemudian ucapkanlah: ALLAHUMMA BARIK 'ALA MUHAMMADIN WA 'ALA ALI MUHAMMAD KAMAA BAARAKTA 'ALA IBRAHIIM INNAKA HAMIIDUM MAJIID. (Ya, Allah berilah berkah kepada Muhammad dan kepada keluarga Muhammad sebagaimana Engkau telah memberi berkah kepada Ibrahim. Sesungguhnya Engkau adalah Maha Terpuji dan Maha Perkasa).\""},"112":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ يَحْيَى بْنِ عَبَّادٍ عَنْ أَبِيهِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَأَتَى الْحَارِثُ بْنُ خَزَمَةَ بِهَاتَيْنِ الْآيَتَيْنِ مِنْ آخِرِ بَرَاءَةَ{ لَقَدْ جَاءَكُمْ رَسُولٌ مِنْ أَنْفُسِكُمْ }إِلَى عُمَرَ بْنِ الْخَطَّابِ فَقَالَ مَنْ مَعَكَ عَلَى هَذَا قَالَ لَا أَدْرِي وَاللَّهِ إِلَّا أَنِّي أَشْهَدُ لَسَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَعَيْتُهَا وَحَفِظْتُهَافَقَالَ عُمَرُ وَأَنَا أَشْهَدُ لَسَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ لَوْ كَانَتْ ثَلَاثَ آيَاتٍ لَجَعَلْتُهَا سُورَةً عَلَى حِدَةٍ فَانْظُرُوا سُورَةً مِنْ الْقُرْآنِ فَضَعُوهَا فِيهَا فَوَضَعْتُهَا فِي آخِرِ بَرَاءَةَ","id":"Telah menceritakan kepada kami [Ali bin Bahr] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Yahya bin 'Abbad] dari [Bapaknya, 'Abbad bin Abdullah bin Zubair] berkata; [Al Harts bin Khazmah] menemui Umar bin Al Khatthab dengan membawa dua ayat terakhir surat al Bara`ah: (Sungguh telah datang kepada kalian seorang rasul dari golongan kalian …) Maka Umar bertanya; \"Siapa yang menjadi saksimu atas hal ini?\"dia menjawab; \"Aku tidak tahu, demi Allah! namun Aku bersumpah sungguh aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, aku memahaminya dan menghafalnya.\" Maka [Umar] berkata; \"Aku juga bersaksi bahwa aku juga benar-benar mendengarnya langsung dari Rasulullah shallallahu 'alaihi wasallam.\" Kemudian dia mengatakan; \"Andaikan jumlah ayat-ayat itu tiga ayat, niscaya akan aku jadikan satu surat tersendiri. Maka carilah salah satu surat dari Al Qur`an (yang sesuai dengannya), lalu letakkanlah keduanya di dalamnya. Aku pun meletakkannya pada akhir surat al Bara`ah."},"113":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ يَعْنِي أَبَا دَاوُدَ الطَّيَالِسِيَّ حَدَّثَنَا أَبُو عَامِرٍ الْخَزَّازُ عَنِ الْحَسَنِ عَنْ سَعْدٍ مَوْلَى أَبِي بَكْرٍ قَالَقَدَّمْتُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمْرًا فَجَعَلُوا يَقْرُنُونَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقْرُنُوا","id":"Telah menceritakan kepada kami [Sulaiman bin Daud] yaitu Abu Daud Ath Thayalisi, telah menceritakan kepada kami [Abu 'Amir Al Khazzaz] dari [Al Hasan] dari [Sa'd] mantan budak Abu Bakar berkata; Aku pernah menyerahkan kurma ke hadapan Rasulullah shallallahu 'alaihi wasallam, kemudian para sahabat menggabungkan dua kurma ketika makan. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menggabungkan dua kurma ketika makan!\""},"114":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا أَبُو عَامِرٍ عَنِ الْحَسَنِ عَنْ سَعْدٍ مَوْلَى أَبِي بَكْرٍوَكَانَ يَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ خِدْمَتُهُ فَقَالَ يَا أَبَا بَكْرٍ أَعْتِقْ سَعْدًا فَقَالَ يَا رَسُولَ اللَّهِ مَا لَنَا مَاهِنٌ غَيْرُهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتِقْ سَعْدًا أَتَتْكَ الرِّجَالُقَالَ أَبُو دَاوُدَ يَعْنِي السَّبْيَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud] telah menceritakan kepada kami [Abu 'Amir] dari [Al Hasan] dari [Sa'd] mantan budak Abu Bakar, bahwa dia melayani Nabi shallallahu 'alaihi wasallam dan beliaupun menyukai pelayanannya, lalu beliau bersabda: \"Wahai Abu Bakar, Bebaskanlah Sa'd.\" Abu bakar menjawab; \"Wahai Rasulullah, kami tidak punya lagi selain dia.\" Sa'd berkata; maka Rasulullah shallallahu 'alaihi wasallam berkata lagi: \"Bebaskanlah Sa'd, niscaya akan datang kepadamu beberapa lelaki.\" Abu Daud berkata; maksudnya adalah para tawanan."},"115":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ شَرِيكٍ عَنْ أَبِي إِسْحَاقَ عَنْ هُبَيْرَةَ خَطَبَنَا الْحَسَنُ بْنُ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ فَقَالَلَقَدْ فَارَقَ��ُمْ رَجُلٌ بِالْأَمْسِ لَمْ يَسْبِقْهُ الْأَوَّلُونَ بِعِلْمٍ وَلَا يُدْرِكُهُ الْآخِرُونَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْعَثُهُ بِالرَّايَةِ جِبْرِيلُ عَنْ يَمِينِهِ وَمِيكَائِيلُ عَنْ شِمَالِهِ لَا يَنْصَرِفُ حَتَّى يُفْتَحَ لَهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Syarik] dari [Abu Ishaq] dari [Hubairah] bahwa [Al Hasan bin Ali] berkhutbah di hadapan kami: \"Sesungguhnya seorang lelaki telah meninggalkan kalian kemarin, yang mana orang-orang terdahulu tidak dapat menandinginya dalam hal ilmu dan orang-orang setelahnya tidak dapat menyainginya. Rasulullah shallallahu 'alaihi wasallam mengutusnya untuk memegang bendera pasukan. Jibril di sebelah kanannya dan Mikail di sebelah kirinya, dan dia tidak akan bergegas pergi (meninggalakan medan perang) hingga musuh dapat ditaklukkan.\""},"116":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ عَمْرِو بْنِ حُبْشِيٍّ قَالَخَطَبَنَا الْحَسَنُ بْنُ عَلِيٍّ بَعْدَ قَتْلِ عَلِيٍّ فَقَالَ لَقَدْ فَارَقَكُمْ رَجُلٌ بِالْأَمْسِ مَا سَبَقَهُ الْأَوَّلُونَ بِعِلْمٍ وَلَا أَدْرَكَهُ الْآخِرُونَ إِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَبْعَثُهُ وَيُعْطِيهِ الرَّايَةَ فَلَا يَنْصَرِفُ حَتَّى يُفْتَحَ لَهُ وَمَا تَرَكَ مِنْ صَفْرَاءَ وَلَا بَيْضَاءَ إِلَّا سَبْعَ مِائَةِ دِرْهَمٍ مِنْ عَطَائِهِ كَانَ يَرْصُدُهَا لِخَادِمٍ لِأَهْلِهِحَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ عَنِ الْحَسَنِ بْنِ عَلِيٍّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَهُ أَنْ يَقُولَ فِي الْوَتْرِ فَذَكَرَ مِثْلَ حَدِيثِ يُونُسَ","id":"Telah menceritakan kepada kami [Waki'] dari [Israil] dari [Abu Ishaq] dari ['Amru bin Hubaisy] berkata; [Al Hasan bin Ali] menyampaikan khutbah kepada kami setelah terbunuhnya Ali; Sesungguhnya seorang lelaki telah meninggalkan kalian kemarin, yang mana orang-orang terdahulu tidak dapat menandinginya dalam hal ilmu dan orang-orang setelahnya tidak dapat menyainginya. Rasulullah shallallahu 'alaihi wasallam mengutusnya dan memberinya bendera pasukan, dan dia tidak akan bergegas pergi (meninggalakan medan perang) hingga musuh dapat ditaklukkan. Dan tidaklah dia meninggalkan Dinar ataupun Dirham kecuali hanya tujuh ratus dirham saja dari pemberiannya yang dia persiapkan untuk menggaji pelayan keluarganya.\" Telah menceritakan kepada kami Abdurrazzaq telah memberitakan kepada kami Sufyan dari Abu Ishaq dari Buraid bin Abu Maryam dari Abu Al Haura` dari Al Hasan bin Ali bahwa Rasulullah shallallahu 'alaihi wasallam mengajarinya agar dia membaca pada shalat witir. lalu dia menyebutkan sebagaimana hadits Yunus."},"117":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي بُرَيْدُ بْنُ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ السَّعْدِيِّ قَالَقُلْتُ لِلْحَسَنِ بْنِ عَلِيٍّ مَا تَذْكُرُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَذْكُرُ أَنِّي أَخَذْتُ تَمْرَةً مِنْ تَمْرِ الصَّدَقَةِ فَأَلْقَيْتُهَا فِي فِيَّ فَانْتَزَعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلُعَابِهَا فَأَلْقَاهَا فِي التَّمْرِ فَقَالَ لَهُ رَجُلٌ مَا عَلَيْكَ لَوْ أَكَلَ هَذِهِ التَّمْرَةَ قَالَ إِنَّا لَا نَأْكُلُ الصَّدَقَةَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] telah menceritakan kepadaku [Buraidah bin Abu Maryam] dari [Abu Al Haura` As Sa'idi] berkata; Aku bertanya pada Al Hasan bin Ali; \"Masalah apakah yang paling engkau ingat dari Rasulullah shallallahu 'alaihi wasallam?\" [Al Hasan] menjawab; \"yang aku ingat adalah bahwa aku pernah mengambil sebutir kurma dari kurma sedekah dan aku memasukkannya ke dalam mulutku. Maka Rasulullah shallallahu 'alaihi wasallam mengeluarkan kurma tersebut yang sudah bercampur dengan air liur, kemudian beliau membuangnya ke gundukan kurma lainnya.\" Ada seseorang yang bertanya; \"Memangnya kenapa jika engkau memakan kurma tersebut?\" Al Hasan menjawab; \"Sesungguhnya kami (ahlul bait) tidak memakan sedekah.\" "},"118":{"ar":"قَالَوَكَانَ يَقُولُ دَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَ فَإِنَّ الصِّدْقَ طُمَأْنِينَةٌ وَإِنَّ الْكَذِبَ رِيبَةٌ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, [Al Hasan] juga berkata; Beliau bersabda: \"Tinggalkanlah apa yang meragukanmu, sesungguhnya kejujuran itu membawa pada ketenangan dan kebohongan itu membawa pada keraguan.\""},"119":{"ar":"قَالَوَكَانَ يُعَلِّمُنَا هَذَا الدُّعَاءَ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَعَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ إِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ وَرُبَّمَا قَالَ تَبَارَكْتَ رَبَّنَا وَتَعَالَيْتَ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, [Al Hasan] juga berkata; Beliau mengajari kami doa: \"ALLAHUMMAHDINI FI MAN HADAIT WA 'AFANI FI MAN 'AFAIT WA TAWALLANI FIMAN TAWALLAIT WA BARIK LI FI MA A'THAIT WAQINI SYARRA MA QADHAIT, INNAHU LA YADZILLU MAN WALAIT (Ya Allah, berilah aku petunjuk sebagaimana orang yang telah Engkau beri petunjuk, berilah aku perlindungan sebagaimana orang yang Engkau beri perlindungan, sayangilah aku sebagaimana orang yang Engkau sayangi dan berilah berkah terhadap apa yang telah Engkau berikan kepadaku dan jauhkan aku dari kejelekan taqdir yang kau tentukan. Sesungguhnya orang yang Engkau bela tidak akan terhina).\" Terkadang beliau juga membaca: \"..TABAARAKTA RABBANA WA TA'ALAIT (Maha Suci Engkau Wahai Rabb kami dan Maha Tinggi Engkau.) \""},"120":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ هُوَ الزُّبَيْرِيُّ حَدَّثَنَا الْعَلَاءُ بْنُ صَالِحٍ حَدَّثَنَا بُرَيْدُ بْنُ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ قَالَكُنَّا عِنْدَ حَسَنِ بْنِ عَلِيٍّ فَسُئِلَ مَا عَقَلْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنْتُ أَمْشِي مَعَهُ فَمَرَّ عَلَى جَرِينٍ مِنْ تَمْرِ الصَّدَقَةِ فَأَخَذْتُ تَمْرَةً فَأَلْقَيْتُهَا فِي فِيَّ فَأَدْخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُصْبُعَهُ فِي فِيَّ فَأَخْرَجَهَا بِلُعَابِي فَقَالَ بَعْضُ الْقَوْمِ وَمَا عَلَيْكَ لَوْ تَرَكْتَهَا قَالَ إِنَّا آلَ مُحَمَّدٍ لَا تَحِلُّ لَنَا الصَّدَقَةُ قَالَ وَعَقَلْتُ مِنْهُ الصَّلَوَاتِ الْخَمْسَ","id":"Telah menceritakan kepada kami [Abu Ahmad] yaitu Az Zubair, telah menceritakan kepada kami [Al 'Ala` bin Shalih] telah menceritakan kepadaku [Buraidah bin Abu Maryam] dari [Abu Al Haura`] berkata; ketika aku sedang bersama [Hasan bin Ali], dia ditanya; \"Apakah yang paling engkau ingat dari Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab; \"Pada suatu hari saya berjalan bersama beliau, kemudian lewatlah di tempat pengumpulan dan pengeringan kurma sedekah. Lalu saya mengambil sebutir kurma dan memasukkannya ke dalam mulutku, maka Rasulullah shallallahu 'alaihi wasallam memasukkan jarinya ke mulutku dan mengeluarkan kuma tersebut yang sudah bercampur dengan air liurku. Kemudian ada sebagian sahabat bertanya; \"Memangnya kenapa jika engkau membiarkannya?\" Rasulullah shallallahu 'alaihi wasallam menjawab; \"Sesungguhnya kami keluarga Muhammad, tidak halal sedekah bagi kami\". Dan saya hapal dari beliau shalat lima waktu.\""},"121":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ إِبْرَاهِيمَ وَهُوَ التُّسْتَرِيُّ أَنْبَأَنَا مُحَمَّدٌ قَالَ نُبِّئْتُ أَنَّجِنَازَةً مَرَّتْ عَلَى الْحَسَنِ بْنِ عَلِيٍّ وَابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَامَ الْحَسَنُ وَقَعَدَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ الْحَسَنُ لِابْنِ عَبَّاسٍ أَلَمْ تَرَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّتْ بِهِ جِنَازَةٌ فَقَامَفَقَالَ ابْنُ عَبَّاسٍ بَلَى وَقَدْ جَلَسَ فَلَمْ يُنْكِرْ الْحَسَنُ مَا قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Yazid] yaitu Ibnu Ibrahim At Tustari, telah memberitakan kepada kami [Muhammad] berkata; [diberitakan kepadaku] bahwa jenazah lewat pada Al Hasan bin Ali dan Ibnu Abbas radliallahu 'anhuma. [Al Hasan] berdiri sedangkan [Ibnu Abbas] radliallahu 'anhuma duduk, maka Al Hasan bertanya kepadanya; \"Tidakkah kau lihat Nabi shallallahu 'alaihi wasallam ketika dilewati jenazah?\" maka Ibnu Abbas berdiri dan berkata; \"Ya, namun beliau juga pernah duduk.\" Al Hasan tidak mengingkari apa yang dikatakan Ibnu Abbas radliallahu 'anhuma."},"122":{"ar":"قَالَوَكَانَ يَقُولُ دَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَ فَإِنَّ الصِّدْقَ طُمَأْنِينَةٌ وَإِنَّ الْكَذِبَ رِيبَةٌ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, [Al Hasan] juga berkata; Beliau bersabda: \"Tinggalkanlah apa yang meragukanmu, menuju sesuatu yang tidak meragukanmu karena kejujuran itu ketenangan dan kebohongan itu keraguan.\""},"123":{"ar":"قَالَوَكَانَ يُعَلِّمُنَا هَذَا الدُّعَاءَ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَعَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ إِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ إِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ قَالَ شُعْبَةُ وَأَظُنُّهُ قَدْ قَالَ هَذِهِ أَيْضًا تَبَارَكْتَ رَبَّنَا وَتَعَالَيْتَقَالَ شُعْبَةُ وَقَدْ حَدَّثَنِي مَنْ سَمِعَ هَذَا مِنْهُ ثُمَّ إِنِّي سَمِعْتُهُ حَدَّثَ بِهَذَا الْحَدِيثِ مَخْرَجَهُ إِلَى الْمَهْدِيِّ بَعْدَ مَوْتِ أَبِيهِ فَلَمْ يَشُكَّ فِي تَبَارَكْتَ وَتَعَالَيْتَ فَقُلْتُ لِشُعْبَةَ إِنَّكَ تَشُكُّ فِيهِ فَقَالَ لَيْسَ فِيهِ شَكٌّ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya, [Al Hasan] berkata; beliau mengajari kami do'a ini; \"ALLAHUMMAHDINI FI MAN HADAIT WA 'AFANI FI MAN 'AFAIT WA TAWALLANI FIMAN TAWALLAIT WA BARIK LI FI MA A'THAIT WAQINI SYARRA MA QADHAIT, INNAHU LA YADZILLU MAN WALAIT (Ya Allah, berilah aku petunjuk sebagaimana orang yang telah Engkau beri petunjuk, berilah aku perlindungan sebagaimana orang yang Engkau beri perlindungan, sayangilah aku sebagaimana orang yang Engkau sayangi dan berilah berkah terhadap apa yang telah Engkau berikan kepadaku dan jauhkan aku dari kejelekan taqdir yang kau tentukan. Sesungguhnya orang yang Engkau bela tidak akan terhina).\" Syu'bah berkata; dan menurutku beliau juga berkata; \"TABAARAKTA RABBANA WA TA'ALAIT (Maha Suci Engkau, Wahai tuhan kami Maha Tinggi Engkau.) \" Dan Syu'bah berkata; dan telah menceritakan kepadaku seseorang yang mendengarnya dari Al Hasan, dan saya mendengar dia meriwayatkan hadits ini pada saat dia keluar untuk menemui Al Mahdi setelah wafat ayahnya, dan Syu'bah tidak merasa ragu dengan lafazh hadits; \"TABAARAKTA RABBANA WA TA'ALAIT (Maha Suci Engkau, Wahai tuhan kami Maha Tinggi Engkau.) \". Muhammad bin Ja'far bertanya kepada Syu'bah; \"Apakah kamu ragu mengenai hal itu?\" dia menjawab; \"Tidak.\""},"124":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنِ ابْنِ سِيرِينَ أَنَّ ابْنَ عَبَّاسٍ وَالْحَسَنَ بْنَ عَلِيٍّمَرَّتْ بِهِمَا جِنَازَةٌ فَقَامَ أَحَدُهُمَا وَجَلَسَ الْآخَرُ فَقَالَ الَّذِي قَامَ أَمَا تَعْلَمُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ قَالَ بَلَى وَقَعَدَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Ayyub] dari [Ibnu Sirin]; bahwa ada jenazah yang lewat di hadapan [Ibnu Abbas] dan [Al Hasan], kemudian salah seorang dari mereka berdiri sedang yang lainnya duduk. Maka rang yang berdiri bertanya; \"Bukankah Rasulullah shallallahu 'alaihi wasallam berdiri?\" sedangkan yang duduk menjawab; \"Ya. dan beliau juga duduk.\""},"125":{"ar":"حَدَّثَنَا وَكِيعٌ وَعَبْدُ الرَّحْمَنِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ مُصْعَبِ بْنِ مُحَمَّدٍ عَنْ يَعْلَى بْنِ أَبِي يَحْيَى عَنْ فَاطِمَةَ بِنْتِ حُسَيْنٍ عَنْ أَبِيهَا قَالَ عَبْدُ الرَّحْمَنِ حُسَيْنُ بْنُ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلسَّائِلِ حَقٌّ وَإِنْ جَاءَ عَلَى فَرَسٍ","id":"Telah menceritakan kepada kami [Waki'] dan [Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan] dari [Mush'ab bin Muhammad] dari [Ya'la bin Abu Yahya] dari [Fathimah binti Husain] dari [Bapaknya], sedangkan [Abdurrahman] berkata; [Husain bin Ali] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang meminta itu mempunyai hak meskipun ia datang dengan mengendarai kuda.\""},"126":{"ar":"أَنْبَأَن��ا وَكِيعٌ حَدَّثَنَا ثَابِتُ بْنُ عُمَارَةَ عَنْ رَبِيعَةَ بْنِ شَيْبَانَ قَالَقُلْتُ لِلْحُسَيْنِ بْنِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ مَا تَعْقِلُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَعِدْتُ مَعَهُ غُرْفَةَ الصَّدَقَةِ فَأَخَذْتُ تَمْرَةً فَلُكْتُهَا فِي فِيَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْقِهَا فَإِنَّهَا لَا تَحِلُّ لَنَا الصَّدَقَةُ","id":"Telah memberitakan kepada kami [Waki'] telah menceritakan kepada kami [Tsabit bin 'Umarah] dari [Rabi'ah bin Syaiban] berkata; Aku bertanya pada [Al Husain bin Ali] radliallahu 'anhu; \"Apa yang paling berkesan bagimu tentang diri Rasulullah shallallahu 'alaihi wasallam?\" Ia menjawab; Aku pernah masuk ke ruang sedekah bersama beliau, lalu aku mengambil sebutir kurma dan memasukkannya ke dalam mulutku. Maka Nabi shallallahu 'alaihi wasallam berkata; \"Buang kurma itu, sesungguhnya sedekah itu tidak halal bagi kita (ahlul bait).\""},"127":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ وَيَعْلَي قَالَا حَدَّثَنَا حَجَّاحٌ يَعْنِي ابْنَ دِينَارٍ الْوَاسِطِيَّ عَنْ شُعَيْبِ بْنِ خَالِدٍ عَنْ حُسَيْنِ بْنِ عَلِيٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ حُسْنِ إِسْلَامِ الْمَرْءِ قِلَّةَ الْكَلَامِ فِيمَا لَا يَعْنِيهِ","id":"Telah menceritakan kepada kami [Ibnu Numair] dan [Ya'La], keduanya berkata; telah menceritakan kepada kami [Hajjaj] yaitu Ibnu Dinar Al Wasithi, dari [Syua'ib bin Khalid] dari [Husain bin Ali] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya diantara tanda baiknya keIslaman seseorang adalah sedikit berkata dalam hal yang tidak berguna baginya.\""},"128":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَلِيٍّ يَزْعُمُ عَنْ حُسَيْنٍ وَابْنِ عَبَّاسٍ أَوْ عَنْ أَحَدِهِمَاأَنَّهُ قَالَ إِنَّمَا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَجْلِ جَنَازَةِ يَهُودِيٍّ مُرَّ بِهَا عَلَيْهِ فَقَالَ آذَانِي رِيحُهَا","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah memberitakan kepada kami [Ibnu Juraij] berkata; saya mendengar [Muhammad bin Ali] menyatakan dari [Husain] dan [Ibnu Abbas] atau salah satu dari keduanya, berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam berdiri karena jenazah seorang yahudi yang lewat, lalu beliau berkata; \"Baunya sangat menggangguku.\""},"129":{"ar":"حَدَّثَنَا يَزِيدُ وَعَبَّادُ بْنُ عَبَّادٍ قَالَا أَنْبَأَنَا هِشَامُ بْنُ أَبِي هِشَامٍ قَالَ عَبَّادٌ ابْنُ زِيَادٍ عَنْ أُمِّهِ عَنْ فَاطِمَةَ ابْنَةِ الْحُسَيْنِ عَنْ أَبِيهَا الْحُسَيْنِ بْنِ عَلِيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مُسْلِمٍ وَلَا مُسْلِمَةٍ يُصَابُ بِمُصِيبَةٍ فَيَذْكُرُهَا وَإِنْ طَالَ عَهْدُهَا قَالَ عَبَّادٌ قَدُمَ عَهْدُهَا فَيُحْدِثُ لِذَلِكَ اسْتِرْجَاعًا إِلَّا جَدَّدَ اللَّهُ لَهُ عِنْدَ ذَلِكَ فَأَعْطَاهُ مِثْلَ أَجْرِهَا يَوْمَ أُصِيبَ بِهَاحَدَّثَنَا يَزِيدُ أَنْبَأَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي إِسْحَاقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ عَنِ الْحُسَيْنِ بْنِ عَلِيٍّ قَالَ عَلَّمَنِي جَدِّي أَوْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ فِي الْوَتْرِ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yazid] dan ['Abbad bin 'Abbad] berkata; telah memberitakan kepada kami [Hisyam bin Abu Hisyam], ['Abbad] berkata; [Ibnu Ziyad] dari [ibunya] dari [Fathimah binti Al Husain] dari [Bapaknya, Al Husain bin Ali] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak seorang muslimpun baik laki-laki maupun perempuan yang tertimpa musibah dan ia mengingat (kembali musibah tersebut) walaupun sudah lama berlalu\" -'Abbad berkata; \"Walau sudah berlangsung lama.\" - kemudian dia menceritakannya dalam rangka beristirja', kecuali Allah menggantinya pada saat itu dan memberinya pahala sebagaimana yang diberikan saat ia tertimpa musibah.\" Telah menceritakan kepada kami Yazid telah memberitakan kepada kami Syarik bin Abdullah dari Abu Ishaq dari Buraid bin Abu Maryam dari Abu Al Haura` dari Al Husain bin Ali berkata; Kakekku pernah mengajariku - atau ia berkata; Nabi shallallahu 'alaihi wasallam pernah mengajariku- beberapa kalimat yang selalu aku ucapkan pada shalat witir…\" kemudian ia memaparkan hadits tersebut."},"130":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو وَأَبُو سَعِيدٍ قَالَا حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ حُسَيْنٍ عَنْ أَبِيهِ عَلِيِّ بْنِ حُسَيْنٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَخِيلُ مَنْ ذُكِرْتُ عِنْدَهُ ثُمَّ لَمْ يُصَلِّ عَلَيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdul Malik bin 'Amru] dan [Abu Sa'id], keduanya berkata; telah menceritakan kepada kami [Sulaiman bin Bilal] dari ['Umarah bin Ghaziyyah] dari [Abdullah bin Ali bin Husain] dari [Bapaknya, Ali bin Husain] dari [Bapaknya], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang bakhil itu adalah orang yang jika namaku disebut di dekatnya, namun dia tidak bershalawat kepadaku.\" Yaitu bacaan; SHALLALLAHU 'ALAIHI WASALLAM."},"131":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنِ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ تَعَالَى عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حُسْنِ إِسْلَامِ الْمَرْءِ تَرْكُهُ مَا لَا يَعْنِيهِ","id":"Telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami [Abdullah bin Umar] dari [Ibnu Syihab] dari [Ali bin Husain] dari [Bapaknya] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diantara tanda baiknya keIslaman seseorang adalah (sikapnya untuk) meninggalkan apa yang tidak ada manfaat baginya.\""},"132":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ قَالَتَزَوَّجَ عَقِيلُ بْنُ أَبِي طَالِبٍ فَخَرَجَ عَلَيْنَا فَقُلْنَا بِالرِّفَاءِ وَالْبَنِينَ فَقَالَ مَهْ لَا تَقُولُوا ذَلِكَ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَانَا عَنْ ذَلِكَ وَقَالَ قُولُوا بَارَكَ اللَّهُ لَهَا فِيكَ وَبَارَكَ لَكَ فِيهَا","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Salim bin Abdullah] dari [Abdullah bin Muhammad bin 'Aqil] menerangkan; ['Aqail bin Abu Thalib] menikah kemudian dia keluar menemui kami, maka kami mengucapkan; \"Semoga mendapat kecocokan dan banyak keturunan.\" Maka dia berkata; \"Diam! Jangan kalian mengatakan hal itu. Nabi shallallahu 'alaihi wasallam melarang kami mengucapkan hal itu, beliau bersabda: \"Ucapkanlah; 'BAARAKALLAHU LAHA FIIKA WA BAARAKA LAKA FIIHA (semoga Allah memberkahimu dengannya dan semoga Allah memberkahinya denganmu) '.\" "},"133":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ وَهُوَ ابْنُ عُلَيَّةَ أَنْبَأَنَا يُونُسُ عَنِ الْحَسَنِأَنَّ عَقِيلَ بْنَ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ تَزَوَّجَ امْرَأَةً مِنْ بَنِي جُشَمَ فَدَخَلَ عَلَيْهِ الْقَوْمُ فَقَالُوا بِالرِّفَاءِ وَالْبَنِينَ فَقَالَ لَا تَفْعَلُوا ذَلِكَ قَالُوا فَمَا نَقُولُ يَا أَبَا يَزِيدَ قَالَ قُولُوا بَارَكَ اللَّهُ لَكُمْ وَبَارَكَ عَلَيْكُمْ إِنَّا كَذَلِكَ كُنَّا نُؤْمَرُ","id":"Telah menceritakan kepada kami [Isma'il] yaitu Ibnu 'Ulayyah, telah memberitakan kepada kami [Yunus] dari [Al Hasan] bahwa ['Aqil bin Abu Thalib] radliallahu 'anhu menikahi seorang wanita dari Bani Jusyaim, kemudian anggota kaum menemuinya dan berkata; \"Semoga kamu mendapatkan kecocokan dan keturunan\" maka 'Aqil berkata; \"Janganlah kalian mengucapkan hal seperti itu!\" mereka bertanya; \"Apa yang harus kami baca Wahai Abu Yazid?\" dia berkata; \"Bacalah: BARAKA ALLAH LAKUM WA BARAKA 'ALAIKUM (semoga Allah memberi berkah kepada kalian dan juga memberi berkah atas kalian), demikianlah kami diperintahkan.\""},"134":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ مُسْلِمِ بْنِ عُبَيْدِ اللَّهِ بْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ الْمَخْزُومِيِّ عَنْ أُمِّ سَلَمَةَ ابْنَةِ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْلَمَّا نَزَلْنَا أَرْضَ الْحَبَشَةِ جَاوَرْنَا بِهَا خَيْرَ جَارٍ النَّجَاشِيَّ أَمِنَّا عَلَى دِينِنَا وَعَبَدْنَا اللَّهَ لَا نُؤْذَى وَلَا نَسْمَعُ شَيْئًا نَكْرَهُهُ فَلَمَّا بَلَغَ ذَلِكَ قُرَيْشًا ائْتَمَرُوا أَنْ يَبْعَثُوا إِلَى النَّجَاشِيِّ فِينَا رَجُلَيْنِ جَلْدَيْنِ وَأَنْ يُهْدُوا لِلنَّجَاشِيِّ هَدَايَا مِمَّا يُسْتَطْرَفُ مِنْ مَتَاعِ مَكَّةَ وَكَانَ مِنْ أَعْجَبِ مَا يَأْتِيهِ مِنْهَا إِلَيْهِ الْأَدَمُ فَجَمَعُوا لَهُ أَدَمًا كَثِيرًا وَلَمْ يَتْرُكُوا مِنْ بَطَارِقَتِهِ بِطْرِيقًا إِلَّا أَهْدَوْا لَهُ هَدِيَّةً ثُمَّ بَعَثُوا بِذَلِكَ مَعَ عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ بْنِ الْمُغِيرَةِ الْمَخْزُومِيِّ وَعَمْرِو بْنِ الْعَاصِ بْنِ وَائِلٍ السَّهْمِيِّ وَأَمَرُوهُمَا أَمْرَهُمْ وَقَالُوا لَهُمَا ادْفَعُوا إِلَى كُلِّ بِطْرِيقٍ هَدِيَّتَهُ قَبْلَ أَنْ تُكَلِّمُوا النَّجَاشِيَّ فِيهِمْ ثُمَّ قَدِّمُوا لِلنَّجَاشِيِّ هَدَايَاهُ ثُمَّ سَلُوهُ أَنْ يُسْلِمَهُمْ إِلَيْكُمْ قَبْلَ أَنْ يُكَلِّمَهُمْ قَالَتْ فَخَرَجَا فَقَدِمَا عَلَى النَّجَاشِيِّ وَنَحْنُ عِنْدَهُ بِخَيْرِ دَارٍ وَعِنْدَ خَيْرِ جَارٍ فَلَمْ يَبْقَ مِنْ بَطَارِقَتِهِ بِطْرِيقٌ إِلَّا دَفَعَا إِلَيْهِ هَدِيَّتَهُ قَبْلَ أَنْ يُكَلِّمَا النَّجَاشِيَّ ثُمَّ قَالَا لِكُلِّ بِطْرِيقٍ مِنْهُمْ إِنَّهُ قَدْ صَبَا إِلَى بَلَدِ الْمَلِكِ مِنَّا غِلْمَانٌ سُفَهَاءُ فَارَقُوا دِينَ قَوْمِهِمْ وَلَمْ يَدْخُلُوا فِي دِينِكُمْ وَجَاءُوا بِدِينٍ مُبْتَدَعٍ لَا نَعْرِفُهُ نَحْنُ وَلَا أَنْتُمْ وَقَدْ بَعَثَنَا إِلَى الْمَلِكِ فِيهِمْ أَشْرَافُ قَوْمِهِمْ لِيَرُدَّهُمْ إِلَيْهِمْ فَإِذَا كَلَّمْنَا الْمَلِكَ فِيهِمْ فَتُشِيرُوا عَلَيْهِ بِأَنْ يُسْلِمَهُمْ إِلَيْنَا وَلَا يُكَلِّمَهُمْ فَإِنَّ قَوْمَهُمْ أَعَلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ فَقَالُوا لَهُمَا نَعَمْ ثُمَّ إِنَّهُمَا قَرَّبَا هَدَايَاهُمْ إِلَى النَّجَاشِيِّ فَقَبِلَهَا مِنْهُمَا ثُمَّ كَلَّمَاهُ فَقَالَا لَهُ أَيُّهَا الْمَلِكُ إِنَّهُ قَدْ صَبَا إِلَى بَلَدِكَ مِنَّا غِلْمَانٌ سُفَهَاءُ فَارَقُوا دِينَ قَوْمِهِمْ وَلَمْ يَدْخُلُوا فِي دِينِكَ وَجَاءُوا بِدِينٍ مُبْتَدَعٍ لَا نَعْرِفُهُ نَحْنُ وَلَا أَنْتَ وَقَدْ بَعَثَنَا إِلَيْكَ فِيهِمْ أَشْرَافُ قَوْمِهِمْ مِنْ آبَائِهِمْ وَأَعْمَامِهِمْ وَعَشَائِرِهِمْ لِتَرُدَّهُمْ إِلَيْهِمْ فَهُمْ أَعَلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ وَعَاتَبُوهُمْ فِيهِ قَالَتْ وَلَمْ يَكُنْ شَيْءٌ أَبْغَضَ إِلَى عَبْدِ اللَّهِ بْنِ أَبِي رَبِيعَةَ وَعَمْرِو بْنِ الْعَاصِ مِنْ أَنْ يَسْمَعَ النَّجَاشِيُّ كَلَامَهُمْ فَقَالَتْ بَطَارِقَتُهُ حَوْلَهُ صَدَقُوا أَيُّهَا الْمَلِكُ قَوْمُهُمْ أَعَلَى بِهِمْ عَيْنًا وَأَعْلَمُ بِمَا عَابُوا عَلَيْهِمْ فَأَسْلِمْهُمْ إِلَيْهِمَا فَلْيَرُدَّاهُمْ إِلَى بِلَادِهِمْ وَقَوْمِهِمْ قَالَ فَغَضِبَ النَّجَاشِيُّ ثُمَّ قَالَ لَا هَا اللَّهِ ايْمُ اللَّهِ إِذَنْ لَا أُسْلِمُهُمْ إِلَيْهِمَا وَلَا أُكَادُ قَوْمًا جَاوَرُونِي وَنَزَلُوا بِلَادِي وَاخْتَارُونِي عَلَى مَنْ سِوَايَ حَتَّى أَدْعُوَهُمْ فَأَسْأَلَهُمْ مَاذَا يَقُولُ هَذَانِ فِي أَمْرِهِمْ فَإِنْ كَانُوا كَمَا يَقُولَانِ أَسْلَمْتُهُمْ إِلَيْهِمَا وَرَدَدْتُهُمْ إِلَى قَوْمِهِمْ وَإِنْ كَانُوا عَلَى غَيْرِ ذَلِكَ مَنَعْتُهُمْ مِنْهُمَا وَأَحْسَنْتُ جِوَارَهُمْ مَا جَاوَرُونِي قَالَتْ ثُمَّ أَرْسَلَ إِلَى أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَاهُمْ فَلَمَّا جَاءَهُمْ رَسُولُهُ اجْتَمَعُوا ثُمَّ قَالَ بَعْضُهُمْ لِبَعْضٍ مَا تَقُولُونَ لِلرَّجُلِ إِذَا جِئْتُمُوهُ قَالُوا نَقُولُ وَاللَّهِ مَا عَلَّمَنَا وَمَا أَمَرَنَا بِهِ نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَائِنٌ فِي ذَلِكَ مَا هُوَ كَائِنٌ فَلَمَّا جَاءُوهُ وَقَدْ دَعَا النَّجَاشِيُّ أَسَاقِفَتَهُ فَنَشَرُوا مَصَاحِفَهُمْ حَوْلَهُ سَأَلَهُمْ فَقَالَ مَا هَذَا الدِّينُ الَّذِي فَارَقْتُمْ فِيهِ قَوْمَكُمْ وَلَمْ تَدْخُلُوا فِي دِينِي وَلَا فِي دِينِ أَحَدٍ مِنْ هَذِهِ الْأُمَمِ قَالَتْ فَكَانَ الَّذِي كَلَّمَهُ جَعْفَرُ بْنُ أَبِي طَالِبٍ فَقَالَ لَهُ أَيُّهَا الْمَلِكُ كُنَّا قَوْمًا أَهْلَ جَاهِلِيَّةٍ نَعْبُدُ الْأَصْنَامَ وَنَأْكُلُ الْمَيْتَةَ وَنَأْتِي الْفَوَاحِشَ وَنَقْطَعُ الْأَرْحَامَ وَنُسِيءُ الْجِوَارَ يَأْكُلُ الْقَوِيُّ مِنَّا الضَّعِيفَ فَكُنَّا عَلَى ذَلِكَ حَتَّى بَعَثَ اللَّهُ إِلَيْنَا رَسُولًا مِنَّا نَعْرِفُ نَسَبَهُ وَصِدْقَهُ وَأَمَانَتَهُ وَعَفَافَهُ فَدَعَانَا إِلَى اللَّهِ لِنُوَحِّدَهُ وَنَعْبُدَهُ وَنَخْلَعَ مَا كُنَّا نَعْبُدُ نَحْنُ وَآبَاؤُنَا مِنْ دُونِهِ مِنْ الْحِجَارَةِ وَالْأَوْثَانِ وَأَمَرَنَا بِصِدْقِ الْحَدِيثِ وَأَدَاءِ الْأَمَانَةِ وَصِلَةِ الرَّحِمِ وَحُسْنِ الْجِوَارِ وَالْكَفِّ عَنْ الْمَحَارِمِ وَالدِّمَاءِ وَنَهَانَا عَنْ الْفَوَاحِشِ وَقَوْلِ الزُّورِ وَأَكْلِ مَالَ الْيَتِيمِ وَقَذْفِ الْمُحْصَنَةِ وَأَمَرَنَا أَنْ نَعْبُدَ اللَّهَ وَحْدَهُ لَا نُشْرِكُ بِهِ شَيْئًا وَأَمَرَنَا بِالصَّلَاةِ وَالزَّكَاةِ وَالصِّيَامِ قَالَ فَعَدَّدَ عَلَيْهِ أُمُورَ الْإِسْلَامِ فَصَدَّقْنَاهُ وَآمَنَّا بِهِ وَاتَّبَعْنَاهُ عَلَى مَا جَاءَ بِهِ فَعَبَدْنَا اللَّهَ وَحْدَهُ فَلَمْ نُشْرِكْ بِهِ شَيْئًا وَحَرَّمْنَا مَا حَرَّمَ عَلَيْنَا وَأَحْلَلْنَا مَا أَحَلَّ لَنَا فَعَدَا عَلَيْنَا قَوْمُنَا فَعَذَّبُونَا وَفَتَنُونَا عَنْ دِينِنَا لِيَرُدُّونَا إِلَى عِبَادَةِ الْأَوْثَانِ مِنْ عِبَادَةِ اللَّهِ وَأَنْ نَسْتَحِلَّ مَا كُنَّا نَسْتَحِلُّ مِنْ الْخَبَائِثِ فَلَمَّا قَهَرُونَا وَظَلَمُونَا وَشَقُّوا عَلَيْنَا وَحَالُوا بَيْنَنَا وَبَيْنَ دِينِنَا خَرَجْنَا إِلَى بَلَدِكَ وَاخْتَرْنَاكَ عَلَى مَنْ سِوَاكَ وَرَغِبْنَا فِي جِوَارِكَ وَرَجَوْنَا أَنْ لَا نُظْلَمَ عِنْدَكَ أَيُّهَا الْمَلِكُ قَالَتْ فَقَالَ لَهُ النَّجَاشِيُّ هَلْ مَعَكَ مِمَّا جَاءَ بِهِ عَنْ اللَّهِ مِنْ شَيْءٍ قَالَتْ فَقَالَ لَهُ جَعْفَرٌ نَعَمْ فَقَالَ لَهُ النَّجَاشِيُّ فَاقْرَأْهُ عَلَيَّ فَقَرَأَ عَلَيْهِ صَدْرًا مِنْ كهيعص قَالَتْ فَبَكَى وَاللَّهِ النَّجَاشِيُّ حَتَّى أَخْضَلَ لِحْيَتَهُ وَبَكَتْ أَسَاقِفَتُهُ حَتَّى أَخْضَلُوا مَصَاحِفَهُمْ حِينَ سَمِعُوا مَا تَلَا عَلَيْهِمْ ثُمَّ قَالَ النَّجَاشِيُّ إِنَّ هَذَا وَاللَّهِ وَالَّذِي جَاءَ بِهِ مُوسَى لَيَخْرُجُ مِنْ مِشْكَاةٍ وَاحِدَةٍ انْطَلِقَا فَوَاللَّهِ لَا أُسْلِمُهُمْ إِلَيْكُمْ أَبَدًا وَلَا أُكَادُ قَالَتْ أُمُّ سَلَمَةَ فَلَمَّا خَرَجَا مِنْ عِنْدِهِ قَالَ عَمْرُو بْنُ الْعَاصِ وَاللَّهِ لَأُنَبِّئَنَّهُمْ غَدًا عَيْبَهُمْ عِنْدَهُمْ ثُمَّ أَسْتَأْصِلُ بِهِ خَضْرَاءَهُمْ قَالَتْ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ أَبِي رَبِيعَةَ وَكَانَ أَتْقَى الرَّجُلَيْنِ فِينَا لَا تَفْعَلْ فَإِنَّ لَهُمْ أَرْحَامًا وَإِنْ كَانُوا قَدْ خَالَفُونَا قَالَ وَاللَّهِ لَأُخْبِرَنَّهُ أَنَّهُمْ يَزْعُمُونَ أَنَّ عِيسَى ابْنَ مَرْيَمَ عَبْدٌ قَالَتْ ثُمَّ غَدَا عَلَيْهِ الْغَدَ فَقَالَ لَهُ أَيُّهَا الْمَلِكُ إِنَّهُمْ يَقُولُونَ فِي عِيسَى ابْنِ مَرْيَمَ قَوْلًا عَظِيمًا فَأَرْسِلْ إِلَيْهِمْ فَاسْأَلْهُمْ عَمَّا يَقُولُونَ فِيهِ قَالَتْ فَأَرْسَلَ إِلَيْهِمْ يَسْأَلُهُمْ عَنْهُ قَالَتْ وَلَمْ يَنْزِلْ بِنَا مِثْلُهُ فَاجْتَمَعَ الْقَوْمُ فَقَالَ بَعْضُهُمْ لِبَعْضٍ مَاذَا تَقُولُونَ فِي عِيسَى إِذَا سَأَلَكُمْ عَنْهُ قَالُوا نَقُولُ وَاللَّهِ فِيهِ مَا قَالَ اللَّهُ وَمَا جَاءَ بِهِ نَبِيُّنَا كَائِنًا فِي ذَلِكَ مَا هُوَ كَائِنٌ فَلَمَّا دَخَلُوا عَلَيْهِ قَالَ لَهُمْ مَا تَقُولُونَ فِي عِيسَى ابْنِ مَرْيَمَ فَقَالَ لَهُ جَعْفَرُ بْنُ أَبِي طَالِبٍ نَقُولُ فِيهِ الَّذِي جَاءَ بِهِ نَبِيُّنَا هُوَ عَبْدُ اللَّهِ وَرَسُولُهُ وَرُوحُهُ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ الْعَذْرَاءِ الْبَتُولِ قَالَتْ فَضَرَبَ النَّجَاشِيُّ يَدَهُ إِلَى الْأَرْضِ فَأَخَذَ مِنْهَا عُودًا ثُمَّ قَالَ مَا عَدَا عِيسَى ابْنُ مَرْيَمَ مَا قُلْتَ هَذَا الْعُودَ فَتَنَاخَرَتْ بَطَارِقَتُهُ حَوْلَهُ حِينَ قَالَ مَا قَالَ فَقَالَ وَإِنْ نَخَرْتُمْ وَاللَّهِ اذْهَبُوا فَأَنْتُمْ سُيُومٌ بِأَرْضِي وَالسُّيُومُ الْآمِنُونَ مَنْ سَبَّكُمْ غُرِّمَ ثُمَّ مَنْ سَبَّكُمْ غُرِّمَ فَمَا أُحِبُّ أَنَّ لِي دَبْرًا ذَهَبًا وَأَنِّي آذَيْتُ رَجُلًا مِنْكُمْ وَالدَّبْرُ بِلِسَانِ الْحَبَشَةِ الْجَبَلُ رُدُّوا عَلَيْهِمَا هَدَايَاهُمَا فَلَا حَاجَةَ لَنَا بِهَا فَوَاللَّهِ مَا أَخَذَ اللَّهُ مِنِّي الرِّشْوَةَ حِينَ رَدَّ عَلَيَّ مُلْكِي فَآخُذَ الرِّشْوَةَ فِيهِ وَمَا أَطَاعَ النَّاسَ فِيَّ فَأُطِيعَهُمْ فِيهِ قَالَتْ فَخَرَجَا مِنْ عِنْدِهِ مَقْبُوحَيْنِ مَرْدُودًا عَلَيْهِمَا مَا جَاءَا بِهِ وَأَقَمْنَا عِنْدَهُ بِخَيْرِ دَارٍ مَعَ خَيْرِ جَارٍ قَالَتْ فَوَاللَّهِ إِنَّا عَلَى ذَلِكَ إِذْ نَزَلَ بِهِ يَعْنِي مَنْ يُنَازِعُهُ فِي مُلْكِهِ قَالَ فَوَاللَّهِ مَا عَلِمْنَا حُزْنًا قَطُّ كَانَ أَشَدَّ مِنْ حُزْنٍ حَزِنَّاهُ عِنْدَ ذَلِكَ تَخَوُّفًا أَنْ يَظْهَرَ ذَلِكَ عَلَى النَّجَاشِيِّ فَيَأْتِيَ رَجُلٌ لَا يَعْرِفُ مِنْ حَقِّنَا مَا كَانَ النَّجَاشِيُّ يَعْرِفُ مِنْهُ قَالَتْ وَسَارَ النَّجَاشِيُّ وَبَيْنَهُمَا عُرْضُ النِّيلِ قَالَتْ فَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَجُلٌ يَخْرُجُ حَتَّى يَحْضُرَ وَقْعَةَ الْقَوْمِ ثُمَّ يَأْتِيَنَا بِالْخَبَرِ قَالَتْ فَقَالَ ال","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Muhammad bin Muslim bin 'Ubaidullah bin Syihab] dari [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam Al Makhzumi] dari [Ummu Salamah, putri Abu Umayyah bin Al Mughirah] istri Nabi shallallahu 'alaihi wasallam, menuturkan; Tatkala kami berada di negeri Habasyah, kami bertetangga dengan tetangga yang sangat baik, yaitu raja Najasyi. Kami merasa aman dalam menjalankan agama kami, kami beribadah kepada Allah dengan tidak diganggu dan kami tidak mendengar sesuatu yang tidak kami sukai. Tatkala hal itu sampai kepada orang Quraisy, mereka bersepakat untuk mengirim utusan kepada Raja Najasyi dengan mengirim dua orang laki-laki yang kuat untuk memberikan sejumlah hadiah kepada Raja Najasyi berupa barang-barang yang dianggap langka dari Makkah. Di antara barang yang sangat menakjubkan yang diberikankan kepada mereka adalah kulit yang samak. Mereka banyak mengumpulkan barang tersebut. Mereka tidak meninggalkan satu komandan pasukan pun kecuali memberinya satu hadiah. Mereka menugaskan Abdullah bin Rabi'ah bin Al Mughirah dan Al Makhzumi dan 'Amru bin Al 'Ash bin Wa`il As Sahmi untuk mengirim barang-barang tersebut dan memerintahkan keduanya menyampaikan misi mereka. Mereka berkata kepada keduanya; \"Serahkan setiap hadiah kepada masing-masing komandan sebelum kalian berbicara dengan Najasyi. Setelah itu berikan hadiah kepada Raja Najasyi, dan mintalah agar dia menyerahkan mereka kepada kalian sebelum raja tersebut berbicara dengan mereka.\" Ummu Salamah kembali menuturkan; Kedua orang itu bergegas keluar (meninggalkan Makkah) untuk menemui Raja Najasyi. Keadaan kami pada saat itu berada di rumah yang paling bagus dan tetangga yang paling baik. Tidak ada satu komandanpun kecuali mereka berdua menyerahkan hadiahnya sebelum berbicara kepada Raja Najasyi. Mereka berdua berkata kepada setiap komandan dari mereka; \"sesungguhnya beberapa anak-anak bangsa kami yang bodoh keluar dari kami dan pergi kepada negri kerajaan kalian, mereka telah meninggalkan agama kaum mereka dan tidak akan masuk pada agama kalian. Mereka membawa agama baru yang kami tidak mengetahuinya dan juga kalian. Para pembesar kaum mereka mengutus kami untuk mengembalikan mereka ke kaum mereka. Maka Jika kami sedang berbicara kepada Raja mengenai mereka, hendaknya kalian memberi masukan kepadanya agar menyerahkan mereka kepada kami dan tidak perlu berbicara kepada mereka. Karena kaum mereka lebih memperhatikan dan mengetahui keadaan mereka dan kekurangan-kekurangan mereka.\" Mereka menjawab kepada keduanya; \"Ya.\" Setelah itu keduanya menyerahkan hadiah kepada Raja Najasyi, dan raja Najasyi menerimanya, kemudaian mereka berdua mengajak bicara Raja dan berkata; \"Wahai sang raja. sesungguhnya beberapa anak-anak bangsa kami yang bodoh keluar dari kami dan pergi kepada negri kerajaan tuan, mereka telah meninggalkan agama kaum mereka dan tidak akan masuk ke agama tuan. Mereka membawa agama baru yang kami tidak mengetahuinya dan juga tuan. Para pembesar kaum mereka yang terdiri dari bapak-bapak mereka, paman-paman mereka dan keluarga mereka mengutus kami untuk menghadap tuan, agar kiranya tuan mengembalikan mereka kepada kaum kami. Karena kaum kami lebih memperhatikan mereka dan mengetahui kekurangan mereka, tetapi mereka mencela mereka.\" Sungguh tidak ada yang lebih membuat marah Abdullah bin Abu Rabi'ah dan 'Amru bin ash kecuali keinginan Raja Najasyi untuk mendengar pembelaan mereka. Kemudian para komandan yang berada di sekelilingnya berkata; \"Mereka benar wahai Raja, kaum mereka lebih memperhatikan mereka dan mengetahui kekurangan-kekurangan mereka, maka serahkanlah kepada mereka agar mereka berdua bisa membawa kembali ke negeri dan kaum mereka.\" Maka Raja Najasyi marah dan berkata; \"Tidak! demi Allah, demi Allah saya tidak akan menyerahkan mereka kepada mereka berdua, dan tidaklah ada seorangpun yang dapat menyuruhku memerangi suatu kaum yang bertetangga denganku, dan mereka tinggal di dalam negeriku, serta mereka memilihku dari selainku, sampai aku memanggil mereka dan menanyakan mereka apa yang dikatakan oleh kedua orang ini. Jika memang sebagaimana yang disebutkan, maka saya akan menyerahkan mereka kepada mereka berdua dan akan saya kembalikan kepada kaum mereka. Jika tidak demikian, maka saya tidak akan menyerahkan mereka dan saya akan tetap melindungi mereka selama mereka memintanya.\" Umu Salamah berkata; Kemudian diutuslah utusan kepada para sahabat Rasulullah shallallahu 'alaihi wasallam untuk memanggil mereka, ketika utusanNya menemui mereka, mereka berkumpul lalu sebagian berkata kepada yang lainnya; \"Apa yang akan kalian katakan kepada sang Raja jika kamu berada di hadapannya?\" Mereka menjawab; \"Demi Allah, kami akan mengatakan sebagaimana yang telah di ajarkan dan diperintahkan Nabi shallallahu 'alaihi wasallam kepada kami, apapun yang terjadi.\" Tatkala mereka menemui Raja, rupanya sang raja juga memanggil para pemuka agamanya, dan mereka telah menyebarkan lembaran-lembaran mereka di sekitar raja. Kemudian raja bertanya kepada mereka; \"Agama apa yang menyebabkan kalian meninggalkan kaum kalian dan kalian juga tidak masuk pada agamaku atau agama umat lainnya?\" Umu Salamah berkata; Yang menjawab sang raja adalah [Ja'far bin Abu Thalib], dia berkata; \"Wahai sang raja! Kami adalah suatu kaum yang bodoh, kami menyembah berhala dan memakan bangkai, melakukan berbagai keburukan dan memutus tali kekerabatan, berbuat jahat terhadap tetangga, orang yang kuat di antara kami memangsa yang lemah, dan kami masih dalam keadaan seperti itu sampai Allah mengutus kepada kami seorang Rasul dari kalangan kami sendiri, kami mengetahui nasabnya dan kejujurannya, amanahnya dan kehati-hatiannya dalam menjaga kehormatannya. Dia mengajak kami kepada Allah agar kami mengesakanNya dan hanya menyembahNya, meninggalkan apa yang kami sembah dan nenek moyang kami yang berupa batu dan patung. Dia menyuruh kami agar kami berbuat jujur dalam berbicara, menunaikan amanah dan menyambung sillaturrahim, berbuat baik terhadap tetangga dan menahan dari hal-hal yang haram dan (menumpahkan) darah. Dia melarang melakukan kekejian-kekejian dan perkataan dusta, memakan harta anak yatim dan menuduh orang yang baik dengan tuduhan berzina. Dia menyuruh kami agar kami menyembah Allah saja, tidak menyekutukanNya dengan sesuatupun, dia menyuruh kami shalat, zakat dan puasa.\" dia menyebutkan berbagai hal yang berkaitan dengan perkara-perkara dalam Islam \"Kami membenarkannya, beriman kepadanya dan mengikuti apa yang beliau bawa. Kami menyembah Allah saja, tidak menyekutukanNya dengan sesuatupun, kami mengharamkan apa yang diharamkan untuk kami dan kami menghalalkan apa yang dihalalkan untuk kami. Namun, kaum kami memusuhi kami dan menyiksa kami. Mereka memfitnah kami dalam menjalankan agama kami agar kami kembali kepada menyembah patung dari ibadah kepada Allah, dan menghalalkan apa yang dulu telah kami halalkan yang berbentuk berbagai ragam kekejian. Tatkala mereka memaksa dan menganiaya kami, membuat kami susah, menghalangi kami dengan agama kami, maka kami keluar ke negeri tuan dan kami memilih tuan daripada yang lainnya karena kami senang bertetangga dengan tuan, dan kami berharap kami tidak di zhalimi di dekat tuan, Wahai raja.\" Umu Salamah menuturkan kembali; Maka Raja Najasyi bertanya kepadanya; \"Apakah ada sesutu yang kau bawa dari apa yang datang dari Allah?\" Ja'far menjawab; \"Ya.\" Raja Najasy berkata; \"Bacakan kepadaku!\" Maka Ja'far membacanya dengan memulai dari; KA HA YA 'AIN SHAD.\" Umu Salamah berkata; Maka Raja Najasyi, demi Allah, menangis sampai basah jenggotnya dan begitu juga para tokoh agamanya ikut menangis sampai mushaf-mushaf mereka basah ketika mendengar apa yang dibacakan di hadapan mereka, Najasyi berkata; \"Demi Allah, kitab ini dan kitab yang dibawa Musa keluar dari satu sumber. Pergilah kalian berdua, demi Allah, saya tidak akan menyerahkan mereka kepada kalian selamanya dan saya tidak akan terpedaya.\" Umu Salamah berkata; Tatkala kedua orang itu keluar dari hadapan sang raja, 'Amru bin Al 'Ash berkata; \"Demi Allah, sungguh saya akan bongkar aib mereka besok, kemudian saya akan kupas kejelekan-kejelekan mereka.\" Abdullah bin Abu Rabi'ah, dia orang yang paling takut di antara mereka berdua, berkata kepadanya; \"Jangan kau lakukan, mereka memiliki kerabat walaupun mereka telah menyelisihi kita.\" Dia menjawab; \"Demi Allah, saya akan tetap kabarkan kepada mereka bahwa Isa bin Maryam menurut mereka adalah seorang hamba.\" Umu Salamah berkata; Esok harinya, dia menemui raja dan berkata kepadanya; \"Wahai raja, sesungguhnya mereka berkata kepada Isa bin Maryam dengan perkataan yang berbahaya. Kirimlah kepada mereka dan tanyakan kepada mereka tentang pendapat mereka.\" Umu Salamah berkata; Maka raja mengirim utusan kepada mereka untuk menanyakannya. Sebelum utusan itu sampai, orang-orang muslim sudah berkumpul, sebagian berkata pada yang lain; \"Apa yang akan kalian katakan mengenai Isa jika dia menanyakanya kepada kalian?\" Mereka menjawab; \"Demi Allah, kami akan menjawab sebagaimana yang telah Allah sebutkan dan yang telah dibawa oleh Nabi kita, apapun yang terjadi.\" Tatkala mereka menemui Raja, maka dia berkata kepada mereka; \"Apa pendapat kalian mengenai Isa bin Maryam?\" Ja'far bin Abu Thalib menjawab; \"Pendapat kami adalah sebagaimana yang dibawa oleh agama kami, yaitu dia adalah hamba Allah dan RasulNya, ruhNya dan kalimatNya yang ditiupkan kepada Maryam, seorang wanita yang tidak menikah.\" Kemudian Raja Najasyi memukulkan tangannya ke tanah dan mengambil sebatang kayu, lalu berkata; \"Itulah Isa putra Maryam, sama seperti saya mengatakan bahwa ini adalah kayu.\" Maka para komandan perang yang berada di sekitarnya mengucapkan perkataan yang menunjukan kemarahan, Raja berkata; \"Demi Allah, walau kalian tidak suka, saya akan mengatakannya. Pergilah kalian (kaum muslimin), kalian akan aman di negeriku, barangsiapa mencela kalian, maka akan dikenai denda, barangsiapa yang mencela kalian, maka akan dikenai denda. Saya tidak suka memiliki satu gunung emas jika saya harus menyakiti salah seorang dari kalian. Dan (raja berkata kepada para komandannya;) kembalikan kepada mereka berdua hadiah-hadiah yang telah mereka berikan, kami tidak membutuhkannya. Demi Allah, Allah tidak mengambil suap dariku ketika mengembalikan kerajaanku, hingga saya harus mengambil suap dalam kekuasaanku, dan Allah pun tidak memaksa orang-orang untuk menaatiku sehingga saya menaati mereka dalam masalah itu.\" Kemudian dua orang tersebut keluar dari hadapannya dalam keadaan kalah dan hadiah-hadiah mereka dikembalikan lagi. Maka kami tinggal di dekat raja dengan sebaik-baik rumah dan bertetangga dengan tetangga yang baik. Demi Allah! kami dalam keadaan demikian sampai suatu saat datang seseorang yang mengkudeta kekuasannya. Demi Allah, kami tidak merasakan kesedihan yang melebihi kesedihan pada saat itu, kami khawatir jika orang itu mengalahkan Raja Najasyiy maka akan datang orang yang tidak mengakui hak kami sebagaimana yang telah dilakukan Raja Najasyi. Maka Raja Najasyi menuju orang tersebut, sedang diantara keduanya terdapat sungai Nil. Kemudian para sahabat Rasulullah shallallahu 'alaihi wasallam berkata; \"Siapa di antara kita yang akan menuju ke tempat berkumpulnya kaum tersebut, kemudian memperoleh kabar untuk kita.\" Maka Zubair bin Awwam berkata; \"Saya.\" Zubair bin Awwam adalah orang paling muda umurnya. Mereka meniupkan kirbah untuknya, kemudian meletakannya di dadanya, sehingga dia dapat berenang dengan menggunakan kirbah tersebut sampai di tepi sungai Nil yang menjadi tempat bertemunya kaum. Kami berdoa kepada Allah untuk Raja Najasyi agar dia dapat mengalahkan musuhnya dan dia tetap berdiri kokoh diatas kerajaanya dan mendapatkan kepercayaan dalam memimpin negerinya Habasyah. (Semua itu kami lakukan) karena ketika kami berada di dekatnya kami mendapatkan tempat tinggal yang baik sampai kami menemui Rasulullah shallallahu 'alaihi wasallam yang berada di Makkah.\""},"135":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنِي أَبِي عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الْقِثَّاءَ بِالرُّطَبِ","id":"Telah menceritakan kepada kami [Ibrahim bin Sa'd] telah menceritakan kepadaku [bapakku] dari [Abdullah bin Ja'far] berkata; saya melihat Nabi shallallahu 'alaihi wasallam makan mentimun dengan kurma basah."},"136":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَنْبَأَنَا حَبِيبُ بْنُ الشَّهِيدِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَقَالَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ لِابْنِ الزُّبَيْرِ أَتَذْكُرُ إِذْ تَلَقَّيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَنْتَ وَابْنُ عَبَّاسٍ فَقَالَ نَعَمْ قَالَ فَحَمَلَنَا وَتَرَكَكَ وَقَالَ إِسْمَاعِيلُ مَرَّةً أَتَذْكُرُ إِذْ تَلَقَّيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَنْتَ وَابْنُ عَبَّاسٍ فَقَالَ نَعَمْ فَحَمَلَنَا وَتَرَكَكَ","id":"Telah menceritakan kepada kami [Isma'il] telah memberitakan kepada kami [Habib bin Asy Syahid] dari [Abdullah bin Abu Mulaikah] berkata; [Abdullah bin Ja'far] berkata pada Ibnu Az Zubair; \"Apakah kamu ingat saat Rasulullah shallallahu 'alaihi wasallam menemui saya, kamu dan Ibnu Abbas?\" Ibnu Az Zubair menjawab; \"Ya.\" Ibnu Az Zubair berkata; \"Beliau membawa kami dan meninggalkanmu.\" -Ismail juga berkata: \"Apakah engkau ingat saat Rasulullah shallallahu 'alaihi wasallam menemui saya, kamu dan Ibnu Abbas.\" dia menjawab; \"Ya.\" beliau membawa kami dan meninggalkanmu."},"137":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا عَاصِمٌ عَنْ مُوَرِّقٍ الْعِجْلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ مِنْ سَفَرٍ تُلُقِّيَ بِالصِّبْيَانِ مِنْ أَهْلِ بَيْتِهِ قَالَ وَإِنَّهُ قَدِمَ مَرَّةً مِنْ سَفَرٍ قَالَ فَسُبِقَ بِي إِلَيْهِ قَالَ فَحَمَلَنِي بَيْنَ يَدَيْهِ قَالَ ثُمَّ جِيءَ بِأَحَدِ ابْنَيْ فَاطِمَةَ إِمَّا حَسَنٍ وَإِمَّا حُسَيْنٍ فَأَرْدَفَهُ خَلْفَهُ قَالَ فَدَخَلْنَا الْمَدِينَةَ ثَلَاثَةً عَلَى دَابَّةٍ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami ['Ashim] dari [Muwarriq Al 'Ijli] dari [Abdullah bin Ja'far] berkata; \"Jika Rasulullah shallallahu 'alaihi wasallam datang dari suatu perjalanan maka beliau akan disambut oleh anak-anak kecil dari Ahli Bait beliau. Pada suatu ketika, beliau datang dari sebuah perjalanan, dan saya dibawa lebih dahulu ke hadapan beliau, maka beliau pun membawaku di depan beliau. Kemudian salah seorang anak Fathimah, Hasan atau Husain di datangkan, kemudian beliau memboncengkannya di belakang beliau.\" Abdullah berkata; \" maka kami bertiga memasuki kota Madinah dengan menaiki satu kendaraan.\""},"138":{"ar":"حَدَّثَنَا يَزِيدُ أَنْبَأَنَا مَهْدِيُّ بْنُ مَيْمُونٍ عَنْ مُحَمَّدِ بْنِ أَبِي يَعْقُوبَ عَنِ الْحَسَنِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا حَدَّثَنَا مَهْدِيٌّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ عَنِ الْحَسَنِ بْنِ سَعْدٍ مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَأَرْدَفَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ خَلْفَهُ فَأَسَرَّ إِلَيَّ حَدِيثًا لَا أُخْبِرُ بِهِ أَحَدًا أَبَدًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ مَا اسْتَتَرَ بِهِ فِي حَاجَتِهِ هَدَفٌ أَوْ حَائِشُ نَخْلٍ فَدَخَلَ يَوْمًا حَائِطًا مِنْ حِيطَانِ الْأَنْصَارِ فَإِذَا جَمَلٌ قَدْ أَتَاهُ فَجَرْجَرَ وَذَرَفَتْ عَيْنَاهُ قَالَ بَهْزٌ وَعَفَّانُ فَلَمَّا رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَنَّ وَذَرَفَتْ عَيْنَاهُ فَمَسَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرَاتَهُ وَذِفْرَاهُ فَسَكَنَ فَقَالَ مَنْ صَاحِبُ الْجَمَلِ فَجَاءَ فَتًى مِنْ الْأَنْصَارِ فَقَالَ هُوَ لِي يَا رَسُولَ اللَّهِ فَقَالَ أَمَا تَتَّقِي اللَّهَ فِي هَذِهِ الْبَهِيمَةِ الَّتِي مَلَّكَكَهَا اللَّهُ إِنَّهُ شَكَا إِلَيَّ أَنَّكَ تُجِيعُهُ وَتُدْئِبُهُ","id":"Telah menceritakan kepada kami [Yazid] telah memberitakan kepada kami [Mahdi bin Maimun] dari [Muhammad bin Ya'qub] dari [Al Hasan bin Sa'd] dari [Abdullah bin Ja'far], (menurut jalur yang lain) telah menceritakan kepada kami [Bahz] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Mahdi] telah menceritakan kepada kami [Muhammad bin Abu Ya'qub] dari [Al Hasan bin Sa'd] mantan budak Al Hasan bin Ali, dari [Abdullah bin Ja'far], berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam mengajakku naik kendaraan di belakang beliau, kemudian beliau membisiki suatu pembicaraan yang tidak akan aku beritahukan kepada seseorang selamanya. Rasulullah shallallahu 'alaihi wasallam jika hendak membuang hajatnya, beliau menyukai untuk menutupi dirinya yaitu melindungi dirinya dengan bangunan yang tinggi atau dengan kebun kurma. Pada suatu hari beliau masuk ke dalam salah satu kebun milik orang Anshar yang ternyata di dalamnya ada seekor unta yang mendatangi beliau dalam keadaan menangis dan matanya meneteskan air mata, maka Rasulullah shallallahu 'alaihi wasallam mengusap telinganya dan pangkal lehernya, maka unta tersebut menjadi tenang. Lalu beliau bertanya; \"Siapa orang yang punya unta ini?\" Datanglah seorang pemuda dari Anshar, dia menjawab; \"Itu milikku Wahai Rasulullah.\" Beliau bertanya: \"Tidakkah kamu bertakwa kepada Allah di dalam memelihara unta yang telah Allah kuasakan kepadamu. Unta ini mengadu kepadaku, bahwasanya kamu membiarkan dia lapar dan lelah.\" "},"139":{"ar":"حَدَّثَنَا يَزِيدُ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَرَأَيْتُ ابْنَ أَبِي رَافِعٍ يَتَخَتَّمُ فِي يَمِينِهِ فَسَأَلْتُهُ عَنْ ذَلِكَ فَذَكَرَ أَنَّهُ رَأَى عَبْدَ اللَّهِ بْنَ جَعْفَرٍ يَتَخَتَّمُ فِي يَمِينِهِ وَقَالَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَتَّمُ فِي يَمِينِهِ","id":"Telah menceritakan kepada kami [Yazid] telah memberitakan kepada kami [Hammad bin Salamah] berkata; saya melihat [Ibnu Abu Rafi'] memakai cincin di jari kanannya, saya pun menanyakan hal itu kepadanya, maka dia menjawab; bahwa dia melihat [Abdullah bin Ja'far] memakai cincin di jari tangan kanannya, dan Abdullah bin Ja'far berkata; \"Rasulullah shallallahu 'alaihi wasallam memakai cincinnya di jari tangan kanannya.\""},"140":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى وَيَحْيَى بْنُ إِسْحَاقَ قَالَا حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الْأَسْوَدِ قَالَ سَمِعْتُ عُبَيْدَ بْنَ أُمِّ كِلَابٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ يَحْيَى بْنُ إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ جَعْفَرٍ قَالَ أَحَدُهُمَا ذِي الْجَنَاحَيْنِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا عَطَسَ حَمِدَ اللَّهَ فَيُقَالُ لَهُ يَرْحَمُكَ اللَّهُ فَيَقُولُ يَهْدِيكُمُ اللَّهُ وَيُصْلِحُ بَالَكُمْ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] dan [Yahya bin Ishaq], keduanya berkata; telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Abu Al Aswad] berkata; saya mendengar ['Ubaid bin Ummu Kilab] menceritakan dari [Abdullah bin Ja'far], menurut [Yahya bin Ishaq], dia berkata; saya mendengar [Abdullah bin Ja'far], sedangkan salah satu dari keduanya berkata; Dzul Janahain, bahwa jika Rasulullah shallallahu 'alaihi wasallam bersin, beliau membaca hamdalah, lalu ada yang menyahut: \"YARHAMUKA ALLAH (semoga Allah merahmatimu) \" maka beliau menimpali; \"YAHDIKUMULLAH WA YUSHLIHU BALAKUM (semoga Allah memberimu hidayah dan memperbaiki urusanmu) \"."},"141":{"ar":"حَدَّثَنَا نَصْرُ بْنُ بَابٍ عَنْ حَجَّاجٍ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ أَنَّهُ قَالَإِنَّ آخِرَ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِحْدَى يَدَيْهِ رُطَبَاتٌ وَفِي الْأُخْرَى قِثَّاءٌ وَهُوَ يَأْكُلُ مِنْ هَذِهِ وَيَعَضُّ مِنْ هَذِهِ وَقَالَ إِنَّ أَطْيَبَ الشَّاةِ لَحْمُ الظَّهْرِ","id":"Telah menceritakan kepada kami [Nashr bin Bab] dari [Hajjaj] sesungguhnya [Qatadah] dari [Abdullah bin Ja'far] berkata; Sesungguhnya hal terakhir yang kulihat dari Rasulullah shallallahu 'alaihi wasallam adalah pada salah satu tangannya ada beberapa kurma dan di tangan yang lainnya ada buah sejenis timun, beliau memakan yang satu, dan menggigit yang lainnya. Beliau bersabda: \"Sesungguhnya daging kambing yang paling baik adalah bagian punggungnya.\""},"142":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ أَبِي يَعْقُوبَ يُحَدِّثُ عَنِ الْحَسَنِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَيْشًا اسْتَعْمَلَ عَلَيْهِمْ زَيْدَ بْنَ حَارِثَةَ وَقَالَ فَإِنْ قُتِلَ زَيْدٌ أَوْ اسْتُشْهِدَ فَأَمِيرُكُمْ جَعْفَرٌ فَإِنْ قُتِلَ أَوْ اسْتُشْهِدَ فَأَمِيرُكُمْ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَقُوا الْعَدُوَّ فَأَخَذَ الرَّايَةَ زَيْدٌ فَقَاتَلَ حَتَّى قُتِلَ ثُمَّ أَخَذَ الرَّايَةَ جَعْفَرٌ فَقَاتَلَ حَتَّى قُتِلَ ثُمَّ أَخَذَهَا عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَقَاتَلَ حَتَّى قُتِلَ ثُمَّ أَخَذَ الرَّايَةَ خَالِدُ بْنُ الْوَلِيدِ فَفَتَحَ اللَّهُ عَلَيْهِ وَأَتَى خَبَرُهُمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ إِلَى النَّاسِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ إِنَّ إِخْوَانَكُمْ لَقُوا الْعَدُوَّ وَإِنَّ زَيْدًا أَخَذَ الرَّايَةَ فَقَاتَلَ حَتَّى قُتِلَ أَوْ اسْتُشْهِدَ ثُمَّ أَخَذَ الرَّايَةَ بَعْدَهُ جَعْفَرُ بْنُ أَبِي طَالِبٍ فَقَاتَلَ حَتَّى قُتِلَ أَوْ اسْتُشْهِدَ ثُمَّ أَخَذَ الرَّايَةَ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَقَاتَلَ حَتَّى قُتِلَ أَوْ اسْتُشْهِدَ ثُمَّ أَخَذَ الرَّايَةَ سَيْفٌ مِنْ سُيُوفِ اللَّهِ خَالِدُ بْنُ الْوَلِيدِ فَفَتَحَ اللَّهُ عَلَيْهِ فَأَمْهَلَ ثُمَّ أَمْهَلَ آلَ جَعْفَرٍ ثَلَاثًا أَنْ يَأْتِيَهُمْ ثُمَّ أَتَاهُمْ فَقَالَ لَا تَبْكُوا عَلَى أَخِي بَعْدَ الْيَوْمِ أَوْ غَدٍ ادْعُوا لِي ابْنَيْ أَخِي قَالَ فَجِيءَ بِنَا كَأَنَّا أَفْرُخٌ فَقَالَ ادْعُوا إِلَيَّ الْحَلَّاقَ فَجِيءَ بِالْحَلَّاقِ فَحَلَقَ رُءُوسَنَا ثُمَّ قَالَ أَمَّا مُحَمَّدٌ فَشَبِيهُ عَمِّنَا أَبِي طَالِبٍ وَأَمَّا عَبْدُ اللَّهِ فَشَبِيهُ خَلْقِي وَخُلُقِي ثُمَّ أَخَذَ بِيَدِي فَأَشَالَهَا فَقَالَ اللَّهُمَّ اخْلُفْ جَعْفَرًا فِي أَهْلِهِ وَبَارِكْ لِعَبْدِ اللَّهِ فِي صَفْقَةِ يَمِينِهِ قَالَهَا ثَلَاثَ مِرَارٍ قَالَ فَجَاءَتْ أُمُّنَا فَذَكَرَتْ لَهُ يُتْمَنَا وَجَعَلَتْ تُفْرِحُ لَهُ فَقَالَ الْعَيْلَةَ تَخَافِينَ عَلَيْهِمْ وَأَنَا وَلِيُّهُمْ فِي الدُّنْيَا وَالْآخِرَةِ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [bapakku] berkata; saya mendengar [Muhammad bin Abu Ya'qub] menceritakan dari [Al Hasan bin Sa'd] dari [Abdullah bin Ja'far] berkata; Rasulullah shallallahu 'alaihi wasallam mengutus sepasukan tentara dibawah pimpinan Zaid bin Haritsah, lalu beliau bersabda: \"Jika Zaid terbunuh atau syahid, maka pemimpin kalian adalah Ja'far. Jika ia terbunuh atau syahid, maka pemimpin kalian adalah Abdullah bin Rawahah.\" Ketika mereka berhadapa dengan musuh, Zaid mengambil bendera dan bertempur hingga terbunuh. Lalu Ja'far mengambil alih bendera dan bertempur hingga terbunuh. Bendera kembali dipegang oleh Abdullah bin Rawahah, dan dia bertempur hingga terbunuh. Kemudian bendera diambil oleh Khalid bin Walid, dan Allah memenangkannya. Maka sampailah kabar ini kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau keluar menemui orang-orang, beliau bertahmid kepada Allah dan memujinya, lalu bersabda: \"Sesungguhnya saudara-saudara kalian bertempur melawan musuh. Yang (pertama kali) memegang bendera adalah Zaid bin Haritsah, dia bertempur hingga terbunuh atau syahid, kemudian bendera diambil oleh Ja'far bin Abu Thalib, dan ia bertempur hingga terbunuh atau syahid, kemudian bendera dipegang Abdullah bin Rawahah, dan ia bertempur hingga ia terbunuh atau syahid. Setelah itu bendera diambil alih oleh salah satu pedang Allah, Khalid bin Walid, dan Allah pun memenangkannya.\" Beliau menunda (untuk datang kepada keluarga korban), dan beliau menunda untuk datang kepada keluarga Ja'far selama tiga hari. Kemudian beliau mendatangi mereka dan berkata; \"Janganlah kalian menangisi saudaraku setelah hari ini atau besok, dan panggilkanlah kedua putra saudaraku.\" Abdullah berkata; Kemudian kami dibawa ke hadapan beliau, seakan-akan kami anak ayam (yang kehilangan induknya). Beliau berkata; \"Panggilkanlah tukang cukur untukku.\" Lalu didatangkanlah tukang cukur, dan dia pun mencukur rambut kami. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Muhammad (bin Ja'far) itu mirip dengan paman kami, Abu Thalib, sedang Abdullah itu mirip dengan fisikku dan kelakuanku.\" Lalu beliau memegang tanganku dan menengadahkannya, lalu berdoa: \"Ya Allah gantikanlah Ja'far bagi keluarganya, serta berkahilah Abdullah atas janji setianya.\" Beliau mengatakannya sebanyak tiga kali. Abdullah berkata; Lalu ibu kami datang dan mengatakan kepada beliau tentang keyatiman kami, sehingga membuat beliau bersedih, kemudian beliau bersabda: \"Janganlah engkau khawatir dengan kehidupan mereka, sesungguhnya aku adalah wali bagi mereka di dunia dan di akhirat.\""},"143":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُسَافِعٍ أَنَّ مُصْعَبَ بْنَ شَيْبَةَ أَخْبَرَهُ عَنْ عُقْبَةَ بْنِ مُحَمَّدِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَكَّ فِي صَلَاتِهِ فَلْيَسْجُدْ سَجْدَتَيْنِ بَعْدَمَا يُسَلِّمُحَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَنْبَأَنَا عَبْدُ اللَّهِ أَنْبَأَنَا ابْنُ جُرَيْجٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُسَافِعٍ عَنْ عُقْبَةَ بْنِ مُحَمَّدِ بْنِ الْحَارِثِ فَذَكَرَ مِثْلَهُ بِإِسْنَادِهِ","id":"Telah menceritakan kepada kami [Hajjaj], berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abdullah bin Musafi'] bahwa [Mush'ab bin Syaibah] mengabarinya dari ['Uqbah bin Muhammad bin Al Harits] dari [Abdullah bin Ja'far], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ragu-ragu dalam shalatnya, hendaklah ia sujud dua kali setelah salam.\" Telah menceritakan kepada kami [Ali bin Ishaq] telah memberitakan kepada kami [Abdullah] telah memberitakan kepada kami [Ibnu Juraij] telah menceritakan kepada kami [Abdullah bin Musafi'] dari ['Uqbah bin Muhammad bin Al Harits], lalu menyebutkan seperti hadits di atas dengan sanadnya."},"144":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مُحَمَّدَ بْنَ أَبِي يَعْقُوبَ يُحَدِّثُ عَنِ الْحَسَنِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَغْلَتَهُ وَأَرْدَفَنِي خَلْفَهُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَبَرَّزَ كَانَ أَحَبَّ مَا تَبَرَّزَ فِيهِ هَدَفٌ يَسْتَتِرُ بِهِ أَوْ حَائِشُ نَخْلٍ فَدَخَلَ حَائِطًا لِرَجُلٍ مِنْ الْأَنْصَارِ فَإِذَا فِيهِ نَاضِحٌ لَهُ فَلَمَّا رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَنَّ وَذَرَفَتْ عَيْنَاهُ فَنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَ ذِفْرَاهُ وَسَرَاتَهُ فَسَكَنَ فَقَالَ مَنْ رَبُّ هَذَا الْجَمَلِ فَجَاءَ شَابٌّ مِنْ الْأَنْصَارِ فَقَالَ أَنَا فَقَالَ أَلَا تَتَّقِي اللَّهَ فِي هَذِهِ الْبَهِيمَةِ الَّتِي مَلَّكَكَ اللَّهُ إِيَّاهَا فَإِنَّهُ شَكَاكَ إِلَيَّ وَزَعَمَ أَنَّكَ تُجِيعُهُ وَتُدْئِبُهُ ثُمَّ ذَهَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَائِطِ فَقَضَى حَاجَتَهُ ثُمَّ تَوَضَّأَ ثُمَّ جَاءَ وَالْمَاءُ يَقْطُرُ مِنْ لِحْيَتِهِ عَلَى صَدْرِهِ فَأَسَرَّ إِلَيَّ شَيْئًا لَا أُحَدِّثُ بِهِ أَحَدًا فَحَرَّجْنَا عَلَيْهِ أَنْ يُحَدِّثَنَا فَقَالَ لَا أُفْشِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِرَّهُ حَتَّى أَلْقَى اللَّهَ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [bapakku] berkata; saya mendengar [Muhammad bin Abu Ya'qub] menceritakan dari [Al Hasan bin Sa'd] dari [Abdullah bin Ja'far] berkata; Rasulullah shallallahu 'alaihi wasallam menaiki bighal betina dan memboncengku di belakangnya. Jika Rasulullah shallallahu 'alaihi wasallam membuang hajatnya, beliau menyukai untuk menutupi dirinya yaitu melindungi dirinya dengan bangunan yang tinggi atau di kebun kurma. Pada suatu ketika beliau masuk ke dalam sebuah kebun milik orang Anshar yang ternyata di di dalamnya ada seekor unta milik orang Anshar tersebut. Tatkala melihat Nabi shallallahu 'alaihi wasallam unta tersebut menangis dan meneteskan air matanya, maka Rasulullah shallallahu 'alaihi wasallam turun mengusap telinganya dan pangkal lehernya, maka unta tersebut menjadi tenang. Lalu beliau bertanya; \"Siapa pemilik unta ini?\" Datanglah seorang pemuda dari Anshar dan menjawab; \"Saya.\" Beliau bertanya: \"Tidakkah kamu bertakwa kepada Allah dalam mengurus unta ini yang telah Allah kuasakan kepadamu. Dia mengadukanmu kepadaku dan dia menyatakan bahwa kamu membiarkan dia lapar dan lelah.\" Setelah itu Rasulullah shallallahu 'alaihi wasallam pergi ke dalam kebun dan melaksanakan hajatnya kemudian berwudhu. Ketika beliau datang, air masih menetes dari jenggot ke dada beliau, dan beliau membisikkan sesuatu kepadaku yang tidak akan saya ceritakan kepada seorang pun, bahkan kami merasa berat ketika beliau menceritakannya kepada kami. Abdullah bin Ja'far berkata; \"Saya tidak akan menyebarkan rahasia Rasulullah shallallahu 'alaihi wasallam hingga aku bertemu Allah.\""},"145":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ إِسْمَاعِيلَ بْنِ مُحَمَّدٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنِ الْعَبَّاسِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ الرَّجُلُ سَجَدَ مَعَهُ سَبْعَةُ آرَابٍ وَجْهِهِ وَكَفَّيْهِ وَرُكْبَتَيْهِ وَقَدَمَيْهِحَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ عَنِ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Abdullah bin Ja'far] dari [Isma'il bin Muhammad] dari ['Amru bin Sa'd] dari [Al Abbas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang sedang bersujud, maka ada tujuh anggota yang ikut bersujud bersamanya. Yaitu: wajahnya, kedua telapak tangannya, kedua lututnya, dan kedua kakinya.\" Telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Abdullah bin Ja'far] dari [Yazid bin Abdullah bin Al Hadi] dari [Muhammad bin Ibrahim] dari [Amir bin Sa'd] dari [Al Abbas bin Abdul Muththalib] dari Nabi shallallahu 'alaihi wasallam, seperti lafazh hadits di atas."},"146":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ حَدَّثَنَا حَاتِمٌ يَعْنِي ابْنَ أَبِي صَغِيرَةَ حَدَّثَنِي بَعْضُ بَنِي عَبْدِ الْمُطَّلِبِ قَالَ قَدِمَ عَلَيْنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ فِي بَعْضِ تِلْكَ الْمَوَاسِمِ قَالَ فَسَمِعْتُهُ يَقُولُ حَدَّثَنِي أَبِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍ عَنْ أَبِيهِ الْعَبَّاسِأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَنَا عَمُّكَ كَبِرَتْ سِنِّي وَاقْتَرَبَ أَجَلِي فَعَلِّمْنِي شَيْئًا يَنْفَعُنِي اللَّهُ بِهِ قَالَ يَا عَبَّاسُ أَنْتَ عَمِّي وَلَا أُغْنِي عَنْكَ مِنْ اللَّهِ شَيْئًا وَلَكِنْ سَلْ رَبَّكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالْآخِرَةِ قَالَهَا ثَلَاثًا ثُمَّ أَتَاهُ عِنْدَ قَرْنِ الْحَوْلِ فَقَالَ لَهُ مِثْلَ ذَلِكَحَدَّثَنَا رَوْحٌ حَدَّثَنَا أَبُو يُونُسَ الْقُشَيْرِيُّ حَاتِمُ بْنُ أَبِي صَغِيرَةَ حَدَّثَنِي رَجُلٌ مِنْ وَلَدِ عَبْدِ الْمُطَّلِبِ قَالَ قَدِمَ عَلَيْنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ فَحَضَرَهُ بَنُو عَبْدِ الْمُطَّلِبِ فَقَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ يُحَدِّثُ عَنْ أَبِيهِ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَ أَتَيْتُ رَسُولَ اللَّهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنَا عَمُّكَ قَدْ كَبِرَتْ سِنِّي فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abdullah bin Bakr] telah menceritakan kepada kami [Hatim] yaitu Ibnu Abu Shaghirah, telah menceritakan kepadaku [beberapa orang dari kalangan Bani Abdul Muththalib] berkata; [Ali bin Abdullah bin Abbas] menemui kami di beberapa musim haji. saya mendengarnya berkata; telah menceritakan kepadaku bapakku [Abdullah bin Abbas] dari [bapakku, Al Abbas] bahwa dia menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, aku adalah pamanmu dan usiaku sudah lanjut serta ajalku telah dekat. Ajarkanlah kepadaku sesuatu yang dapat bermanfaat bagiku.\" Beliau bersabda: \"Wahai Abbas, engkau adalah pamanku dan aku tidak punya kuasa apapun atasmu di sisi Allah. Tetapi mintalah kepada Rabbmu ampunan dan keselamatan di dunia dan di akhirat.\" Beliau mengatakannya sebanyak tiga kali. Lalu Abbas menemui beliau lagi pada penghujung tahun dan beliau mengatakan sebagaimana yang dikatakan sebelumnya. Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Abu Yunus Al Qusyairi, Hatim bin Abu Shaghirah] telah menceritakan kepadaku [seseorang keturunan Abdul Muththalib] berkata; [Ali bin Abdullah bin Abbas] menemui kami,, aka anak-anak Abdul Muththalib menemuinya. Dia berkata; saya mendengar [Abdullah bin Abbas] menceritakan dari [Bapaknya, Abbas bin Abdul Muththalib] berkata; Aku menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, aku adalah pamanmu dan usiaku telah lanjut\" lalu dia menyebutkan riwayat secara makna."},"147":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ هَلْ نَفَعْتَ أَبَا طَالِبٍ بِشَيْءٍ فَإِنَّهُ كَانَ يَحُوطُكَ وَيَغْضَبُ لَكَ قَالَ نَعَمْ هُوَ فِي ضَحْضَاحٍ مِنْ النَّارِ وَلَوْلَا ذَلِكَ لَكَانَ فِي الدَّرْكِ الْأَسْفَلِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami [Abdul Malik bin 'Umair] dari [Abdullah bin Al Harits bin Naufal] dari [Abbas bin Abdul Muththalib] berkata; \"Wahai Rasulullah, apakah anda dapat memberi manfaat kepada Abu Thalib karena dia telah mengasuhmu dan marah untuk (memberikan pembelaan) kepadamu?\" Beliau menjawab; \"Ya. ia berada di bagian neraka yang dangkal, dan kalaulah bukan karena hal tersebut niscaya berada di dasar neraka.\""},"148":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا يَحْيَى بْنُ الْعَلَاءِ عَنْ عَمِّهِ شُعَيْبِ بْنِ خَالِدٍ حَدَّثَنِي سِمَاكُ بْنُ حَرْبٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمِيرَةَ عَنْ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَكُنَّا جُلُوسًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَطْحَاءِ فَمَرَّتْ سَحَابَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَدْرُونَ مَا هَذَا قَالَ قُلْنَا السَّحَابُ قَالَ وَالْمُزْنُ قُلْنَا وَالْمُزْنُ قَالَ وَالْعَنَانُ قَالَ فَسَكَتْنَا فَقَالَ هَلْ تَدْرُونَ كَمْ بَيْنَ السَّمَاءِ وَالْأَرْضِ قَالَ قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ بَيْنَهُمَا مَسِيرَةُ خَمْسِ مِائَةِ سَنَةٍ وَمِنْ كُلِّ سَمَاءٍ إِلَى سَمَاءٍ مَسِيرَةُ خَمْسِ مِائَةِ سَنَةٍ وَكِثَفُ كُلِّ سَمَاءٍ مَسِيرَةُ خَمْسِ مِائَةِ سَنَةٍ وَفَوْقَ السَّمَاءِ السَّابِعَةِ بَحْرٌ بَيْنَ أَسْفَلِهِ وَأَعْلَاهُ كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ ثُمَّ فَوْقَ ذَلِكَ ثَمَانِيَةُ أَوْعَالٍ بَيْنَ رُكَبِهِنَّ وَأَظْلَافِهِنَّ كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ ثُمَّ فَوْقَ ذَلِكَ الْعَرْشُ بَيْنَ أَسْفَلِهِ وَأَعْلَاهُ كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَاللَّهُ تَبَارَكَ وَتَعَالَى فَوْقَ ذَلِكَ وَلَيْسَ يَخْفَى عَلَيْهِ مِنْ أَعْمَالِ بَنِي آدَمَ شَيْءٌقَالَ عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّارُ وَمُحَمَّدُ بْنُ بَكَّارٍ قَالَا حَدَّثَنَا الْوَلِيدُ بْنُ أَبِي ثَوْرٍ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمِيرَةَ عَنِ الْأَحْنَفِ بْنِ قَيْسٍ عَنِ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah memberitakan kepada kami [Yahya bin Al 'Ala`] dari [pamannya, Syu'aib bin Khalid] telah menceritakan kepadaku [Simak bin Harb] dari [Abdullah bin 'Amirah] dari [Abbas bin Abdul Muththalib] berkata; Kami bermajlis bersama Rasulullah shallallahu 'alaihi wasallam di Al Bathha`, tiba-tiba sekumpulan awan melintas, maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Tahukah kalian apakah itu?\" Kami menjawab; \"Itu adalah kumpulan awan.\" Beliau berkata; \"Dan mega.\" kami mengikuti; \"Dan mega.\" Lalu beliau bersabda: \"Dan mendung.\" Maka kamipun diam. Beliau bertanya lagi; \"Apakah kalian tahu berapa jarak antara langit dan bumi?\" Kami menjawab; \"Allah dan RasulNya lebih mengetahui.\" Beliau berkata; \"Jaraknya adalah sejauh perjalanan lima ratus tahun. Jarak antara langit yang satu dengan langit berikutnya adalah sejauh perjalanan lima ratus tahun juga. Tebal langit adalah sejauh perjalanan lima ratus tahun. Di atas langit ke tujuh ada lautan yang jarak antara dasar dengan permukaannya adalah sebagaimana jarak bumi dan langit. Lalu di atasnya lagi ada delapan penyangga yang jarak antara ujung dengan pangkalnya seperti jarak antara langit dan bumi. Di atasnya lagi ada Arsy yang jarak antara dasar dan permukaannya adalah seperti jarak antara langit dan bumi. Allah Tabaraka Wa Ta'ala berada di atasnya. Tidak ada satu amalan pun yang dilakukan oleh keturunan Adam yang tersembunyi dari-Nya.\" Abdullah berkata; telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzar] dan [Muhammad bin Bakkar] berkata, telah menceritakan kepada kami [Al Walid bin Abu Tsaur] dari [Simak bin Harb] dari [Abdullah bin 'Amirah] dari [Al Ahnaf bin Qais] dari [Al Abbas bin Abdul Muththalib] dari Nabi shallallahu 'alaihi wasallam seperti di atas."},"149":{"ar":"حَدَّثَنَا يَزِيدُ هَوَ ابْنُ هَارُونَ أَنْبَأَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنِ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ قُرَيْشًا إِذَا لَقِيَ بَعْضُهُمْ بَعْضًا لَقُوهُمْ بِبِشْرٍ حَسَنٍ وَإِذَا لَقُونَا لَقُونَا بِوُجُوهٍ لَا نَعْرِفُهَا قَالَ فَغَضِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَضَبًا شَدِيدًا وَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَا يَدْخُلُ قَلْبَ رَجُلٍ الْإِيمَانُ حَتَّى يُحِبَّكُمْ لِلَّهِ وَلِرَسُولِهِحَدَّثَنَا جَرِيرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَبْدِ الْمُطَّلِبِ بْنِ رَبِيعَةَ قَالَ دَخَلَ الْعَبَّاسُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّا لَنَخْرُجُ فَنَرَى قُرَيْشًا تَحَدَّثُ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yazid] yaitu Ibnu Harun, telah memberitakan kepada kami [Isma'il] yaitu Ibnu Abu Khalid, dari [Yazid bin Abu Ziyad] dari [Abdullah bin Al Harits] dari [Al Abbas bin Abdul Muththalib] berkata; Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Wahai Rasulullah, jika orang-orang Quraisy bertemu satu sama lain, mereka selalu berseri-seri dan berwajah manis. Sedang jika bertemu dengan kami, maka mereka memasang tampang yang kami tidak mengerti.\" Al Abbas berkata; Maka Nabi shallallahu 'alaihi wasallam sangat marah dan bersabda: \"Demi Dzat yang jiwaku ada di tangan-Nya, iman tidak akan masuk kedalam hati seseorang sampai ia mencintai kalian karena Allah dan RasulNya.\" Telah menceritakan kepada kami [Jarir] dari [Yazid bin Abu Ziyad] dari [Abdullah bin Al Harits] dari [Abdul Muththalib bin Rabi'ah] berkata; [Al Abbas] menemui Rasulullah shallallahu 'alaihi wasallam lalu mengatakan: \"Ketika kami keluar, kami melihat orang-orang Quraisy saling berbincang..\" lalu dia menyebutkan hadits itu."},"150":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ أَخْبَرَنِي كَثِيرُ بْنُ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ عَنْ أَبِيهِ الْعَبَّاسِ قَالَشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُنَيْنًا قَالَ فَلَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا مَعَهُ إِلَّا أَنَا وَأَبُو سُفْيَانَ بْنُ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ فَلَزِمْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ نُفَارِقْهُ وَهُوَ عَلَى بَغْلَةٍ شَهْبَاءَ وَرُبَّمَا قَالَ مَعْمَرٌ بَيْضَاءَ أَهْدَاهَا لَهُ فَرْوَةُ بْنُ نَعَامَةَ الْجُذَامِيُّ فَلَمَّا الْتَقَى الْمُسْلِمُونَ وَالْكُفَّارُ وَلَّى الْمُسْلِمُونَ مُدْبِرِينَ وَطَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكُضُ بَغْلَتَهُ قِبَلَ الْكُفَّارِ قَالَ الْعَبَّاسُ وَأَنَا آخِذٌ بِلِجَامِ بَغْلَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُفُّهَا وَهُوَ لَا يَأْلُو مَا أَسْرَعَ نَحْوَ الْمُشْرِكِينَ وَأَبُو سُفْيَانَ بْنُ الْحَارِثِ آخِذٌ بِغَرْزِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبَّاسُ نَادِ يَا أَصْحَابَ السَّمُرَةِ قَالَ وَكُنْتُ رَجُلًا صَيِّتًا فَقُلْتُ بِأَعْلَى صَوْتِي أَيْنَ أَصْحَابُ السَّمُرَةِ قَالَ فَوَاللَّهِ لَكَأَنَّ عَطْفَتَهُمْ حِينَ سَمِعُوا صَوْتِي عَطْفَةُ الْبَقَرِ عَلَى أَوْلَادِهَا فَقَالُوا يَا لَبَّيْكَ يَا لَبَّيْكَ وَأَقْبَلَ الْمُسْلِمُونَ فَاقْتَتَلُوا هُمْ وَالْكُفَّارُ فَنَادَتْ الْأَنْصَارُ يَقُولُونَ يَا مَعْشَرَ الْأَنْصَارِ ثُمَّ قَصَّرَتْ الدَّاعُونَ عَلَى بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ فَنَادَوْا يَا بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ قَالَ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى بَغْلَتِهِ كَالْمُتَطَاوِلِ عَلَيْهَا إِلَى قِتَالِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا حِينَ حَمِيَ الْوَطِيسُ قَالَ ثُمَّ أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَصَيَاتٍ فَرَمَى بِهِنَّ وُجُوهَ الْكُفَّارِ ثُمَّ قَالَ انْهَزَمُوا وَرَبِّ الْكَعْبَةِ انْهَزَمُوا وَرَبِّ الْكَعْبَةِ قَالَ فَذَهَبْتُ أَنْظُرُ فَإِذَا الْقِتَالُ عَلَى هَيْئَتِهِ فِيمَا أَرَى قَالَ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ رَمَاهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَصَيَاتِهِ فَمَا زِلْتُ أَرَى حَدَّهُمْ كَلِيلًا وَأَمْرَهُمْ مُدْبِرًا حَتَّى هَزَمَهُمْ اللَّهُ قَالَ وَكَأَنِّي أَنْظُرُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْكُضُ خَلْفَهُمْ عَلَى بَغْلَتِهِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] telah mengabarkan kepadaku [Katsir bin Abbas bin Abdul Muththalib] dari [Bapaknya, Al Abbas] berkata; Saya menyaksikan perang Hunain bersama Rasulullah shallallahu 'alaihi wasallam. Saya melihat Nabi shallallahu 'alaihi wasallam tidak di kawal oleh seorangpun kecuali aku dan Abu Sufyan bin Al Harits bin Abdul Muththalib, maka kami memutuskan untuk tetap mendampingi Rasulullah shallallahu 'alaihi wasallam dan tidak meninggalkan beliau. Pada saat itu, beliau berada di atas keledai putih kehitam-hitaman -Ma'mar berkata; berwarna putih- pemberian Farwah bin Nu'amah Al Judzami. Tatkala pasukan kaum muslim dan pasukan kafir bertemu, orang-orang muslim kabur sedangkan Rasulullah shallallahu 'alaihi wasallam mengarahkan bighalnya ke arah orang kafir. Al Abbas berkata; Saya memegang kekang bighal Rasulullah shallallahu 'alaihi wasallam, saya menahannya agar kuda tersebut tidak berjalan cepat menuju orang-orang musyrik, sedangkan Abu Sufyan bin Al Harits memegang pijkan kaki Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bersabda: \"Wahai Abbas panggillah orang-orang yang mengikuti Bai'atur Ridlwan.\" Aku adalah orang yang sangat tinggi suaranya, maka aku pun mengangkat suaraku dengan tinggi; \"Dimanakah ashhab as samurrah (orang yang mengikuti Bai'atur Ridlwan)?\" Demi Allah, rasa sayang mereka (kepada Rasulullah shallallah 'alaihi wa sallam) ketika mendengar suaraku (memanggil mereka) seperti rasa sayang seekor induk sapi terhadap anak-anaknya. Mereka menjawab; \"Kami datang memenuhi panggilanmu, kami datang memenuhi panggilanmu.\" Maka kaum muslimin pun datang, kemudian terjadilah pertempuran antara kaum muslimin dan orang-orang kafir. Orang-orang Anshar pun (tak ketinggalan) menyeru; \"Wahai segenap kaum Anshar!\" Kemudian panggilan semakin menyempit kepada Bani Al Harits bin Al Khazraj, mereka memanggil; \"Wahai Bani Al Harits bin Al Khazraj.\" Rasulullah shallallahu 'alaihi wasallam melihat pada saat di atas bighalnya, seakan-akan beliau berdiri di atasnya, memandangi peperangan yang sedang terjadi, dan bersabda: \"Inilah yang terjadi ketika peperangan sangat sengit sedang terjadi.\" Kemudian beliau mengambil (segenggam) kerikil dan melemparkannya kepada arah orang-orang kafir, lalu bersabda: \"Mereka akan kalah, Demi Rabb Ka'bah, mereka akan kalah, Demi Rabb Ka'bah.\" Al Abbas melanjutkan ceritanya; Aku bergegas melihat peperangan, dan ternyata peperangan masih dalam keadaan seperti yang kulihat. Demi Allah, tidak ada yang dilakukan Rasulullah shallallahu 'alaihi wasallam kecuali melempar kerikil-kerikil tersebut kepada arah mereka, dan saya dapat melihat kekuatan mereka melemah dan akhirnya mundur sehingga Allah mengalahkan mereka. Saya tetap memperhatikan Nabi shallallahu 'alaihi wasallam yang sedang mengejar di belakang mereka di atas bighalnya.\""},"151":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ مَرَّةً أَوْ مَرَّتَيْنِ فَلَمْ أَحْفَظْهُ عَنْ كَثِيرِ بْنِ عَبَّاسٍ قَالَكَانَ عَبَّاسٌ وَأَبُو سُفْيَانَ مَعَهُ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَخَطَبَهُمْ وَقَالَ الْآنَ حَمِيَ الْوَطِيسُ وَقَالَ نَادِ يَا أَصْحَابَ سُورَةِ الْبَقَرَةِ","id":"Telah menceritakan kepada kami [Sufyan] berkata; saya mendengar [Az Zuhri] sekali atau dua kali, namun saya tidak dapat mengingatnya, dari [Katsir bin Abbas] berkata; Abbas dan Abu Sufyan bersama Nabi shallallahu 'alaihi wasallam, beliau berkhutbah di hadapan mereka: \"Sekarang peperangan sudah semakin sengit!\" lalu beliau bersabda (kepada Abbas dan Abu Sufyan): \"serulah; 'Wahai orang-orang yang kepadanya diturunkan surat Al Baqarah.\""},"152":{"ar":"حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ أَبُو عَبْدِ اللَّهِ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَبْدِ الْمُطَّلِبِ بْنِ رَبِيعَةَ قَالَدَخَلَ الْعَبَّاسُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا لَنَخْرُجُ فَنَرَى قُرَيْشًا تَحَدَّثُ فَإِذَا رَأَوْنَا سَكَتُوا فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَرَّ عِرْقٌ بَيْنَ عَيْنَيْهِ ثُمَّ قَالَ وَاللَّهِ لَا يَدْخُلُ قَلْبَ امْرِئٍ إِيمَانٌ حَتَّى يُحِبَّكُمْ لِلَّهِ وَلِقَرَابَتِي","id":"Telah menceritakan kepada kami [Jarir bin Abdul Hamid, Abu Abdullah] dari [Yazid bin Abu Ziyad] dari [Abdullah bin Al Harits] dari [Abdul Muththalib bin Rabi'ah] berkata; Al Abbas menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Kami keluar kemudian kami melihat orang-orang Quraisy sedang berbincang-bincang, tatkala mereka melihat kami mereka terdiam.\" Maka Rasulullah shallallahu 'alaihi wasallam marah dan keringatnya keluar antara kedua matanya kemudian bersabda: \"Demi Allah, iman tidak akan masuk ke dalam hati seseorang sehingga dia mencintai kalian karena Allah dan karena hubungan kekerabatan kalian denganku.\" "},"153":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثُ بْنُ سَعِيدٍ عَنِ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ عَامِرِ بْنِ سَعْدٍ عَنِ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَاقَ طَعْمَ الْإِيمَانِ مَنْ رَضِيَ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits bin Sa'id] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim bin Al Harits] dari ['Amir bin Sa'd] dari [Al Abbas bin Abdul Muththalib] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang bisa merasakan manisnya iman adalah orang yang rela Allah sebagai Rabbnya, Islam sebagai diennya, dan Muhammad sebagai Rasulnya.\""},"154":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ الْقُرَشِيُّ عَنِ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ عَامِرِ بْنِ سَعْدٍ عَنِ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَجَدَ الْعَبْدُ سَجَدَ مَعَهُ سَبْعَةُ آرَابٍ وَجْهُهُ وَكَفَّاهُ وَرُكْبَتَاهُ وَقَدَمَاهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Bakr bin Mudlar Al Qurasyi] dari [Ibnu Al Had] dari [Muhammad bin Ibrahim Al Harits] dari ['Amru bin Sa'd] dari [Al Abbas bin Abdul Muththalib] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba bersujud maka ada tujuh anggota badan yang ikut bersujud bersamanya. Yaitu: wajahnya, kedua telapak tangannya, kedua lututnya, dan kedua kakinya.\" "},"155":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ عَنِ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنِ ابْنِ عَبَّاسٍ عَنِ الْفَضْلِ بْنِ عَبَّاسٍأَنَّهُ كَانَ رِدْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَمْعٍ فَلَمْ يَزَلْ يُلَبِّي حَتَّى رَمَى الْجَمْرَةَ","id":"Telah menceritakan kepada kami ['Abbad bin 'Abbad] dari [Ibnu Juraij] dari ['Atho`] dari [Ibnu Abbas] dari [Al Fadhl bin Abbas], bahwa dia membonceng Nabi shallallahu 'alaihi wasallam dari Muzdalifah, beliau tetap bertalbiyah hingga beliau melempar jumrah."},"156":{"ar":"حَدَّثَنَا يَحْيَى عَنِ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ عَنِ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْدَفَ الْفَضْلَ بْنَ عَبَّاسٍ مِنْ جَمْعٍ قَالَ عَطَاءٌ فَأَخْبَرَنِي ابْنُ عَبَّاسٍ أَنَّ الْفَضْلَ أَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَزَلْ يُلَبِّي حَتَّى رَمَى الْجَمْرَةَ","id":"Telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] telah menceritakan kepadaku ['Atho`] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam memboncengkan Al Fadhl bin Abbas dari Muzdalifah. 'Atho` berkata; telah menceritakan kepadaku Ibnu Abbas bahwa [Al Fadhl] mengabarinya, bahwa Nabi shallallahu 'alaihi wasallam tetap bertalbiyah sampai melempar jumrah."},"157":{"ar":"حَدَّثَنَا يَحْيَى عَنِ ابْنِ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَخْبَرَنِي أَبُو مَعْبَدٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يُخْبِرُ عَنِ الْفَضْلِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشِيَّةَ عَرَفَةَ غَدَاةَ جَمْعٍ لِلنَّاسِ حِينَ دَفَعْنَا عَلَيْكُمْ السَّكِينَةَ وَهُوَ كَافٌّ نَاقَتَهُ حَتَّى إِذَا دَخَلَ مِنًى حِينَ هَبَطَ مُحَسِّرًا قَالَ عَلَيْكُمْ بِحَصَى الْخَذْفِ الَّذِي يُرْمَى بِهِ الْجَمْرَةُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُشِيرُ بِيَدِهِ كَمَا يَخْذِفُ الْإِنْسَانُو قَالَ رَوْحٌ وَالبُرْسَانِيُّ عَشِيَّةَ عَرَفَةَ وَغَدَاةَ جَمْعٍ وَقَالَا حِينَ دَفَعُوا","id":"Telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] telah mengabarkan kepadaku [Abu Zubair] telah menceritakan kepadaku [Abu Ma'bad] berkata; saya mendengar [Ibnu Abbas] mengabari dari [Al Fadhl], berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada Sore Hari di 'Arafah dan Pagi Hari di Muzdalifah kepada orang-orang ketika kami mulai berangkat: \"Hendaklah berjalan dengan tenang!\" sambil menarik tali kekang unta beliau. Ketika beliau masuk di Mina, tepatnya ketika menuruni lembah Muhassir, beliau bersabda: \"Hendaklah kalian (mempersiapkan) batu kerikil untuk melempar jumrah.\" Rasulullah shallallahu 'alaihi wasallam mengisyaratkan dengan tangan beliau sebagaimana orang yang melempar. [Rauh] dan [Al Bursani] berkata; \"Pada Sore Hari di 'Arafah dan Pagi Hari di Muzdalifah..\" dan \"Ketika mereka mulai berangkat.\""},"158":{"ar":"حَدَّثَنَا حُجَيْنٌ وَيُونُسُ قَالَا حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ أَبِي مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنِ الْفَضْلِ بْنِ عَبَّاسٍ وَكَانَ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ قَالَ فِي عَشِيَّةِ عَرَفَةَ وَغَدَاةِ جَمْعٍ لِلنَّاسِ حِينَ دَفَعُوا عَلَيْكُمْ السَّكِينَةَ وَهُوَ كَافٌّ نَاقَتَهُ حَتَّى إِذَا دَخَلَ مُحْسِّرًا وَهُوَ مِنْ مِنًى قَالَ عَلَيْكُمْ بِحَصَى الْخَذْفِ الَّذِي يُرْمَى بِهِ الْجَمْرَةُ وَقَالَ لَمْ يَزَلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُلَبِّي حَتَّى رَمَى الْجَمْرَةَ","id":"Telah menceritakan kepada kami [Hujain] dan [Yunus], keduanya berkata; telah menceritakan kepada kami [Laits bin Sa'id] dari [Abu Zubair] dari [Abu Ma'bad] mantan budak Ibnu Abbas, dari [Abdullah bin Abbas] dari [Al Fadhl bin Abbas], dia berkata; bahwa dia dibonceng Nabi shallallahu 'alaihi wasallam dan beliau bersabda pada Sore Hari 'Arafah dan Pagi Hari Muzdalifah kepada orang-orang ketika kami mulai berangkat: \"Hendaklah kalian berjalan dengan tenang!\" sambil menarik tali kekang unta beliau, sehingga ketika beliau masuk lembah Muhassir di Mina, beliau bersabda: \"Hendaklah kalian (mempersiapkan) batu kerikil untuk melempar jumrah.\" Al Fadhl berkata; \"Rasulullah shallallahu 'alaihi wasallam tetap bertalbiyah sampai beliau melempar jumrah.\""},"159":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيٍّ عَنْ عَبَّاسِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنِ الْفَضْلِ بْنِ عَبَّاسٍ قَالَزَارَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبَّاسًا فِي بَادِيَةٍ لَنَا وَلَنَا كُلَيْبَةٌ وَحِمَارَةٌ تَرْعَى فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ وَهُمَا بَيْنَ يَدَيْهِ فَلَمْ تُؤَخَّرَا وَلَمْ تُزْجَرَا","id":"Telah menceritakan kepada kami [Hajjaj] berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Muhammad bin Umar bin Ali] dari [Abbas bin 'Ubaidullah bin Abbas] dari [Al Fadhl bin Abbas] berkata; Nabi shallallahu 'alaihi wasallam mengunjungi Abbas pada saat berada di kampung kami. Kami mempunyai seekor anjing dan keledai yang sedang memakan rumput. Lalu Nabi shallallahu 'alaihi wasallam mengerjakan shalat ashar sementara kedua binatang itu berada di depan beliau, dan keduanya tidak disingkirkan dan juga tidak diusir. "},"160":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ أَبِي الطُّفَيْلِ عَنِ الْفَضْلِ بْنِ عَبَّاسٍأَنَّهُ كَانَ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَمْعٍ إِلَى مِنًى فَلَمْ يَزَلْ يُلَبِّي حَتَّى رَمَى الْجَمْرَةَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin 'Utsman bin Khutsaim] dari [Abu Thufail] dari [Al Fadhl bin Abbas] bahwa dia dibonceng Nabi shallallahu 'alaihi wasallam dari Muzdalifah menuju Mina, dan beliau tetap bertalbiyah hingga beliau melempar jumrah."},"161":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَكِيمٍ الْعَدَنِيُّ حَدَّثَنِي الْحَكَمُ يَعْنِي ابْنَ أَبَانَ قَالَ سَمِعْتُ عِكْرِمَةَ يَقُولُ قَالَ الْفَضْلُ بْنُ عَبَّاسٍلَمَّا أَفَاضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ فَبَلَغْنَا الشِّعْبَ نَزَلَ فَتَوَضَّأَ ثُمَّ رَكِبْنَا حَتَّى جِئْنَا الْمُزْدَلِفَةَ","id":"Telah menceritakan kepada kami [Yazid bin Abu Hakim Al 'Adani] telah menceritakan kepadaku [Al Hakam] yaitu Ibnu Aban berkata; saya mendengar ['Ikrimah] berkata; [Al Fadhl bin Abbas] berkata: \"Ketika Rasulullah shallallahu 'alaihi wasallam bergegas meninggalkan (Arafah) yang pada saat itu aku bersama beliau. Ketika kami sampai di sebuah lembah, beliau singgah dan berwudhu, kemudian kami melanjutkan perjalanan kembali hingga tiba di Muzdalifah.\""},"162":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي نَجِيحٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ أَوْ عَنْ مُجَاهِدِ بْنِ جَبْرٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ حَدَّثَنِي أَخِي الْفَضْلُ بْنُ عَبَّاسٍ وَكَانَ مَعَهُ حِينَ دَخَلَهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُصَلِّ فِي الْكَعْبَةِ وَلَكِنَّهُ لَمَّا دَخَلَهَا وَقَعَ سَاجِدًا بَيْنَ الْعَمُودَيْنِ ثُمَّ جَلَسَ يَدْعُو","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Abdullah bin Abu Nujaih] dari ['Atho` bin Abu Rabah] atau dari [Mujahid bin Jubair] dari [Abdullah bin Abbas] telah menceritakan kepadaku [saudaraku, Al Fadhl bin Abbas] dan dia bersamanya ketika memasuki Ka'bah, bahwa Rasulullah shallallahu 'alaihi wasallam tidak shalat di dalam Ka'bah tapi beliau ketika memasukinya bersujud di antara kedua tiangnya lalu duduk berdoa."},"163":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ عَطَاءٍ عَنِ ابْنِ عَبَّاسٍ عَنِ الْفَضْلِ بْنِ عَبَّاسٍوَكَانَ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَفَاضَ مِنْ عَرَفَةَ قَالَ فَرَأَى النَّاسَ يُوضِعُونَ فَأَمَرَ مُنَادِيَهُ فَنَادَى لَيْسَ الْبِرُّ بِإِيضَاعِ الْخَيْلِ وَالْإِبِلِ فَعَلَيْكُمْ بِالسَّكِينَةِ","id":"Telah menceritakan kepada kami ['Abdah bin Sulaiman] telah menceritakan kepada kami [Ibnu Abu Laila] dari ['Atho`] dari [Ibnu Abbas] dari [Al Fadhl bin Abbas] bahwa dia membonceng Nabi shallallahu 'alaihi wasallam ketika berangkat dari Arafah lalu dia melihat orang-orang berjalan dengan tergesa-gesa, maka beliau menyuruh seorang penyerunya menyerukan; \"Tidaklah termasuk kebaikan memaksa kuda dan unta untuk berlari, tapi berangkatlah dengan tenang!\""},"164":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ قَالَ قَالَتْ عَائِشَةُ وُأُمُّ سَلَمَةَ زَوْجَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْبِحُ مِنْ أَهْلِهِ جُنُبًا فَيَغْتَسِلُ قَبْلَ أَنْ يُصَلِّيَ الْفَجْرَ ثُمَّ يَصُومُ يَوْمَئِذٍقَالَ فَذَكَرْتُ ذَلِكَ لِأَبِي هُرَيْرَةَ فَقَالَ لَا أَدْرِي أَخْبَرَنِي ذَلِكَ الْفَضْلُ بْنُ عَبَّاسٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [anak saudara Ibnu Syihab] dari [pamannya] berkata; telah mengabarkan kepadaku [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] berkata; [Aisyah] dan [Ummu Salamah], istri Nabi shallallahu 'alaihi wasallam, keduanya mengatakan; \"pada suatu pagi Rasulullah shallallahu 'alaihi wasallam dalam keadaan junub karena jima', kemudian beliau mandi sebelum beliau mengerjakan shalat fajar, dan pada hari itu beliau melanjutkan berpuasa.\" Kemudian (hadits tersebut) saya ceritakan kepada Abu Hurairah, maka dia mengatakan; \"Aku tidak tahu, tetapi Al Fadhl bin Abbas radhia Allahu ta'ala 'anhu yang memberitahukan kepadaku.\""},"165":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عُمَرَ أَبُو الْمُنْذِرِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي عَلِيٍّ الزَّرَّادِ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ تَمَّامِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ قَالَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أُتِيَ فَقَالَ مَا لِي أَرَاكُمْ تَأْتُونِي قُلْحًا اسْتَاكُوا لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَفَرَضْتُ عَلَيْهِمْ السِّوَاكَ كَمَا فَرَضْتُ عَلَيْهِمْ الْوُضُوءَ","id":"Telah menceritakan kepada kami [Isma'il bin 'Amru, Abu Al Mundzir] berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Ali Az Zarad] berkata; telah menceritakan kepadaku [Ja'far bin Tammam] dari [Bapaknya] berkata; Para sahabat menemui Nabi shallallahu 'alaihi wasallam, atau ada yang datang pada beliau. Maka beliau bertanya: \"Apa yang menyebabkan kalian menemuiku dengan gigi yang kuning. Bersiwaklah kalian, seandainya tidak akan memberatkan umatku, niscaya aku akan wajibkan bagi mereka untuk bersiwak sebagaimana aku wajibkan atas mereka berwudhu.\""},"166":{"ar":"حَدَّثَنَا جَرِيرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُفُّ عَبْدَ اللَّهِ وَعُبَيْدَ اللَّهِ وَكَثِيرًا مِنْ بَنِي الْعَبَّاسِ ثُمَّ يَقُولُ مَنْ سَبَقَ إِلَيَّ فَلَهُ كَذَا وَكَذَا قَالَ فَيَسْتَبِقُونَ إِلَيْهِ فَيَقَعُونَ عَلَى ظَهْرِهِ وَصَدْرِهِ فَيُقَبِّلُهُمْ وَيَلْزَمُهُمْ","id":"Telah menceritakan kepada kami [Jarir] dari [Yazid bin Abu Ziyad] dari [Abdullah bin al Harits] berkata; Rasulullah shallallahu 'alaihi wasallam membariskan Abdullah, Ubaidullah dan banyak lagi sahabat dari kalangan Bani Al Abbas, seraya bersabda: \"Barangsiapa paling dahulu sampai kepadaku, maka ia akan mendapatkan ini dan itu.\" Abdullah berkata; Lalu mereka saling berlomba untuk sampai kepada Rasulullah shallallahu 'alaihi wasallam, sehingga diantara mereka ada yang menyentuh dada beliau dan ada juga yang menyentuh punggung beliau. Kemudian beliau menciumi mereka dan memeluk mereka.\""},"167":{"ar":"حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا يَحْيَى بْنُ أَبِي إِسْحَاقَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عُبَيْدِ اللَّهِ بْنِ الْعَبَّاسِ قَالَجَاءَتْ الْغُمَيْصَاءُ أَوْ الرُّمَيْصَاءُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَشْكُو زَوْجَهَا وَتَزْعُمُ أَنَّهُ لَا يَصِلُ إِلَيْهَا فَمَا كَانَ إِلَّا يَسِيرًا حَتَّى جَاءَ زَوْجُهَا فَزَعَمَ أَنَّهَا كَاذِبَةٌ وَلَكِنَّهَا تُرِيدُ أَنْ تَرْجِعَ إِلَى زَوْجِهَا الْأَوَّلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لَكِ ذَلِكَ حَتَّى يَذُوقَ عُسَيْلَتَكِ رَجُلٌ غَيْرُهُ","id":"Telah menceritakan kepada kami [Husyaim] telah memberitakan kepada kami [Yahya bin Abu Ishaq] dari [Sulaiman bin Yasar] dari [Ubaidullah bin Abbas] berkata; Al Ghumaisha' atau Ar Rumaisha' menemui Rasulullah shallallahu 'alaihi wasallam mengadukan suaminya, dan perempuan itu menyatakan bahwa suaminya tidak mau menggaulinya. Tidak lama kemudian datanglah suaminya dan menyatakan bahwa istrinya berdusta, namun dia melakukannya hanya karena ingin kembali kepada suami pertamanya. Maka Rasulullah shallallahu 'alaihi wasallam berkata kepada perempuan itu: \"Engkau tidak akan bisa melakukannya hingga suami kedua merasakan madumu.\""},"168":{"ar":"حَدَّثَنَا مُعَاوِيةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ عَنْ مَنْصُورٍ عَنْ أَبِي هَاشِمٍ عَنْ يَحْيَى بْنِ عَبَّادٍ أَوْ عَنْ أَبِي هَاشِمٍ عَنْ حَجَّاجٍ شَكَّ مَنْصُورٌ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنِ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُقَالَ وَقَالَ مَنْصُورٌ وَحَدَّثَنِي عَوْنٌ عَنْ أَخِيهِ عُبَيْدِ اللَّهِ بِهَذَا","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amru] berkata; Telah menceritakan kepada kami [Za`idah] dari [Manshur] dari [Abu Hasyim] dari [Yahya bin 'Abbad] atau dari [Abu Hasyim] dari [Hajjaj], -Manshur ragu- dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila mengucapkan: SAMI'ALLAHU LIMAN HAMIDAH (Allah Maha Mendengar bagi siapa saja yang memujiNya), beliau mengucapkan: ALLAHUMMA RABBANA LAKA AL HAMDU MIL`AS SAMAWATI WA MIL`AL ARDLI WA MIL`A MA SYI`TA MIN SYAI`IN BA'DU (Wahai Tuhan kami, milikMu segala puji sepenuh langit dan sepenuh bumi serta sepenuh apa pun setelah itu yang Engkau kehendaki). Ahmad berkata; [Manshur] berkata; dan telah menceritakan kepadaku ['Aun] dari saudaranya yaitu [Ubaidullah] seperti ini."},"169":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ عَنِ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيدَ عَلَى ابْنَةِ حَمْزَةَ أَنْ يَتَزَوَّجَهَا فَقَالَ إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِ وَإِنَّهُ يَحْرُمُ مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah menceritakan kepada kami [Abdullah bin Bakr] dan [Muhammad bin Ja'far] mereka berdua berkata; Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Jabir bin Zaid] dari [Ibnu Abbas]; bahwa Rasulullah shallallahu 'alaihi wasallam hendak dinikahkan dengan anak perempuan Hamzah, lalu beliau bersabda: \"Dia putri saudara sesusuanku, sesungguhnya diharamkan karena faktor sebagaimana apa yang diharamkan karena faktor nasab (garis keturunan).\""},"170":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ عِكْرِمَةَ عَنِ ابْنِ عَبَّاسٍأَنَّهُ كَانَ لَا يَرَى بَأْسًا أَنْ يَتَزَوَّجَ الرَّجُلُ وَهُوَ مُحْرِمٌ وَيَقُولُ إِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ مَيْمُونَةَ بِنْتَ الْحَارِثِ بِمَاءٍ يُقَالُ لَهُ سَرِفُ وَهُوَ مُحْرِمٌ فَلَمَّا قَضَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَّتَهُ أَقْبَلَ حَتَّى إِذَا كَانَ بِذَلِكَ الْمَاءِ أَعْرَسَ بِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Bakr] dan [Muhammad bin Ja'far] mereka berdua berkata; Telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Ya'la bin Hakim] dari [Ikrimah] dari [Ibnu Abbas]; bahwa ia berpendapat; \"tidak apa-apa orang yang sedang ihram melakukan pernikahan, \" dan ia mengatakan; \"Sesungguhnya Nabiyullah shallallahu 'alaihi wasallam menikahi Maimunah binti Al Harits di suatu sumber air yang bernama Saraf, saat itu beliau sedang ihram. Setelah Nabiyullah shallallahu 'alaihi wasallam menyelesaikan hajinya, beliau datang, lalu ketika berada di sumber air itu, beliau tinggal bersamanya.\""},"171":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي يَحْيَى الْقَتَّاتِ عَنْ مُجَاهِدٍ عَنِ ابْنِ عَبَّاسٍ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَجُلٍ وَفَخِذُهُ خَارِجَةٌ فَقَالَ غَطِّ فَخِذَكَ فَإِنَّ فَخِذَ الرَّجُلِ مِنْ عَوْرَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Sabiq] telah menceritakan kepada kami [Israil] dari [Abu Yahya Al Qattat] dari [Mujahid] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melewati seorang laki-laki yang terlihat pahanya, maka beliau bersabda, \"Tutuplah pahamu, karena sesungguhnya paha laki-laki itu termasuk aurat.\""},"172":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنِ ابْنِ عَبَّاسٍ قَالَقَالَ أَيُّ الْقِرَاءَتَيْنِ كَانَتْ أَخِيرًا قِرَاءَةُ عَبْدِ اللَّهِ أَوْ قِرَاءَةُ زَيْدٍ قَالَ قُلْنَا قِرَاءَةُ زَيْدٍ قَالَ لَا إِلَّا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْرِضُ الْقُرْآنَ عَلَى جَبْرَائِيلَ كُلَّ عَامٍ مَرَّةً فَلَمَّا كَانَ فِي الْعَامِ الَّذِي قُبِضَ فِيهِ عَرَضَهُ عَلَيْهِ مَرَّتَيْنِ وَكَانَتْ آخِرَ الْقِرَاءَةِ قِرَاءَةُ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Sabiq] telah menceritakan kepada kami [Israil] dari [Ibrahim bin Muhajir] dari [Mujahid] dari [Ibnu Abbas], ia berkata; \"Bacaan siapa yang terakhir, bacaan Abdullah atau bacaan Zaid?\" kami menjawab; \"Bacaan Zaid.\" Ia berkata; \"Bukan, karena Rasulullah shallallahu 'alaihi wasallam setiap setahun sekali membacakan Al Qur`an kepada Jibra`il, namun pada tahun beliau wafat, beliau membacakannya dua kali, dan bacaan yang terakhir adalah bacaan Abdullah.\""},"173":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِ�� عَمْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنِ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ الم غُلِبَتْ الرُّومُ }قَالَ غُلِبَتْ وَغَلَبَتْ قَالَ كَانَ الْمُشْرِكُونَ يُحِبُّونَ أَنْ تَظْهَرَ فَارِسُ عَلَى الرُّومِ لِأَنَّهُمْ أَهْلُ أَوْثَانٍ وَكَانَ الْمُسْلِمُونَ يُحِبُّونَ أَنْ تَظْهَرَ الرُّومُ عَلَى فَارِسَ لِأَنَّهُمْ أَهْلُ كِتَابٍ فَذَكَرُوهُ لِأَبِي بَكْرٍ فَذَكَرَهُ أَبُو بَكْرٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُمْ سَيَغْلِبُونَ قَالَ فَذَكَرَهُ أَبُو بَكْرٍ لَهُمْ فَقَالُوا اجْعَلْ بَيْنَنَا وَبَيْنَكَ أَجَلًا فَإِنْ ظَهَرْنَا كَانَ لَنَا كَذَا وَكَذَا وَإِنْ ظَهَرْتُمْ كَانَ لَكُمْ كَذَا وَكَذَا فَجَعَلَ أَجَلًا خَمْسَ سِنِينَ فَلَمْ يَظْهَرُوا فَذَكَرَ ذَلِكَ أَبُو بَكْرٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا جَعَلْتَهَا إِلَى دُونَ قَالَ أُرَاهُ قَالَ الْعَشْرِ قَالَ قَالَ سَعِيدُ بْنُ جُبَيْرٍ الْبِضْعُ مَا دُونَ الْعَشْرِ ثُمَّ ظَهَرَتْ الرُّومُ بَعْدُ قَالَ فَذَلِكَ قَوْلُهُ{ الم غُلِبَتْ الرُّومُ إِلَى قَوْلِهِ وَيَوْمَئِذٍ يَفْرَحُ الْمُؤْمِنُونَ }قَالَ يَفْرَحُونَ{ بِنَصْرِ اللَّهِ }","id":"Telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah menceritakan kepada kami [Abu Ishaq] dari [Sufyan] dari [Habib bin Abu Amrah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] tentang firmanNya (Alif laam Miim. Telah dikalahkan bangsa Romawi), ia berkata; \"Bangsa Romawi dikalahkan dan akhirnya kalah.\" Ia berkata; \"Orang-orang Musyrik senang (berharap) jika bangsa Persia dapat mengalahkan bangsa Romawi, karena mereka adalah penyembah berhala, sedang kaum Muslimin senang (berharap) jika Romawi dapat mengalahkan Persia, karena mereka adalah Ahli Kitab. Maka orang-orang menceritakannya pada Abu Bakar, maka Abu Bakar menceritakannya pada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh nantinya mereka akan menang.\" Ibnu Abbas berkata; Lalu Abu Bakar memberitahukan kepada mereka, dan mereka berkata; \"Tentukan waktunya antara kami dan engkau; bila kami menang, maka bagi kami anu dan anu, dan bila kalian menang, maka bagi kalian anu dan anu.\" Lalu ditetapkanlah waktu lima tahun, namun mereka (bangsa Romawi) belum juga menang, akhirnya Abu Bakar menyampaikan hal itu pada Nabi Shallallahu 'alaihi Wasallam, maka beliau bersabda: \"Sebaiknya engkau tetapkan lebih dari itu.\" Ia berkata; Menurutku beliau mengatakan: \"Sepuluh tahun.\" Abdullah berkata; Sa'id bin Jubair berkata; Al Bidl'u adalah di bawah sepuluh, maka setelah itu bangsa Romawi memperoleh kemenangan. Ia melanjutkan, \"Itulah (makna) firmanNya: (Alif laam Miim. Telah dikalahkan bangsa Rumawi) hingga firmanNya (dan di hari (kemenangan bangsa Rumawi) itu bergembiralah orang-orang yang beriman). Ia berkata; \"Mereka bergembira dengan pertolongan Allah.\""},"174":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ رَجُلٍ قَالَقَالَ لَهَا ابْنُ عَبَّاسٍ إِنَّمَا سُمِّيتِ أُمَّ الْمُؤْمِنِينَ لِتَسْعَدِي وَإِنَّهُ لَاسْمُكِ قَبْلَ أَنْ تُولَدِي","id":"Telah menceritakan kepada kami [Sufyan] dari [Laits] dari [Seorang laki-laki] berkata; [Ibnu Abbas] mengatakan kepada Aisyah; \"Sesungguhnya engkau disebut ummul mukminin adalah agar engkau bahagia, karena sesungguhnya itu bukanlah namamu sebelum engkau dilahirkan.\""},"175":{"ar":"حَدَّثَنِي مُعَاوِيَةُ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ هِشَامٍ عَنْ قَيْسِ بْنِ سَعْدٍ حَدَّثَنِي عَطَاءٌ أَنَّ ابْنَ عَبَّاسٍ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ","id":"Telah menceritakan kepadaku [Mu'awiyah] berkata; Telah menceritakan kepada kami [Za`idah] dari [Hisyam] dari [Qais bin Sa'd] telah menceritakan kepadaku ['Atho`] bahwa [Ibnu Abbas] menceritakan kepadanya; bahwa Rasulullah shallallahu 'alaihi wasallam apabila mengangkat kepalanya dari ruku' mengatakan: \"ALLAHUMMA RABBANA LAKA AL HAMDU MIL`AS SAMAWATI WA MIL`AL ARDLI WA MIL`A MA SYI`TA MIN SYAI`IN BA'DU\" (Wahai Tuhan kami, milikMu segala puji sepenuh langit dan sepenuh bumi serta sepenuh apa pun setelah itu yang Engkau kehendaki).\""},"176":{"ar":"حَدَّثَنَا مُعَاوِيَةُ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ أَبِي حَفْصَةَ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ قَالَكَانَ الْفَتْحُ فِي ثَلَاثَ عَشْرَةَ خَلَتْ مِنْ رَمَضَانَ","id":"Telah menceritakan kepada kami [Mu'awiyah] telah menceritakan kepada kami [Abu Ishaq] dari [Muhammad bin Abu Hafshah] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas], ia berkata; \"Penaklukan kota Makkah terjadi pada hari ketiga belas Ramadlan.\""},"177":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنِ ابْنِ عَوْنٍ عَنْ مُجَاهِدٍ قَالَ كُنَّا عِنْدَ ابْنِ عَبَّاسٍ فَذَكَرُوا الدَّجَّالَ فَقَالُوا إِنَّهُ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ ك ف ر قَالَ مَا تَقُولُونَ قَالَ يَقُولُونَ مَكْتُوبٌ بَيْنَ عَيْنَيْهِ ك ف ر قَالَ فَقَالَ ابْنُ عَبَّاسٍ لَمْ أَسْمَعْهُ قَالَ ذَلِكَ وَلَكِنْ قَالَأَمَّا إِبْرَاهِيمُ عَلَيْهِ السَّلَام فَانْظُرُوا إِلَى صَاحِبِكُمْ وَأَمَّا مُوسَى عَلَيْهِ السَّلَام فَرَجُلٌ آدَمُ جَعْدٌ عَلَى جَمَلٍ أَحْمَرَ مَخْطُومٍ بِخُلْبَةٍ كَأَنِّي أَنْظُرُ إِلَيْهِ إِذَا انْحَدَرَ فِي الْوَادِي يُلَبِّي","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Ibnu 'Aun] dari [Mujahid], ia berkata; Kami pernah bersama [Ibnu Abbas], lalu mereka menyebutkan tentang Dajjal, mereka berkata; \"Sesungguhnya di antara kedua matanya tertulis Kaaf Faa' Raa'.\" Dia berkata; \"Apa yang kalian katakan?\" Mujahid berkata; \"Mereka mengatakan bahwa di antara kedua matanya tertulis Kaaf faa' Raa'.\" Mujahid berkata; Maka Ibnu Abbas berkata; \"Aku tidak pernah mendengar beliau mengatakan itu, tetapi beliau mengatakan: \"Adapun Ibrahim 'Alaihis Salam, maka lihatlah pada teman kalian, sedangkan Musa 'Alaihis Salam, ia adalah seorang laki-laki (berkulit) kecoklatan dan bertubuh kekar yang sedang (menunggang) unta merah yang kendalinya terbuat dari sabut kurma, seolah-olah aku melihat kepadanya ketika menuruni lembah sambil bertalbiyah.\""},"178":{"ar":"حَدَّثَنَا إِسْحَاقُ هُوَ الْأَزْرَقُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَنْبَغِي لَهُ أَنْ يَتَمَثَّلَ بِمَثَلِي","id":"Telah menceritakan kepada kami [Ishaq] ia adalah Al Azraq telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang melihatku dalam mimpi maka sungguh ia telah melihatku, karena setan tidak dapat merubah diri seperti diriku.\""},"179":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ خُصَيْفٍ حَدَّثَنَا أَبُو عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فَقَامُوا صَفَّيْنِ فَقَامَ صَفٌّ خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفٌّ مُسْتَقْبِلَ الْعَدُوِّ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّفِّ الَّذِينَ يَلُونَهُ رَكْعَةً ثُمَّ قَامُوا فَذَهَبُوا فَقَامُوا مَقَامَ أُولَئِكَ مُسْتَقْبِلَ الْعَدُوِّ وَجَاءَ أُولَئِكَ فَقَامُوا مَقَامَهُمْ فَصَلَّى بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً ثُمَّ سَلَّمَ ثُمَّ قَامُوا فَصَلَّوْا لِأَنْفُسِهِمْ رَكْعَةً ثُمَّ سَلَّمُوا ثُمَّ ذَهَبُوا فَقَامُوا مَقَامَ أُولَئِكَ مُسْتَقْبِلَ الْعَدُوِّ وَرَجَعَ أُولَئِكَ إِلَى مَقَامِهِمْ فَصَلَّوْا لِأَنْفُسِهِمْ رَكْعَةً ثُمَّ سَلَّمُوا","id":"Telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Khushaif] telah menceritakan kepada kami [Abu Ubaidah] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam shalat bersama kami dalam shalat Khauf, lalu mereka pun berdiri membentuk dua shaf, satu shaf berdiri di belakang Nabi shallallahu 'alaihi wasallam sementara shaf yang lain berada menghadap musuh. Lalu Rasulullah shallallahu 'alaihi wasallam shalat dengan shaf yang setelahnya satu rakaat, kemudian mereka bangun dan pergi menempati posisi mereka yang menghadap musuh, dan mereka pun menempati posisi mereka, maka Rasulullah shallallahu 'alaihi wasallam shalat bersama mereka satu rakaat kemudian beliau salam. Lantas mereka menyelesaikan sendiri shalatnya satu rakaat, kemudian salam dan pergi menempati posisi mereka menghadap musuh, mereka pun kembali ke tempat mereka lalu masing-masing shalat sendiri satu rakaat kemudia mereka salam."},"180":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا خُصَيْفٌ الْجَزَرِيُّ قَالَ حَدَّثَنِي أَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ قَالَعَلَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّشَهُّدَ وَأَمَرَهُ أَنْ يُعَلِّمَ النَّاسَ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Khushaif Al Jazari] ia berkata; Telah menceritakan kepadaku [Abu Ubaidah bin Abdullah] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengajarkan tasyahud kepadanya dan memerintahkan untuk mengajarkan kepada manusia, (yaitu); (ATTAHIYYATU LILLAH WASH SHALAWATU WATH THAYYIBAT, AS SALAMU'ALAIKA AYYUHAN NABIYYU WARAHMATULLAHI WABARAKATUH, AS SALAMU'ALAINA WA'ALA 'IBADILLAHISSHALIHIN, ASYHADU ALLA ILAHA ILLALAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WARASULUH) (Segala penghormatan hanya milik Allah, juga segala pengagungan dan kebaikan. Semoga kesejahteraan terlimpahkan kepadamu semoga terlimpahkan kepada kita dan hamba-hamba Allah yang shalih, Aku bersaksi bahwa tiada Ilah selain Allah dan aku bersaksi bahwa Muhammad adalah hamba dan RasulNya)."},"181":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا نُسَلِّمُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الصَّلَاةِ فَيَرُدُّ عَلَيْنَا فَلَمَّا رَجَعْنَا مِنْ عِنْدِ النَّجَاشِيِّ سَلَّمْنَا عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْنَا فَقُلْنَا يَا رَسُولَ اللَّهِ كُنَّا نُسَلِّمُ عَلَيْكَ فِي الصَّلَاةِ فَتَرُدُّ عَلَيْنَا فَقَالَ إِنَّ فِيَّ أَوْ فِي الصَّلَاةِ لَشُغْلًا","id":"Telah menceritakan kepada kami [Muhammad bin Fudlail] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; Kami memberi salam kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang shalat, lalu beliau membalasnya. Ketika kami pulang dari pertemuan dengan Najasyi, kami kembali memberi salam kepada beliau, namun beliau tidak membalasnya, maka kami bertanya; Wahai Rasulullah, dulu kami memberi salam kepada engkau ketika shalat, engkau pun membalasnya? Beliau menjawab: \"Sesungguhnya aku\" atau, \"Di dalam shalat itu sedang sibuk.\""},"182":{"ar":"حَدَّثَنَا عَمْرُو بْنُ الْهَيْثَمِ أَبُو قَطَنٍ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ سَعِيدِ بْنِ عَمْرٍو عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَتَى لَيْلَةُ الْقَدْرِ قَالَ مَنْ يَذْكُرُ مِنْكُمْ لَيْلَةَ الصَّهْبَاوَاتِ قَالَ عَبْدُ اللَّهِ أَنَا بِأَبِي أَنْتَ وَأُمِّي وَإِنَّ فِي يَدِي لَتَمَرَاتٍ أَسْتَحِرُ بِهِنَّ مُسْتَتِرًا بِمُؤْخِرَةِ رَحْلِي مِنْ الْفَجْرِ وَذَلِكَ حِينَ طَلَعَ الْقَمَرُ","id":"Telah menceritakan kepada kami [Amru bin Al Haitsam Abu Qathn] telah menceritakan kepada kami [Al Mas'udi] dari [Sa'id bin Amru] dari [Abu Ubaidah] dari [Abdullah bin Mas'ud] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam lalu berkata; Kapan terjadi lailatul qadar? Beliau bersabda: \"Siapa dari kalian yang ingat malam berwarna merah itu?\" Abdullah berkata; Aku, demi ayah dan ibuku jadi tebusanmu. Dan sesungguhnya di kedua tanganku ada beberapa kurma yang menjadikan menu sahurku sambil bersembunyi di balik bagian belakang tungganganku karena fajar tiba. Hal itu terjadi ketika bulan telah muncul."},"183":{"ar":"حَدَّثَنَا عَمْرُو بْنُ الْهَيْثَمِ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ خَمْسًا فَقِيلَ زِيدَ فِي الصَّلَاةِ قِيلَ صَلَّيْتَ خَمْسًا فَسَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Amru bin Al Haitsam] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam shalat Zhuhur sebanyak lima rakaat, lalu dikatakan; (Engkau) telah menambah dalam shalat. dikatakan; Engkau shalat lima rakaat. Lalu beliau sujud dua kali."},"184":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْكَرِيمِ قَالَ أَخْبَرَنِي زِيَادُ بْنُ أَبِي مَرْيَمَ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلِ بْنِ مُقَرِّنٍ قَالَدَخَلْتُ مَعَ أَبِي عَلَى عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فَقَالَ أَنْتَ سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ النَّدَمُ تَوْبَةٌ قَالَ نَعَمْ وَقَالَ مَرَّةً سَمِعْتُهُ يَقُولُ النَّدَمُ تَوْبَةٌ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abdul Karim] ia berkata; Telah mengabarkan kepadaku [Ziyad bin Abu Maryam] dari [Abdullah bin Ma'qil bin Muqarrin] ia berkata; Aku bersama ayahku masuk ke tempatnya [Abdullah bin Mas'ud] lalu ia berkata; Engkau telah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Penyesalan itu adalah taubat.\" Ia berkata; Ya. Dan ia berkata sekali lagi; Aku mendengar beliau bersabda: \"Penyesalan itu adalah taubat.\""},"185":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ ذَرٍّ عَنْ وَائِلِ بْنِ مَهَانَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَصَدَّقْنَ يَا مَعْشَرَ النِّسَاءِ وَلَوْ مِنْ حُلِيِّكُنَّ فَإِنَّكُنَّ أَكْثَرُ أَهْلِ النَّارِ فَقَامَتْ امْرَأَةٌ لَيْسَتْ مِنْ عِلْيَةِ النِّسَاءِ فَقَالَتْ لِمَ يَا رَسُولَ اللَّهِ قَالَ لِأَنَّكُنَّ تُكْثِرْنَ اللَّعْنَ وَتَكْفُرْنَ الْعَشِيرَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Dzarr] dari [Wa`il bin Mahanah] dari [Abdullah bin Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekahlah kalian wahai para kaum wanita. meskipun dari perhiasan kalian sebab kalian merupakan penghuni neraka yang paling banyak.\" Lalu seorang wanita yang bukan tokoh wanita bertanya; Mengapa demikian wahai Rasulullah? Beliau menjawab: \"Karena kalian banyak mencela dan tidak menghargai kebaikan suami.\""},"186":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَهُمَا بَعْدَ السَّلَامِ وَقَالَ مَرَّةً إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ السَّجْدَتَيْنِ فِي السَّهْوِ بَعْدَ السَّلَامِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] bahwa Nabi shallallahu 'alaihi wasallam sujud dua kali setelah salam. Ia berkata sekali lagi; Sesungguhnya Nabi shallallahu 'alaihi wasallam sujud dua kali setelah salam ketika lupa."},"187":{"ar":"حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ عَنْ عَاصِمِ بْنِ أَبِي النَّجُودِ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنْقَضِي الْأَيَّامُ وَلَا يَذْهَبُ الدَّهْرُ حَتَّى يَمْلِكَ الْعَرَبَ رَجُلٌ مِنْ أَهْلِ بَيْتِي اسْمُهُ يُوَاطِئُ اسْمِي","id":"Telah menceritakan kepada kami [Umar bin Ubaid] dari ['Ashim bin Abu An Najud] dari [Zirr bin Hubaisy] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah akan berakhir hari-hari dan tidak akan masa pergi hingga ada seorang laki-laki dari Ahlu Baitku menguasai bangsa Arab, namanya sama dengan namaku.\""},"188":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ سَمِعْتُ ابْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَشَارَ بِيَدِهِ نَحْوَ الْمَشْرِقِ فَقَالَ هَا إِنَّ الْفِتَنَ مِنْ هَاهُنَا إِنَّ الْفِتَنَ مِنْ هَاهُنَا إِنَّ الْفِتَنَ مِنْ هَاهُنَا مِنْ حَيْثُ يَطْلُعُ قَرْنُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Az Zubairi] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] aku mendengar [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda sambil menunjukkan tangannya ke arah timur, beliau bersabda: \"Ketahuilah, sesungguhnya fitnah akan muncul dari sini, fitnah akan muncul dari sini, fitnah akan muncul dari sini, dari tempat terbitnya tanduk setan.\""},"189":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنِ ابْنِ عُمَرَ قَالَوَقَّتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ نَجْدٍ قَرْنًا وَلِأَهْلِ الشَّأْمِ الْجُحْفَةَ وَقَالَ هَؤُلَاءِ الثَّلَاثُ حَفِظْتُهُنَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحُدِّثْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَلِأَهْلِ الْيَمَنِ يَلَمْلَمُ فَقِيلَ لَهُ الْعِرَاقُ قَالَ لَمْ يَكُنْ يَوْمَئِذٍ عِرَاقٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menentukan miqat bagi penduduk Madinah mulai dari Dzul Hulaifah, penduduk Najd dari Qarn dan penduduk Syam dari Juhfah.\" Ibnu Umar berkata, \"Ketiga miqat itu aku hafal dari Rasulullah shallallahu 'alaihi wasallam, dan aku diberitahu bahwa Rasulullah shallallahu 'alaihi wasallam mengatakan; \"Dan bagi penduduk Yaman mulai dari Yalamlam.\" Lalu ditanyakan kepadanya, \"Maksudnya Irak?\" Ia menjawab, \"Ketika itu belum Irak.\""},"190":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا مَرْثَدٌ يَعْنِي ابْنَ عَامِرٍ الْهُنَائِيَّ حَدَّثَنِي أَبُو عَمْرٍو النَّدَبِيُّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ الْخَطَّابِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ لَيَعْجَبُ مِنْ الصَّلَاةِ فِي الْجَمِيعِ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Martsad] -yakni Ibnu Amir Al Huna`i- telah menceritakan kepadaku [Abu Amru An Nadabi] telah menceritakan kepadaku [Abdullah bin Umar bin Al Khaththab] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, Allah kagum dengan shalat yang dilakukan dengan berjama'ah.\""},"191":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا أَبُو مَعْشَرٍ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِطَعَامٍ وَقَدْ حَسَّنَهُ صَاحِبُهُ فَأَدْخَلَ يَدَهُ فِيهِ فَإِذَا طَعَامٌ رَدِيءٌ فَقَالَ بِعْ هَذَا عَلَى حِدَةٍ وَهَذَا عَلَى حِدَةٍ فَمَنْ غَشَّنَا فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Khalaf bin Al Walid] telah menceritakan kepada kami [Abu Ma'syar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah melewati tumpukan makanan dan telah diperbagus oleh pemiliknya. Lalu beliau memasukkan tangannya dan ternyata ada makanan yang telah rusak. Maka beliau pun berkata, \"Juallah yang ini dengan harga tertentu dan yang ini dengan harga tertentu pula. Barangsiapa menipu kami, ia bukan golongan kami.\""},"192":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ ثَابِتِ بْنِ ثَوْبَانَ حَدَّثَنَا حَسَّانُ بْنُ عَطِيَّةَ عَنْ أَبِي مُنِيبٍ الْجُرَشِيِّ عَنِ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُعِثْتُ بَيْنَ يَدَيْ السَّاعَةِ بِالسَّيْفِ حَتَّى يُعْبَدَ اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَجُعِلَ رِزْقِي تَحْتَ ظِلِّ رُمْحِي وَجُعِلَ الذِّلَّةُ وَالصَّغَارُ عَلَى مَنْ خَالَفَ أَمْرِي وَمَنْ تَشَبَّهَ بِقَوْمٍ فَهُوَ مِنْهُمْ","id":"Telah menceritakan kepada kami [Abu An Nadlr] telah menceritakan kepada kami [Abdurrahman bin Tsabit bin Tsauban] telah menceritakan kepada kami [Hassan bin 'Athiyah] dari [Abu Munib Al Jurasyi] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diutus menjelang hari kiamat dengan pedang hingga hanya Allah yang diibadahi tanpa ada sekutu bagi-Nya, dan rizkiku ditempatkan di bawah bayang-bayang tombak. Kehinaan dan kerendahan dijadikan bagi orang yang menyelisihi perintahku. Barangsiapa menyerupai suatu kaum berarti ia termasuk golongan mereka.\""},"193":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا لَيْثٌ عَنْ مُجَاهِدٍ عَنِ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي الْبَيْتِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Laits] dari [Mujahid] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat sunnah dua rakaat di rumah.\""},"194":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنِ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَقُّ امْرِئٍ يَبِيتُ لَيْلَتَيْنِ وَلَهُ مَا يُرِيدُ أَنْ يُوصِيَ فِيهِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seseorang untuk bermalam selama dua malam sementara ia mempunyai sesuatu untuk diwasiatkan, kecuali wasiat tersebut telah tertulis di sampingnya.\""},"195":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنِ نَافِعٍ عَنِ ابْنِ عُمَرَ قَالَ أَحْسِبُهُ قَدْ رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِذَا مَاتَ أَحَدُكُمْ يُعْرَضُ عَلَيْهِ مَقْعَدُهُ غُدْوَةً وَعَشِيَّةً إِنْ كَانَ مِنْ أَهْلِ الْجَنَّةِ فَمِنْ الْجَنَّةِ وَإِنْ كَانَ مِنْ أَهْلِ النَّارِ فَمِنْ النَّارِ يُقَالُ هَذَا مَقْعَدُكَ حَتَّى تُبْعَثَ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Menurutku ia telah memarfu'kannya kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian meninggal dunia, maka akan diperlihatkan kepadanya tempat duduknya setiap pagi dan sore. Jika ia termasuk ahli surga maka akan diperlihatkan surga, dan jika ia termasuk ahli neraka maka akan diperlihatkan neraka. Dikatakan kepadanya, 'Inilah tempat dudukmu', hingga ia dibangkitkan di hari kiamat.\""},"196":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ نَافِعٍأَنَّ ابْنَ عُمَرَ اسْتُصْرِخَ عَلَى صَفِيَّةَ فَسَارَ فِي تِلْكَ اللَّيْلَةِ مَسِيرَةَ ثَلَاثِ لَيَالٍ سَارَ حَتَّى أَمْسَى فَقُلْتُ الصَّلَاةَ فَسَارَ وَلَمْ يَلْتَفِتْ فَسَارَ حَتَّى أَظْلَمَ فَقَالَ لَهُ سَالِمٌ أَوْ رَجُلٌ الصَّلَاةَ وَقَدْ أَمْسَيْتَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا عَجِلَ بِهِ السَّيْرُ جَمَعَ مَا بَيْنَ هَاتَيْنِ الصَّلَاتَيْنِ وَإِنِّي أُرِيدُ أَنْ أَجْمَعَ بَيْنَهُمَا فَسِيرُوا فَسَارَ حَتَّى غَابَ الشَّفَقُ ثُمَّ نَزَلَ فَجَمَعَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Ayyub] dari [Nafi'] bahwa [Ibnu Umar] dimintai tolong menemani Shafiyah, lalu ia berjalan pada malam itu sejauh perjalanan tiga hari, ia berjalan hingga sore hari. Aku berkata, 'Shalatlah'. Namun ia tetap berjalan dan tidak menoleh, ia masih berjalan hingga hari sudah gelap, maka Salim atau seseorang berkata kepadanya, 'Shalatlah karena hari telah sore.' Maka Ibnu Umar pun menjawab, 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam jika tergesa dalam perjalanan, beliau menjamak di antara kedua shalat ini, dan aku ingin menjamak keduanya, maka (tetap) berjalanlah kalian.' Lalu Ibnu Umar berjalan hingga terbenam matahari, kemudian singgah dan menjamak kedua shalat itu.\""},"197":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ أَنَّهُ سَمِعَ عَلِيًّا الْأَزْدِيَّ يُحَدِّثُ أَنَّهُ سَمِعَ ابْنَ عُمَرَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ صَلَاةُ اللَّيْلِ وَالنَّهَارِ مَثْنَى مَثْنَىوَكَانَ شُعْبَةُ يَفْرَقُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha] bahwa ia mendengar [Ali Al Azdi] menceritakan, bahwa ia mendengar [Ibnu Umar] menceritakan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Shalat pada malam dan siang hari itu adalah dua rakaat-dua rakaat.\" Dan Syu'bah ketika itu sedang menyisirinya.\""},"198":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْبُدُوا الرَّحْمَنَ وَأَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ وَادْخُلُوا الْجِنَانَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami ['Atho` bin As Sa`ib] dari [bapaknya], dari [Abdullah bin 'Amru], dia berkata; bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sembahlah Ar Rahman (Allah), sebarkanlah salam, berilah makan kepada orang miskin, maka engkau akan masuk surga.\""},"199":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَجُلًا قَالَ اللَّهُمَّ اغْفِرْ لِي وَلِمُحَمَّدٍ وَحْدَنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ حَجَبْتَهَا عَنْ نَاسٍ كَثِيرٍ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Atho` bin As Sa`ib] dari [bapaknya] dari [Abdullah bin 'Amru], dia berkata; bahwa ada seorang lelaki berdoa: \"Ya Allah, ampunilah aku dan Muhammad saja.\" Maka Rasulullah Shallallahu 'alaihi wa Salam pun bersabda: \"sungguh engkau telah menghalangi doa tersebut untuk orang banyak\""},"200":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ مُحَمَّدِ بْنِ زِيَادٍ الْأَلْهَانِيِّ عَنْ أَبِي رَاشِدٍ الْحُبْرَانِيِّ قَالَأَتَيْتُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ فَقُلْتُ لَهُ حَدِّثْنَا مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَلْقَى بَيْنَ يَدَيَّ صَحِيفَةً فَقَالَ هَذَا مَا كَتَبَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرْتُ فِيهَا فَإِذَا فِيهَا أَنَّ أَبَا بَكْرٍ الصِّدِّيقَ قَالَ يَا رَسُولَ اللَّهِ عَلِّمْنِي مَا أَقُولُ إِذَا أَصْبَحْتُ وَإِذَا أَمْسَيْتُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا بَكْرٍ قُلْ اللَّهُمَّ فَاطِرَ السَّمَوَاتِ وَالْأَرْضِ عَالِمَ الْغَيْبِ وَالشَّهَادَةِ لَا إِلَهَ إِلَّا أَنْتَ رَبَّ كُلِّ شَيْءٍ وَمَلِيكَهُ أَعُوذُ بِكَ مِنْ شَرِّ نَفْسِي وَمِنْ شَرِّ الشَّيْطَانِ وَشِرْكِهِ وَأَنْ أَقْتَرِفَ عَلَى نَفْسِي سُوءًا أَوْ أَجُرَّهُ إِلَى مُسْلِمٍ","id":"Telah menceritakan kepada kami [Khalaf bin Walid] telah menceritakan kepada kami [Ibnu 'Ayyasy] dari [Muhammad bin Ziyad Al Alhani] dari [Abu Rasyid Al Hubrani] dia berkata; aku mendatangi [Abdullah bin 'Amru bin Al 'Ash], aku katakan kepadanya: \"ceritakan kepada kami apa yang telah engkau dengar dari Rasul Shallallahu 'alaihi wa Salam.\" Maka dia menyodorkan ke tanganku sebuah lembaran shahifah seraya berkata: \"Ini yang dituliskan Rasulullah Shallallahu 'alaihi wa Salam untukku.\" Maka akupun melihat lembaran shahifah tersebut, dan aku dapatkan dalam lembaran tersebut bahwa Abu Bakar Ash Shidiq pernah bertanya kepada beliau: \"Wahai Rasulullah, ajarilah aku, apa yang harus aku ucapkan ketika berada pada waktu pagi dan sore hari?\" Maka Rasulullah Shallallahu 'alaihi wa Salam pun menjawab: \"wahai Abu Bakar, ucapkalah: ALLAHUMMA FAATHIROS SAMAAWAATI WAL ARDLI, `AALIMAL GHAIBI WASY SYAHAADAH, LAA ILLAHA ILLA ANTA, RABBA KULLI SYAI` WA MALIIKAHU, A`UUDZU BIKA MIN SYARRI NAFSII WA MIN SYARRI ASY SYAITHAANI WA SYIRKIHI, WA AN AQTARIFA `ALAA NAFSII SUU`AN AU AJURROHU ILA MUSLIM (Ya Allah, Tuhan pencipta langit dan bumi, Tuhan yang mengetahui yang Ghaib dan yang nyata, tiada tuhan yang berhak untuk disembah kecuali Engkau, Tuhan yang menguasai segala sesuatu dan merajainya, aku berlindung kepada-Mu dari kejahatan diriku, kejahan setan dan bala tentaranya, atau aku berbuat kejelekkan pada diriku atau aku mendorongnya pada seorang muslim).\""},"201":{"ar":"حَدَّثَنَا أَبُو مُغِيرَةَ حَدَّثَنَا هِشَامُ بْنُ الْغَازِ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَهَبَطْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ثَنِيَّةِ أَذَاخِرَ قَالَ فَنَظَرَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا عَلَيَّ رَيْطَةٌ مُضَرَّجَةٌ بِعُصْفُرٍ فَقَالَ مَا هَذِهِ فَعَرَفْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَرِهَهَا فَأَتَيْتُ أَهْلِي وَهُمْ يَسْجُرُونَ تَنُّورَهُمْ فَلَفَفْتُهَا ثُمَّ أَلْقَيْتُهَا فِيهِ ثُمَّ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا فَعَلَتْ الرَّيْطَةُ قَالَ قُلْتُ قَدْ عَرَفْتُ مَا كَرِهْتَ مِنْهَا فَأَتَيْتُ أَهْلِي وَهُمْ يَسْجُرُونَ تَنُّورَهُمْ فَأَلْقَيْتُهَا فِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا كَسَوْتَهَا بَعْضَ أَهْلِكَ وَذَكَرَ أَنَّهُ حِينَ هَبَطَ بِهِمْ مِنْ ثَنِيَّةِ أَذَاخِرَ صَلَّى بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى جَدْرٍ اتَّخَذَهُ قِبْلَةً فَأَقْبَلَتْ بَهْمَةٌ تَمُرُّ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا زَالَ يُدَارِئُهَا وَيَدْنُو مِنْ الْجَدْرِ حَتَّى نَظَرْتُ إِلَى بَطْنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ لَصِقَ بِالْجِدَارِ وَمَرَّتْ مِنْ خَلْفِهِ","id":"Telah menceritakan kepada kami [Abu Mughirah] telah menceritakan kepada kami [Hisyam bin Al Ghoz] telah menceritakan kepadaku ['Amru bin Syu'aib] dari [bapaknya] dari [kakeknya], dia berkata; \"kami bersama Rasulullah Shallallahu 'alaihi wa Salam turun dari suatu tempat yang bernama Tsaniyah Adzakhir.\" Dia berkata; \"maka beliau melihat ke arahku, sedang aku waktu itu menggunakan kain tipis nan lembut yang sudah dicelup dengan warna kuning. Maka beliau pun berkata: \"apa-apaan ini\"! aku tahu sesungguhnya Rasulullah shallallahu 'alaihi wasallam marah dan tidak suka. Lalu aku pulang dan menemui keluargaku, waktu itu mereka sedang menghidupkan tungku masak, maka akupun segera melepas kainku dan aku lemparkan ke dalam tungku masak tersebut. Kemudian aku kembali menemui Rasulullah Shallallahu 'alaihi wa Salam. Beliau bertanya: \"Apa yang terjadi dengan kain itu?\" dia berkata; aku berkata; \"aku tahu bahwa engkau tidak suka dengan kain tersebut, maka aku pun pulang ke rumahku menemui mereka, dan aku dapati mereka sedang menyalakan tungku masak sehingga aku masukkan kain tersebut ke dalam tungku.\" Maka beliau pun bersabda: \"kenapa tidak kamu pakaikan saja untuk sebagian keluargamu.\" Dan dia menyebutkan bahwa ketika turun dari Tsaniyah Adzakhir, Rasulullah shalat bersama dengan mereka dan menghadap ke arah tembok yang dijadikan sebagai kiblat. Lalu muncullah seekor anak kambing lewat di hadapan Rasulullah Shallallahu 'alaihi wa Salam, maka Nabi pun berusaha mencegah anak kambing tersebut sambil terus mendekat ke arah tembok. Sehingga aku lihat perut Nabi menempel tembok dan anak kambing itu lewat di belakang beliau.\""},"202":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ سَمِعْتُ أَبَا كَبْشَةَ السَّلُولِيَّ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعُونَ حَسَنَةً أَعْلَاهَا مِنْحَةُ الْعَنْزِ مَا مِنْهَا حَسَنَةٌ يَعْمَلُ بِهَا عَبْدٌ رَجَاءَ ثَوَابِهَا وَتَصْدِيقَ مَوْعُودِهَا إِلَّا أَدْخَلَهُ اللَّهُ بِهَا الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Hassan bin 'Athiyyah] dia berkata; aku mendengar [Abu Kabsyah As Saluli] berkata; aku mendengar [Abdullah bin 'Amru bin Al 'Ash] berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Ada empat puluh cabang kebaikkan, yang paling baik dari semuanya adalah Manihatul 'Anz (binatang ternak yang dipinjamkan untuk diambil susunya), tidaklah seorang hamba beramal dari salah satu cabang kebaikkan tersebut dengan hanya mengharapkan pahala dan janji Allah, kecuali Allah akan memasukkannya ke surga\""},"203":{"ar":"قَالَوَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ خَلَقَ خَلْقَهُ ثُمَّ جَعَلَهُمْ فِي ظُلْمَةٍ ثُمَّ أَخَذَ مِنْ نُورِهِ مَا شَاءَ فَأَلْقَاهُ عَلَيْهِمْ فَأَصَابَ النُّورُ مَنْ شَاءَ أَنْ يُصِيبَهُ وَأَخْطَأَ مَنْ شَاءَ فَمَنْ أَصَابَهُ النُّورُ يَوْمَئِذٍ فَقَدْ اهْتَدَى وَمَنْ أَخْطَأَ يَوْمَئِذٍ ضَلَّ فَلِذَلِكَ قُلْتُ جَفَّ الْقَلَمُ بِمَا هُوَ كَائِنٌ","id":"(Masih dari jalur yang sama dengan hadits sebelumnya), dia ([Abdullah bin 'Amru]) berkata; aku mendengar Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"sesungguhnya Allah menciptakan makhluq-Nya kemudian dijadikanlah mereka dalam kondisi kegelapan, lalu Dia mengambil cahaya-Nya dengan sekehendak-Nya kemudian dilemparkan kepada mereka, cahaya itu akan mengenai bagi yang dikehendaki-Nya, dan tidak akan mengenai bagi yang tidak dikehendaki-Nya. Bagi yang mendapatkan cahaya pada hari itu ia akan mendapatkan petunjuk, dan bagi yang tidak mendapatkan cahaya pada hari itu ia akan tersesat. Maka itu yang aku katakan bahwa pena Allah telah kering dengan apa yang telah ditentukan.\""},"204":{"ar":"و حَدَّثَنَا عَلِيُّ بْنُ أَبِي إِسْحَاقَ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ جُنَادَةَ الْمَعَافِرِيُّ أَنَّ أَبَا عَبْدِ الرَّحْمَنِ الْحُبُلِيَّ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو حَدَّثَهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الدُّنْيَا سِجْنُ الْمُؤْمِنِ وَسَنَتُهُ فَإِذَا فَارَقَ الدُّنْيَا فَارَقَ السِّجْنَ وَالسَّنَةَ","id":"Telah menceritakan kepada kami [Ali bin Abu Ishaq] telah menceritakan kepada kami [Abdullah] telah mengkhabarkan kepada kami [Yahya bin Ayub] telah mengkhabarkan kepadaku [Abdullah bin junadah Al Ma'arifi] dia berkata; bahwa [Abu Abdurrahman Al Hubuli] telah menceritakan kepadanya dari [Abdullah bin 'Amru] bahwa dia telah menceritakan kepadanya dari Nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Dunia adalah penjara orang mukmin, maka apabila dia berpisah dengan dunia (meninggal dunia) berarti ia telah berpisah dengan penjaranya.\" "},"205":{"ar":"حَدَّثَنَا عَفَّانُ وَبَهْزٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَ سَمِعْتُ أَبَا الْعَبَّاسِ وَكَانَ رَجُلًا شَاعِرًا سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَهُ فِي الْجِهَادِ فَقَالَ أَحَيٌّ وَالِدَاكَ قَالَ نَعَمْ قَالَ فَفِيهِمَا فَجَاهِدْقَالَ بَهْزٌ أَخْبَرَنِي ابْنُ أَبِي ثَابِتٍ عَنْ أَبِي الْعَبَّاسِ قَالَ سَأَلْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو","id":"Telah menceritakan kepada kami ['Affan] dan [Bahz] mereka berkata: telah menceritakan kepada kami [Syu'bah] dari [Habib bin Abu Tsabit] dia berkata; aku mendengar [Abul Abbas] -dia adalah seorang lelaki yang pandai bersya'ir- berkata; aku mendengar [Abdullah bin 'Amru] berkata; seorang lelaki datang kepada Rasulullah Shallallahu 'alaihi wa Salam meminta izin kepadanya untuk pergi berjihad. Maka beliau bertanya: \"Apakah kedua orang tuamu masih hidup?\" \"Masih\" jawabnya. Beliau bersabda: \"Kepada keduanya hendaknya kamu berjihad.\" [Bahz] berkata: telah menceritakan kepada kami [Ibnu Abu Tsabit] dari [Abul Abbas] dia berkata: \"aku bertanya [Abdullah bin 'Amru].\""},"206":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي يَعْلَى بْنُ عَطَاءٍ عَنْ أَبِيهِ قَالَ أَظُنُّهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ شُعْبَةُ شَكَّقَامَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَأْذِنُهُ فِي الْجِهَادِ فَقَالَ فَهَلْ لَكَ وَالِدَانِ قَالَ نَعَمْ قَالَ أُمِّي قَالَ انْطَلِقْ فَبِرَّهَا قَالَ فَانْطَلَقَ يَتَخَلَّلُ الرِّكَابَ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] telah mengkhabarkan kepadaku [Ya'la bin Atho`] dari [bapaknya], dia berkata; aku mengira bahwa hadits itu berasal dari [Abdullah bin 'Amru], dia berkata; -Syu'bah masih meragukan- Seorang laki-laki berdiri kepada Rasulullah Shallallahu 'alaihi wa Salam dan meminta izin kepadanya untuk pergi jihad. Maka beliau bersabda: \"Apakah engkau masih mempunyai kedua orang tua?\" Dia berkata; \"Ya, ibuku\" Beliau bersabda: \"Pergi dan berbuat baiklah kepada ibumu.\" Dia berkata; maka lelaki itu pun pergi di antara orang-orang."},"207":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ ثَابِتٍ حَدَّثَنَا رَجُلٌ مِنْ الشَّامِ وَكَانَ يَتْبَعُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ وَيَسْمَعُ قَالَكُنْتُ مَعَهُ فَلَقِيَ نَوْفًا فَقَالَ نَوْفٌ ذُكِرَ لَنَا أَنَّ اللَّهَ تَعَالَى قَالَ لِمَلَائِكَتِهِ ادْعُوا لِي عِبَادِي قَالُوا يَا رَبِّ كَيْفَ وَالسَّمَوَاتُ السَّبْعُ دُونَهُمْ وَالْعَرْشُ فَوْقَ ذَلِكَ قَالَ إِنَّهُمْ إِذَا قَالُوا لَا إِلَهَ إِلَّا اللَّهُ اسْتَجَابُوا قَالَ يَقُولُ لَهُ عَبْدُ اللَّهِ بْنُ عَمْرٍو صَلَّيْ��َا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْمَغْرِبِ أَوْ غَيْرَهَا قَالَ فَجَلَسَ قَوْمٌ أَنَا فِيهِمْ يَنْتَظِرُونَ الصَّلَاةَ الْأُخْرَى قَالَ فَأَقْبَلَ إِلَيْنَا يُسْرِعُ الْمَشْيَ كَأَنِّي أَنْظُرُ إِلَى رَفْعِهِ إِزَارَهُ لِيَكُونَ أَحَثَّ لَهُ فِي الْمَشْيِ فَانْتَهَى إِلَيْنَا فَقَالَ أَلَا أَبْشِرُوا هَذَاكَ رَبُّكُمْ أَمَرَ بِبَابِ السَّمَاءِ الْوُسْطَى أَوْ قَالَ بِبَابِ السَّمَاءِ فَفُتِحَ فَفَاخَرَ بِكُمْ الْمَلَائِكَةَ قَالَ انْظُرُوا إِلَى عِبَادِي أَدَّوْا حَقًّا مِنْ حَقِّي ثُمَّ هُمْ يَنْتَظِرُونَ أَدَاءَ حَقٍّ آخَرَ يُؤَدُّونَهُ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Sulaiman] -yaitu Ibnul Mughirah- dari [Tsabit] telah menceritakan kepada kami [seorang laki-laki] dari Syam, dia adalah seorang yang selalu mengikuti dan mendengar Abdullah bin 'Amru bin Al 'Ash, ia berkata; aku sedang bersama Abdullah bin 'Amru, lalu dia bertemu dengan Nauf, maka Nauf pun berkata: telah disebutkan kepadaku bahwa Allah Ta`ala berfirman kepada para Malaikat-Nya: \"Panggilkanlah hamba-hamba-Ku.\" Mereka menjawab: \"Wahai Rabb, bagaimana mungkin, langit yang tujuh lapis ada di atas mereka, dan Arsy ada di atasnya lagi?\" Allah menjawab: \"Sesungguhnya jika mereka mengucapkan LAA ILAAHA ILLAH maka doa mereka akan dikabulkan.\" (Lelaki dari Syam) berkata: [Abdullah bin 'Amru] berkata kepada Nauf; \"kami shalat maghrib bersama Rasulullah Shallallahu 'alaihi wa Salam atau shalat selainnya, maka orang-orang duduk sedang aku juga di antara mereka sedang menunggu shalat yang lain, kemudian beliau membalikkan badannya dan berjalan dengan cepat, seakan-akan aku melihat sarungnya diangkat lebih tinggi agar bisa berjalan dengan cepat, lalu beliau berhenti di hadapan kami dan bersabda: \"maukah kalian aku beri kabar gembira, Rabb kalian memerintahkan pintu langit yang tengah, \" atau beliau berkata: \"pintu langit agar dibuka. Kemudian Dia membangga-banggakan kalian di hadapan para malaikat-Nya. Dia berkata; \"Lihatlah hamba-hamba Ku, mereka melaksanakan hak kewajiban dari-Ku, kemudian mereka juga sedang menunggu untuk mengerjakan hak untuk-Ku yang lainnya.\""},"208":{"ar":"حَدَّثَنَا عَمْرُو بْنُ الْهَيْثَمِ أَبُو قَطَنٍ وَأَبُو النَّضْرِ قَالَا حَدَّثَنَا الْمَسْعُودِيُّ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدُ الْمُعْطِي الْعُلْيَا أُمَّكَ وَأَبَاكَ وَأُخْتَكَ وَأَخَاكَ ثُمَّ أَدْنَاكَ أَدْنَاكَ وَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ هَؤُلَاءِ بَنُو يَرْبُوعٍ قَتَلَةُ فُلَانٍ قَالَ أَلَا لَا تَجْنِي نَفْسٌ عَلَى أُخْرَى و قَالَ أَبِي قَالَ أَبُو النَّضْرِ فِي حَدِيثِهِ دَخَلْتُ الْمَسْجِدَ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ وَيَقُولُ يَدُ الْمُعْطِي الْعُلْيَا","id":"Telah menceritakan kepada kami ['Amru bin Al Haitsam Abu Qaththan] dan [Abu An Nadlr] mereka berkata; telah menceritakan kepada kami [Al Mas'udi] dari [Iyad bin laqith] dari [Abu Rimtsah] dari Nabi Shallallahu 'alaihi wa Salam beliau bersabda: \"Yang paling berhak memberi adalah ibumu, bapakmu, saudara perempuanmu, dan saudara lelakimu, kemudian orang yang ada di bawahmu kebawah.\" Seorang laki-laki berkata; \" Wahai Rasulullah, mereka itu adalah Bani Yarbu` orang yang telah membunuh si Fulan.\" Beliau berkata: \"Ketahuilah, janganlah seseorang membuat kecelakaan bagi orang lain.\" Bapakku berkata; Abu An Nadlr berkata dalam haditsnya; aku masuk ke dalam masjid ketika itu Rasulullah Shallallahu 'alaihi wa Salam sedang berkhutbah, beliau berkata; \"orang yang paling berhak memberi\""},"209":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ حَدَّثَنَا إِيَادُ بْنُ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ نَاسٌ مِنْ رَبِيعَةَ يَخْتَصِمُونَ فِي دَمٍ فَقَالَ الْيَدُ الْعُلْيَا أُمُّكَ وَأَبُوكَ وَأُخْتُكَ وَأَخُوكَ وَأَدْنَاكَ أَدْنَاكَ قَالَ فَنَظَرَ فَقَالَ مَنْ هَذَا مَعَكَ أَبَا رِمْثَةَ قَالَ قُلْتُ ابْنِي قَالَ أَمَا إِنَّهُ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِوَذَكَرَ قِصَّةَ الْخَاتَمِ","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Salamah- dari [Abdul Malik bin Umair], dia berkata; telah menceritakan kepada kami [Iyad bin laqith] dari [Abu Rimtsah], dia berkata: aku mendatangi Nabi Shallallahu 'alaihi wa Salam sedang di sisi beliau orang-orang dari suku Rabi'ah, mereka memperdebatkan tentang dam (denda), maka beliau bersabda: \"Yang paling berhak memberi adalah ibumu, bapakmu, saudara perempuanmu, saudara lelakimu, dan orang yang ada di bawahmu kebawah.\" Kemudian beliau melihat lalu bersabda, \"Siapa orang yang bersama kamu ini?\" Dia berkata; aku menjawab: \"Ini anakku.\" Beliau bersabda: \"Adapun dia tidak akan berbuat jahat kepadamu dan kamu tidak akan berbuat jahat kepadanya.\" Kemudian disebutlah hadits tersebut diatas."},"210":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ إِيَادِ بْنِ لَقِيطٍ السَّدُوسِيِّ قَالَ سَمِعْتُ أَبَا رِمْثَةَ التَّيْمِيَّ قَالَجِئْتُ مَعَ أَبِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ابْنُكَ هَذَا قُلْتُ نَعَمْ قَالَ أَتُحِبُّهُ قُلْتُ نَعَمْ قَالَ أَمَا إِنَّهُ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Iyad bin laqith As Sadusi], dia berkata: Aku mendengar [Abu Rimtsah At Taimi] berkata: Aku datang bersama dengan bapakku kepada Nabi Shallallahu 'alaihi wa Salam, maka beliau bersabda: \"Apakah ini anakmu?\" 'Iya\" jawabku. Beliau bersabda: \"Apakah engkau menyayanginya?\" \"Iya\" jawabku. Beliau bersabda: \"Adapun dia (anak tersebut) tidak akan berbuat jahat kepadamu dan kamu tidak akan berbuat jahat kepadanya.\""},"211":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ وَعَفَّانُ قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادٍ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَقَالَ انْطَلَقْتُ مَعَ أَبِي نَحْوَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَيْتُهُ قَالَ لِي أَبِي هَلْ تَدْرِي مَنْ هَذَا قُلْتُ لَا فَقَالَ لِي أَبِي هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاقْشَعْرَرْتُ حِينَ قَالَ ذَاكَ وَكُنْتُ أَظُنُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَا يُشْبِهُ النَّاسَ فَإِذَا بَشَرٌ لَهُ وَفْرَةٌ قَالَ عَفَّانُ فِي حَدِيثِهِ ذُو وَفْرَةٍ وَبِهَا رَدْعٌ مِنْ حِنَّاءٍ عَلَيْهِ ثَوْبَانِ أَخْضَرَانِ فَسَلَّمَ عَلَيْهِ أَبِي ثُمَّ جَلَسْنَا فَتَحَدَّثْنَا سَاعَةً ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي ابْنُكَ هَذَا قَالَ إِي وَرَبِّ الْكَعْبَةِ قَالَ حَقًّا قَالَ أَشْهَدُ بِهِ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا مِنْ ثَبْتِ شَبَهِي بِأَبِي وَمِنْ حَلِفِ أَبِي عَلَيَّ ثُمَّ قَالَ أَمَا إِنَّهُ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ قَالَ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ ثُمَّ نَظَرَ إِلَى مِثْلِ السِّلْعَةِ بَيْنَ كَتِفَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَأَطَبُّ الرِّجَالِ أَلَا أُعَالِجُهَا لَكَ قَالَ لَا طَبِيبُهَا الَّذِي خَلَقَهَا","id":"Telah menceritakan kepada kami [Hisyam bin Abdul Malik] dan ['Affan] mereka berkata; telah menceritakan kepada kami [Ubaidullah bin Iyadl] telah menceritakan kepada kami [Iyadl] dari [Abu Rimtsah], dia berkata: aku bersama bapakku bertolak menuju Rasulullah Shallallahu 'alaihi wa Salam, maka ketika aku melihatnya, bapakku berkata kepadaku; \"Tahukah engkau siapa orang ini?\"Tidak\" jawabku. Bapakku berkata: \"Dia adalah Muhammad Rasulullah Shallallahu 'alaihi wa Salam.\" Dia berkata; \"maka aku pun bergetar ketika bapakku mengatakan begitu, aku mengira bahwa Rasulullah Shallallahu 'alaihi wa Salam adalah seorang laki-laki yang tidak sama dengan kebanyakkan manusia, ternyata dia adalah seorang laki-laki yang rambutnya menyentuh daun telinganya.\" Affan berkata di dalam haditsnya; \"Mempunyai rambut yang menyentuh daun telinga, rambutnya ada inai, dan mengenakan dua lembar selendang berwarna biru. Kemudian bapakku mengucapkan salam kepadanya, kemudian kamu duduk dan berbicang-bincang selama satu jam. Lalu Rasulullah Shallallahu 'alaihi wa Salam berkata kepada bapakku: \"Apakah ini anakmu? ' Dia menjawab, \"Ya, demi Rabbul Ka'bah.\" Dia berkata; \"Ini benar.\" Lalu berkata lagi, \"Aku berani bersaksi atasnya.\" Maka tersenyumlah Rasulullah Shallallahu 'alaihi wa Salam kepada bapakku yang menguatkan kemiripanku dengannya dan juga karena sumpahnya kepada Allah atas diriku. Kemudian beliau bersabda: \"Adapun dia, sungguh tidak akan berbuat jahat kepadamu dan kamu tidak akan berbuat jahat padanya.\" Lalu beliau membaca ayat: \"dan seorang yang berdosa tidak akan memikul dosa orang lain.\" Kemudian bapakku melihat semisal luka yang ada pada pundak Rasulullah Shallallahu 'alaihi wa Salam, dan berkata; \"wahai Rasulullah, sesungguhnya aku adalah orang yang paling paham tentang kedokteran di antara orang-orang, maka bolehkan aku mengobati lukamu?\" \"Tidak, dokternya adalah yang telah menciptakannya (Allah).\" Jawab beliau. "},"212":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنِ ابْنِ أَبْجَرَ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ مَعَ أَبِي وَأَنَا غُلَامٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ لَهُ أَبِي إِنِّي رَجُلٌ طَبِيبٌ فَأَرِنِي هَذِهِ السِّلْعَةَ الَّتِي بِظَهْرِكَ قَالَ وَمَا تَصْنَعُ بِهَا قَالَ أَقْطَعُهَا قَالَ لَسْتَ بِطَبِيبٍ وَلَكِنَّكَ رَفِيقٌ طَبِيبُهَا الَّذِي وَضَعَهَا وَقَالَ غَيْرُهُ الَّذِي خَلَقَهَا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Bakr bin Abi Syaibah] telah menceritakan kepada kami [Husain bin Ali] dari [Ibnu Abjar] dari [Iyad bin Laqith] dari [Abu Rimtsah], dia berkata: aku bersama dengan ayahku pergi kepada Rasulullah Shallallahu 'alaihi wa Salam sedang aku masih seorang bocah. Dia berkata; maka ayahku berkata kepada Rasulullah Shallallahu 'alaihi wa Salam; \"sesungguhnya aku adalah seorang laki-laki yang paham ilmu kedokteran, maka perlihatkanlah kepadaku luka yang ada di punggungmu.\" Beliau bersabda: \"Apa yang akan kamu lakukan?\" \"Aku akan membelahnya.\" Jawabnya. Beliau bersabda: \"Sesungguhnya engkau bukan seorang dokter, engkau hanya bisa membantu memberinkan manfaat, dokternya adalah Dzat yang telah menjadikannya terluka.\" Yang lain berkata: \"yang menciptakannya.\""},"213":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ عَلِيِّ بْنِ صَالِحٍ حَدَّثَنِي إِيَادُ بْنُ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَحَجَجْتُ فَرَأَيْتُ رَجُلًا جَالِسًا فِي ظِلِّ الْكَعْبَةِ فَقَالَ أَبِي تَدْرِي مَنْ هَذَا هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا انْتَهَيْنَا إِلَيْهِ إِذَا رَجُلٌ ذُو وَفْرَةٍ بِهِ رَدْعٌ وَعَلَيْهِ ثَوْبَانِ أَخْضَرَانِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Abu Bakr bin Abi Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Ali bin Shalih] telah menceritakan kepadaku [Iyad bin Laqith] dari [Abi Rimtsah], dia berkata; \"aku pernah melakukan ibadah haji dan aku lihat seorang laki-laki duduk di bawah bayang-bayang Ka'bah, lalu bapakku berkata; 'Tahukah kamu siapa orang ini, ini adalah Rasulullah Shallallahu 'alaihi wa Salam.' Maka ketika kami sampai dihadapannya, aku lihat bahwa dia adalah seorang laki-laki yang mempunyai rambut yang menyentuh daun telinga, berbau harum, dan mengenakan dua selendang berwana biru.\""},"214":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدِ بْنِ بُكَيْرٍ النَّاقِدُ حَدَّثَنَا هُشَيْمٌ غَيْرَ مَرَّةٍ قَالَ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِي رِمْثَةَ التَّيْمِيِّأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي ابْنٌ لِي فَقَالَ ابْنُكَ هَذَا قُلْتُ أَشْهَدُ بِهِ قَالَ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ قَالَ وَرَأَيْتُ الشَّيْبَ أَحْمَرَ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Amru bin Muhammad bin Bukair An Naqid] telah menceritakan kepada kami [Husyaim] telah mengkabarkan kepadaku [Abdul Malik bin Umair] dari [Iyad bin Laqith] dari [Abu Rimtsah At Taimi], dia berkata; aku datang kepada Nabi Shallallahu 'alaihi wa Salam sedang aku bersama dengan anakku, maka beliaupun berkata; \"Apakah ini putramu?\" Aku menjawab: \"Aku bersaksi dengannya.\" Beliau berkata; \"Dia tidak akan berbuat jahat kepadamu dan kamu tidak akan berbuat jahat kepadanya.\" Dia berkata; \"dan aku melihat uban (beliau) berwarna merah.\""},"215":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي شَيْبَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ إِبْرَاهِيمَ التُّسْتَرِيُّ حَدَّثَنَا صَدَقَةُ بْنُ أَبِي عِمْرَانَ عَنْ رَجُلٍ هُوَ ثَابِتُ بْنُ مُنْقِذٍ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ أَنَا وَأَبِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا كُنَّا فِي بَعْضِ الطَّرِيقِ فَلَقِينَاهُ فَقَالَ لِي أَبِي يَا بُنَيَّ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَكُنْتُ أَحْسَبُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُشْبِهُ النَّاسَ فَإِذَا رَجُلٌ لَهُ وَفْرَةٌ بِهَا رَدْعٌ مِنْ حِنَّاءٍ عَلَيْهِ بُرْدَانِ أَخْضَرَانِ قَالَ كَأَنِّي أَنْظُرُ إِلَى سَاقَيْهِ قَالَ فَقَالَ لِأَبِي مَنْ هَذَا مَعَكَ قَالَ هَذَا وَاللَّهِ ابْنِي قَالَ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَلِفِ أَبِي عَلَيَّ ثُمَّ قَالَ صَدَقْتَ أَمَا إِنَّكَ لَا تَجْنِي عَلَيْهِ وَلَا يَجْنِي عَلَيْكَ قَالَ وَتَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Syaiban bin Abi Syaibah] telah menceritakan kepada kami [Yazid] -yaitu Ibnu Ibrahim At Tustari telah menceritakan kepada kami [Shodaqoh bin Abi Imron] dari seorang lelaki yaitu [Tsabit bin Munqidz] dari [Abu Rimtsah], dia berkata: \"aku bersama dengan bapakku pergi kepada Rasulullah Shallallahu 'alaihi wa Salam, maka ketika kami sedang berada pada salah satu jalan kami bertemu dengannya (Shallallahu 'alaihi wa Salam), lalu bapakku berkata kepadaku, 'Wahai anakku, ini adalah Rasulullah Shallallahu 'alaihi wa Salam.'\" Dia berkata; \"aku mengira bahwa Rasulullah Shallallahu 'alaihi wa Salam adalah seseorang yang tidak mirip dengan kebanyakkan manusia, padahal beliau adalah seorang laki-laki yang mempunyai rambut yang menyentuh daun telinga, mengenakan inai, dan mengenakan dua selendang berwana biru.\" Dia berkata; \"seakan aku melihat pada kedua betisnya.\" Dia berkata; Rasulullah berkata kepada bapakku: \"Siapa yang bersamamu ini?\" Dia menjawab, \"Demi Allah ini adalah putraku.\" Dia berkata; Rasulullah Shallallahu 'alaihi wa Salam tertawa karena bapakku bersumpah kepada Allah atas aku. Kemudian beliau bersabda: \"Engkau telah berkata benar, adapun dia, sungguh tidak akan berbuat jahat kepadamu dan kamu tidak akan berbuat jahat kepadanya.\" Dia berkata; kemudian Rasulullah Shallallahu 'alaihi wa Salam membaca ayat; \"dan seorang yang berdosa tidak akan memikul dosa orang lain\"."},"216":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي جَعْفَرُ بْنُ حُمَيْدٍ الْكُوفِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِيهِ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ مَعَ أَبِي نَحْوَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَيْتُهُ قَالَ أَبِي هَلْ تَدْرِي مَنْ هَذَا قُلْتُ لَا قَالَ هَذَا مُحَمَّدٌ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاقْشَعْرَرْتُ حِينَ قَالَ ذَلِكَ وَكُنْتُ أَظُنُّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ لَا يُشْبِهُ النَّاسَ فَإِذَا بَشَرٌ ذُو وَفْرَةٍ وَبِهَا رَدْعُ حِنَّاءٍ وَعَلَيْهِ بُرَدَانِ أَخْضَرَانِ فَسَلَّمَ عَلَيْهِ أَبِي ثُمَّ جَلَسْنَا فَتَحَدَّثْنَا سَاعَةً ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي ابْنُكَ هَذَا قَالَ إِي وَرَبِّ الْكَعْبَةِ قَالَ حَقًّا قَالَ أَشْهَدُ بِهِ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا مِنْ تَثْبِيتِ شَبَهِي بِأَبِي وَمِنْ حَلِفِ أَبِي عَلَيَّ ثُمَّ قَالَ أَمَا إِنَّهُ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }ثُمَّ نَظَرَ إِلَى مِثْلِ السِّلْعَةِ بَيْنَ كَتِفَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي كَأَطَبِّ الرِّجَالِ أَلَا أُعَالِجُهَا لَكَ قَالَ لَا طَبِيبُهَا الَّذِي خَلَقَهَا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Ja'far bin Humaid Al Kufi] telah menceritakan kepada kami [Ubaidullah bin Iyad bin laqith] dari [bapaknya] dari [Abu Rimtsah], dia berkata: aku bersama bapakku bertolak menuju Rasulullah Shallallahu 'alaihi wa Salam, maka ketika aku melihatnya, bapakku berkata kepadaku; \"Tahukah kamu siapa orang ini?\" \"Tidak\" jawabku. Bapakku berkata; \"Dia adalah Muhammad Rasulullah Shallallahu 'alaihi wa Salam.\" Dia berkata; maka aku pun bergetar ketika bapakku mengatakan kepadaku begitu, aku mengira bahwa Rasulullah Shallallahu 'alaihi wa Salam adalah seorang laki-laki yang tidak sama dengan kebanyakkan manusia, ternyata dia adalah seorang laki-laki yang rambutnya menyentuh daun telinganya, pada rambutnya terdapat inai dan mengenakan dua lembar selendang berwarna biru. Lalu bapakku mengucapkan salam kepadanya. Kemudian kami duduk dan berbincang selama satu jam. kemudian Rasulullah Shallallahu 'alaihi wa Salam berkata kepada bapakku, \"Apakah ini anakmu?\" dia menjawab, \"Ya, demi Rabbul Ka'bah.\" Dia berkata; \"Ini benar.\" Lalu berkata lagi, \"Aku berani bersaksi atasnya.\" Maka tersenyumlah Rasulullah Shallallahu 'alaihi wa Salam kepada bapakku yang menguatkan kemiripanku dengannya dan juga karena sumpahnya kepada Allah atas diriku. Kemudian beliau bersabda: \"Adapun dia, sungguh tidak akan berbuat jahat kepadamu dan kamu tidak akan berbuat jahat padanya.\" Lalu beliau membaca ayat: \"dan seorang yang berdosa tidak akan memikul dosa orang lain.\" Kemudian bapakku melihat semisal luka yang ada pada pundak Rasulullah Shallallahu 'alaihi wa Salam, dan berkata; \"wahai Rasulullah, sesungguihnya aku adalah orang yang paling paham tentang kedokteran di antara orang-orang, maka bolehkan aku mengobati lukamu?\" \"Tidak, dokternya adalah yang telah menciptakannya (Allah).\" Jawab beliau. "},"217":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبِي وَأَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادِ بْنِ لَقِيطٍ عَنْ أَبِيهِ عَنْ أَبِي رِمْثَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ بُرْدَانِ أَخْضَرَانِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku bapakku dan [Abu Khaitsamah Zuhair bin Harb] mereka berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Ubaidullah bin Iyad bin laqith] dari [bapaknya], dari [Abu Rimtsah], dia berkata; \"Aku mendatangi Rasulullah Shallallahu 'alaihi wa Salam sedang beliau mengenakan dua selendang hijau.\""},"218":{"ar":"أَخْبَرَنَا هُشَيْمُ بْنُ بَشِيرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ أَبِي صَالِحٍ ذَكْوَانُ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينُكَ عَلَى مَا يُصَدِّقُكَ بِهِ صَاحِبُكَ","id":"Telah mengkabarkan kepada kami [Husyaim bin Basyir] telah mengkabarkan kepada kami [Abdullah bin Abu Shalih Dzakwan] dari [bapaknya] dari [Abu Hurairah], dia berkata; Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sumpahmu itu tergantung pada pembenaran yang dilakukan oleh temanmu kepadamu.\""},"219":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا مَنْصُورٌ وَهِشَامٌ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَالْعَجْمَاءُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Manshur] dan [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah], dia berkata; Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Mati karena tercebur ke dalam sumur adalah sia-sia, mati karena kecelakaan dalam penambangan adalah sia-sia, binatang yang mati tertanduk adalah sia-sia, dan pada harta terpendam yang ditemukan terdapat kewajiban mengeluarkan zakat seperlimanya.\""},"220":{"ar":"أَخْبَرَنَا هُشَيْمٌ عَنِ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَدَخَلَ عُيَيْنَةُ بْنُ حِصْنٍ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَآهُ يُقَبِّلُ حَسَنًا أَوْ حُسَيْنًا فَقَالَ لَهُ لَا تُقَبِّلْهُ يَا رَسُولَ اللَّهِ لَقَدْ وُلِدَ لِي عَشَرَةٌ مَا قَبَّلْتُ أَحَدًا مِنْهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مَنْ لَا يَرْحَمُ لَا يُرْحَمُ","id":"Telah mengkabarkan kepada kami [Husyaim] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; 'Uyainah bin Hishn pernah mengunjungi Rasulullah Shallallahu 'alaihi wa Salam, lalu ia melihat beliau mencium Hasan dan Husain, maka iapun berkata kepada beliau: \"Wahai Rasulullah, jangan engkau menciumnya, sesungguhnya aku telah dikaruniai anak sebanyak sepuluh orang, dan satupun dari mereka tidak ada yang pernah aku cium.\" Maka Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sesungguhnya barangsiapa yang tidak mencintai maka ia tidak berhak untuk dicintai.\""},"221":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو بِشْرٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ أُمَّتِي الْقَرْنُ الَّذِي بُعِثْتُ فِيهِمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ وَاللَّهُ أَعْلَمُ أَقَالَ الثَّالِثَةَ أَمْ لَا ثُمَّ يَجِيءُ قَوْمٌ يُحِبُّونَ السَّمَانَةَ يَشْهَدُونَ قَبْلَ أَنْ يُسْتَشْهَدُوا","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Abu Bisyr] dari [Abdullah bin Syaqiq] dari [Abu Hurairah], dia berkata; Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Sebaik-baik ummatku ialah orang-orang yang aku diutus ditengah-tengah mereka, kemudian generasi setelahnya, kemudian generasi setelahnya.\" Allahu a'lam, apakah beliau mengatakannya hingga tiga kali ataukah tidak?\" \"Kemudian setelah itu datang satu generasi yang suka menggemukkan badan, dan mereka akan memberi kesaksian sebelum mereka diminta untuk memberi kesaksian.\""},"222":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ يَعْنِي ابْنَ عَمْرِو بْنِ حَزْمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَجَدَ عَيْنَ مَالِهِ عِنْدَ رَجُلٍ قَدْ أَفْلَسَ فَهُوَ أَحَقُّ بِهِ مِمَّنْ سِوَاهُ","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abu Bakar bin Muhammad] -yaitu Ibnu 'Amru bin Hazm dari [Umar bin Abdul Aziz] dari [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] dari [Abu Hurairah], dia berkata; Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Barangsiapa mendapati harta bendanya ada pada seseorang yang sedang pailit, maka ia lebih berhak atasnya daripada selainnya.\""},"223":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا خَالِدٌ عَنْ يُوسُفَ أَوْ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اخْتَلَفُوا فِي الطَّرِيقِ رُفِعَ مِنْ بَيْنِهِمْ سَبْعَةُ أَذْرُعٍ","id":"Telah menceritakan kepada kami [Husyaim] telah mengkabarkan kepada kami [Khalid] dari [Yusuf] atau dari bapaknya dari [Abdullah bin Al Harits] dari [Abu Hurairah], bahwa Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Jika orang-orang bertengkar mengenai (tanah) yang ada di jalanan maka ambillah dari setiap mereka tujuh hasta.\""},"224":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو الْجُهَيْمِ الْوَاسِطِيُّ عَنِ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرُؤُ الْقَيْسِ صَاحِبُ لِوَاءِ الشُّعَرَاءِ إِلَى النَّارِ","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Abul Juhaim Al Wasithiy] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah], dia berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Umru-u Al Qois adalah pembawa bendera para penyair menuju ke neraka.\""},"225":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ سَيَّارٍ عَنْ جَبْرِ بْنِ عَبِيدَةَ عَنْ أَبِي هُرَيْرَةَ قَالَوَعَدَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ الْهِنْدِ فَإِنْ اسْتُشْهِدْتُ كُنْتُ مِنْ خَيْرِ الشُّهَدَاءِ وَإِنْ رَجَعْتُ فَأَنَا أَبُو هُرَيْرَةَ الْمُحَرَّرُ","id":"Telah menceritakan kepada kami [Husyaim] dari [Sayyar] dari [Jabr bin Abidah] dari [Abu Hurairah], dia berkata; \"Pada perang Al hind Rasulullah Shallallahu 'alaihi wa Salam menjanjikan kepada kami, jika aku mati syahid maka aku adalah sebaik-baik para syuhada', dan jika aku pulang kembali maka aku adalah Abu Hurairah yang merdeka.\""},"226":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شِدَّةُ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ فَأَبْرِدُوا بِالصَّلَاةِ","id":"Telah menceritakan kepada kami [Husyaim] dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] dari Nabi Shallallahu 'alaihi wa Salam, beliau bersabda: \"Panas yang terik datang dari jilatan api neraka jahannam, maka dinginkanlah ia dengan shalat.\""},"227":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبِكْرُ تُسْتَأْمَرُ وَالثَّيِّبُ تُشَاوَرُ قِيلَ يَا رَسُولَ اللَّهِ إِنَّ الْبِكْرَ تَسْتَحِي قَالَ سُكُوتُهَا رِضَاهَا","id":"Telah menceritakan kepada kami [Husyaim] dari [Umar bin Abu Salamah] dari [bapaknya] dari [Abu Hurairah], dia berkata: Rasulullah Shallallahu 'alaihi wa Salam bersabda: \"Seorang gadis itu dimintai izinnya (untuk dinikahi) dan seorang janda itu diajak bermusyawarah.\" Dikatakan kepada Rasulullah: \"Wahai Rasulullah, sesungguhnya seorang gadis itu merasa malu.\" Beliau berkata: \"Diamnya adalah tanda setujunya.\""},"228":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا أَبُو بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَاسًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانُوا فِي سَفَرٍ فَمَرُّوا بِحَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ فَاسْتَضَافُوهُمْ فَأَبَوْا أَنْ يُضَيِّفُوهُمْ فَعَرَضَ لِإِنْسَانٍ مِنْهُمْ فِي عَقْلِهِ أَوْ لُدِغَ قَالَ فَقَالُوا لِأَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ فِيكُمْ مِنْ رَاقٍ فَقَالَ رَجُلٌ مِنْهُمْ نَعَمْ فَأَتَى صَاحِبَهُمْ فَرَقَاهُ بِفَاتِحَةِ الْكِتَابِ فَبَرَأَ فَأُعْطِيَ قَطِيعًا مِنْ غَنَمٍ فَأَبَى أَنْ يَقْبَلَ حَتَّى أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا رَقَيْتُهُ إِلَّا بِفَاتِحَةِ الْكِتَابِ قَالَ فَضَحِكَ وَقَالَ مَا يُدْرِيكَ أَنَّهَا رُقْيَةٌ قَالَ ثُمَّ قَالَ خُذُوا وَاضْرِبُوا لِي بِسَهْمٍ مَعَكُمْ","id":"Telah menceritakan kepada kami [Husyaim] berkata; telah menceritakan kepada kami [Abu Bisyr] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] berkata; Beberapa orang sahabat Nabi shallallahu 'alaihi wasallam mengadakan safar, ketika mereka melewati salah satu perkampungan arab, mereka hendak bertamu namun mereka enggan menerimanya. Lalu ada diantara penduduk itu terkena sengatan, dan akhirnya mereka bertanya kepada sahabat Rasulullah shallallahu 'alaihi wasallam; \"Apakah ada di antara kalian yang bisa meruqyah?\" maka seorang sabahat Nabi menjawab; \"Ya, \" kemudian ia menemui orang yang terkena sengatan dan meruqyahnya dengan membacakan surat Al Fatihah, dan orang itu pun sembuh. Maka ia pun diberi beberapa kambing, namun ia enggan menerimanya hingga ia bertemu dengan Nabi shallallahu 'alaihi wasallam, ketika sampai, ia pun menceritakan kejadian tersebut kepada beliau, dan berkata; \"Wahai Rasulullah, demi Dzat yang mengutusmu dengan kebenaran, aku tidak meruqyahnya kecuali hanya dengan membacakan surat Al Fatihah, \" Abu Sa'id Al Khudri berkata; Beliau lalu tertawa, dan bersabda: \"Apa engkau tahu bahwa surat Al Fatihah adalah ruqyah?\" Abu Sa'id Al Khudri berkata; \"Kemudian beliau bersabda: \"Ambillah pemberian itu dan berikan untukku satu bagian bersama kalian.\""},"229":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا سَيِّدُ وَلَدِ آدَمَ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأَنَا أَوَّلُ مَنْ تَنْشَقُّ عَنْهُ الْأَرْضُ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ وَأَنَا أَوَّلُ شَافِعٍ يَوْمَ الْقِيَامَةِ وَلَا فَخْرَ","id":"Telah menceritakan kepada kami [Husyaim] berkata; telah menceritakan kepada kami [Ali bin Zaid] dari [Abu Nadhrah] dari [Abu Sa'id] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku adalah pemimpin anak Adam pada hari kiamat, dan ini bukannya aku sombong, aku adalah orang yang pertama kali dibuka kuburnya pada hari kiamat dan ini bukannya aku sombong, serta aku yang pertama kali yang memberi syafa'at dan ini bukannya aku sombong.\""},"230":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّقَالَ جَاءَ مَاعِزُ بْنُ مَالِكٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ أَنَّهُ أَتَى فَاحِشَةً فَرَدَّهُ مِرَارًا قَالَ ثُمَّ أَمَرَ بِهِ فَرُجِمَ قَالَ فَانْطَلَقْنَا فَرَجَمْنَاهُ قَالَ فَانْطَلَقْنَا إِلَى الْحَرَّةِ فَرَجَمْنَاهُ ثُمَّ وَلَّيْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْنَاهُ فَلَمَّا كَانَ مِنْ الْعَشِيِّ قَالَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا بَالُ أَقْوَامٍسَقَطَتْ عَلَى أَبِي كَلِمَةٌ","id":"Telah menceritakan kepada kami [Husyaim] dari [Dawud bin Abu Hind] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] ia berkata; \"Maiz bin Malik menemui Rasulullah shallallahu 'alaihi wasallam untuk memberitahukan kepada beliau, bahwa dirinya telah berzina, namun beliau menolaknya berulang-ulang, tapi akhirnya beliau memerintahkan agar ia dirajam, lalu kami pun membawanya menuju ke padang pasir dan merajamnya, setelah itu kami kembali kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan hal itu, pada sore harinya Rasulullah bersabda, memuji kepada Allah dan menyanjung-Nya kemudian bersabda; \"Bagaimana keadaan suatu kaum yang tidak terhina karena satu kalimat.\""},"231":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يَزِيدُ بْنُ أَبِي زِيَادٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي نُعْمٍ الْبَجَلِيُّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ مَا يَقْتُلُ الْمُحْرِمُ قَالَ الْحَيَّةَ وَالْعَقْرَبَ وَالْفُوَيْسِقَةَ وَيَرْمِي الْغُرَابَ وَلَا يَقْتُلُهُ وَالْكَلْبَ الْعَقُورَ وَالْحِدَأَةَ وَالسَّبُعَ الْعَادِيَ","id":"Telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Yazid bin Abu Ziyad] berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Nu'm Al Bajali] dari [Abu Sa'id Al Khudri], dia menuturkan; Nabi shallallahu 'alaihi wasallam ditanya; \"binatang apa saja yang diperbolehkan bagi orang yang sedang ihram untuk membunuhnya?\" maka beliau bersabda: \"Ular, kalajengking, tikus, melempari burung gagak tetapi tidak membunuhnya, anjing galak dan liar serta hewan buas lainnya.\""},"232":{"ar":"حَدَّثَنَا مُعْتَمِرٌ قَالَ حَدَّثَنَا أَبِي أَخْبَرَنَا أَبُو نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَرِّ أَنْ يُنْبَذَ فِيهِ وَعَنْ التَّمْرِ وَالْبُسْرِ وَعَنْ التَّمْرِ وَالزَّبِيبِ أَنْ يُخْلَطَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Mu'tamir] berkata; [bapakku] telah menceritakan kepada kami, ia berkata; telah mengabarkan kepada kami [Abu Nadhrah] dari [Abu Sa'id], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang dari membuat an nabidz di al jarr, dan kurma matang dengan kurma mentah, atau kurma dengan kismis jika keduanya dicampur.\" "},"233":{"ar":"حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ قَالَ أَنْبَأَنِي أَبُو نَضْرَةَ عَنْ أَبِي سَعِيدٍأَنَّ صَاحِبَ التَّمْرِ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَمْرَةٍ فَأَنْكَرَهَا قَالَ أَنَّى لَكَ هَذَا فَقَالَ اشْتَرَيْنَا بِصَاعَيْنِ مِنْ تَمْرِنَا صَاعًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَيْتُمْ","id":"Telah menceritakan kepada kami [Mu'tamir] dari [bapaknya], ia berkata; telah memberitakan kepadaku [Abu Nadhrah] dari [Abu Sa'id] berkata; \"Bahwasannya seorang pemilik kurma menemui Rasulullah shallallahu 'alaihi wasallam dengan membawa kurma namun beliau mengingkarinya, beliau bersabda: \"Dari mana kamu dapatkan ini?\" ia menjawab, \"Kami membelinya (menukar) satu sho` dengan dua sho` kurma kami, \" maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Engkau telah melakukan riba.\""},"234":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أَدُلُّكُمْ عَلَى مَا يُكَفِّرُ اللَّهُ بِهِ الْخَطَايَا وَيَزِيدُ بِهِ فِي الْحَسَنَاتِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ إِسْبَاغُ الْوُضُوءِ عَلَى الْمَكَارِهِ وَكَثْرَةُ الْخُطَا إِلَى هَذِهِ الْمَسَاجِدِ وَانْتِظَارُ الصَّلَاةِ بَعْدَ الصَّلَاةِ مَا مِنْكُمْ مِنْ رَجُلٍ يَخْرُجُ مِنْ بَيْتِهِ مُتَطَهِّرًا فَيُصَلِّي مَعَ الْمُسْلِمِينَ الصَّلَاةَ ثُمَّ يَجْلِسُ فِي الْمَجْلِسِ يَنْتَظِرُ الصَّلَاةَ الْأُخْرَى إِنَّ الْمَلَائِكَةَ تَقُولُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ فَإِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاعْدِلُوا صُفُوفَكُمْ وَأَقِيمُوهَا وَسُدُّوا الْفُرَجَ فَإِنِّي أَرَاكُمْ مِنْ وَرَاءِ ظَهْرِي فَإِذَا قَالَ إِمَامُكُمْ اللَّهُ أَكْبَرُ فَقُولُوا اللَّهُ أَكْبَرُ وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ وَإِنَّ خَيْرَ الصُّفُوفِ صُفُوفِ الرِّجَالِ الْمُقَدَّمُ وَشَرُّهَا الْمُؤَخَّرُ وَخَيْرُ صُفُوفِ النِّسَاءِ الْمُؤَخَّرُ وَشَرُّهَا الْمُقَدَّمُ يَا مَعْشَرَ النِّسَاءِ إِذَا سَجَدَ الرِّجَالُ فَاغْضُضْنَ أَبْصَارَكُنَّ لَا تَرَيْنَ عَوْرَاتِ الرِّجَالِ مِنْ ضِيقِ الْأُزُرِ","id":"Telah menceritakan kepada kami [Abu 'Amir Abdul Malik bin 'Amru] berkata; telah menceritakan kepada kami [Zuhair] -yaitu Ibnu Muhammad- dari [Abdullah bin Muhammad bin 'Aqil] dari [Sa'id Ibnul Musayyab] dari [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku tunjukkan kepada kalian sesuatu yang dengannya Allah akan menghapus kesalahan dan menambah kebaikan?\" para sahabat menjawab, \"Tentu, wahai Rasulullah, \" maka beliau bersabda: \"Sempurnakanlah wudlu di waktu yang tidak mengenakkan, memperbanyak langkah menuju masjid dan menunggu shalat setelah shalat. Tidaklah seorang dari kalian keluar dari rumahnya dalam keadaan suci lalu shalat bersama kaum muslimin, kemudian ia duduk menunggu shalat berikutnya, kecuali malaikat akan berdoa; 'Ya Allah ampunilah ia, ya Allah rahmatilah ia.' Jika kalian akan menegakkan shalat maka luruskan barisan shalat kalian dan rapatkanlah, serta penuhilah tempat yang kosong, karena sesungguhnya aku dapat melihat kalian dari belakang punggungku. Jika imam kalian mengucapkan; 'ALLAHUAKBAR' maka ucapkanlah; 'ALLAHUAKBAR, ' jika ia ruku' maka ruku'lah, jika ia mengucapkan 'SAMI'A ALLAHU LIMAN HAMIDAH' maka ucapkanlah RABBANA LAKALHAMDU.' Dan sesungguh sebaik-baik shaf laki-laki adalah yang paling depan dan yang paling jelek adalah yang paling belakang, dan sebaik-baik shaf wanita adalah yang paling belakang dan yang paling buruk adalah yang paling depan. Wahai kaum wanita, jika para laki-laki bersujud maka tundukanlah pandangan kalian, janganlah kalian melihat aurat laki-laki karena sempitnya sarung.\""},"235":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا عَبَّادٌ يَعْنِي ابْنَ رَاشِدٍ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَإِنَّكُمْ لَتَعْمَلُونَ أَعْمَالًا هِيَ أَدَقُّ فِي أَعْيُنِكُمْ مِنْ الشَّعْرِ كُنَّا نَعُدُّهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُوبِقَاتِ","id":"Telah menceritakan kepada kami [Abdul Malik bin 'Amru] berkata; telah menceritakan kepada kami [Abbad] -yaitu Ibnu Rasyid- dari [Dawud bin Abu hind] dari [Abu Nadhrah] dari [Abu Sa'id] berkata; \"Sungguh, kalian benar-benar akan melakukan amalan yang ia lebih tipis dimata kalian daripada rambut, kami menghitungnya pada masa Rasulullah shallallahu 'alaihi wasallam sebagai amalan yang membinasakan.\""},"236":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ حَسَنٍ الْحَارِثِيُّ حَدَّثَنَا سَعِيدُ بْنُ عَمْرِو بْنِ سُلَيْمٍ قَالَ سَمِعْتُ رَجُلًا مِنَّا قَالَ عَبْدُ الْمَلِكِ نَسِيتُ اسْمَهُ وَلَكِنْ اسْمُهُ مُعَاوِيَةُ أَوْ ابْنُ مُعَاوِيَةَ يُحَدِّثُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ يَعْرِفُ مَنْ يَحْمِلُهُ وَمَنْ يُغَسِّلُهُ وَمَنْ يُدَلِّيهِ فِي قَبْرِهِفَقَالَ ابْنُ عُمَرَ وَهُوَ فِي الْمَجْلِسِ مِمَّنْ سَمِعْتَ هَذَا قَالَ مِنْ أَبِي سَعِيدٍ فَانْطَلَقَ ابْنُ عُمَرَ إِلَى أَبِي سَعِيدٍ فَقَالَ يَا أَبَا سَعِيدٍ مِمَّنْ سَمِعْتَ هَذَا قَالَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu 'Amir] berkata; telah menceritakan kepada kami [Abdul Malik bin Hasan Al Haritsi] berkata; telah menceritakan kepada kami [Sa'id bin 'Amru bin Sulaim] berkata; aku mendengar seorang lelaki dari kami, -Abdul Malik berkata; aku lupa namanya, tetapi kira-kira namanya adalah [Mu'awiyah] atau Ibnu Mu'awiyah, - ia menceritakan dari [Abu Sa'id Al Khudri], bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang meninggal dunia itu mengetahui siapa yang mengusungnya, memandikan dan memasukkannya ke liang kubur.\" Lalu Ibnu Umar yang sedang berada di majlis berkata; \"Dari mana engkau mendengar itu?\" Ia berkata; \"Dari Abu Sa'id, \" maka pergilah Ibnu Umar menemui Abu Sa'id, dan bertanya; \"Wahai Abu Sa'id, dari mana engkau mendapatkan hadits itu?\" ia menjawab, \"Dari Nabi shallallahu 'alaihi wasallam.\""},"237":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍأَمَرَنَا نَبِيُّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَقْرَأَ بِفَاتِحَةِ الْكِتَابِ وَمَا تَيَسَّرَ","id":"Telah menceritakan kepada kami [Abdush Shamad] berkata; telah menceritakan kepada kami [Hammam] berkata; telah menceritakan kepada kami [Qotadah] dari [Abu Nadhrah] dari [Abu Sa'id] ia berkata; \"Nabi kita memerintahkan kepada kita agar kita membaca Al Fatihah dan surat yang ringan bagi kita.\""},"238":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ وَإِسْمَاعِيلُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Husyaim] berkata, telah menceritakan kepada kami [Abdul Aziz bin Shuhaib]. Dan [Isma'il] berkata, telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa sengaja berdusta atas namaku maka hendaklah dia mempersiapkan tempat duduknya di dalam neraka.\""},"239":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَيْنَبَ ابْنَةِ جَحْشٍ أَوْلَمَ قَالَ فَأَطْعَمَنَا خُبْزًا وَلَحْمًا","id":"Telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami [Humaid] bin [Anas bin Malik] berkata; \"Ketika malam pertama Rasulullah shallallahu 'alaihi wasallam di rumah Zainab binti Jahsy, beliau mengadakan walimah, dan kami memakan roti beserta daging pada walimah tersebut.\""},"240":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي بُرْدَةِ حِبَرَةٍ قَالَ أَحْسَبُهُ عَقَدَ بَيْنَ طَرَفَيْهَا","id":"Telah menceritakan kepada kami [Husyaim] dari [Humaid] dari [Anas bin Malik] Radhiyallahu Ta'ala 'anhu, bahwasanya Nabi shallallahu 'alaihi wasallam shalat memakai selendang yang bercampur dengan wol. Anas berkata; \"Menurutku beliau menggabungkan kedua ujungnya.\""},"241":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى جَمِيعِ نِسَائِهِ فِي لَيْلَةٍ بِغُسْلٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Husyaim] [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah berkeliling menggilir semua istrinya dalam satu malam dengan satu kali mandi.\""},"242":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ الْخَلَاءَ قَالَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْخُبْثِ وَالْخَبَائِثِ","id":"Telah menceritakan kepada kami [Husyaim] dari [Abdul Aziz] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam apabila hendak memasuki kamar mandi, beliau mengucapkan: \"ALLAAHUMMA INNI A'UUDZU BIKA MINAL KHUBUTSI WAL KHABAA`ITSI (Ya Allah, aku berlindung kepada-Mu dari setan laki-laki dan setan perempuan).\""},"243":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرٍ أَخْبَرَنَا عَنْ أَنَسٍ وَيُونُسُ عَنْ الْحَسَنِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصُرْ أَخَاكَ ظَالِمًا أَوْ مَظْلُومًا قِيلَ يَا رَسُولَ اللَّهِ هَذَا أَنْصُرُهُ مَظْلُومًا فَكَيْفَ أَنْصُرُهُ إِذَا كَانَ ظَالِمًا قَالَ تَحْجُزُهُ تَمْنَعُهُ فَإِنَّ ذَلِكَ نَصْرُهُ","id":"Telah menceritakan kepada kami [Husyaim] berkata; [Ubaidullah bin Abu Bakr] berkata; telah mengabarkan kepada kami dari [Anas bin Malik], dan [Yunus] dari [Al Hasan] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tolonglah saudaramu baik yang terzhalimi atau yang menzhalimi, \" mereka bertanya; \"Kalau yang terzhalimi kami memahaminya, tapi bagaimana kami menolong saudara kami yang menzhalimi?\" beliau menjawab: \"Menahan dan melarangnya dari berbuat kezhaliman, itulah bentuk pertolongan untuknya.\""},"244":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَبْدُ الْعَزِيزِ وَإِسْمَاعِيلُ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السُّحُورِ بَرَكَةً","id":"Telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami [Abdul Aziz] dan [Isma'il] dari [Abdul Aziz] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makan sahurlah kalian! Karena dalam makan sahur terdapat keberkahan.\""},"245":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ حُمَيْدٍ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَلَمَّا اتَّخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفِيَّةَ أَقَامَ عِنْدَهَا ثَلَاثًا وَكَانَتْ ثَيِّبًا","id":"Telah menceritakan kepada kami [Husyaim] dari [Humaid] berkata, telah menceritakan kepada kami [Anas bin Malik] ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam menikahi Shafiyyah beliau tinggal bersamanya selama tiga hari, dan Shafiyyah adalah seorang janda.\""},"246":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ سَمِعْتُهُ يُحَدِّثُ قَالَشَهِدْتُ وَلِيمَتَيْنِ مِنْ نِسَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَمَا أَطْعَمَنَا فِيهَا خُبْزًا وَلَا لَحْمًا قَالَ قُلْتُ فَمَهْ قَالَ الْحَيْسَ يَعْنِي التَّمْرَ وَالْأَقِطَ بِالسَّمْنِ","id":"Telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami ['Ali bin Zaid] dari [Anas bin Malik] ia berkata; \"Aku mendengarnya menceritakan, ia berkata; \"Aku dua kali menghadiri walimah yang dilakukan oleh Rasulullah shallallahu 'alaihi wasallam ketika menikahi istri-istrinya, \" Anas berkata; \"Beliau tidak memberi kami makanan roti ataupun daging\" Ali bin Zaid bertanya; \"Lalu apa?\" Anas menjawab; \"Yang ada hanya hayyis (kurma, dan susu kering yang dicampur dengan minyak samin).\""},"247":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا الْعَوَّامُ حَدَّثَنَا الْأَزْهَرُ بْنُ رَاشِدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَسْتَضِيئُوا بِنَارِ الْمُشْرِكِينَ وَلَا تَنْقُشُوا خَوَاتِيمَكُمْ عَرَبِيًّا","id":"Telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada kami [Al Awwam] berkata, telah menceritakan kepada kami [Al Azhar bin Rasyid] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengambil penerangan dari apinya orang musyrik, dan jangan mengukir cincin kalian dengan tulisan arab.\""},"248":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍأَنَّهُمْ غَزَوْا غَزْوَةً فِيمَا بَيْنَ مَكَّةَ وَالْمَدِينَةِ فَهَاجَتْ عَلَيْهِمْ رِيحٌ شَدِيدَةٌ حَتَّى دَفَعَتْ الرِّجَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا لِمَوْتِ الْمُنَافِقِ فَرَجَعْنَا إِلَى الْمَدِينَةِ فَوَجَدْنَاهُ مُنَافِقًا عَظِيمَ النِّفَاقِ قَدْ مَاتَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] Sesungguhnya mereka berperang dalam suatu peperangan antara Makkah dan Madinah, lalu bertiuplah angin yang sangat kencang sampai angin tersebut bisa menjadikan seseorang terjengkang. Rasulullah shallallahu 'alaihi wasallam lantas bersabda: \"Ini adalah untuk kematian seorang munafiq\" lalu kami pulang ke Madinah dan mendapati seorang dedengkot munafiq yang telah tewas."},"249":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ قَالَسَأَلْتُ جَابِرًا عَنْ الْعَقَبَةِ فَقَالَ شَهِدَهَا سَبْعُونَ فَوَافَقَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ آخِذٌ بِيَدِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذْتُ وَأَعْطَيْتُ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] berkata; saya telah bertanya kepada [Jabir] tentang Al 'aqobah maka dia menjawab, \"Yang menyaksikan adalah tujuh puluh orang lalu Rasulullah shallallahu 'alaihi wasallam menyetujuinya dan Al 'Abbas Bin Abdul Muthollib memegang tangan beliau, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya terima dan saya berikan\"."},"250":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ قَالَ أَخْبَرَنِي جَابِرٌأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَتْرُكَنَّهَا أَهْلُهَا مُرْطِبَةً قَالُوا فَمَنْ يَأْكُلُهَا يَا رَسُولَ اللَّهِ قَالَ عَافِيَةُ الطَّيْرِ وَالسِّبَاعِ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] berkata; telah mengabarkan kepadaku [Jabir] telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh penduduknya akan meninggalkannya dalam keadaan basah dan segar\" mereka bertanya, siapa yang memakannya Wahai Rasulullah! Beliau menjawab, burung-burung dan hewan buas\"."},"251":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَأْتِيَنَّ عَلَى الْمَدِينَةِ زَمَانٌ يَنْطَلِقُ النَّاسُ فِيهَا إِلَى الْآفَاقِ يَلْتَمِسُونَ الرَّخَاءَ فَيَجِدُونَ رَخَاءً ثُمَّ يَأْتُونَ فَيَتَحَمَّلُونَ بِأَهْلِيهِمْ إِلَى الرَّخَاءِ وَالْمَدِينَةُ خَيْرٌ لَهُمْ لَوْ كَانُوا يَعْلَمُونَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] telah mengabarkan kepadaku [Jabir bin Abdullah] Sesungguhnya Rasulullah shallallahu 'alaihi wasallam berkata; \"Akan datang suatu masa di Madinah, Penduduknya akan menuju ke arah yang terpencil, lalu mereka mendapatkan padang yang luas kemudian mereka membawa keluarganya ke tempat tersebut. Dan Madinah adalah lebih baik bagi mereka seandainya mereka mengetahuinya\"."},"252":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ قَالَسَأَلْتُ جَابِرًا عَنْ مِيثَرَةِ الْأُرْجُوَانِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَرْكَبُهَا وَلَا أَلْبَسُ قَمِيصًا مَكْفُوفًا بِحَرِيرٍ وَلَا أَلْبَسُ الْقَسِّيَّ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] berkata; saya telah bertanya kepada [Jabir] tentang 'pelana sutra yang kemerah-merahan', maka ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya tidak akan menaikinya, saya tidak memakai gamis yang terselip sutra dan saya juga tidak memakai baju dari kapas yang bercampur sutra\"."},"253":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ قَالَسَأَلْتُ جَابِرًا عَنْ الْفَأْرَةِ تَمُوتُ فِي الطَّعَامِ أَوْ الشَّرَابِ أَطْعَمُهُ قَالَ لَا زَجَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ كُنَّا نَضَعُ السَّمْنَ فِي الْجِرَارِ فَقَالَ إِذَا مَاتَتْ الْفَأْرَةُ فِيهِ فَلَا تَطْعَمُوهُ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] berkata; saya telah bertanya kepada [Jabir] tentang tikus yang mati pada makanan atau minuman apakah saya (boleh) memakannya?, maka ia berkata; Jangan! Rasulullah shallallahu 'alaihi wasallam melarang hal itu. Kami meletakkan minyak samin dalam bejana tanah lalu (Rasulullah shallallahu 'alaihi wasallam) bersabda: \"Jika ada tikus yang mati di dalamnya maka janganlah kalian memakannya\"."},"254":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ قَالَسَأَلْتُ جَابِرًا عَنْ الضَّبِّ فَقَالَ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِ فَقَالَ لَا أَطْعَمُهُ وَقَذِرَهُفَقَالَ عُمَرُ بْنُ الْخَطَّابِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُحَرِّمْهُ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَيَنْفَعُ بِهِ غَيْرَ وَاحِدٍ وَهُوَ طَعَامُ عَامَّةِ الرِّعَاءِ وَلَوْ كَانَ عِنْدِي لَطَعِمْتُهُ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] berkata; saya telah bertanya kepada [Jabir] tentang tentang biawak, maka ia berkata; pernah diberikan kepada Rasulullah shallallahu 'alaihi wasallam barang itu, maka beliau bersabda: saya tidak memakannya. Beliau merasa jijik dengannya, lalu ['Umar bin Al Khatthab] berkata; \"Rasulullah shallallahu 'alaihi wasallam tidaklah mengharamkannya, dan Allah AzzaWaJalla memberi manfaat dengannya bukan hanya pada seorang, akan tetapi dia adalah makanan para pengembala, kalau ada padaku niscaya saya akan memakannya\"."},"255":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ قَالَسَأَلْتُ جَابِرًا عَنْ الرَّجُلِ يَتَوَلَّى مَوْلَى الرَّجُلِ بِغَيْرِ إِذْنِهِ فَقَالَ كَتَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ بَطْنٍ عُقُولَهُمْ ثُمَّ كَتَبَ إِنَّهُ لَا يَحِلُّ أَنْ يُتَوَلَّى مَوْلَى رَجُلٍ مُسْلِمٍ بِغَيْرِ إِذْنِهِ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] berkata; saya telah bertanya kepada [Jabir] tentang seorang laki-laki yang mengambil pelayan orang tanpa seijin majikannya, maka dia menjawab, Rasulullah shallallahu 'alaihi wasallam menetapkan untuk setiap tubuh diyatnya kemudian sesungguhnya (Rasulullah shallallahu 'alaihi wasallam) juga menetapkan bahwa tidak halal mengambil pembantu seorang muslim tanpa seijin majikannya."},"256":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ فِي صَحِيفَتِهِ مَنْ فَعَلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] Sesungguhnya Rasulullah shallallahu 'alaihi wasallam melaknat di lembarannya, \"Siapa yang telah melakukannya!\"."},"257":{"ar":"حَدَّثَنَا حَسَنٌ حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَرَكَ دِينَارًا فَهُوَ كَيَّةٌ","id":"Telah menceritakan kepada kami [Hasan] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] berkata; saya telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meninggalkan satu dinar maka itu adalah bara api\"."},"258":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَزَوَّجَنِي أَبِي فِي إِمَارَةِ عُثْمَانَ فَدَعَا نَفَرًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ صَفْوَانُ بْنُ أُمَيَّةَ وَهُوَ شَيْخٌ كَبِيرٌ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ انْهَسُوا اللَّحْمَ نَهْسًا فَإِنَّهُ أَهْنَأُ وَأَمْرَأُ أَوْ أَشْهَى وَأَمْرَأُ قَالَ سُفْيَانُ الشَّكُّ مِنِّي أَوْ مِنْهُ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdul Karim] dari [Abdullah bin Al Harits] berkata; bapakku menikahkanku pada masa pemerintahan 'Utsman lalu dia mengundang beberapa orang sahabat Rasulullah Shallallahu'alaihiwasallam. Datanglah [Shafwan bin Umayyah], dia sudah tua renta lalu dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Gigitlah daging, itu lebih enak dan lebih bermanfaat\" atau \"Lebih lezat dan lebih bermanfaat.\" Sufyan berkata; --kepastian redaksi lebih enak atau lebih lezat tersebut dariku atau darinya (Abdul Karim Radliyallahu'anhu)."},"259":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ التَّيْمِيِّ يَعْنِي سُلَيْمَانَ عَنْ أَبِي عُثْمَانَ يَعْنِي النَّهْدِيَّ عَنْ عَامِرِ بْنِ مَالِكٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَالطَّاعُونُ وَالْبَطْنُ وَالْغَرَقُ وَالنُّفَسَاءُ شَهَادَةٌحَدَّثَنَا بِهِ أَبُو عُثْمَانَ مِرَارًا وَقَدْ رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّةً","id":"Telah menceritakan kepada kami [Yazid bin Sa'id] dari [At Taimi] yaitu Sulaiman dari [Abu 'Utsman] yaitu An-Nahdi dari ['Amir Bin Malik] dari [Shafwan bin Umayyah] berkata; (orang yang mati karena) wabah tho'un, sakit perut, orang yang mati karena tenggelam dan melahirkan adalah mati syahid. Telah menceritakan kepada kami dengan hadits ini, Abu 'Utsman berulang-ulang, dan sesekali dia memarfu'kannya kepada Nabi Shallallahu'alaihiwasallam."},"260":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا شَرِيكٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ بْنِ أُمَيَّةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعَارَ مِنْهُ يَوْمَ خَيْبَرَ أَدْرَاعًا فَقَالَ أَغَصْبًا يَا مُحَمَّدُ فَقَالَ بَلْ عَارِيَةٌ مَضْمُونَةٌ قَالَ فَضَاعَ بَعْضُهَا فَعَرَضَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَضْمَنَهَا لَهُ فَقَالَ أَنَا الْيَوْمَ يَا رَسُولَ اللَّهِ فِي الْإِسْلَامِ أَرْغَبُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Syarik] dari [Abdul Aziz bin Rofi'] dari [Umayyah bin Shafwan] dari [bapaknya] Rasulullah Shallallahu'alaihiwasallam meminjam darinya pada Perang Khaibar baju besi. Dia berkata; apakah sebagai rampasan Wahai Rasulullah Shallallahu'alaihiwasallam? beliau bersabda: \"Itu adalah sebagai pinjaman yang ada jaminannya.\" (Shafwan bin Umayyah radliyallahu'anhu) berkata; lalu sebagiannya hilang lalu Rasulullah Shallallahu'alaihiwasallam menyanggupi untuk menjaminnya. (Shafwan bin Umayyah radliyallahu'anhu) berkata; Wahai Rasulullah saya pada hari ini, sangat senang kepada Islam."},"261":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ حَدَّثَنَا الزُّهْرِيُّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ أَبِيهِأَنَّ صَفْوَانَ بْنَ أُمَيَّةَ بْنِ خَلَفٍ قِيلَ لَهُ هَلَكَ مَنْ لَمْ يُهَاجِرْ قَالَ فَقُلْتُ لَا أَصِلُ إِلَى أَهْلِي حَتَّى آتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَكِبْتُ رَاحِلَتِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ زَعَمُوا أَنَّهُ هَلَكَ مَنْ لَمْ يُهَاجِرْ قَالَ كَلَّا أَبَا وَهْبٍ فَارْجِعْ إِلَى أَبَاطِحِ مَكَّةَ قَالَ فَبَيْنَمَا أَنَا رَاقِدٌ إِذْ جَاءَ السَّارِقُ فَأَخَذَ ثَوْبِي مِنْ تَحْتِ رَأْسِي فَأَدْرَكْتُهُ فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ هَذَا سَرَقَ ثَوْبِي فَأَمَرَ بِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْطَعَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ لَيْسَ هَذَا أَرَدْتُ هُوَ عَلَيْهِ صَدَقَةٌ قَالَ فَهَلَّا قَبْلَ أَنْ تَأْتِيَنِي بِهِ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Muhammad bin Abu Hafshah] telah menceritakan kepada kami [Az-Zuhri] dari [Shafwan bin Abdillah bin Shafwan] dari [bapaknya] dikatakan kepada Shafwan bin Umayyah bin Khalaf, celakalah orang yang tidak berhijrah. (Shafwan bin Umayyah radliyallahu'anhu) berkata; saya tidak akan menemui keluargaku hingga saya datang kepada Rasulullah Shallallahu'alaihiwasallam, lalu saya menunggang kendaraanku, saya temui Rasulullah Shallallahu'alaihiwasallam saya tanyakan, wahai Rasulullah! Orang-orang mengatakan 'Celaka orang yang tidak berhijrah. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Sekali-kali tidak, wahai Abu Wahab! kembalilah ke tanah Makkah!\" (Shafwan bin Umayyah radliyallahu'anhu) berkata; ketika saya sedang tidur, tiba-tiba datang seorang pencuri yang mengambil bajuku dari bawah kepalaku, lalu saya mendapatkannya hingga saya membawanya kepada Nabi Shallallahu'alaihiwasallam. Saya katakan, orang ini mencuri bajuku. Beliau Shallallahu'alaihiwasallam menyuruh untuk memotong tangannya. (Shafwan bin Umayyah radliyallahu'anhu) berkata; Wahai Rasulullah Shallallahu'alaihiwasallam, 'Bukanlah ini yang saya inginkan, akan tetapi saya ingin menjadikan baju itu sebagai sedekah padanya.' (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Kenapa kamu tidak mengatakannya sebelum kamu membawanya kepadaku?\""},"262":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ عَنْ ابْنِ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَأَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ وَإِنَّهُ لَأَبْغَضُ النَّاسِ إِلَيَّ فَمَا زَالَ يُعْطِينِي حَتَّى صَارَ وَإِنَّهُ أَحَبُّ النَّاسِ إِلَيَّ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] dari [Ibnu Mubarok] dari [Yunus] dari [Az-Zuhri] dari [Sa'id bin Musayyab] dari [Shafwan bin Umayyah] berkata; Rasulullah Shallallahu'alaihiwasallam pada Perang Hunain memberi harta rampasan kepadaku, padahal dia adalah orang yang paling saya benci. (Rasulullah Shallallahu'alaihiwasallam) tiada berhenti memberiku hingga beliau menjadi orang yang paling saya cintai."},"263":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عَطَاءٍ عَنْ طَارِقِ بْنِ مُرَقَّعٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّ رَجُلًا سَرَقَ بُرْدَهُ فَرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِقَطْعِهِ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ تَجَاوَزْتُ عَنْهُ قَالَ فَلَوْلَا كَانَ هَذَا قَبْلَ أَنْ تَأْتِيَنِي بِهِ يَا أَبَا وَهْبٍ فَقَطَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Sa'id] yaitu Ibnu Abu 'Arubah, dari [Qatadah] dari ['Atho'] dari [Thoriq bin Muroqqi'] dari [Shafwan bin Umayyah] seseorang mencuri mantelnya lalu dibawa kepada Nabi Shallallahu'alaihiwasallam, lalu beliau menyuruh untuk memotongnya. Lalu (Shafwan bin Umayyah radliyallahu'anhu) berkata; 'Wahai Rasulullah saya telah memaafkannya.' (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Kalau saja itu sebelum kamu membawanya kepadaku Wahai Abu Wahb?.\" Lalu Rasulullah Shallallahu'alaihiwasallam memotongnya."},"264":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ صَفْوَانَ بْنِ أُمَيَّةَأَنَّهُ قِيلَ لَهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مَنْ هَاجَرَ قَالَ فَقُلْتُ لَا أَدْخُلُ مَنْزِلِي حَتَّى آتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْأَلَهُ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ هَذَا سَرَقَ خَمِيصَةً لِي لِرَجُلٍ مَعَهُ فَأَمَرَ بِقَطْعِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ فَإِنِّي قَدْ وَهَبْتُهَا لَهُ قَالَ فَهَلَّا قَبْلَ أَنْ تَأْتِيَنِي بِهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُمْ يَقُولُونَ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مَنْ هَاجَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا هِجْرَةَ بَعْدَ فَتْحِ مَكَّةَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ فَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [bapaknya] dari [Shafwan bin Umayyah] dikatakan kepadanya, tidak akan masuk surga kecuali orang yang berhijrah. (Shafwan bin Umayyah radliyallahu'anhu) berkata; saya tidak akan memasuki rumahku sampai saya menemui Rasulullah Shallallahu'alaihiwasallam dan menanyakannya. Lalu saya mendatangi Nabi Shallallahu'alaihiwasallam dan berkata; Wahai Rasulullah orang ini telah mencuri khomishoh (pakaian yang jahitannya ada yang terbuat dari sutra) milikku untuk temannya yang bersamanya. Lalu (Rasulullah Shallallahu'alaihiwasallam) menyuruh untuk memotongnya. Lalu saya berkata; Wahai Rasulullah, saya telah memberikan kepadanya. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Kenapa tidak kau katakan sebelum dibawa ke hadapanku?.\" (Shafwan bin Umayyah radliyallahu'anhu) berkata; 'Wahai Rasulullah, mereka mengatakan tidak akan masuk surga kecuali orang yang telah berhijrah.' Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada hijrah setelah Fathu Makkah, tapi jihad dan niat, jika kalian diminta untuk datang ke medan perang maka berangkatlah.\""},"265":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا سُلَيْمَانُ يَعْنِي التَّيْمِيَّ عَنْ أَبِي عُثْمَانَ يَعْنِي النَّهْدِيَّ عَنْ عَامِرٍ يَعْنِي ابْنَ مَالِكٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الطَّاعُونُ شَهَادَةٌ وَالْغَرَقُ شَهَادَةٌ وَالْبَطْنُ شَهَادَةٌ وَالنُّفَسَاءُ شَهَادَةٌ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami [Sulaiman] yaitu At Taimi, dari [Abu 'Utsman] yaitu An-Nahdi dari ['Amir] yaitu Ibnu Malik dari [Shafwan bin Umayyah] dari Nabi Shallallahu'alaihiwasallam bersabda: \"(korban penyakit) Thaun adalah syahid, tenggelam adalah syahid, mati karena penyakit perut adalah syahid dan orang yang meninggal karena melahirkan juga syahid.\""},"266":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ عَنْ أَبِي عُثْمَانَ عَنْ عَامِرِ بْنِ مَالِكٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَقَالَ الطَّاعُونُ وَالْبَطْنُ وَالْغَرَقُ وَالنُّفَسَاءُ شَهَادَةٌقَالَ سُلَيْمَانُ حَدَّثَنَا بِهِ يَعْنِي أَبَا عُثْمَانَ مِرَارًا وَرَفَعَهُ مَرَّةً إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Utsman] dari [Sulaiman] dari [Abu 'Utsman] dari ['Amir Bin Malik] dari [Shafwan bin Umayyah] berkata; \"(korban penyakit) Thaun adalah syahid, tenggelam adalah syahid, orang yang meninggal karena melahirkan juga syahid.\" Sulaiman berkata; telah menceritakannya kepada kami yaitu Abu 'Utsman berkali-kali dan sesekali memarfu'kannya kepada Nabi Shallallahu'alaihiwasallam."},"267":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَ قَالَ قَالَ صَفْوَانُ بْنُ أُمَيَّةَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا آخُذُ اللَّحْمَ عَنْ الْعَظْمِ بِيَدِي فَقَالَ يَا صَفْوَانُ قُلْتُ لَبَّيْكَ قَالَ قَرِّبْ اللَّحْمَ مِنْ فِيكَ فَإِنَّهُ أَهْنَأُ وَأَمْرَأُ","id":"Telah menceritakan kepada kami [Isma'il Bin Ibrahim] telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Abdurrahman bin Mu'awiyah] dari ['Utsman bin Abu Sulaiman] berkata; [Shafwan bin Umayyah] berkata; Rasulullah Shallallahu'alaihiwasallam melihatku ketika saya sedang mengambil daging dari tulangnya dengan tanganku, lalu bersabda: \"Wahai Shafwan\" saya menjawab 'Ya.' Beliau bersabda: \"Dekatkanlah daging dari mulutmu, itu lebih lezat dan lebih bermanfaat.\""},"268":{"ar":"حَدَّثَنَا هُشَيْمُ بْنُ بَشِيرٍ عَنْ أَبِي بِشْرٍ جَعْفَرِ بْنِ إِيَاسٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ يَأْتِينِي الرَّجُلُ يَسْأَلُنِي الْبَيْعَ لَيْسَ عِنْدِي مَا أَبِيعُهُ ثُمَّ أَبِيعُهُ مِنْ السُّوقِ فَقَالَ لَا تَبِعْ مَا لَيْسَ عِنْدَكَ","id":"Telah menceritakan kepada kami [Husyaim bin Basyir] dari [Abu Bisr Ja'far bin Iyas] dari [Yusuf bin Mahak] dari [Hakim bin Hizam] berkata; wahai Rasulullah! ada seorang laki-laki yang datang kepadaku dan memintaku untuk menjual sesuatu yang bukan hakku untuk menjualnya, kemudian saya menjualnya di pasar, maka (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Janganlah kamu menjual sesuatu yang bukan hak kamu.\""},"269":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ يُحَدِّثُ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْ لَا أَخِرَّ إِلَّا قَائِمًا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ الرَّجُلُ يَسْأَلُنِي الْبَيْعَ وَلَيْسَ عِنْدِي أَفَأَبِيعُهُ قَالَ لَا تَبِعْ مَا لَيْسَ عِنْدَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Yusuf bin Mahak] menceritakan dari [Hakim bin Hizam] berkata; saya berbaiat kepada Rasulullah Shallallahu'alaihiwasallam untuk tidak akan meninggal kecuali dalam keadaan menegakkan Islam. (Hakim bin Hizam Radliyallahu'anhu) berkata; Wahai Rasulullah, seseorang memintaku untuk menjual kepadanya yang bukan milikku, apakah saya harus menjualnya?. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Janganlah kau jual barang yang bukan milikmu!\""},"270":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَيُّوبُ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَبِيعَ مَا لَيْسَ عِنْدِي قَالَ أَيُّوبُ أَوْ قَالَ سِلْعَةً لَيْسَتْ عِنْدِي","id":"Telah menceritakan kepada kami [Isma'il Bin Ibrahim] telah mengabarkan kepada kami [Ayyub] dari [Yusuf Bin Mahak] dari [Hakim bin Hizam] berkata; Rasulullah Shallallahu'alaihiwasallam melarangku menjual apa yang bukan milikku. Ayyub berkata; atau bersabda: \"Dagangan yang bukan milikku.\""},"271":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ شُعْبَةَ حَدَّثَنَا أَبُو بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ يُطْلَبُ مِنِّي الْمَتَاعُ وَلَيْسَ عِنْدِي أَفَأَبِيعُهُ لَهُ قَالَ لَا تَبِعْ مَا لَيْسَ عِنْدَكَ","id":"Telah menceritakan kepada kami [Yahya bin 'Adam] dari [Syu'bah] telah menceritakan kepada kami [Abu Bisyr] dari [Yusuf Bin Mahak] dari [Hakim Bin Hizam] berkata; Wahai Rasulullah, saya membawa dagangan dan mau dibeli seseorang, padahal itu bukan milikku apakah saya boleh menjualnya untuk pemiliknya?. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Janganlah kau jual barang yang bukan milikmu.\""},"272":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا هِشَامٌ يَعْنِي الدَّسْتُوَائِيَّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ رَجُلٍ أَنَّ يُوسُفَ بْنَ مَاهَكَ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَصْمَةَ أَخْبَرَهُ أَنَّ حَكِيمَ بْنَ حِزَامٍ أَخْبَرَهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَشْتَرِي بُيُوعًا فَمَا يَحِلُّ لِي مِنْهَا وَمَا يُحَرَّمُ عَلَيَّ قَالَ فَإِذَا اشْتَرَيْتَ بَيْعًا فَلَا تَبِعْهُ حَتَّى تَقْبِضَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Hisyam] yaitu Ad Dastuwa'i, telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [seseorang] [Yusuf Bin Mahak] mengabarinya, [Abdullah bin 'Ashmar] mengabarinya, [Hakim Bin Hizam] mengabarinya. (Hakim Bin Hizam Radliyallahu'anhu) berkata; Wahai Rasulullah, saya telah membeli dagangan, mana yang halal bagiku dan mana yang haram bagiku?. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Jika kamu membeli barang janganlah kau jual lagi sehingga kau membawanya.\" "},"273":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ أُمُورًا كُنْتُ أَتَحَنَّثُ بِهَا فِي الْجَاهِلِيَّةِ مِنْ عَتَاقَةٍ وَصِلَةِ رَحِمٍ هَلْ لِي فِيهَا أَجْرٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمْتَ عَلَى مَا أَسْلَفْتَ مِنْ خَيْرٍ","id":"Telah menceritakan kepada kami [Abdurrozaq] telah menceritakan kepada kami [Ma'mar] dari [Az-Zuhri] dari ['Urwah Az-Zubair] dari [Hakim bin Hizam] berkata; Wahai Rasulullah, bagaimana pendapat anda tentang perkara-perkara kebaikan yang pernah saya lakukan pada masa Jahiliyyah seperti memerdekakan budak dan menyambung kekerabatan, apakah saya mendapatkan pahala darinya? Nabi Shallallahu'alaihiwasallam bersabda kepadanya, \"Setelah kamu masuk Islam, kamu akan mendapatkan pahala atas kebaikan yang pernah kamu lakukan.\""},"274":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ حَكِيمَ بْنَ حِزَامٍ أَخْبَرَهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ أُمُورًا كُنْتُ أَتَحَنَّثُ بِهَا فِي الْجَاهِلِيَّةِ فَقَالَ أَسْلَمْتَ عَلَى مَا أَسْلَفْتَ وَالتَّحَنُّثُ التَّعَبُّدُ","id":"Telah menceritakan kepada kami ['Utsman bin 'Umar] telah mengabarkan kepada kami [Yunus] dari [Az-Zuhri] dari ['Urwah] [Hakim bin Hizam] mengabarinya, berkata; Wahai Rasulullah, bagaimana pendapat anda tentang perkara-perkara kebaikan yang pernah saya lakukan pada masa Jahiliyyah?. (Nabi Shallallahu'alaihiwasallam) bersabda: \"Setelah kamu masuk Islam, kamu akan mendapatkan pahala atas apa yang pernah kamu lakukan\" dan tahannuts adalah beribadah."},"275":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ سُلَيْمَانَ حَدَّثَنَا عَبَّادٌ يَعْنِي ابْنَ الْعَوَّامِ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ أَيُّوبَ بْنِ بَشِيرٍ الْأَنْصَارِيِّ عَنْ حَكِيمِ بْنِ حِزَامٍأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّدَقَاتِ أَيُّهَا أَفْضَلُ قَالَ عَلَى ذِي الرَّحِمِ الْكَاشِحِ","id":"Telah menceritakan kepada kami Abdullah berkata; saya telah mendapatkan dalam tulisan bapakku dengan tulisan dia sendiri, telah menceritakan kepada kami [Sa'id] yaitu Ibnu Sulaiman, telah menceritakan kepada kami ['Abbad] yaitu Ibnu Al 'Awwam, dari [Sufyan bin Husain] dari [Az-Zuhri] dari [Ayyub bin Bisyr Al Anshori] dari [Hakim bin Hizam] ada seorang laki-laki yang bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang sedekah mana yang paling afdhal? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Sedekah atas sanak keluarga yang membutuhkan.\""},"276":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ حَكِيمِ بْنِ حِزَامٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَذَبَا وَكَتَمَا مُحِقَتْ بَرَكَةُ بَيْعِهِمَا","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Qatadah] dari [Abu Al kholil] dari [Abdullah bin Al Harits bin Nufail] dari [Hakim bin Hizam] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kedua orang yang melakukan akad jual beli berhak khiyar (pilihan antara mengambil barang atau mengembalikannya karena adanya cacat) selama keduanya belum berpisah. Jika keduanya jujur dan menjelaskan barangnya maka keduanya akan di berkahi pada jual belinya, namun jika keduanya berdusta dan menyembunyikan maka barakah jual belinya akan dihapus.\""},"277":{"ar":"حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ مُبَارَكٍ أَخْبَرَنَا لَيْثُ بْنُ سَعْدٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ الْمُغِيرَةِ عَنْ عِرَاكِ بْنِ مَالِكٍ أَنَّ حَكِيمَ بْنَ حِزَامٍ قَالَكَانَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبَّ رَجُلٍ فِي النَّاسِ إِلَيَّ فِي الْجَاهِلِيَّةِ فَلَمَّا تَنَبَّأَ وَخَرَجَ إِلَى الْمَدِينَةِ شَهِدَ حَكِيمُ بْنُ حِزَامٍ الْمَوْسِمَ وَهُوَ كَافِرٌ فَوَجَدَ حُلَّةً لِذِي يَزَنَ تُبَاعُ فَاشْتَرَاهَا بِخَمْسِينَ دِينَارًا لِيُهْدِيَهَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدِمَ بِهَا عَلَيْهِ الْمَدِينَةَ فَأَرَادَهُ عَلَى قَبْضِهَا هَدِيَّةً فَأَبَى قَالَ عُبَيْدُ اللَّهِ حَسِبْتُ أَنَّهُ قَالَ إِنَّا لَا نَقْبَلُ شَيْئًا مِنْ الْمُشْرِكِينَ وَلَكِنْ إِنْ شِئْتَ أَخَذْنَاهَا بِالثَّمَنِ فَأَعْطَيْتُهُ حِينَ أَبَى عَلَيَّ الْهَدِيَّةَ","id":"Telah menceritakan kepada kami ['Attab bin Ziyad] telah menceritakan kepada kami [Abdullah] yaitu Ibnu Mubarok, telah menceritakan kepada kami [Laits bin Sa'd] telah menceritakan kepadaku ['Ubaidullah bin Al Mugirah] dari ['Irak bin Malik] [Hakim bin Hizam] berkata; Muhammad Shallallahu'alaihiwasallam adalah orang paling saya cintai pada masa Jahiliyyah. Ketika dia mencari berita dengan keluar menuju Madinah, Hakim bin Hizam mengikuti haji padahal dia masih kafir, maka dia menemukan baju Dziyazan yang sedang dijual lalu dia membelinya dengan lima puluh dinar, untuk dihadiahkan kepada Rasulullah Shallallahu'alaihiwasallam. Dia membawanya ke Madinah dengan maksud memberikannya dan berharap beliau menerimanya sebagai hadiah namun beliau menolak. 'Ubaidillah berkata; saya kira dia berkata; \"kami tidak menerima sesuatu dari orang musyrik, namun jika kamu mau, saya akan mengambilnya dengan membayarkan uang.\" (Hizam Radliyallahu'anhu berkata), lalu saya tetap memberikannya ketika beliau menolak hadiah dari saya."},"278":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنِ ابْنِ حِزَامٍأَنَّهُ مَرَّ بِأُنَاسٍ مِنْ أَهْلِ الذِّمَّةِ قَدْ أُقِيمُوا فِي الشَّمْسِ بِالشَّامِ فَقَالَ مَا هَؤُلَاءِ قَالُوا بَقِيَ عَلَيْهِمْ شَيْءٌ مِنْ الْخَرَاجِ فَقَالَ إِنِّي أَشْهَدُ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُعَذِّبُ يَوْمَ الْقِيَامَةِ الَّذِينَ يُعَذِّبُونَ النَّاسَقَالَ وَأَمِيرُ النَّاسِ يَوْمَئِذٍ عُمَيْرُ بْنُ سَعْدٍ عَلَى فِلَسْطِينَ قَالَ فَدَخَلَ عَلَيْهِ فَحَدَّثَهُ فَخَلَّى سَبِيلَهُمْ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ هِشَامِ بْنِ حَكِيمٍ أَنَّهُ مَرَّ بِالشَّامِ عَلَى قَوْمٍ مِنْ الْأَنْبَاطِ وَقَدْ أُقِيمُوا فِي الشَّمْسِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari [Ibnu Hizam] dia pernah melewati orang-orang dzimmi yang dijemur di bawah matahari di Syam. Lalu dia bertanya, ada apa dengan mereka? Mereka menjawab, mereka masih memiliki tanggungan khoroj (pajak yang dibebankan kepada para orang kafir yang berada di bawah kekuasaan Islam). Lalu (Hakim bin Hizam Radliyallahu'anhuma) berkata; saya bersaksi saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah 'Azzawajalla pada Hari Kiamat menyiksa orang-orang yang menyiksa manusia\" (Hisyam Radliyallahu'anhu) berkata; Amir mereka di Palestina pada waktu itu adalah 'Umair bin Sa'ad. Hisyam berkata; lalu (Hakim Radliyallahu'anhu) menemuinya dan menceritakannnya hingga melepaskan mereka. Telah berbicara kepada kami [Ibnu Numair] telah berbicara kepada kami [Hisyam] dari [bapaknya] dari [Hisyam bin Hakim] dia melewati sebuah kaum dari Anbath di Syam yang dijemur di bawah terik matahari, lalu ia menyebutkan makna hadits (seperti yang di atas)."},"279":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ وَهِشَامِ بْنِ عُرْوَةَ أَنَّهُمَا حَدَّثَاهُ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِأَنَّ هِشَامَ بْنَ حَكِيمٍ رَأَى نَاسًا مِنْ أَهْلِ الذِّمَّةِ قِيَامًا فِي الشَّمْسِ فَقَالَ مَا هَؤُلَاءِ فَقَالُوا مِنْ أَهْلِ الْجِزْيَةِ فَدَخَلَ عَلَى عُمَيْرِ بْنِ سَعْدٍ وَكَانَ عَلَى طَائِفَةِ الشَّامِ فَقَالَ هِشَامٌ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ عَذَّبَ النَّاسَ فِي الدُّنْيَا عَذَّبَهُ اللَّهُ تَبَارَكَ وَتَعَالَىفَقَالَ عُمَيْرٌ خَلُّوا عَنْهُمْ","id":"Telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az-Zuhri] dan [Hisyam bin 'Urwah] keduanya menceritakannya dari ['Urwah bin Zubair] dari [Hisyam bin Hakim] melihat beberapa orang dari ahli Dzimmah dijemur di bawah Matahari. Lalu dia bertanya, siapakah mereka?. Mereka menjawab, dari ahlu jizyah. Lalu dia menemui 'Umair bin Sa'd, dia sedang berada di Syam. Hisyam berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barang siapa yang menyiksa manusia di dunia, maka Allah subhanahu wata'ala akan menyiksanya. Umair berkata; lepaskankanlah mereka."},"280":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ حَدَّثَنِي شُرَيْحُ بْنُ عُبَيْدٍ الْحَضْرَمِيُّ وَغَيْرُهُ قَالَجَلَدَ عِيَاضُ بْنُ غَنْمٍ صَاحِبَ دَارِيَا حِينَ فُتِحَتْ فَأَغْلَظَ لَهُ هِشَامُ بْنُ حَكِيمٍ الْقَوْلَ حَتَّى غَضِبَ عِيَاضٌ ثُمَّ مَكَثَ لَيَالِيَ فَأَتَاهُ هِشَامُ بْنُ حَكِيمٍ فَاعْتَذَرَ إِلَيْهِ ثُمَّ قَالَ هِشَامٌ لِعِيَاضٍ أَلَمْ تَسْمَعْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مِنْ أَشَدِّ النَّاسِ عَذَابًا أَشَدَّهُمْ عَذَابًا فِي الدُّنْيَا لِلنَّاسِ فَقَالَ عِيَاضُ بْنُ غَنْمٍ يَا هِشَامُ بْنَ حَكِيمٍ قَدْ سَمِعْنَا مَا سَمِعْتَ وَرَأَيْنَا مَا رَأَيْتَ أَوَلَمْ تَسْمَعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَرَادَ أَنْ يَنْصَحَ لِسُلْطَانٍ بِأَمْرٍ فَلَا يُبْدِ لَهُ عَلَانِيَةً وَلَكِنْ لِيَأْخُذْ بِيَدِهِ فَيَخْلُوَ بِهِ فَإِنْ قَبِلَ مِنْهُ فَذَاكَ وَإِلَّا كَانَ قَدْ أَدَّى الَّذِي عَلَيْهِ لَهُوَإِنَّكَ يَا هِشَامُ لَأَنْتَ الْجَرِيءُ إِذْ تَجْتَرِئُ عَلَى سُلْطَانِ اللَّهِ فَهَلَّا خَشِيتَ أَنْ يَقْتُلَكَ السُّلْطَانُ فَتَكُونَ قَتِيلَ سُلْطَانِ اللَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Abu Al Mughiroh] telah menceritakan kepada kami [Shafwan] telah menceritakan kepadaku [Syuraih bin 'Ubaid Al Hadlromi] dan yang lainnya berkata; ['Iyadl bin Ghonim] mencambuk orang Dariya ketika ditaklukkan. [Hisyam bin Hakim] meninggikan suaranya kepadanya untuk menegur sehingga 'Iyadl marah. ('Iyadl Radliyallahu'anhu) tinggal beberapa hari, lalu Hisyam bin Hakim mendatanginya, memberikan alasan. Hisyam berkata kepada 'Iyadl, tidakkah kau mendengar Nabi Shallallahu'alaihiwasallam bersabda: \" Orang yang paling keras siksaannya adalah orang-orang yang paling keras menyiksa manusia di dunia?.\" 'Iyadl bin ghanim berkata; Wahai Hisyam bin Hakim, kami pernah mendengar apa yang kau dengar dan kami juga melihat apa yang kau lihat, namun tidakkah kau mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang hendak menasehati penguasa dengan suatu perkara, maka jangan dilakukan dengan terang-terangan, tapi gandenglah tangannya dan menyepilah berdua. Jika diterima memang begitu, jika tidak maka dia telah melaksakan kewajibannya\", kamu Wahai Hisyam, kamu sungguh orang yang berani, jika kamu berani kepada penguasa Allah, kenapa kamu tidak takut dibunuh penguasa dan kau menjadi korban penguasa Allah subhanahu wata'ala?. "},"281":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ أَخْبَرَنَا يُونُسُ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّهُ بَلَغَهُأَنَّ عِيَاضَ بْنَ غَنْمٍ رَأَى نَبَطًا يُشَمَّسُونَ فِي الْجِزْيَةِ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ النَّاسَ فِي الدُّنْيَا","id":"Telah menceritakan kepada kami ['Utsman bin 'Umar] berkata; telah mengabarkan kepada kami [Yunus] dari [Az-Zuhri] dari ['Urwah] telah sampai kepadanya [dari seseorang] bahwa, ['Iyadl bin Ghanim] melihat rakyat jelata yang dijemur karena masalah jizyah. Lalu berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah subhanahu wata'ala menyiksa orang yang menyiksa manusia di dunia.\""},"282":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنِ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِأَنَّ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ وَجَدَ عِيَاضَ بْنَ غَنْمٍ وَهُوَ عَلَى حِمْصَ يُشَمِّسُ نَاسًا مِنْ النَّبَطِ فِي أَدَاءِ الْجِزْيَةِ فَقَالَ لَهُ هِشَامٌ مَا هَذَا يَا عِيَاضُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ النَّاسَ فِي الدُّنْيَا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syua'ib] dari [Az-Zuhri] telah mengabarkan kepadaku ['Urwah bin Az-Zubair] [Hisyam bin Hakim bin Hizam] mendapatkan 'Iyadl bin Ghanim di Himsh menjemur rakyat jelata dalam masalah pembayaran jizyah, lalu Hisyam berkata kepadanya, Wahai 'Iyadl, saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah subhanahu wata'ala menyiksa orang yang menyiksa manusia di dunia.\""},"283":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِأَنَّ عِيَاضَ بْنَ غَنْمٍ وَهِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ مَرَّا بِعَامِلِ حِمْصَ وَهُوَ يُشَمِّسُ أَنْبَاطًا فِي الشَّمْسِ فَقَالَ أَحَدُهُمَا لِلْعَامِلِ مَا هَذَا يَا فُلَانُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ النَّاسَ فِي الدُّنْيَا","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [anak saudara Ibnu Syihab] dari [pamannya] berkata; telah mengabarkan kepadaku ['Urwah bin Az-Zubair] ['Iyadl bin Ghonm] dan [Hisyam bin Hakim bin Hizam] melewati pejabat Himsh yang sedang mennjemur rakyat jelata di matahari, lalu salah satunya berkata kepada pejabat tadi, kenapa itu wahai fulan saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Allah subhanahu wata'ala akan menyiksa orang yang menyiksa manusia di dunia.\""},"284":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ رَبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ مُتْعَةِ النِّسَاءِ يَوْمَ الْفَتْحِ","id":"Telah menceritakan kepada kami [Isma'il Bin Ibrahim] telah menceritakan kepada kami [Ma'mar] dari [Az-Zuhri] dari [Rabi' bin Sabrah] dari [Bapaknya] Rasulullah Shallallahu'alaihiwasallam melarang menikahi wanita secara Mut'ah pada peristiwa Fathu Makkah."},"285":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ الرَّبِيعِ بْنِ سَبْرَةَ الْجُهَنِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَلَغَ الْغُلَامُ سَبْعَ سِنِينَ أُمِرَ بِالصَّلَاةِ فَإِذَا بَلَغَ عَشْرًا ضُرِبَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Zaid bin Al Habhab] telah menceritakan kepadaku [Abdul Malik bin Rabi' bin Sabrah Al Juhani] dari [bapaknya] dari [kakeknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Apabila seorang anak telah mencapai tujuh tahun, maka ia diperintahkan untuk shalat, dan apabila ia telah mencapai sepuluh tahun, maka ia dipukul untuk shalat.\""},"286":{"ar":"حَدَّثَنَا زَيْدٌ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ فَلْيَسْتَتِرْ لِصَلَاتِهِ وَلَوْ بِسَهْمٍ","id":"Telah menceritakan kepada kami [Zaid] telah mengabarkan kepadaku [Abdul Malik bin Rabi' bin Sabrah] dari [bapaknya] dari [kakeknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika salah satu dari kalian shalat, ambillah pembatas di depannya walau dengan anak panah.\""},"287":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُتْرَةُ الرَّجُلِ فِي الصَّلَاةِ السَّهْمُ وَإِذَا صَلَّى أَحَدُكُمْ فَلْيَسْتَتِرْ بِسَهْمٍ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Abdul Malik bin Rabi' bin Sabrah] dari [Bapaknya] dari [kakeknya] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Pembatas laki-laki dalam shalatnya adalah anak panah, jika salah seorang diantara kalian shalat, ambillah anak panah sebagai pembatas.\""},"288":{"ar":"قَالَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُصَلِّيَ فِي أَعْطَانِ الْإِبِلِ وَرَخَّصَ أَنْ نُصَلِّيَ فِي مُرَاحِ الْغَنَمِ وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُتْعَةِ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Abdul Malik bin Rabi' bin Sabrah] dari [Bapaknya] dari [Kakeknya] dia berkata; Rasulullah Shallallahu'alaihiwasallam melarang kita shalat di kandang unta dan memberi keringanan untuk Shalat di kandang kambing. Rasulullah Shallallahu'alaihiwasallam juga melarang nikah Mut'ah."},"289":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا عُمَارَةُ بْنُ غَزِيَّةَ الْأَنْصَارِيُّ قَالَ حَدَّثَنَا الرَّبِيعُ بْنُ سَبْرَةَ الْجُهَنِيُّ عَنْ أَبِيهِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ فَأَقَمْنَا خَمْسَ عَشْرَةَ مِنْ بَيْنِ لَيْلَةٍ وَيَوْمٍ قَالَ قَالَ فَأَذِنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُتْعَةِ قَالَ وَخَرَجْتُ أَنَا وَابْنُ عَمٍّ لِي فِي أَسْفَلِ مَكَّةَ أَوْ قَالَ فِي أَعْلَى مَكَّةَ فَلَقِينَا فَتَاةً مِنْ بَنِي عَامِرِ بْنِ صَعْصَعَةَ كَأَنَّهَا الْبَكْرَةُ الْعَنَطْنَطَةُ قَالَ وَأَنَا قَرِيبٌ مِنْ الدَّمَامَةِ وَعَلَيَّ بُرْدٌ جَدِيدٌ غَضٌّ وَعَلَى ابْنِ عَمِّي بُرْدٌ خَلَقٌ قَالَ فَقُلْنَا لَهَا هَلْ لَكِ أَنْ يَسْتَمْتِعَ مِنْكِ أَحَدُنَا قَالَتْ وَهَلْ يَصْلُحُ ذَلِكَ قَالَ قُلْنَا نَعَمْ قَالَ فَجَعَلَتْ تَنْظُرُ إِلَى ابْنِ عَمِّي فَقُلْتُ لَهَا إِنَّ بُرْدِي هَذَا جَدِيدٌ غَضٌّ وَبُرْدَ ابْنِ عَمِّي هَذَا خَلَقٌ مَحٌّ قَالَتْ بُرْدُ ابْنِ عَمِّكَ هَذَا لَا بَأْسَ بِهِ قَالَ فَاسْتَمْتَعَ مِنْهَا فَلَمْ نَخْرُجْ مِنْ مَكَّةَ حَتَّى حَرَّمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] berkata; telah menceritakan kepada kami ['Umaroh bin Ghoziyyah Al Anshori] berkata; telah menceritakan kepada kami [Rabi' bin Sabrah Al Juhani] dari [Bapaknya] berkata; Kami berangkat bersama Rasulullah Shallallahu'alaihiwasallam pada Fathu Makkah. Kami tinggal selama lima belas hari dan satu malam. (Rabi' bin Sabrah Al Juhani Radliyallahu'anhu) berkata; (Bapaknya) berkata; Rasulullah Shallallahu'alaihiwasallam mengijinkan nikah Mut'ah. Saya dan anak pamanku keluar ke daerah yang rendah di Makkah atau daerah yang tinggi, lalu kami bertemu seorang wanita muda dari Bani 'Amir bin Sho'sho'ah, sepertinya dia adalah unta muda yang sangat bagus dan berleher panjang (maksudnya gadis belia yang berperawakan menarik). Saya orang termasuk orang buruk rupa, namun saya memakai mantel baru yang sangat bagus, sedang anak pamanku membawa mantel yang sudah usang. Kami mengatakan kepadanya, maukah kau menikah mut'ah dengan salah satu dari kami? Lalu wanita itu bertanya, apakah hal itu boleh? Ya, jawabku. Lalu dia melihat ke anak pamanku, lalu saya katakan kepadanya, mantelku ini baru dan bagus sedangkan mantel anak pamanku itu sudah usang dan lusuh. (wanita itu) berkata; mantel anak pamanmu itu tidak masalah. Lalu (anak pamannya) menikahinya secara mut'ah. Kami tidak berangkat lagi ke Makkah sampai Rasulullah Shallallahu'alaihiwasallam mengharamkannya."},"290":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَبْدَ رَبِّهِ بْنَ سَعِيدٍ يُحَدِّثُ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنِ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ يُقَالُ لَهُ السَّبْرِيُّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَمَرَهُمْ بِالْمُتْعَةِ قَالَ فَخَطَبْتُ أَنَا وَرَجُلٌ امْرَأَةً قَالَ فَلَقِيتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ثَلَاثٍ فَإِذَا هُوَ يُحَرِّمُهَا أَشَدَّ التَّحْرِيمِ وَيَقُولُ فِيهَا أَشَدَّ الْقَوْلِ وَيَنْهَى عَنْهَا أَشَدَّ النَّهْيِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] berkata; saya telah mendengar ['Abdu rabbihi bin Sa'id] menceritakan dari [Abdul Aziz bin 'Umar bin Abdul Aziz] dari [Rabi' bin Sabrah] dari [Bapaknya] yang bernama As-Sabri dari Nabi Shallallahu'alaihiwasallam beliau menyuruh mereka nikah Mut'ah. (Bapak Rabi') berkata; lantas saya dan seorang temanku melamar seorang wanita. Lalu saya bertemu Nabi Shallallahu'alaihiwasallam setelah tiga hari, ternyata beliau telah mengharamkannya dengan sangat, mengatakannya dengan sangat serius dan melarangnya dengan larangan yang keras."},"291":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُصَلَّى فِي أَعْطَانِ الْإِبِلِ وَرَخَّصَ أَنْ يُصَلَّى فِي مُرَاحِ الْغَنَمِ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Abdul Malik bin Rabi' bin Sabrah] dari [Bapaknya] dari [kakeknya] Rasulullah Shallallahu'alaihiwasallam melarang Shalat di kandang unta dan memberi keringanan Shalat di kandang kambing."},"292":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنِ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِكَاحِ الْمُتْعَةِ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az-Zuhri] dari [Rabi' bin Sabrah] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam melarang nikah Mut'ah (menikahi wanita untuk jangka waktu tertentu)."},"293":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ قَالَ أَخْبَرَنِي الرَّبِيعُ بْنُ سَبْرَةَ الْجُهَنِيُّ عَنْ أَبِيهِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَضَيْنَا عُمْرَتَنَا قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَمْتِعُوا مِنْ هَذِهِ النِّسَاءِ قَالَ وَالِاسْتِمْتَاعُ عِنْدَنَا يَوْمُ التَّزْوِيجِ قَالَ فَعَرَضْنَا ذَلِكَ عَلَى النِّسَاءِ فَأَبَيْنَ إِلَّا أَنْ يُضْرَبَ بَيْنَنَا وَبَيْنَهُنَّ أَجَلًا قَالَ فَذَكَرْنَا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ افْعَلُوا فَانْطَلَقْتُ أَنَا وَابْنُ عَمٍّ لِي وَمَعَهُ بُرْدَةٌ وَمَعِي بُرْدَةٌ وَبُرْدَتُهُ أَجْوَدُ مِنْ بُرْدَتِي وَأَنَا أَشَبُّ مِنْهُ فَأَتَيْنَا امْرَأَةً فَعَرَضْنَا ذَلِكَ عَلَيْهَا فَأَعْجَبَهَا شَبَابِي وَأَعْجَبَهَا بُرْدُ ابْنِ عَمِّي فَقَالَتْ بُرْدٌ كَبُرْدٍ قَالَ فَتَزَوَّجْتُهَا فَكَانَ الْأَجَلُ بَيْنِي وَبَيْنَهَا عَشْرًا قَالَ فَبِتُّ عِنْدَهَا تِلْكَ اللَّيْلَةَ ثُمَّ أَصْبَحْتُ غَادِيًا إِلَى الْمَسْجِدِ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْبَابِ وَالْحَجَرِ يَخْطُبُ النَّاسَ يَقُولُ أَلَا أَيُّهَا النَّاسُ قَدْ كُنْتُ أَذِنْتُ لَكُمْ فِي الِاسْتِمْتَاعِ مِنْ هَذِهِ النِّسَاءِ أَلَا وَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قَدْ حَرَّمَ ذَلِكَ إِلَى يَوْمِ الْقِيَامَةِ فَمَنْ كَانَ عِنْدَهُ مِنْهُنَّ شَيْءٌ فَلْيُخَلِّ سَبِيلَهَا وَلَا تَأْخُذُوا مِمَّا آتَيْتُمُوهُنَّ شَيْئًا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abdul Aziz] berkata; telah mengabarkan kepadaku [Rabi' bin Sabrah Al Juhani] dari [Bapaknya] berkata; kami keluar bersama Rasulullah Shallallahu'alaihiwasallam. Setelah kami melaksanakan Umrah, Rasulullah Shallallahu'alaihiwasallam bersabda kepada kami, \"Nikahilah para wanita itu dengan cara mut'ah (nikah dalam jangka waktu tertentu).\" (Sabrah Al Juhani Radliyallahu'anhu) berkata; istimta' menurut kami adalah hari pernikahan. Lalu kami menawarkan hal itu kepada para wanita, namun mereka menolaknya kecuali ditentukan jangka waktunya. Lalu hal ltu kami sampaikan kepada Nabi Shallallahu'alaihiwasallam. Beliau bersabda: \"Lakukanlah\", lalu saya berangkat bersama dengan anak pamanku dengan membawa mantel, namun mantelnya lebih baik daripada mantelku, hanya saya lebih muda darinya. Kami menemui wanita dan menawarkan diri kami, ternyata dia suka dengan kemudaanku namun dia juga suka dengan mantel temanku. (wanita itu) berkata; mantel itu sebagaimana mantel yang lainnya. Lalu saya menikahinya, dengan masa waku sepuluh hari. Saya tinggal bersama dengannya pada malam itu, lalu pada pagi hari saya berangkat ke masjid, ternyata Rasulullah Shallallahu'alaihiwasallam sedang berada di antara pintu dan kamar, beliau berkhutbah dan bersabda: \"Ketahuilah wahai manusia, dahulu saya mengijinkan kepada kalian nikah mut'ah. Namun sekarang Allah subhanahu wata'ala telah mengharamkannya sampai Hari Kiamat. Siapa yang telah memilikinya maka lepaskanlah dan jangan kalian ambil apa yang telah kalian berikan kepada mereka sedikitpun."},"294":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ زُرَارَةَ قَالَ حَجَّاجٌ فِي حَدِيثِهِ قَالَ سَمِعْتُ زُرَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] berkata telah menceritakan kepadaku [Syu'bah] berkata; saya telah mendengar [Qatadah] menceritakan dari [Zurarah] [Hajjaj] berkata; dalam haditsnya. Berkata; saya telah mendengar [Zurarah] dari [Abdurrahman bin Abza] dari Nabi Shallallahu'alaihiwasallam berwitir dengan surat, SABBIHISMA ROBBIKAL A'LA."},"295":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ وَزُبَيْدٍ الْإِيَامِيِّ عَنْ ذَرٍّ عَنِ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا سَلَّمَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ وَرَفَعَ بِهَا صَوْتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] dan [Zubaid Al Iyami] dari [Dzar] dari [Abu Abdurrahman bin Abza] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam beliau membaca dalam witir dengan surat, Sucikanlah nama Tuhanmu yang Maha Tingi, dan Katakanlah: \"Hai orang-orang kafir dan Katakanlah: \"Dia-lah Allah, yang Maha Esa. jika telah selesai salam beliau bersabda: \"Maha Suci Raja Yang Maha Suci, Maha Suci Raja Yang Maha Suci Maha Suci Raja Yang Maha Suci\" dan mengangkat suaranya."},"296":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا هَمَّامٌ أَخْبَرَنَا قَتَادَةُ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْوِتْرِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَكَانَ إِذَا سَلَّمَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ يُطَوِّلُهَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammam] telah mengabarkan kepada kami [Qatadah] dari ['Azroh] dari [Sa'id bin Abdurrahman bin Abza] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam, beliau membaca dalam Shalat witirnya, dengan Sucikanlah nama Tuhanmu yang Maha Tingi, dan Katakanlah: \"Hai orang-orang kafir dan Katakanlah: \"Dia-lah Allah, yang Maha Esa. jika telah selesai salam beliau bersabda: \"Maha Suci Raja Yang Maha Suci\" dan memanjangkannya tiga kali."},"297":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ زُبَيْدٌ وَسَلَمَةُ أَخْبَرَانِي أَنَّهُمَا سَمِعَا ذَرًّا عَنِ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَكَانَ إِذَا سَلَّمَ يَقُولُ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا يَرْفَعُ صَوْتَهُ بِالْآخِرَةِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Syu'bah] [Zubaid] dan [Salamah] berkata; telah mengabarkan kepadaku keduanya telah mendengar [Dzar] dari [Ibnu Abdurrahman bin Abaz] dari [Bapaknya] dari Nabi Shallallahu'alaihiwasallam membaca dalam Shalat witirnya dengan Sucikanlah nama Tuhanmu yang Maha Tingi, dan Katakanlah: \"Hai orang-orang kafir dan Katakanlah: \"Dia-lah Allah, yang Maha Esa. dan jika telah selesai salam beliau bersabda: \"Maha Suci Raja Yang Maha Suci\" beliau membacanya tiga kali dengan mengangkat suaranya pada terakhirnya."},"298":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَيَقُولُ إِذَا سَلَّمَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مِرَارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari ['Azrah] dari [Sa'id bin Abdurrahman bin Abza] dari [Bapaknya] Rasulullah Shallallahu'alaihiwasallam membaca dalam Shalat witirnya dengan Sucikanlah nama Tuhanmu yang Maha Tingi, dan Katakanlah: \"Hai orang-orang kafir dan Katakanlah: \"Dia-lah Allah, yang Maha Esa. jika telah selesai salam beliau bersabda: \"Maha Suci Raja Yang Maha Suci\" tiga kali."},"299":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ زُبَيْدٍ عَنْ ذَرِّ بْنِ عَبْدِ اللَّهِ الْمُرْهِبِيِّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِقَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَإِذَا أَرَادَ أَنْ يَنْصَرِفَ مِنْ الْوِتْرِ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍ ثُمَّ يَرْفَعُ صَوْتَهُ فِي الثَّالِثَةِ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Sufyan] dari [Zubaid] dari [Dzar bin Abdullah Al Murhibi] dari [Sa'id bin Abdurrahman bin Abza] dari [Bapaknya] berkata; Nabi Shallallahu'alaihiwasallam Shalat witir dengan Sucikanlah nama Tuhanmu yang Maha Tingi (Surat Al a'la), dan Katakanlah: \"Hai orang-orang kafir (Surat alkafirun) dan Katakanlah: \"Dia-lah Allah, yang Maha Esa (surat Al ikhlas).. Jika hendak meninggalkan witirnya beliau bersabda: \"Maha Suci, Raja Yang Maha Suci\" tiga kali. Lalu mengangkat suaranya pada kali ketiganya."},"300":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ زُبَيْدٍ عَنْ ذَرٍّ الْهَمْدَانِيِّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى الْخُزَاعِيِّ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَيَقُولُ إِذَا جَلَسَ فِي آخِرِ صَلَاتِهِ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثًا يَمُدُّ بِالْآخِرَةِ صَوْتَهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Zubaid] dari [Dzar Al Hamdani] dari [Sa'id bin Abdurrahman bin Abza Al Khuza'i] dari [Bapaknya] Nabi Shallallahu'alaihiwasallam membaca dalam Shalat witirnya dengan Sucikanlah nama Tuhanmu yang Maha Tinggi (surat Al a'la), dan Katakanlah: \"Hai orang-orang kafir (surat alkafirun) dan Katakanlah: \"Dia-lah Allah, yang Maha Esa (surat Al ikhlash). dan membaca jika beliau duduk pada akhir Shalatnya, \"Maha Suci, Raja Yang Maha Suci\" membacanya tiga kali, dengan memanjangkan terakhir kalinya."},"301":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِذَا أَصْبَحَ وَإِذَا أَمْسَى أَصْبَحْنَا عَلَى فِطْرَةِ الْإِسْلَامِ وَعَلَى كَلِمَةِ الْإِخْلَاصِ وَعَلَى دِينِ نَبِيِّنَا مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى مِلَّةِ أَبِينَا إِبْرَاهِيمَ حَنِيفًا وَمَا كَانَ مِنْ الْمُشْرِكِينَ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Salamah] dari [Abdullah bin Abdurrahman bin Abza] dari [Bapaknya] Nabi Shallallahu'alaihiwasallam jika masuk waktu pagi atau masuk waktu sore memanjatkan doa \"Di waktu pagi kami memegang teguh agama Islam, diatas kalimat ikhlas, agama Nabi kita Muhammad Shallallahu'alaihiwasallam dan agama bapak kami Ibrahim, di atas jalan yang lurus, dan tidak tergolong orang-orang musrik.\""},"302":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي الْفَجْرِ فَتَرَكَ آيَةً فَلَمَّا صَلَّى قَالَ أَفِي الْقَوْمِ أُبَيُّ بْنُ كَعْبٍ قَالَ أُبَيٌّ يَا رَسُولَ اللَّهِ نُسِخَتْ آيَةُ كَذَا وَكَذَا أَوْ نُسِّيتَهَا قَالَ نُسِّيتُهَا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepada kami [Salamah bin Kuhail] dari [Dzar] dari [Sa'id bin Abdurrahman bin Abza] dari [Bapaknya] Nabi Shallallahu'alaihiwasallam Shalat fajar, dan meninggalkan satu ayat (dalam bacaanya). Tatkala selesai Shalat, beliau bersabda: \"Apakah di antara kalian ada Ubbay bin Ka'b? Ubbay berkata; Wahai Rasulullah apakah ayat begini telah dihapus) atau anda telah lupa? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Saya telah lupa.\""},"303":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنَا قَتَادَةُ عَنْ زُرَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] telah menceritakan kepada kami [Qatadah] dari [Zurarah] dari [Abdurrahman bin Abza] Nabi Shallallahu'alaihiwasallam membaca dalam Shalat witirnya dengan Sucikanlah nama Tuhanmu yang Maha Tinggi (surat Al a'la)."},"304":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ حَدَّثَنِي جَمِيلٌ أَخْبَرَنَا وَمُجَاهِدٌ عَنْ نَافِعِ بْنِ عَبْدِ الْحَارِثِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَعَادَةِ الْمَرْءِ الْجَارُ الصَّالِحُ وَالْمَرْكَبُ الْهَنِيءُ وَالْمَسْكَنُ الْوَاسِعُحَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبٍ عَنْ جَمِيلٍ عَنْ نَافِعِ بْنِ عَبْدِ الْحَارِثِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Habib bin Abu Tsabit] telah menceritakan kepadaku [Jamil] telah mengabarkan kepada kami [Mujahid] dari [Nafi' bin Abdul Harits] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Termasuk kebahagiaan seseorang adalah tetangga yang baik, kendaraan yang menyenangkan dan tempat tinggal yang luas.\" Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Habib] dari [Jamil] dari [Nafi' bin Abdul Harits] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: lalu disebutkan sama."},"305":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ قَالَ قَالَ نَافِعُ بْنُ عَبْدِ الْحَارِثِخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى دَخَلَ حَائِطًا فَقَالَ لِي أَمْسِكْ عَلَيَّ الْبَابَ فَجَاءَ حَتَّى جَلَسَ عَلَى الْقُفِّ وَدَلَّى رِجْلَيْهِ فِي الْبِئْرِ فَضُرِبَ الْبَابُ قُلْتُ مَنْ هَذَا قَالَ أَبُو بَكْرٍ قُلْتُ يَا رَسُولَ اللَّهِ هَذَا أَبُو بَكْرٍ قَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ قَالَ فَأَذِنْتُ لَهُ وَبَشَّرْتُهُ بِالْجَنَّةِ قَالَ فَدَخَلَ فَجَلَسَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْقُفِّ وَدَلَّى رِجْلَيْهِ فِي الْبِئْرِ ثُمَّ ضُرِبَ الْبَابُ فَقُلْتُ مَنْ هَذَا فَقَالَ عُمَرُ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا عُمَرُ قَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ قَالَ فَأَذِنْتُ لَهُ وَبَشَّرْتُهُ بِالْجَنَّةِ قَالَ فَدَخَلَ فَجَلَسَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْقُفِّ وَدَلَّى رِجْلَيْهِ فِي الْبِئْرِ قَالَ ثُمَّ ضُرِبَ الْبَابُ فَقُلْتُ مَنْ هَذَا قَالَ عُثْمَانُ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا عُثْمَانُ قَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ مَعَهَا بَلَاءٌ فَأَذِنْتُ لَهُ وَبَشَّرْتُهُ بِالْجَنَّةِ فَجَلَسَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْقُفِّ وَدَلَّى رِجْلَيْهِ فِي الْبِئْرِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] berkata; [Nafi' bin Abdul Harits] berkata; Saya berangkat bersama Rasulullah Shallallahu'alaihiwasallam hingga memasuki sebuah bangunan. Lalu beliau bersabda kepadaku, \"Tolong jagalah pintunya!.\" Beliau masuk lalu duduk di tepi kolam, lalu menjulurkan kedua kakinya pada kolam. Lantas ada yang mengetuk pintu, saya bertanya, siapa ini? ia berkata 'Abu Bakar.' Saya (Nafi' bin Abdul Harits Radliyallahu'anhu) berkata 'wahai Rasulullah itu Abu Bakar.' Beliau bersabda: \"Biarkan dia masuk, berilah dia kabar gembira dengan surga.\" (Nafi' bin Abdul Harits Radliyallahu'anhu) berkata; saya mengijinkannya dan saya beri kabar gembira surga, lalu (Abu Bakar radliyallahu'anhu) masuk dan duduk bersama Rasulullah Shallallahu'alaihiwasallam di tepi kolam dan ikut menjulurkan kedua kakinya pada kolam. Lalu ada yang mengetuk pintu, saya bertanya, siapa itu? Dia berkata; 'Umar. Saya berkata; Wahai Rasulullah itu adalah 'Umar. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Biarkan dia, berilah dia kabar gembira dengan surga \" (Nafi' bin Abdul Harits Radliyallahu'anhu) berkata; saya mengijinkan dia masuk dan memberinya kabar gembira surga, hingga ('Umar radliyallahu'anhu) masuk dan duduk bersama Rasulullah Shallallahu'alaihiwasallam di tepi kolam dan ikut menurunkan kedua kakinya pada kolam. Lalu ada yang mengetuk pintu lagi, maka saya bertanya, Siapa itu? Dia menjawab, 'Utsman. Saya berkata; wahai Rasulullah ini adalah 'Utsman. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Biarkan dia masuk, berilah ia kabar gembira dengan surga, dia akan mendapatkan ujian\", maka saya mengijinkannya masuk dan memberinya kabar genbira dengan surga, hingga ia duduk bersama Rasulullah Shallallahu'alaihiwasallam di tepi kolam dan ikut menjulurkan kedua kakinya pada kolam."},"306":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنِي مُوسَى بْنُ عُقْبَةَ قَالَ سَمِعْتُ أَبَا سَلَمَةَ يُحَدِّثُ وَلَا أَعْلَمُهُ إِلَّا عَنْ نَافِعِ بْنِ عَبْدِ الْحَارِثِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ حَائِطًا مِنْ حَوَائِطِ الْمَدِينَةِ فَجَلَسَ عَلَى قُفِّ الْبِئْرِ فَجَاءَ أَبُو بَكْرٍ يَسْتَأْذِنُ فَقَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ ثُمَّ جَاءَ عُمَرُ يَسْتَأْذِنُ فَقَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ ثُمَّ جَاءَ عُثْمَانُ يَسْتَأْذِنُ فَقَالَ ائْذَنْ لَهُ وَبَشِّرْهُ بِالْجَنَّةِ وَسَيَلْقَى بَلَاءً","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepadaku [Musa bin 'Uqbah] berkata; saya telah mendengar [Abu Salamah] menceritakan dan saya tidak mengetahuinya kecuali dari [Nafi' bin Abdul Harits] Pernah Rasulullah Shallallahu'alaihiwasallam masuk ke sebuah kebun yang terletak di Madinah, lalu beliau duduk di tepi sumur, lalu datanglah Abu Bakar meminta ijin. Beliau bersabda: \"Ijinkanlah dia dan berikan kabar gembira dengan surga.\" Lalu datanglah 'Umar meminta ijin juga. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ijinkanlah dia dan berikan kabar gembira dengan surga.\" Lalu datang 'Utsman meminta ijin pula. Lalu (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ijinkanlah dia dan berikan kabar gembira dengan surga dan dia akan mendapatkan cobaan.\""},"307":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنِي ابْنُ جُرَيْجٍ حَدَّثَنِي عُثْمَانُ بْنُ السَّائِبِ مَوْلَاهُمْ عَنْ أَبِيهِ السَّائِبِ مَوْلَى أَبِي مَحْذُورَةَ وَعَنْ أُمِّ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ أَنَّهُمَا سَمِعَاهُ مِنْ أَبِي مَحْذُورَةَ قَالَ أَبُو مَحْذُورَةَخَرَجْتُ فِي عَشَرَةِ فِتْيَانٍ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ أَبْغَضُ النَّاسِ إِلَيْنَا فَأَذَّنُوا فَقُمْنَا نُؤَذِّنُ نَسْتَهْزِئُ بِهِمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْتُونِي بِهَؤُلَاءِ الْفِتْيَانِ فَقَالَ أَذِّنُوا فَأَذَّنُوا فَكُنْتُ أَحَدَهُمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ هَذَا الَّذِي سَمِعْتُ صَوْتَهُ اذْهَبْ فَأَذِّنْ لِأَهْلِ مَكَّةَ فَمَسَحَ عَلَى نَاصِيَتِهِ وَقَالَ قُلْ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ مَرَّتَيْنِ وَأَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ مَرَّتَيْنِ ثُمَّ ارْجِعْ فَاشْهَدْ أَنْ لَا إِلَهَ إِلَّا اللَّهُ مَرَّتَيْنِ وَأَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ مَرَّتَيْنِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ مَرَّتَيْنِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ وَإِذَا أَذَّنْتَ بِالْأَوَّلِ مِنْ الصُّبْحِ فَقُلْ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ وَإِذَا أَقَمْتَ فَقُلْهَا مَرَّتَيْنِ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ أَسَمِعْتَقَالَ وَكَانَ أَبُو مَحْذُورَةَ لَا يَجُزُّ نَاصِيَتَهُ وَلَا يُفَرِّقُهَا لِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَيْهَا حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عُثْمَانُ بْنُ السَّائِبِ عَنْ أُمِّ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ عَنْ أَبِي مَحْذُورَةَ قَالَ لَمَّا رَجَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى حُنَيْنٍ خَرَجْتُ عَاشِرَ عَشَرَةٍ فَذَكَرَ الْحَدِيثَ إِلَّا أَنَّهُ قَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ مَرَّتَيْنِ فَقَطْ و قَالَ رَوْحٌ أَيْضًا مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Abdurrozaq] telah mengabarkan kepadaku [Ibnu Juraij] telah menceritakan kepadaku ['Utsman bin As-Sa'ib] budak mereka, dari Bapaknya [As-Sa'ib], budak Bani Mahdzurah dan dari [Ummu Abdul Malik bin Abu Mahdzurah] keduanya mendengarnya dari [Abu Mahdzurah] Abu Mahdzurah berkata; \"Saya keluar dengan sepuluh pemuda bersama Nabi Shallallahu'alaihiwasallam yang saat itu beliau adalah orang yang paling kami benci. Lalu mereka mengumandangkan adzan pada kami. Kami berdiri dan mengumandangkan adzan seraya menghinanya. Nabi Shallallahu'alaihiwasallam bersabda: \"Datangkan para pemuda itu kepadaku\" Lalu beliau bersabda: \"Adzanlah kalian\" lalu mereka mengkumandangkan adzan, saya adalah salah satu di antara mereka. Nabi Shallallahu'alaihiwasallam bersabda: \"Ya. Inilah dia suara yang saya dengar. Pergilah dan kumandangkanlah adzan kepada penduduk Makkah\", lalu beliau mengusap ubun-ubunnya (Abu Mahdzurah) dan bersabda: \"Ucapkanlah: ALLAHU AKBAR ALLAHU AKBAR, ALLAHU AKBAR ALLAHU AKBAR, ASYHADU AN LAA ILAAHA ILLA ALLAH dua kali, dan ASYHADU ANNA MUHAMMADAR RASULULLAH dua kali, kemudian ulangilah (dengan suara pelan) ASYHADU AN LAA ILAAHA ILLA ALLAH dua kali, dan ASYHADU ANNA MUHAMMADAR RASULULLAH dua kali, HAYYA 'ALAS SHOLAAH, HAYYA 'ALAS SHOLAAH, HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH dua kali, ALLAHU AKBAR ALLAHU AKBAR, LAA ILAAHA ILLA ALLAH, dan jika kamu adzan pada awal subuh maka ucapkanlah: ASSOLAATU KHOIRUN MINAN NAUM, ASSHALATU KHOIRUN MINAN NAUM, Jika mengiqomatinya maka ucapkan dua kali: QOD QOOMATIS SHOLAAAH QOD QOOMATIS SHOLAAH, apakah kamu mendengar? (Ibnu Abi Mahdzurah Radliyallahu'anhu) berkata; maka Abu Mahdzurah tidak pernah mencukur rambut ubun-ubunnya serta memotongnya karena Rasulullah Shallallahu'alaihiwasallam telah mengusapnya. Telah menceritakan kepada kami [Muhammad bin Bakar] telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Utsman bin As-Sa'ib] dari [Ummu Abdul Malik bin Abi Mahdzurah] dari [Abu Mahdzurah] dia berkata; tatkala Nabi Shallallahu'alaihiwasallam kembali ke Hunain, kami keluar bersepuluh, lalu dia menyebutkan Hadits yang sama, hanya saja dia menyebutkan bahwa Rasulullah Shallallahu'alaihiwasallam mengucapkan ALLAHU AKBAR ALLAHU AKBAR dua kali saja, dan Rauh juga berkata dua kali."},"308":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي جَعْفَرٍ قَالَ عَبْدُ الرَّحْمَنِ لَيْسَ هُوَ الْفَرَّاءَ عَنْ أَبِي سَلْمَانَ عَنْ أَبِي مَحْذُورَةَقَالَ كُنْتُ أُؤَذِّنُ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الصُّبْحِ فَإِذَا قُلْتُ حَيَّ عَلَى الْفَلَاحِ قُلْتُ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ الْأَذَانُ الْأَوَّلُ","id":"Telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Abu Ja'far] berkata; dia bukan yang Al Farra' dari [Abu Salman] dari [Abu Mahdzurah] berkata; saya mengumandangkan adzaan pada masa Nabi Shallallahu'alaihiwasallam pada Shalat subuh, jika saya baca, HAYYA 'ALAL FALAH, saya baca setelahnya AS-SOLATU KHOIRUN MIN AN-NAUM (Shalat itu lebih baik daripada tidur) AS-SOLATU KHOIRUN MIN AN-NAUM, pada adzan awal."},"309":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا الْحَارِثُ بْنُ عُبَيْدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي سُنَّةَ الْأَذَانِ فَمَسَحَ بِمُقَدَّمِ رَأْسِي وَقَالَ قُلْ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ تَرْفَعُ بِهَا صَوْتَكَ ثُمَّ تَقُولُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ مَرَّتَيْنِ تَخْفِضُ بِهَا صَوْتَكَ ثُمَّ تَرْفَعُ صَوْتَكَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ مَرَّتَيْنِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ مَرَّتَيْنِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ مَرَّتَيْنِ فَإِنْ كَانَ صَلَاةُ الصُّبْحِ قُلْتَ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ مَرَّتَيْنِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Suraij An-Nu'man] telah menceritakan kepada kami [Al Harits bin 'Ubaid] dari [Muhammad bin Abdul Malik bin Abu Mahdzurah] dari [Bapaknya] dari [kakeknya] berkata; saya bertanya Wahai Rasulullah ajarkanlah kepadaku cara adzan, lalu beliau mengusap bagian depan kepalaku dan bersabda bacalah ALLAHU AKBAR ALLAHU AKBAR, dengan mengangkat suaramu, lalu kau baca ASYHADU AN LAA ILAAHA ILLA ALLAH ASYHADU AN LAA ILAAHA ILLA ALLAH ASYHADU ANNA MUHAMMADAR RASULULLAH dua kali dengan merenadahkan suaramu, kemudia kau angkat suaramu untuk membaca ASYHADU AN LAA ILAAHA ILLA ALLAH dua kali, ASYHADU ANNA MUHAMMADAR RASULULLAH dua kali, HAYYA 'ALAS SHOLAAH, HAYYA 'ALAS SHOLAAH, HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH dua kali. Pada Shalat subuh, bacalah ASSOLAATU KHOIRUN MINAN NAUM, ASSHALATU KHOIRUN MINAN NAUM dua kali, ALLAHU AKBAR ALLAHU AKBAR LAA ILAAHA ILLA ALLAH."},"310":{"ar":"حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ وَمُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ أَنَّ عَبْدَ اللَّهِ بْنَ مُحَيْرِيزٍ أَخْبَرَهُ وَكَانَ يَتِيمًا فِي حَجْرِ أَبِي مَحْذُورَةَ قَالَ رَوْحٌ ابْنُ مِعْيَرٍ وَلَمْ يَقُلْهُ ابْنُ بَكْرٍ حِينَ جَهَّزَهُ إِلَى الشَّامِ قَالَفَقُلْتُ لِأَبِي مَحْذُورَةَ يَا عَمِّ إِنِّي خَارِجٌ إِلَى الشَّامِ وَأَخْشَى أَنْ أُسْأَلَ عَنْ تَأْذِينِكَ فَأَخْبَرَنِي أَنَّ أَبَا مَحْذُورَةَ قَالَ لَهُ نَعَمْ خَرَجْتُ فِي نَفَرٍ فَكُنَّا بِبَعْضِ طَرِيقِ حُنَيْنٍ فَقَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حُنَيْنٍ فَلَقِيَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَعْضِ الطَّرِيقِ فَأَذَّنَ مُؤَذِّنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّلَاةِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْنَا صَوْتَ الْمُؤَذِّنِ وَنَحْنُ مُتَنَكِّبُونَ فَصَرَخْنَا نَحْكِيهِ وَنَسْتَهْزِئُ بِهِ فَسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّوْتَ فَأَرْسَلَ إِلَيْنَا إِلَى أَنْ وَقَفْنَا بَيْنَ يَدَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّكُمْ الَّذِي سَمِعْتُ صَوْتَهُ قَدْ ارْتَفَعَ فَأَشَارَ الْقَوْمُ كُلُّهُمْ إِلَيَّ وَصَدَقُوا فَأَرْسَلَ كُلَّهُمْ وَحَبَسَنِي فَقَالَ قُمْ فَأَذِّنْ بِالصَّلَاةِ فَقُمْتُ وَلَا شَيْءَ أَكْرَهُ إِلَيَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا مِمَّا يَأْمُرُنِي بِهِ فَقُمْتُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْ��ِ وَسَلَّمَ فَأَلْقَى إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّأْذِينَ هُوَ نَفْسُهُ فَقَالَ قُلْ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ ثُمَّ قَالَ لِي ارْجِعْ فَامْدُدْ مِنْ صَوْتِكَ ثُمَّ قَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ ثُمَّ دَعَانِي حِينَ قَضَيْتُ التَّأْذِينَ فَأَعْطَانِي صُرَّةً فِيهَا شَيْءٌ مِنْ فِضَّةٍ ثُمَّ وَضَعَ يَدَهُ عَلَى نَاصِيَةِ أَبِي مَحْذُورَةَ ثُمَّ أَمَارَّهَا عَلَى وَجْهِهِ مَرَّتَيْنِ ثُمَّ مَرَّتَيْنِ عَلَى يَدَيْهِ ثُمَّ عَلَى كَبِدِهِ ثُمَّ بَلَغَتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُرَّةَ أَبِي مَحْذُورَةَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارَكَ اللَّهُ فِيكَ فَقُلْتُ يَا رَسُولَ اللَّهِ مُرْنِي بِالتَّأْذِينِ بِمَكَّةَ فَقَالَ قَدْ أَمَرْتُكَ بِهِ وَذَهَبَ كُلُّ شَيْءٍ كَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ كَرَاهِيَةٍ وَعَادَ ذَلِكَ مَحَبَّةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدِمْتُ عَلَى عَتَّابِ بْنِ أُسَيْدٍ عَامِلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ فَأَذَّنْتُ مَعَهُ بِالصَّلَاةِ عَنْ أَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخْبَرَنِي ذَلِكَ مَنْ أَدْرَكْتُ مِنْ أَهْلِي مِمَّنْ أَدْرَكَ أَبَا مَحْذُورَةَ عَلَى نَحْوِ مَا أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَيْرِيزٍ","id":"Telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Ibnu Juraij] dan [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abdul aziz bin Abdul Malik bin Abu Mahdzurah] [Abdullah bin Muhairiz] mengabarinya, dia adalah seorang yatim di rumah Abu Mahdzurah. Rauh berkata; Ibnu Mi'yar, dan tidak mengatakan Ibnu Bakr ketika dia mempersiapkannya ke Syam. (Abdullah bin Muhairiz Radliyallahu'anhu) berkata; Saya bertanya kepada [Abu Mahdzurah] \"Wahai pamanku, saya hendak keluar ke Syam, saya takut kalau saya ditanya tentang adzanmu, maka kabarkan kepadaku.\" Lalu Abu Mahdzurah berkata kepadanya, Ya. Saya keluar bersama beberapa orang menuju ke Hunain, lalu Rasulullah Shallallahu'alaihiwasallam kembali dari Hunain dan bertemu kami di jalan. Lalu seorang muadzin Rasulullah Shallallahu'alaihiwasallam beradzan untuk suatu Shalat, di hadapan Rasulullah Shallallahu'alaihiwasallam. Kami mendengar suara muadzin dalam keadaan berpaling. Kami berteriak mengadukannya dan mencelanya, lalu Rasulullah Shallallahu'alaihiwasallam mendengar suara itu, lalu mengutus seseorang kepada kami agar kami menghadap beliau. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapa di antara kalian yang tadi saya dengar suaranya sedemikian tinggi?\" anggota kaum memberi syarat semuanya kepadaku, dan mereka berkata apa adanya. Mereka semuanya di suruh pergi dan beliau menahanku, lalu beliau bersabda: \"Berdiri dan adzanlah untuk Shalat.\" Lalu saya berdiri, ketika itu tidak ada yang lebih saya benci daripada Rasulullah Shallallahu'alaihiwasallam ataupun apa yang beliau perintahkan. Lalu saya berdiri di depan Rasulullah Shallallahu'alaihiwasallam, lalu beliau menyampaikan cara adzan langsung. Beliau bersabda: bacalah: ALLAHU AKBAR, ALLAHU AKBAR. ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU AN LAA ILAAHA ILLA ALLAH. ASYHADU ANNA MUHAMMADAR RASULULLAH, ASYHADU ANNA MUHAMMADAR RASULULLAH. Kemudian bersabda kepadaku, Ulangi dan pandjangkan suaramu lalu beliau membaca, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU AN LAA ILAAHA ILLA ALLAH. ASYHADU ANNA MUHAMMADAR RASULULLAH, ASYHADU ANNA MUHAMMADAR RASULULLAH. HAYYA 'ALAS SHOLAAH, HAYYA 'ALAS SHOLAAH, HAYYA 'ALAL FALAAH, HAYYA 'ALAL FALAAH. ALLAHU AKBAR, ALLAHU AKBAR LAA ILAAHA ILLA ALLAH. Lalu beliau memanggilku setelah saya melakukan adzan, memberiku kantong yang berisi perak. Lalu beliau meletakkan tangannya pada ubun-ubun Abu Mahdzurah kemudian mengulanginya pada bagian wajahnya dua kali, lalu dua kali dengan kedua tangannya, lalu pada hatinya. Sampai tangan Rasulullah Shallallahu'alaihiwasallam mencapai pusar Abu Mahdzurah lalu beliau bersabda: \"Baroka allahhu fik (semoga Allah memberi berkah kepadamu).\" Lalu saya berkata kepada Rasulullah Shallallahu'alaihiwasallam, perintahkanlah saya adzan di Makkah. Beliau menjawab, ya silahkan. Maka apa yang ada pada diriku, berupa kebencian kepada Rasulullah Shallallahu'alaihiwasallam hilang, dan berubah menjadi kesukaan kepada beliau. Lalu saya menemui 'Attab bin Usaid, pekerja Rasulullah Shallallahu'alaihiwasallam di Makkah. Saya mengumandangkan adzan untuk Shalat atas perintah Rasulullah Shallallahu'alaihiwasallam. Maka angota keluargaku mengabariku siapa saja yang menjumpaiku, siapa yang menjumpai Abu Mahdzurah sebagaimana yang telah dikabarkan Abdullah bin Muhairiz kepadaku."},"311":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَامِرٌ الْأَحْوَلُ حَدَّثَنِي مَكْحُولٌ أَنَّ عَبْدَ اللَّهِ بْنَ مُحَيْرِيزٍ حَدَّثَهُ أَنَّ أَبَا مَحْذُورَةَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَهُ الْأَذَانَ تِسْعَ عَشْرَةَ كَلِمَةً وَالْإِقَامَةَ سَبْعَ عَشْرَةَ كَلِمَةً الْأَذَانُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ وَالْإِقَامَةُ مَثْنَى مَثْنَى اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami ['Amir Al Ahwal] telah menceritakan kepadaku [Makhul] [Abdullah bin Muhairiz] menceritakannya [Abu Mahdzurah] menceritakan kepadanya, Rasulullah Shallallahu'alaihiwasallam mengajarinya adzan sembilan belas kalimat dan iqomat tujuh belas kalimat. Adzan: ALLAHU AKBAR ALLAHU AKBAR. ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU AN LAA ILAAHA ILLA ALLAH. ASYHADU ANNA MUHAMMADAR RASULULLAH, ASYHADU ANNA MUHAMMADAR RASULULLAH. ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU ANNA MUHAMMADAR RASULULLAH ASYHADU ANNA MUHAMMADAR RASULULLAH. HAYYA 'ALAS SHOLAAH, HAYYA 'ALAS SHOLAAH. HAYYA 'ALAL FALAAH HAYYA 'ALAL FALAAH. ALLAHU AKBAR ALLAHU AKBAR LAA ILAAHA ILLA ALLAH. Dan iqomah dua-dua: ALLAHU AKBAR, ALLAHU AKBAR. ASYHADU AN LAA ILAAHA ILLA ALLAH, ASYHADU ANNA MUHAMMADAR RASULULLAH. HAYYA 'ALAS SHOLAAH, HAYYA 'ALAS SHOLAAH. HAYYA 'ALAL FALAAH, HAYYA 'ALAL FALAAH. QOD QOOMATIS SHALATU, QOD QOOMATIS SHALATU, ALLAHU AKBAR, ALLAHU AKBAR. LAA ILAAHA ILLA ALLAH."},"312":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ وَاصِلٍ الْأَحْدَبِ عَنْ أَبِي وَائِلٍ قَالَجَلَسْتُ إِلَى شَيْبَةَ بْنِ عُثْمَانَ فَقَالَ جَلَسَ عُمَرُ بْنُ الْخَطَّابِ فِي مَجْلِسَكَ هَذَا فَقَالَ لَقَدْ هَمَمْتُ أَنْ لَا أَدَعَ فِي الْكَعْبَةِ صَفْرَاءَ وَلَا بَيْضَاءَ إِلَّا قَسَمْتُهَا بَيْنَ النَّاسِ قَالَ قُلْتُ لَيْسَ ذَلِكَ لَكَ قَدْ سَبَقَكَ صَاحِبَاكَ لَمْ يَفْعَلَا ذَلِكَ فَقَالَ هُمَا الْمَرْءَانِ يُقْتَدَى بِهِمَا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Washil Al Ahdab] dari [Abu Wa'il] berkata; saya berada dalam dalam majlis [Syaibah bin Utsman] lalu dia (Syaibah bin Utsman radliyallahu'anhu) berkata; ['Umar bin Khattab] telah duduk dalam majlis kamu ini, lalu ('Umar bin Khattab radliyallahu'anhu) berkata; sungguh saya ingin sekali untuk tidak meninggalkan dinar dan dirham di Ka'bah kecuali saya bagikan pada manusia. (Syaibah radliyallahu'anhu) berkata; dua sahabatmu yang telah mendahului kamu tidak melakukan hal itu. Dia ('Umar bin Khattab radliyallahu'anhu) berkata; keduanya adalah orang yang harus diikuti."},"313":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ وَاصِلٍ عَنْ أَبِي وَائِلٍ قَالَجَلَسْتُ إِلَى شَيْبَةَ بْنِ عُثْمَانَ فِي هَذَا الْمَسْجِدِ فَقَالَ جَلَسَ إِلَيَّ عُمَرُ بْنُ الْخَطَّابِ مَجْلِسَكَ هَذَا فَقَالَ لَقَدْ هَمَمْتُ أَنْ لَا أَدَعَ فِيهَا صَفْرَاءَ وَلَا بَيْضَاءَ إِلَّا قَسَمْتُهَا بَيْنَ الْمُسْلِمِينَ قَالَ قُلْتُ مَا أَنْتَ بِفَاعِلٍ قَالَ لِمَ قُلْتُ لَمْ يَفْعَلْهُ صَاحِبَاكَ قَالَ هُمَا الْمَرْءَانِ يُقْتَدَى بِهِمَا","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Washil] dari [Abu Wa'il] berkata; saya duduk bersama [Syaibah bin 'Utsman], lalu dia (Syaibah bin 'Utsman radliyallahu'anhu) berkata; 'Umar bin Khattab telah duduk dalam majlis kamu ini. Dia ('Umar bin Khattab Radliyallahu'anhuma) berkata; sungguh saya ingin sekali, untuk tidak meninggalkan dinar dan dirham kecuali saya bagikan kepada kaum muslimin. (Syaibah bin 'Utsman radliyallahu'anhu) berkata; saya bertanya: kenapa kau melakukannya? saya katakan, dua sahabatmu tidak melakukannya. ('Umar bin Khattab Radliyallahu'anhu) menjawab, keduanya adalah orang yang harus diikuti."},"314":{"ar":"حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ أَبِي الْحَكَمِ أَوْ الْحَكَمِ بْنِ سُفْيَانَ الثَّقَفِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ ثُمَّ تَوَضَّأَ وَنَضَحَ فَرْجَهُحَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ قَالَ قَالَ شَرِيكٌ سَأَلْتُ أَهْلَ الْحَكَمِ بْنِ سُفْيَانَ فَذَكَرُوا أَنَّهُ لَمْ يُدْرِكْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Abu Al Hakam] atau Al Hakam bin Sufyan Ats-Tsaqofi berkata; saya pernah melihat Rasulullah Shallallahu'alaihiwasallam kencing lalu berwudhu dan memerciki kemaluannya. Telah menceritakan kepada kami Aswad bin 'Amir berkata; Syarik berkata; saya telah bertanya kepada keluarga Al Hakam bin Sufyan, maka mereka menyebutkan dia tidak bertemu Nabi Shallallahu'alaihiwasallam."},"315":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ وَجَدْتُ فِي كِتَابِ أَبِي بِخَطِّ يَدِهِ حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ رَجُلٍ مِنْ ثَقِيفٍ هُوَ الْحَكَمُ بْنُ سُفْيَانَ أَوْ سُفْيَانُ بْنُ الْحَكَمِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَالَ ثُمَّ يَعْنِي نَضَحَ فَرْجَهُ","id":"Telah menceritakan kepada kami Abdullah berkata; saya telah mendapatkan dalam kitab bapakku dengan tulisan tangannya, telah menceritakan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Mujahid] dari seorang laki-laki dari Tsaqif, yaitu Al Hakam bin Sufyan atau [Sufyan bin Al Hakam] berkata; saya pernah melihat Rasulullah Shallallahu'alaihiwasallam kencing lalu memerciki kemaluannya."},"316":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَحَسْنُ بْنُ مُوسَى قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُثْمَانَ بْنِ طَلْحَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْبَيْتَ فَصَلَّى رَكْعَتَيْنِ وِجَاهَكَ حِينَ تَدْخُلُ بَيْنَ السَّارِيَتَيْنِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Hasan bin Musa] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari ['Utsman bin Thalhah] Nabi Shallallahu'alaihiwasallam masuk Baitullah, lalu Shalat dua rekaat menghadap ke kamu ketika kamu masuk di antara dua tiang."},"317":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا خَالِدٌ عَنِ الْقَاسِمِ بْنِ رَبِيعَةَ ب��نِ جَوْشَنٍ عَنْ عُقْبَةَ بْنِ أَوْسٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ يَوْمَ فَتْحِ مَكَّةَ فَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ نَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ قَالَ هُشَيْمٌ مَرَّةً أُخْرَى الْحَمْدُ لِلَّهِ الَّذِي صَدَقَ وَعْدَهُ وَنَصَرَ عَبْدَهُ أَلَا إِنَّ كُلَّ مَأْثَرَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ تُعَدُّ وَتُدَّعَى وَكُلَّ دَمٍ أَوْ دَعْوَى مَوْضُوعَةٌ تَحْتَ قَدَمَيَّ هَاتَيْنِ إِلَّا سِدَانَةَ الْبَيْتِ وَسِقَايَةَ الْحَاجِّ أَلَا وَإِنَّ قَتِيلَ خَطَإِ الْعَمْدِ قَالَ هُشَيْمٌ مَرَّةً بِالسَّوْطِ وَالْعَصَا وَالْحَجَرِ دِيَةٌ مُغَلَّظَةٌ مِائَةٌ مِنْ الْإِبِلِ مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا وَقَالَ مَرَّةً أَرْبَعُونَ مِنْ ثَنِيَّةٍ إِلَى بَازِلِ عَامِهَا كُلُّهُنَّ خَلِفَةٌحَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُمَيْدٌ عَنِ الْقَاسِمِ بْنِ رَبِيعَةَ أَنَّهُ قَالَ فِي هَذَا الْحَدِيثِ وَإِنَّ قَتِيلَ خَطَإِ الْعَمْدِ بِالسَّوْطِ وَالْعَصَا وَالْحَجَرِ مِائَةٌ مِنْ الْإِبِلِ مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا فَمَنْ ازْدَادَ بَعِيرًا فَهُوَ مِنْ أَهْلِ الْجَاهِلِيَّةِ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ عَنِ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَرِيبٍ مِنْ ذَلِكَ إِلَّا أَنَّهُ قَالَ مِائَةٌ مِنْ الْإِبِلِ ثَلَاثُونَ حِقَّةً وَثَلَاثُونَ جَذَعَةً وَثَلَاثُونَ بَنَاتُ لَبُونٍ وَأَرْبَعُونَ ثَنِيَّةً خَلِفَةً إِلَى بَازِلِ عَامِهِ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Khalid] dari [Al Qasim bin Rabi'ah bin Jausyan] dari ['Uqbah bin Aus] dari [seorang laki-laki sahabat Nabi Shallallahu'alaihiwasallam], Nabi Shallallahu'alaihiwasallam pernah berkhutbah pada Fathu Makkah, Beliau bersabda: \"LAA ILAAHA ILLA ALLAHU WAHDAH NASHORO 'ABDAH WAHAZAMAL AHZAABA WAHDAH (tiada Ilah selain Allah semata yang menolong hamba-Nya serta yang menghancurkan tentara musuh semata).\" Husyaim berkata (dalam riwayatnya) suatu kali: ALHAMDULILLAHIL LADZI SHODAQO WA'DAH WANASHORO 'ABDAH. Ketahuilah bahwasanya setiap kebanggaan jahiliyah yang selalu dibangga-banggakan dan diagung-agungkan, dan setiap darah dan klaim-klaim jahiliyah, harus ditumpas dibawah telapak kakiku ini, kecuali kepengurusan Baitul Haram dan memberi minuman orang yang haji. Ketahuilah, pembunuh yang tidak disengaja, -Hisyam berkata (dalam riwayatnya): \"Dengan cemeti, tongkat dan batu, ada diyat yang mugholladzoh (diyat pembunuh seperti yang disengaja) adalah seratus unta, empat puluh dalam keadaan hamil, dan pada suatu kali berkata; empat puluh yang sudah berumur dua tahun sampai sembilan tahun, semuanya hamil. Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Humaid] dari [Al Qasim bin Rabi'ah] dia berkata; dalam hadits ini, pembunuh yang tidak disengaja dengan cambuk, tongkat dan batu diatnya adalah seratus unta, empat puluh di antaranya yang sedang hamil, siapa yang menambahi dengan unta maka itu termasuk orang Jahiliyyah. Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Yunus] dari [Al Qasim bin Rabi'ah] dari Nabi Shallallahu'alaihiwasallam yang mendekati hal itu kecuali tambahan, seratus unta, tiga puluh diantara hiqqoh (unta betina yang memasuki tahun ke empat), tiga puluh diantara jadza'ah (unta yang berumur antara enam bulan sampai satu tahun) dan tiga puluh diantara banat labun (unta yang memasuki umur tiga tahun) dan empat puluh di antaranya unta yang masuk tahun ke enam dan hamil sampai umur sembilan tahun."},"318":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ السَّائِبِ بْنِ عُمَرَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ السَّائِبِأَنَّ عَبْدَ اللَّهِ بْنَ السَّائِبِ كَانَ يَقُودُ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ وَيُقِيمُهُ عِنْدَ الشِّقَّةِ الثَّالِثَةِ مِمَّا يَلِي الْبَابَ مِمَّا يَلِي الْحَجَرَ فَقُلْتُ يَعْنِي الْقَائِلُ ابْنُ عَبَّاسٍ لِعَبْدِ اللَّهِ بْنِ السَّائِبِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُومُ هَاهُنَا أَوْ يُصَلِّي هَاهُنَا فَيَقُولُ نَعَمْ فَيَقُومُ ابْنُ عَبَّاسٍ فَيُصَلِّي","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'ib bin 'Umar] berkata; telah menceritakan kepadaku [Muhammad bin Abdullah bin Sa'ib] [Abdullah bin Sa'ib] pernah menuntun Abdullah bin 'Abbas, lantas menghentikannya pada sisi yang ketiga (dari Ka'bah) yang menghadap pintu dan menghadap Hajar Aswad. Lalu saya (Ibnu 'Abbas) berkata kepada Abdillah bin Sa'ib, apakah Rasulullah Shallallahu'alaihiwasallam Shalat berdiri di sini atau Shalat di sini? Lalu Abdullah berkata; Ya. Ibnu Abbas berdiri lalu Shalat."},"319":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَبَّادِ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ الْفَتْحِ فَوَضَعَ نَعْلَيْهِ عَنْ يَسَارِهِقَالَ عَبْد اللَّهِ سَمِعْتُ هَذَا الْحَدِيثَ مِنْ أَبِي ثَلَاثَ مِرَارٍ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] berkata; telah menceritakan kepadaku [Muhammad bin 'Abbad bin Ja'far] dari [Abdullah bin Sufyan] dari [Abdullah bin As-Sa'ib] Rasulullah Shallallahu'alaihiwasallam pada saat Fathu Makkah mengerjakan Shalat, beliau meletakkan kedua sandalnya di sisi kirinya. Abdullah berkata; saya telah mendengar hadits ini dari Bapakku tiga kali."},"320":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ مُحَمَّدِ بْنِ عَبَّادٍ الْمَخْزُومِيِّ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْتَتَحَ الصَّلَاةَ يَوْمَ الْفَتْحِ فِي الْفَجْرِ فَقَرَأَ بِسُورَةِ الْمُؤْمِنِينَ فَلَمَّا بَلَغَ ذِكْرَ مُوسَى وَهَارُونَ أَصَابَتْهُ سَعْلَةٌ فَرَكَعَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ibnu Juraij] dari [Muhammad bin 'Abbad Al Makhzumi] dari [Abdullah bin As-Sa'ib] Nabi Shallallahu'alaihiwasallam membuka Shalat pada saat Fathu Makkah dalam Shalat fajar dengan surat Al Mukminun, tatkala sampai penyebutan Musa dan Harun maka beliau batuk lalu ruku'."},"321":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ سَمِعْتُ مُحَمَّدَ بْنَ عَبَّادِ بْنِ جَعْفَرٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ سُفْيَانَ وَعَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ وَعَبْدُ اللَّهِ بْنُ الْمُسَيَّبِ الْعَابِدِيُّ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الصُّبْحَ بِمَكَّةَ قَالَ فَافْتَتَحَ سُورَةً فَلَمَّا انْتَهَى إِلَى ذِكْرِ مُوسَى وَهَارُونَ أَوْ ذِكْرِ عِيسَى مُحَمَّدُ بْنُ عَبَّادٍ يَشُكُّ فَاخْتَلَفُوا عَلَيْهِ أَخَذَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْلَةٌ فَرَكَعَقَالَ وَابْنُ السَّائِبِ حَاضِرُ ذَلِكَ","id":"Telah menceritakan kepada kami [Hajjaj] berkata; [Ibnu Juraij] berkata; saya telah mendengar [Muhammad bin 'Abbad bin Ja'far] berkata; telah mengabarkan kepadaku [Abu Salamah bin Sufyan] dan [Abdullah bin 'Amr bin Al 'Ash] dan [Abdullah bin Al Musayyab Al 'Abidi] dari [Abdullah bin As-Sa'ib] Nabi Shallallahu'alaihiwasallam Shalat subuh di Makkah. (Abdullah bin As-Sa'ib Radliyallahu'anhu) berkata; beliau membuka dengan suatu surat, tatkala sampai kata Musa dan Harun atau kata 'Isa, Muhammad bin 'Abbad ragu, lalu mereka berselisih atasnya, Nabi Shallallahu'alaihiwasallam batuk lalu ruku'. (Abdullah bin Al Musayyab Radliyallahu'anhu) berkata; Ibnu As-Sa'ib melihat hal itu."},"322":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَرَوْحٌ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَبَّادِ بْنِ جَعْفَرٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ سُفْيَانَ وَعَبْدُ اللَّهِ بْنُ عَمْرٍو قَالَ رَوْحٌ ابْنُ الْعَاصِ وَعَبْدُ اللَّهِ بْنُ الْمُسَيَّبِ الْعَابِدِيُّ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ بِمَكَّةَ فَاسْتَفْتَحَ سُورَةَ الْمُؤْمِنِينَ حَتَّى إِذَا جَاءَ ذِكْرُ مُوسَى وَهَارُونَ أَوْ ذِكْرُ عِيسَى قَالَ رَوْحٌ مُحَمَّدُ بْنُ عَبَّادٍ يَشُكُّ وَاخْتَلَفُوا عَلَيْهِ أَخَذَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْلَةٌ فَحَذَفَ فَرَكَعَقَالَ وَعَبْدُ اللَّهِ بْنُ السَّائِبِ حَاضِرُ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] dan [Rauh] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; saya telah mendengar [Muhammad bin 'Abbad bin Ja'far] berkata; telah mengabarkan kepadaku [Abu Salamah bin Sufyan] dan [Abdullah bin 'Amr] [Rauh bin Al 'Ash] dan [Abdullah bin Al Musayyab Al 'Abidi] berkata; dari [Abdullah bin As-Sa'ib] berkata; Rasulullah Shallallahu'alaihiwasallam Shalat subuh bersama kami di Makkah lalu membukanya dengan surat Al Mukminin sampai pada penyebutan Musa dan Harun atau 'Isa. [Rauh] berkata; Muhammad bin 'Abbad ragu dan mereka saling berselisih, Nabi Shallallahu'alaihiwasallam batuk lalu beliau memotong dan ruku'. (Abdullah bin Al Musayyab Radliyallahu'anhu) berkata; [Ibnu As-Sa'ib] melihat hal itu."},"323":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ بْنُ أَبِي الْوَضَّاحِ عَنْ عَبْدِ الْكَرِيمِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَبْلَ الظُّهْرِ بَعْدَ الزَّوَالِ أَرْبَعًا وَيَقُولُ إِنَّ أَبْوَابَ السَّمَاءِ تُفْتَحُ فَأُحِبُّ أَنْ أُقَدِّمَ فِيهَا عَمَلًا صَالِحًا","id":"Telah menceritakan kepada kami [Abu Daud Ath-Thoyalisi], berkata; telah menceritakan kepada kami [Muhammad bin Muslim bin Abu Al Wadloh] dari [Abdul Karim] dari [Mujahid] dari [Abdullah bin As-Sa'ib] berkata; Rasulullah Shallallahu'alaihiwasallam Shalat sebelum dhuhur setelah tergelincirnya matahari empat rekaat, beliau bersabda: \"Pintu-pintu langit dibuka, dan saya senang mempersembahkan amalan sholeh ketika itu.\""},"324":{"ar":"حَدَّثَنَا هَوْذَةُ بْنُ خَلِيفَةَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ مُحَمَّدُ بْنُ عَبَّادٍ حَدَّثَنِي حَدِيثًا رَفَعَهُ إِلَى أَبِي سَلَمَةَ بْنِ سُفْيَانَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَحَضَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ وَصَلَّى فِي قِبَلِ الْكَعْبَةِ فَخَلَعَ نَعْلَيْهِ فَوَضَعَهُمَا عَنْ يَسَارِهِ ثُمَّ اسْتَفْتَحَ سُورَةَ الْمُؤْمِنِينَ فَلَمَّا جَاءَ ذِكْرُ عِيسَى أَوْ مُوسَى أَخَذَتْهُ سَعْلَةٌ فَرَكَعَ","id":"Telah menceritakan kepada kami [Haudzan bin Khalifah] telah mengabarkan kepada kami [Ibnu Juraij] berkata [Muhammad bin 'Abbad] telah menceritakan kepadaku sebuah hadits yang di marfu'kan sampai pada [Abu Salamah bin Sufyan] dan [Abdullah bin 'Amr] dari [Abdullah bin As-Sa'ib] berkata; saya menghadiri Rasulullah Shallallahu'alaihiwasallam pada Fathu Makkah pada arah Ka'bah, lalu beliau melepas kedua sandalnya, lalu meletakkan keduanya di sebelah kirinya. Beliau membaca surat Al Mukminun. Tatkala sampai pada penyebutan Musa dan Harun (Nabi Shallallahu'alaihiwasallam) batuk lalu ruku'."},"325":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَرَوْحٌ قَالَا حَدَّثَنَا ابْنُ جُرَيْجٍ وَابْنُ بَكْرٍ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي يَحْيَى بْنُ عُبَيْدٍ مَوْلَى السَّائِبِ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ السَّائِبِ أَخْبَرَهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِيمَا بَيْنَ رُكْنَيْ بَنِي جُمَحَ وَالرُّكْنِ الْأَسْوَدِ{ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ }","id":"Telah menceritakan kepada kami [Abdurrazaq] dan [Rauh] berkata; telah menceritakan kepada kami [Ibnu Juraij] dan [Ibnu Bakr] berkata; telah mengabarkan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Yahya bin 'Ubaid] budak As-Sa'ib, bahwa [Bapaknya] mengabarinya [Abdullah bin As-Sa'ib] mengabarinya, dia telah mendengar Nabi Shallallahu'alaihiwasallam ketika berada di dua rukun yaitu Bani Jumah dan Rukun Aswad membaca: \"ROBBANAA AATINAA FID DUNYA HASANAH WA FIL AAKHIROTI HASANAH WAQINA 'ADZABAN NAAR, (Ya Allah, berikan kami kebaikan di dunia dan kebaikan di akhirat dan jagalah kami dari adzab neraka) \""},"326":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي يَحْيَى بْنُ عُبَيْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بَيْنَ الرُّكْنِ الْيَمَانِي وَالْحَجَرِ{ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ }قَالَ عَبْدُ الرَّزَّاقِ وَابْنُ بَكْرٍ وَرَوْحٌ فِي هَذَا الْحَدِيثِ إِنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِيمَا بَيْنَ رُكْنِ بَنِي جُمَحَ وَالرُّكْنِ الْأَسْوَدِ{ رَبَّنَا آتِنَا }","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Yahya bin 'Ubaid] dari [Bapaknya] dari [Abdullah bin As-Sa'ib] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam membaca antara rukun Yamani dan Hajar Aswad membaca, \"ROBBANAA AATINAA FID DUNYA HASANAH WA FIL AAKHIROTI HASANAH WAQINA 'ADZABAN NAAR, (Ya Allah, berikan kami kebaikan di dunia dan kebaikan di akhirat dan jagalah kami dari adzab neraka) \" Telah menceritakan kepada kami [Abdurrazaq] dan [Ibnu Bakr] dan [Rauh] dalam hadits ini, dia telah mendengar Nabi Shallallahu'alaihiwasallam ketika berada di dua rukun yaitu Bani Jumah dan Rukun Aswad membaca, \"ROBBANAA AATINAA.\""},"327":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَبَّادِ بْنِ جَعْفَرٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ سُفْيَانَ وَعَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ وَعَبْدُ اللَّهِ بْنُ الْمُسَيَّبِ الْعَابِدِيُّ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِقَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَاسْتَفْتَحَ سُورَةَ الْمُؤْمِنِينَ حَتَّى إِذَا جَاءَ ذِكْرُ مُوسَى وَهَارُونَ أَوْ ذِكْرُ عِيسَى مُحَمَّدُ بْنُ عَبَّادٍ شَكَّ اخْتَلَفُوا عَلَيْهِ أَخَذَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَعْلَةٌ فَحَذَفَ فَرَكَعَقَالَ وَابْنُ السَّائِبِ حَاضِرُ ذَلِكَ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] berkata; saya telah mendengar [Muhammad bin 'Abbad bin Ja'far] berkata; telah mengabarkan kepadaku [Abu Salamah bin Sufyan] dan [Abdullah bin 'Amr bin Al 'Ash] dan [Abdullah bin Al Musayyab Al 'Abidi] dari [Abdullah bin As-Sa'ib] berkata; Rasulullah Shallallahu'alaihiwasallam Shalat subuh bersama kami, lalu membukanya dengan surat Al Mukminin sampai pada penyebutan Musa dan Harun atau 'Isa --Muhammad bin 'Abbad ragu tentang kepastian yang mereka perselisihkan-- Nabi Shallallahu'alaihiwasallam terkena batuk lalu menghentikannya dan ruku'. (Abdullah bin Al Musayyab Radliyallahu'anhuma) berkata; Ibnu As-Sa'ib melihat hal itu."},"328":{"ar":"حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ حَدَّثَنِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ عَنْ عَلِيٍّ الْأَزْدِيِّ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ حُبْشِيٍّ الْخَثْعَمِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ إِيمَانٌ لَا شَكَّ فِيهِ وَجِهَادٌ لَا غُلُولَ فِيهِ وَحَجَّةٌ مَبْرُورَةٌ قِيلَ فَأَيُّ الصَّلَاةِ أَفْضَلُ قَالَ طُولُ الْقُنُوتِ قِيلَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ جَهْدُ الْمُقِلِّ قِيلَ فَأَيُّ الْهِجْرَةِ أَفْضَلُ قَالَ مَنْ هَجَرَ مَا حَرَّمَ اللَّهُ عَلَيْهِ قِيلَ فَأَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ جَاهَدَ الْمُشْرِكِينَ بِمَالِهِ وَنَفْسِهِ قِيلَ فَأَيُّ الْقَتْلِ أَشْرَفُ قَالَ مَنْ أُهَرِيقَ دَمُهُ وَعُقِرَ جَوَادُهُ","id":"Telah menceritakan kepada kami [Hajjaj] berkata; [Ibnu Juraij] berkata; telah menceritakan kepadaku ['Utsman bin Abu Sulaiman] dari ['Ali bin Al Azdi] dari ['Ubaid bin 'Umair] dari [Abdullah bin Hubsyi Al Khots'ami] Nabi Shallallahu'alaihiwasallam ditanya tentang amalan apa yang paling utama? Beliau bersabda: \"Iman yang tidak ada keraguan di dalamnya, jihad yang tidak ada ghulul (mengambil harta rampasan orang sebelum di bagikan) di dalamnya serta haji yang mabrur.Ditanyakan lagi: Shalat mana yang paling utama? Beliau bersabda: \"Yang panjang waktu berdirinya\" Ditanyakan: sedekah mana yang paling utama? Beliau bersabda: \"Kesungguhan yang maksimal saat kondisi terdesak\" Ditanyakan, hijrah mana yang paling utama? Beliau bersabda: \"Berhijrah dari apa yang diharamkan oleh Allah padanya\", Ditanyakan, jihad mana yang paling utama? Beliau bersabda: \"Orang yang berjihad pada orang-orang musyrik dengan harta dan jiwanya\" Ditanyakan, terbunuh bagaimana yang paling utama? Beliau Shallallahu'alaihiwasallam: \"Orang yang terkucur darahnya, dan terbunuh kudanya.\""},"329":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرُ بْنُ حَوْشَبٍ حَدَّثَنِي إِسْمَاعِيلُ بْنُ أُمَيَّةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكَانَ لَهُمْ غُلَامٌ يُقَالُ لَهُ طَهْمَانُ أَوْ ذَكْوَانُ فَأَعْتَقَ جَدُّهُ نِصْفَهُ فَجَاءَ الْعَبْدُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُعْتَقُ فِي عِتْقِكَ وَتُرَقُّ فِي رِقِّكَ قَالَ وَكَانَ يَخْدِمُ سَيِّدَهُ حَتَّى مَاتَقَالَ عَبْدُ الرَّزَّاقِ وَكَانَ مَعْمَرٌ يَعْنِي ابْنَ حَوْشَبٍ رَجُلًا صَالِحًا","id":"Telah menceritakan kepada kami [Abdurrozaq] telah menceritakan kepada kami [Ma'mar bin Husyab] telah menceritakan kepadaku [Isma'il bin Umayyah] dari [Bapaknya] dari [kakeknya] berkata; mereka memiliki seorang budak laki-laki yang bernama Tuhman atau Dzakwan lalu kakek Isma'il bin Umayyah memerdekakan setengahnya, lalu sang budak datang kepada Nabi Shallallahu'alaihiwasallam. Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Separuh dirimu kamu merdeka dan separuh dirimu masih menjadi budak\", maka dia tetap membantu tuannya hingga meninggal, Abdur Rozzaq berkata; Ma'mar yaitu Ibnu Hausyab adalah seorang laki-laki yang shaleh."},"330":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا عَامِرُ بْنُ صَالِحِ بْنِ رُسْتُمَ الْمُزَنِيُّ حَدَّثَنَا أَيُّوبُ بْنُ مُوسَى بْنِ عَمْرِو بْنِ سَعِيدِ بْنِ الْعَاصِي قَالَ أَوْ ابْنُ سَعِيدِ بْنِ الْعَاصِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نَحَلَ وَالِدٌ وَلَدَهُ أَفْضَلَ مِنْ أَدَبٍ حَسَنٍقَالَ أَبُو عَبْد الرَّحْمَنِ حَدَّثَنَا بِهِ خَلَفُ بْنُ هِشَامٍ الْبَزَّارُ وَالْقَوَارِيرِيُّ قَالَا حَدَّثَنَا عَامِرُ بْنُ أَبِي عَامِرٍ بِإِسْنَادِهِ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun] berkata; telah mengabarkan kepada kami ['Amir bin Sholih bin Rustum Al Muzanni] telah menceritakan kepada kami [Ayyub bin Musa bin 'Amr bin Sa'id bin Al 'Ashi] berkata; atau Ibnu Sa'id bin Al 'Ash dari [ayahnya] dari [kakeknya] berkata: Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada pemberian orang tua terhadap anaknya yang lebih utama dari sebuah adab yang baik.\" Abu Abdur Rahman berkata; telah menceritakan kepada kami dengan hadits itu [Khalaf bin Hisyam Al Bazzar] dan [Al Qawariri] berkata; telah menceritakan kepada kami ['Amir bin Abu 'Amir] dengan sanadnya lalu dia menyebutkan seperti itu."},"331":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ زَكَرِيَّا عَنِ الشَّعْبِيِّ عَنِ الْحَارِثِ بْنِ مَالِكِ ابْنِ بَرْصَاءَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ يَقُولُ لَا يُغْزَى هَذَا يَعْنِي بَعْدَ الْيَوْمِ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Zakariya] dari [Sya'bi] dari [Al Harits bin Malik bin Barsho'] berkata; saya mendengar Nabi Shallallahu'alaihiwasallam bersabda pada hari Penaklukan Makkah, \"Tempat ini (Bumi Makkah) tidak diperangi lagi yakni setetah hari ini hingga Hari Kiamat.\""},"332":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنِي زَكَرِيَّا عَنْ عَامِرٍ قَالَ قَالَ الْحَارِثُ بْنُ مَالِكِ ابْنِ بَرْصَاءَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ فَتْحِ مَكَّةَ وَهُوَ يَقُولُ لَا يُغْزَى بَعْدَهَا إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid] berkata; telah menceritakan kepadaku [Zakariya] dari ['Amir] berkata; [Al Harits bin Malik bin Barsho'] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam pada Fathu Makkah beliau bersabda: \"Tidak boleh diperangi setelah ini sampai Hari Kiamat.\""},"333":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ أَبُو الْحَسَنِ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ فِرَاسٍ عَنِ الشَّعْبِيِّ قَالَ قَالَ مُطِيعُ بْنُ الْأَسْوَدِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ لَا يَنْبَغِي أَنْ يُقْتَلَ قُرَشِيٌّ بَعْدَ يَوْمِهِ هَذَا صَبْرًا","id":"Telah menceritakan kepada kami [Mu'awiyah bin Hisyam Abu Al Hasan] berkata; telah menceritakan kepada kami [Syaiban] dari [Firos] dari [Asy-Sya'bi] berkata; [Muthi' bin Al Aswad] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda pada hari Penaklukan Makkah, \"Orang Quraiys tidak layak dibunuh setelah hari ini dengan cara dijadikan obyek sasaran panah-memanah.\""},"334":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ عَنْ عَبْدِ اللَّهِ بْنِ مُطِيعٍ عَنْ أَبِيهِقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ فَتْحِ مَكَّةَ لَا يُقْتَلُ قُرَشِيٌّ صَبْرًا بَعْدَ الْيَوْمِ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Zakariya] dari ['Amir] dari [Abdullah bin Muthi'] dari [Bapaknya] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda pada Fathu Makkah, \"Tidak boleh orang Quraisy dibunuh dengan cara dijadikan obyek sasaran panah-memanah.\""},"335":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَاقَ حَدَّثَنِي شُعْبَةُ بْنُ الْحَجَّاجِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مُطِيعِ بْنِ الْأَسْوَدِ أَخِي بَنِي عَدِيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ مُطِيعٍ وَكَانَ اسْمُهُ الْعَاصُ فَسَمَّاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُطِيعًا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَمَرَ بِقَتْلِ هَؤُلَاءِ الرَّهْطِ بِمَكَّةَ يَقُولُ لَا تُغْزَى مَكَّةُ بَعْدَ هَذَا الْعَامِ أَبَدًا وَلَا يُقْتَلُ رَجُلٌ مِنْ قُرَيْشٍ بَعْدَ الْعَامِ صَبْرًا أَبَدًا","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Syu'bah bin Al Hajjaj] dari [Abdullah bin Abu As-Safar] dari ['Amir Asy-Sya'bi] dari [Abdullah bin Muthi' bin Al Aswad, dari Bani 'Adi bin Ka'b] dari [Bapaknya, Muthi', namanya adalah Al 'Ash] lalu Rasulullah Shallallahu'alaihiwasallam memberinya nama Muthi, berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda ketika menyuruh membunuh beberapa orang di Makkah, \"Tidak boleh diperangi kota Makkah sejak tahun selamanya dan tidak boleh seseorang dari Quraisy dibunuh dengan cara dijadikan obyek sasaran panah-memanah.\""},"336":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ زَكَرِيَّا حَدَّثَنَا عَامِرٌ عَنْ عَبْدِ اللَّهِ بْنِ مُطِيعٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ يَقُولُ لَا يُقْتَلُ قُرَشِيٌّ صَبْرًا بَعْدَ الْيَوْمِ وَلَمْ يُدْرِكْ الْإِسْلَامُ أَحَدًا مِنْ عُصَاةِ قُرَيْشٍ غَيْرَ مُطِيعٍ وَكَانَ اسْمُهُ عَاصِي فَسَمَّاهُ مُطِيعًا يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Zakariya] telah menceritakan kepada kami ['Amir] dari [Abdullah bin Muthi'] dari [Bapaknya] telah mendengar Rasulullah Shallallahu'alaihiwasallam pada Fathu Makkah bersabda: \"Tidak boleh orang Quraisy dibunuh dengan cara dijadikan obyek sasaran panah-memanah sejak hari ini. Agama Islam tidak mendapatkan seorangpun dari kalangan ahli maksiat Quraisy selain Muthi', namanya adalah 'Ashi, lalu ada yang memberi nama Muthi' yaitu Nabi Shallallahu'alaihiwasallam. "},"337":{"ar":"حَدَّثَنَا مُوسَى بْنُ طَارِقٍ أَبُو قُرَّةَ الزُّبَيْدِيُّ مِنْ أَهْلِ الْحُصَيْبِ وَإِلَى جَانِبِهَا رِمَعٌ وَهِيَ قَرْيَةُ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَ أَبِي وَكَانَ أَبُو قُرَّةَ قَاضِيًا لَهُمْ بِالْيَمَنِ قَالَ حَدَّثَنَا أَيْمَنُ بْنُ نَابِلٍ أَبُو عِمْرَانَ قَالَ سَمِعْتُ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ قُدَامَةُ يَعْنِي ابْنَ عَبْدِ اللَّهِ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى جَمْرَةَ الْعَقَبَةِ يَوْمَ النَّحْرِقَالَ أَبُو قُرَّةَ وَزَادَنِي سُفْيَانُ الثَّوْرِيُّ فِي حَدِيثِ أَيْمَنَ هَذَا عَلَى نَاقَةٍ صَهْبَاءَ بِلَا زَجْرٍ وَلَا طَرْدٍ وَلَا إِلَيْكَ إِلَيْكَ","id":"Telah menceritakan kepada kami [Musa bin Thoriq Abu Qurroh Az-Zubaidi] dari penduduk Husaib sampai ke sampingnya, di Rima', yaitu daerah Abu Musa Al 'Asy'ari, berkata; bapakku Abu Qurroh adalah seorang hakim mereka di Yaman, berkata; telah menceritakan kepada kami [Aiman bin Nabil, Abu 'Imron] berkata; saya telah mendengar seorang sahabat Nabi Shallallahu'alaihiwasallam yang bernama [Qudamah] yaitu Ibnu Abdullah berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam melempar jumrah 'Aqobah pada Hari Nahr. [Abu Qurroh] berkata; [Sufyan At Tsauri] menambahkan dalam hadits Aiman ini, di atas unta Shoba' (merah kehitam-hitaman) tanpa memukul dan mendorong juga tanpa berdesak-desakan."},"338":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَيْمَنُ بْنُ نَابِلٍ قَالَ سَمِعْتُ شَيْخًا مِنْ بَنِي كِلَابٍ يُقَالُ لَهُ قُدَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ يَرْمِي الْجَمْرَةَ عَلَى نَاقَةٍ لَهُ صَهْبَاءَ لَا ضَرْبَ وَلَا طَرْدَ وَلَا إِلَيْكَ إِلَيْكَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Aiman bin Nabil] berkata; saya telah mendengar seorang syaikh dari Bani Kilab yang bernama [Qudamah bin Abdullah bin 'Ammar] berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam pada Hari Nahr melempar jumrah di atas untanya Shohba' dengan tidak memukulnya atau menariknya atau berdesak-desakan."},"339":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الزُّبَيْرِيُّ حَدَّثَنَا أَيْمَنُ بْنُ نَابِلٍ حَدَّثَنَا قُدَامَةُ بْنُ عَبْدِ اللَّهِ الْكِلَابِيُّأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى الْجَمْرَةَ جَمْرَةَ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي يَوْمَ النَّحْرِ عَلَى نَاقَةٍ لَهُ صَهْبَاءَ لَا ضَرْبَ وَلَا طَرْدَ وَلَا إِلَيْكَ إِلَيْكَحَدَّثَنَا قُرَّانٌ فِي الْحَدِيثِ قَالَ يَرْمِي الْجِمَارَ عَلَى نَاقَةٍ لَهُ","id":"Telah menceritakan kepada kami [Abu Ahmad, Muhammad bin Abdullah Az-Zubairi] telah menceritakan kepada kami [Aiman bin Nabil] telah menceritakan kepada kami [Qudamah bin Abdullah Al Kilabi] dia telah melihat Rasulullah Shallallahu'alaihiwasallam melempar jumrah yaitu Jumrah 'Aqobah, dari bawah bukit pada Hari Nahr di atas untanya Shohba' dengan tidak memukulnya atau menariknya atau berdesak-desakan. Telah menceritakan kepada kami [Qurron] dalam haditsnya, berkata; melempar kerikil di atas unta beliau."},"340":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ وَمُحْرِزُ بْنُ عَوْنِ بْنِ أَبِي عَوْنٍ أَبُو الْفَضْلِ قَالَا حَدَّثَنَا قُرَّانُ بْنُ تَمَّامٍ الْأَسَدِيُّ حَدَّثَنَا أَيْمَنُ عَنْ قُدَامَةَ بْنِ عَبْدِ اللَّهِقَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاقَةٍ يَسْتَلِمُ الْحَجَرَ بِمِحْجَنِهِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Suraij bin Yunus] dan [Muhriz bin 'Aun bin Abu 'Aun, Abu Al Fadl] berkata; telah menceritakan kepada kami [Qurron bin Tamam Al Asadi] telah menceritakan kepada kami ['Aiman] dari [Qudamah bin Abdullah] berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam di atas unta beliau menyentuh hajar dengan tongkat."},"341":{"ar":"قَالَ أَبُو عَبْد الرَّحْمَنِ حَدَّثَنِي مُحْرِزُ بْنُ عَوْنٍ وَعَبَّادُ بْنُ مُوسَى قَالَا حَدَّثَنَا قُرَّانُ بْنُ تَمَّامٍ عَنْ أَيْمَنَ بْنِ نَابِلٍ عَنْ قُدَامَةَ بْنِ عَبْدِ اللَّهِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي الْجِمَارَ عَلَى نَاقَةٍ لَا ضَرْبَ وَلَا طَرْدَ وَلَا إِلَيْكَ إِلَيْكَ وَزَادَ عَبَّادٌ فِي حَدِيثِهِ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاقَةٍ صَهْبَاءَ يَرْمِي الْجَمْرَةَ","id":"Berkata; Abu Abdurrahman telah menceritakan kepadaku [Muhriz bin 'Aun] dan ['Abbad bin Musa] berkata; telah menceritakan kepada kami [Qurron bin Tamam] dari ['Aiman bin Nabil] dari [Qudamah bin Abdullah] dia telah melihat Nabi Shallallahu'alaihiwasallam melempar jumrah di atas untanya dengan tidak memukulnya atau menariknya atau berdesak-desakan. 'Abbad menambahkan dalam haditsnya, berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam di atas unta Shohba' melempar jumrah."},"342":{"ar":"حَدَّثَنَا مُعْتَمِرٌ عَنْ أَيْمَنَ بْنِ نَابِلٍ عَنْ قُدَامَةَ بْنِ عَبْدِ اللَّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ يَرْمِي الْجَمْرَةَ عَلَى نَاقَةٍ لَهُ صَهْبَاءَ لَا ضَرْبَ وَلَا طَرْدَ وَلَا إِلَيْكَ إِلَيْكَ","id":"Telah menceritakan kepada kami [Mu'tamir] dari ['Aiman bin Nabil] dari [Qudamah bin Abdullah] berkata; saya telah melihat Rasulullah Shallallahu'alaihiwasallam pada Hari Nahr, melempar jumrah di atas untanya Shohba' dengan tidak memukulnya atau menariknya atau berdesak-desakan."},"343":{"ar":"حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ قَالَا حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ الثَّقَفِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ قُلْ لِي فِي الْإِسْلَامِ قَوْلًا لَا أَسْأَلُ عَنْهُ أَحَدًا غَيْرَكَ قَالَ أَبُو مُعَاوِيَةَ بَعْدَكَ قَالَ قُلْ آمَنْتُ بِاللَّهِ ثُمَّ اسْتَقِمْ","id":"Telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Sufyan bin Abdullah Ats-Tsaqofi] berkata; saya berkata; Wahai Rasulullah, katakanlah kepadaku dalam Islam sebuah perkataan, yang saya tidak perlu menanyakan lagi kepada selain anda. Abu Mu'awiyah berkata; \"Setelah anda\", beliau bersabda: \"Katakanlah, saya beriman kepada Allah, lalu beristiqomahlah.\""},"344":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ سُفْيَانَ عَنْ أَبِيهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي أَمْرًا فِي الْإِسْلَامِ لَا أَسْأَلُ عَنْهُ أَحَدًا بَعْدَكَ قَالَ قُلْ آمَنْتُ بِاللَّهِ ثُمَّ اسْتَقِمْ قَالَ يَا رَسُولَ اللَّهِ فَأَيَّ شَيْءٍ أَتَّقِي قَالَ فَأَشَارَ بِيَدِهِ إِلَى لِسَانِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atho'] dari [Abdullah bin Sufyan] dari [Bapaknya] ada seorang laki-laki berkata; Wahai Rasulullah, khabarkanlah kepadaku suatu urusan dalam Islam, yang saya tidak perlu menanyakan lagi kepada seorangpun setelah anda. Beliau bersabda: \"Katakanlah, saya beriman kepada Allah, lalu beristiqomahlah.\" Dia berkata; Wahai Rasulullah, apa yang harus saya jaga betul. Beliau memberi isyarat dengan tangannya ke arah lisannya."},"345":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ وَيَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا إِبْرَاهِيمُ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَاعِزٍ الْعَامِرِيِّ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ الثَّقَفِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ حَدِّثْنِي بِأَمْرٍ أَعْتَصِمُ بِهِ قَالَ قُلْ رَبِّيَ اللَّهُ ثُمَّ اسْتَقِمْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَا أَكْبَرُ مَا تَخَافُ عَلَيَّ قَالَ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِسَانِ نَفْسِهِ ثُمَّ قَالَ هَذَا قَالَ يَزِيدُ فِي حَدِيثِهِ بِطَرْفِ لِسَانِ نَفْسِهِ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Ibrahim] yaitu Ibnu Sa'd, telah menceritakan kepada kami [Ibnu Syihab] dan [Yazid bin Harun] berkata; telah memberitakan kepada kami [Ibrahim] berkata; telah menceritakan kepadaku [Ibnu Syihab] dari [Muhammad bin Abdurrahman bin Ma'iz bin Al 'Amiri] dari [Sufyan bin Abdullah Ats-Tsaqofi] berkata; saya berkata; kepada Rasulullah Shallallahu'alaihiwasallam, apa sesuatu yang anda paling takuti dari saya. Dia berkata; Rasulullah Shallallahu'alaihiwasallam memegang lidah beliau, lalu bersabda: \"Ini.\" Yazid berkata dalam haditsnya, \"Dengan ujung lidah beliau sendiri.\""},"346":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَاعِزٍ عَنْ سُفْيَانَ بْنِ عَبْدِ اللَّهِ الثَّقَفِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ حَدِّثْنِي بِأَمْرٍ أَعْتَصِمُ بِهِ قَالَ قُلْ رَبِّيَ اللَّهُ ثُمَّ اسْتَقِمْ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَا أَخْوَفُ مَا تَخَافُ عَلَيَّ قَالَ فَأَخَذَ بِلِسَانِ نَفْسِهِ ثُمَّ قَالَ هَذَا","id":"Telah menceritakan kepada kami ['Ali bin Ishaq] berkata; telah memberitakan kepada kami [Abdullah] yaitu Ibnu Al Mubarok, berkata; telah memberitakan kepada kami [Ma'mar] dari [Az-Zuhri] dari [Abdurrahman bin Ma'iz] dari [Sufyan bin Abdullah Ats-Tsaqofi] berkata; saya berkata; Wahai Rasulullah, ceritakan kepadaku suatu hal yang saya akan berpegang teguh terhadapnya. Beliau bersabda: \"Katakanlah robku adalah Allah lalu beristiqomahlah. (Sufyan bin Abdullah Ats-Tsaqofi Radliyallahu'anhuma) berkata; Wahai Rasulullah, apa yang paling anda takuti terhadapku. Beliau memegang lisannya lalu bersabda: ini."},"347":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ قَالَ سَمِعْتُ رَجُلًا يَمَانِيًّا يُحَدِّثُ عَنْ أَبِيهِ قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً كُنْتُ فِيهَا فَنَهَانَا أَنْ نَقْتُلَ الْعُسَفَاءَ وَالْوُصَفَاءَ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [ayyub] berkata; saya telah mendengar seorang laki-laki Yaman menceritakan dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam mengutus sebuah pasukan yang saya ikut menyertainya, beliau melarang membunuh budak laki-laki dan budak perempuan."},"348":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا حَدَّثَنَا هَمَّامٌ قَالَ عَفَّانُ فِي حَدِيثِهِ حَدَّثَنَا قَتَادَةُ عَنْ كَثِيرٍ عَنْ أَبِي عِيَاضٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُجْلَسَ بَيْنَ الضِّحِّ وَالظِّلِّ وَقَالَ مَجْلِسُ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan] berkata; telah menceritakan kepada kami [Hammam] berkata; ['Affan] dalam haditsnya, telah menceritakan kepada kami [Qatadah] dari [Katsir] dari [Abu 'Iyadl] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam], Nabi Shallallahu'alaihiwasallam melarang duduk di antara tempat yang terkena sinar matahari dan teduh. Beliau bersabda: \"Itu adalah tempat duduknya setan\""},"349":{"ar":"حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ التَّيْمِيُّ قَالَ أَخْبَرَنَا حُمَيْدٌ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَرَأَيْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَامَ حَتَّى نَفَخَ ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Mu'tamir bin Sulaiman At Taimi] berkata; telah mengabarkan kepada kami [Humaid] dari [Abdullah bin 'Ubaid] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam] berkata; saya pernah melihat Nabiyullah ShallallahuAlaihiWasallam tidur hingga mendengkur kemudian beliau bangun, lalu Shalat tanpa berwudhu."},"350":{"ar":"حَدَّثَنَا عَبْدُ الرَزَّاقِ وَرَوْحٍ قَالَا حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي حَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ رَجُلٍ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الطَّوَافُ صَلَاةٌ فَإِذَا طُفْتُمْ فَأَقِلُّوا الْكَلَامَوَلَمْ يَرْفَعْهُ مُحَمَّدُ بْنُ بَكْرٍ","id":"Telah menceritakan kepada kami [Abdurrazaq] dan [Rauh] berkata; telah menceritakan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Hasan bin Muslim] dari [Thawus] dari [seorang laki-laki yang mendapatkan masa Nabi Shallallahu'alaihiwasallam], Nabi Shallallahu'alaihiwasallam bersabda: \" thawaf adalah Shalat maka jika kalian thawaf sedikitkan dari berbicara\" Muhammad bin Bakr tidak memarfu'kan hadits ini."},"351":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ حُمَيْدٍ عَنْ رَجُلٍ مِنْ أَهْلِ مَكَّةَ يُقَالُ لَهُ يُوسُفُ قَالَكُنْتُ أَنَا وَرَجُلٌ مِنْ قُرَيْشٍ نَلِي مَالَ أَيْتَامٍ قَالَ وَكَانَ رَجُلٌ قَدْ ذَهَبَ مِنِّي بِأَلْفِ دِرْهَمٍ قَالَ فَوَقَعَتْ لَهُ فِي يَدِي أَلْفُ دِرْهَمٍ قَالَ فَقُلْتُ لِلْقُرَشِيِّ إِنَّهُ قَدْ ذَهَبَ لِي بِأَلْفِ دِرْهَمٍ وَقَدْ أَصَبْتُ لَهُ أَلْفَ دِرْهَمٍ قَالَ فَقَالَ الْقُرَشِيُّ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَدِّ الْأَمَانَةَ إِلَى مَنْ ائْتَمَنَكَ وَلَا تَخُنْ مَنْ خَانَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Humaid] dari seorang laki-laki penduduk Makkah yang bernama [Yusuf] berkata; saya bersama seorang laki-laki dari Quraisy mengurus harta anak-anak yatim. (Yusuf) berkata; laki-laki tersebut kabur membawa pergi seribu dirham. (Yusuf) berkata; lalu uang seribu dirham miliknya terjatuh di tanganku. (Yusuf) berkata; saya berkata kepada Al Qurosyi, ada yang membawa pergi uangku seribu dirham dan saya menemukan seribu dirham miliknya. (Yusuf) berkata; lalu [Al Qurasyi] berkata; telah menceritakan kepadaku [bapakku] telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tunaikanlah amanat kepada orang yang memberimu amanat, dan janganlah kamu berkhianat kepada orang yang telah menghianati dirimu.\""},"352":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ وَالضَّحَّاكُ بْنُ مَخْلَدٍ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ وَعَبْدُ اللَّهِ بْنُ الْحَارِثِ قَالَ عَرَضَ عَلَيَّ ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ أَبِي سُفْيَانَ أَنَّ عَمْرَو بْنَ أَبِي صَفْوَانَ أَخْبَرَهُ قَالَ الضَّحَّاكُ وَعَبْدُ اللَّهِ بْنُ الْحَارِثِ أَنَّ عَمْرَو بْنَ عَبْدِ اللَّهِ بْنِ صَفْوَانَ أَخْبَرَهُ أَنَّ كَلَدَةَ بْنَ الْحَنْبَلِأَخْبَرَهُ أَنَّ صَفْوَانَ بْنَ أُمَيَّةَ بَعَثَهُ فِي الْفَتْحِ بِلِبَإٍ وَجَدَايَةٍ وَضَغَابِيسَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَعْلَى الْوَادِي قَالَ فَدَخَلْتُ عَلَيْهِ وَلَمْ أُسَلِّمْ وَلَمْ أَسْتَأْذِنْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعْ فَقُلْ السَّلَامُ عَلَيْكُمْ أَدْخُلُ بَعْدَ مَا أَسْلَمَ صَفْوَانُ قَالَ عَمْرٌو أَخْبَرَنِي هَذَا الْخَبَرَ أُمَيَّةُ بْنُ صَفْوَانَ وَلَمْ يَقُلْ سَمِعْتُهُ مِنْ كَلَدَةَ قَالَ الضَّحَّاكُ وَابْنُ الْحَارِثِ وَذَلِكَ بَعْدَمَا أَسْلَمَ وَقَالَ الضَّحَّاكُ وَعَبْدُ اللَّهِ بْنُ الْحَارِثِ بِلَبَنٍ وَجَدَايَةٍ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] Dan [Adl Dlahhak bin Makhlad] berkata; telah mengabarkan kepadaku [Ibnu Juraij] Dan [Abdullah bin Al Harits] berkata; [Ibnu Juraij] menunjukan kepadaku, berkata; telah mengabarkan kepadaku ['Amar bin Abu Sufyan] ['Amr bin Abu Shafwan] mengabarinya. [Adl Dlahhak] dan [Abdullah Al Harits] berkata; ['Amr bin Abdullah bin Shafwan] mengabarinya, [Kaldah bin Hanbal] mengabarinya, Shafwan bin Umayyah pada hari Penaklukan Makkah mengutusnya untuk membawa susu yang baru diperah dari hewan ternak yang baru melahirkan, serta anak biawak yang berumur enam bulan dan rempah rempah kepada Nabi Shallallahu'alaihiwasallam. Nabi Shallallahu'alaihiwasallam berada pada ketinggian bukit. (Kaldah) berkata; saya menemui beliau tanpa salam dan memohon ijin, lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Kembalilah dan ucapkan: 'Assalamu 'alaikum', saya masuk Islam setelah Islamnya Shafwan. ['Amr] berkata; Umayyah bin Shafwan mengabariku kabar ini hanya dia tidak berkata 'Saya mendengarnya dari Kaldah.' [Adl Dlahhak] dan [Ibnu Harits] berkata; yang demikian itu setelah keIslaman (Kaldah). [Adl Dlahhak] dan [Abdullah bin Harits] berkata; \"Membawa susu dan anak biawak.\""},"353":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَاقَ عَنْ عَمْرِو بْنِ أَبِي سُفْيَانَ سَمِعَهُ مِنْ مُسْلِمِ بْنِ ثَفِنَةَ قَالَاسْتَعْمَلَ ابْنُ عَلْقَمَةَ أَبِي عَلَى عِرَافَةِ قَوْمِهِ وَأَمَرَهُ أَنْ يُصَدِّقَهُمْ قَالَ فَبَعَثَنِي أَبِي فِي طَائِفَةٍ لِآتِيَهُ بِصَدَقَتِهِمْ قَالَ فَخَرَجْتُ حَتَّى أَتَيْتُ شَيْخًا كَبِيرًا يُقَالُ لَهُ سِعْرٌ فَقُلْتُ إِنَّ أَبِي بَعَثَنِي إِلَيْكَ لِتُؤَدِّيَ صَدَقَةَ غَنَمِكَ قَالَ يَا ابْنَ أَخِي وَأَيُّ نَحْوٍ تَأْخُذُونَ قُلْتُ نَخْتَارُ حَتَّى إِنَّا لَنَشْبُرُ ضُرُوعَ الْغَنَمِ قَالَ ابْنَ أَخِي فَإِنِّي أُحَدِّثُكَ أَنِّي كُنْتُ فِي شِعْبٍ مِنْ هَذِهِ الشِّعَابِ فِي غَنَمٍ لِي عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَنِي رَجُلَانِ عَلَى بَعِيرٍ فَقَالَا نَحْنُ رَسُولَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكَ لِتُؤَدِّيَ صَدَقَةَ غَنَمِكَ قُلْتُ مَا عَلَيَّ فِيهَا قَالَا شَاةٌ فَأَعْمِدُ إِلَى شَاةٍ قَدْ عَلِمْتُ مَكَانَهَا مُمْتَلِئَةٍ مَحْضًا وَشَحْمًا فَأَخْرَجْتُهَا إِلَيْهِمَا فَقَالَا هَذِهِ الشَّافِعُ الْحَائِلُ وَقَدْ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَأْخُذَ شَافِع��ا قُلْتُ فَأَيُّ شَيْءٍ قَالَا عَنَاقًا جَذَعَةً أَوْ ثَنِيَّةً قَالَ فَأَعْمِدُ إِلَى عَنَاقٍ مُعْتَاطٍ قَالَ وَالْمُعْتَاطُ الَّتِي لَمْ تَلِدْ وَلَدًا وَقَدْ حَانَ وِلَادُهَا فَأَخْرَجْتُهَا إِلَيْهِمَا فَقَالَا نَاوِلْنَاهَا فَدَفَعْتُهَا إِلَيْهِمَا فَجَعَلَاهَا مَعَهُمَا عَلَى بَعِيرِهِمَا ثُمَّ انْطَلَقَاقَالَ عَبْد اللَّهِ سَمِعْتُ أَبِي يَقُولُ كَذَا قَالَ وَكِيعٌ مُسْلِمُ بْنُ ثَفِنَةَ صُحِّفَ و قَالَ رَوْحٌ ابْنُ شُعْبَةَ وَهُوَ الصَّوَابُ و قَالَ أَبِي و قَالَ بِشْرُ بْنُ السَّرِيِّ لَا إِلَهَ إِلَّا اللَّهُ هُوَ ذَا وَلَدُهُ هَاهُنَا يَعْنِي مُسْلِمَ بْنَ شُعْبَةَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Zakariya bin Ishaq] dari ['Amr bin Abu Sufyan] telah mendengarnya dari [Muslim bin Tsafinah] berkata; Ibnu Al Qomah menugaskan bapakku untuk menjadi pemimpin kaumnya dan menyuruhnya untuk mengambil zakat mereka. (Muslim Radliyallahu'anhu) berkata; lalu ayahku mengutusku kepada sebuah kaum agar saya mengambil zakat mereka. Lalu saya keluar hingga menemui seorang yang telah tua yang bernama [Si'ir], lalu saya katakan, 'Ayahku mengutusku kepadamu agar kamu menunaikan zakat kambingmu.' (orang tua itu) berkata; 'Wahai anak saudaraku! kambing seperti apa yang akan kalian ambil? saya berkata; biarkan saya memilih sampai saya bisa mengukur susu kambingmu. Dia berkata; wahai anak saudaraku, saya akan memberitahumu bahwa ketika saya berada di sebuah bukit bersama kambing-kambingku pada masa Nabi Shallallahu'alaihiwasallam, tiba-tiba datang kepadaku [dua orang laki-laki] yang mengendarai unta dan berkata; kami adalah utusan Nabi Shallallahu'alaihiwasallam yang datang kepadamu agar kamu menunaikan zakat kambingmu, saya berkata; apa yang wajib saya keluarkan darinya? (Keduanya) berkata; seekor kambing. Lalu saya pergi menuju seekor kambing, yang saya melihatnya telah mengandung dan gemuk, lalu saya mengeluarkannya kepada mereka. Lalu keduanya berkata 'Ini adalah kambing yang sedang hamil, padahal Rasulullah Shallallahu'alaihiwasallam melarang kami untuk mengambil kambing yang hamil', saya bertanya 'Kalau begitu kambing yang bagaimana? ' Keduanya berkata 'Anak kambing betina yang berumur enam hingga satu tahun, atau yang baru berumur tiga tahun', (orang tua itu) berkata; lalu saya menuju 'anaq (kambing betina yang berumur enam bulan hingga satu tahun) yang mu'tath, dia berkata; mu'tath adalah kambing yang tidak bisa melahirkan anak (karena gemuk) padahal sudah masanya untuk bisa melahirkan anak, lalu saya mengeluarkannya kepada keduanya dan keduanya berkata; 'Berikan kepada kami, maka saya memberikannya kepada mereka hingga keduanya menaikkannya ke atas unta mereka lalu pergi.' Abdullah berkata; 'Saya telah mendengar ayahku berkata seperti ini.' Waki' berkata; nama Muslim bin Tsafinah adalah salah baca. Rauh berkata; yang benar adalah Ibnu Syu'bah. Bapakku dan Bisyr bin As-Sari berkata; LAA ILAAHA ILLA ALLAH, dalam hadits ini dia itu adalah anaknya, yaitu Muslim bin Syu'bah."},"354":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَاقَ قَالَ حَدَّثَنِي عَمْرُو بْنُ أَبِي سُفْيَانَ قَالَ حَدَّثَنِي مُسْلِمُ بْنُ شُعْبَةَأَنَّ ابْنَ عَلْقَمَةَ اسْتَعْمَلَ أَبَاهُ عَلَى عِرَافَةِ قَوْمِهِ قَالَ مُسْلِمٌ فَبَعَثَنِي إِلَى مُصَدِّقَةٍ فِي طَائِفَةٍ مِنْ قَوْمِي قَالَ فَخَرَجْتُ حَتَّى آتِيَ شَيْخًا يُقَالُ لَهُ سِعْرٌ فِي شِعْبٍ مِنْ الشِّعَابِ فَقُلْتُ إِنَّ أَبِي بَعَثَنِي إِلَيْكَ لِتُعْطِيَنِي صَدَقَةَ غَنَمِكَ فَقَالَ أَيْ ابْنَ أَخِي وَأَيَّ نَحْوٍ تَأْخُذُونَ فَقُلْتُ نَأْخُذُ أَفْضَلَ مَا نَجِدُ فَقَالَ الشَّيْخُ إِنِّي لَفِي شِعْبٍ مِنْ هَذِهِ الشِّعَابِ فِي غَنَمٍ لِي إِذْ جَاءَنِي رَجُلَانِ مُرْتَدِفَانِ بَعِيرًا فَقَالَا إِنَّا رَسُولَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَنَا إِلَيْكَ لِتُؤْتِيَنَا صَدَقَةَ غَنَمِكَ قُلْتُ وَمَا هِيَ قَالَا شَاةٌ فَعَمِدْتُ إِلَى شَاةٍ قَدْ عَلِمْتُ مَكَانَهَا مُمْتَلِئَةً مَحْضًا أَوْ مَحْضًا وَشَحْمًا فَأَخْرَجْتُهَا إِلَيْهِمَا فَقَالَا هَذِهِ شَافِعٌ وَقَدْ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَأْخُذَ شَافِعًا وَالشَّافِعُ الَّتِي فِي بَطْنِهَا وَلَدُهَا قَالَ فَقُلْتُ فَأَيَّ شَيْءٍ تَأْخُذَانِ قَالَا عَنَاقًا أَوْ جَذَعَةً أَوْ ثَنِيَّةً قَالَ فَأَخْرَجَ لَهُمَا عَنَاقًا قَالَ فَقَالَا ادْفَعْهَا إِلَيْنَا فَتَنَاوَلَاهَا وَجَعَلَاهَا مَعَهُمَا عَلَى بَعِيرِهِمَا","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Zakariya bin Ishaq] berkata; telah menceritakan kepadaku ['Amr bin Abu Sufyan] berkata; telah menceritakan kepadaku [Muslim bin Syu'bah] Ibnu Al Qomah menugaskan bapaknya untuk menjadi pemimpin kaumnya. Muslim berkata; lalu ayahku mengutusku kepada sebuah kelompok dari kaumku agar saya mengambil zakat. (Muslim Radliyallahu'anhu) berkata; Lalu saya keluar hingga menemui seorang yang telah tua yang bernama [Si'ir], di sebuah bukit. lalu saya katakan 'Ayahku mengutusku kepadamu agar kamu memberikan zakat kambingmu.' (orang tua itu) berkata; 'Wahai anak saudaraku! kambing seperti apa yang akan kalian ambil? saya berkata; biarkan saya memilih sampai saya bisa mengukur susu kambingmu.' Orang tua itu berkata; ketika saya berada di sebuah bukit bersama kambing-kambingku, tiba-tiba datang kepadaku [dua orang laki-laki] yang mengendarai unta berboncengan dan berkata; kami adalah utusan Rasulullah Shallallahu'alaihiwasallam yang telah mengutus kami agar kamu memberikan zakat kambingmu, saya berkata; 'Apa yang wajib saya keluarkan darinya? (Keduanya) berkata; seekor kambing. Lalu saya pergi menuju seekor kambing, yang saya melihatnya telah mengandung dan gemuk atau mengandung dan berlemak, lalu saya mengeluarkannya kepada mereka. Lalu keduanya berkata; 'Ini adalah kambing syafi', padahal Rasulullah Shallallahu'alaihiwasallam melarang kami untuk mengambil kambing syafi', syafi' adalah kambing yang sedang hamil.' Saya bertanya, 'Kalau begitu kambing yang bagaimana yang akan kalian berdua ambil? ' Keduanya berkata 'Anak kambing betina yang berumur belum sampai satu tahun, atau yang baru berumur satu tahun, atau yang telah masuk umur tiga tahun.' (Muslim Radliyallahu'anhu) berkata; lalu orang itu mengeluarkan 'anaq (kambing betina yang berumur enam bulan hingga satu tahun). (Muslim Radliyallahu'anhu) berkata; keduanya berkata; 'Berikan kepada kami', lalu keduanya menerimanya lalu menaikkannya ke atas unta."},"355":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ أَخْبَرَنَا سُفْيَانُ وَعَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَ وَقَالَ نَافِعُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ بِشْرِ بْنِ سُحَيْمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فِي يَوْمِ التَّشْرِيقِ قَالَ عَبْدُ الرَّحْمَنِ فِي أَيَّامِ الْحَجِّ فَقَالَ لَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسٌ مُسْلِمَةٌ وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah mengabarkan kepada kami [Sufyan] dan [Abdurrahman] dari [Sufyan] dari [Habib bin Abu Tsabit] berkata; dan [Nafi' bin Jubair bin Muthim] berkata; dari [Bisyr bin Suhaim] Nabi Shallallahu'alaihiwasallam berkhutbah pada Hari Tasyriq. Abdur Rahman berkata; di sekitar Hari Haji, bersabda: \"Tidak akan masuk surga melainkan orang Islam dan hari-hari ini adalah hari makan dan minum.\" "},"356":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ بَعَثَ بِشْرَ بْنَ سُحَيْمٍ فَأَمَرَهُ أَنْ يُنَادِيَ أَلَا إِنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسُ مُؤْمِنٍ وَإِنَّهَا أَيَّامُ أَكْلٍ وَشُرْبٍ يَعْنِي أَيَّامَ التَّشْرِيقِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Dinar] dari [Nafi' Bin Jubair Bin Muth'im] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam] dari Nabi Shallallahu'alaihiwasallam beliau mengutus Bisyr bin Suhaim, lalu beliau menyuruhnya untuk menyiarkan bahwa tidak masuk surga kecuali seorang mukmin, dan hari itu yaitu hari makan dan minum, yaitu Hari Tasyriq."},"357":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ أَنَّهُ سَمِعَ نَافِعَ بْنَ جُبَيْرِ بْنِ مُطْعِمٍ يُحَدِّثُ عَنْ رَجُلٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ بِشْرُ بْنُ سُحَيْمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فَقَالَ إِنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مُؤْمِنٌ وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] berkata; telah mengabarkan kepadaku [Habib bin Abu Tsabit] telah mendengar [Nafi' Bin Jubair Bin Muth'im] menceritakan dari salah seorang sahabat Nabi Shallallahu'alaihiwasallam yang bernama [Bisyr bin Suhaim], Nabi Shallallahu'alaihiwasallam berkhutbah lalu beliau bersabda: \"Tidak masuk surga kecuali seorang mukmin, dan hari-hari ini adalah hari makan dan minum.\""},"358":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ أَنَّ مُحَمَّدَ بْنَ الْأَسْوَدِ بْنِ خَلَفٍ أَخْبَرَهُ أَنَّ أَبَاهُ الْأَسْوَدَرَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَايِعُ النَّاسَ يَوْمَ الْفَتْحِ قَالَ جَلَسَ عِنْدَ قَرْنِ مَسْقَلَةَ فَبَايَعَ النَّاسَ عَلَى الْإِسْلَامِ وَالشَّهَادَةِ قَالَ قُلْتُ وَمَا الشَّهَادَةُ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ الْأَسْوَدِ بْنِ خَلَفٍ أَنَّهُ بَايَعَهُمْ عَلَى الْإِيمَانِ بِاللَّهِ وَشَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrozaq] telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Abdullah bin 'Utsman bin khutsaim] [Muhammad bin Al 'Aswad bin Khalaf] mengabarinya, ayahnya yaitu [Al Aswad] melihat Nabi Shallallahu'alaihiwasallam membaiat manusia pada hari Penaklukan Makkah. Dia berkata; (Rasulullah Shallallahu'alaihiwasallam) duduk di Qarn Masqalah, beliau membaiat orang-orang atas Islam dan syahadat. (Ibnu Juraij Radliyallahu'anhu) berkata; saya bertanya, apa itu syahadah? (Abdullah bin 'Utsman bin Khutsaim Radliyallahu'anhu) berkata; Muhammad bin Al Aswad bin Khalaf mengabariku (Rasulullah Shallallahu'alaihiwasallam) membaiat mereka atas Iman kepada Allah dan syahadat LAA ILAAHA ILLA ALLAH WA ANNA MUHAMMADAN ABDUHU WA RASULUH Shallallahu'alaihiwasallam."},"359":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَنْ عُثَيْمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ جَاءَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَدْ أَسْلَمْتُ فَقَالَ أَلْقِ عَنْكَ شَعَرَ الْكُفْرِ يَقُولُ أَحْلِقْ قَالَ وَأَخْبَرَنِي آخَرُ مَعَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِآخَرَ أَلْقِ عَنْكَ شَعَرَ الْكُفْرِ وَاخْتَتِنْ","id":"Telah menceritakan kepada kami [Abdurrozaq] telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku, dari ['Utsaim bin Kulaib] dari [Bapaknya] dari [kakeknya] dia datang kepada Nabi Shallallahu'alaihiwasallam dan berkata; saya telah masuk Islam. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Buanglah bulu-bulu kekafiran darimu\" Dan bersabda: \"Cukurlah.\" ('Utsaim Radliyallahu'anhu) berkata; telah mengabarinya orang lain yang bersamanya, Nabi Shallallahu'alaihiwasallam bersabda kepada orang lain itu, \"Buanglah bulu-bulu kekafiran darimu dan berkhitanlah.\""},"360":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ عَمْرَو بْنَ أَوْسٍ قَالَ أَخْبَرَنِي مَنْ سَمِعَمُنَادِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَامَتْ الصَّلَاةُ أَوْ حِينَ حَانَتْ الصَّلَاةُ أَوْ نَحْوَ هَذَا أَنْ صَلُّوا فِي رِحَالِكُمْ لِمَطَرٍ كَانَ","id":"Telah menceritakan kepada kami [Abu Nua'im] telah menceritakan kepada kami [Mis'ar] dari ['Amr bin Dinar] berkata; saya telah mendengar ['Amru bin Aus] berkata; telah mengabarkan kepadaku [orang yang pernah mendengar Muaddzin Rasulullah Shallallahu'alaihiwasallam] ketika Shalat ditegakkan atau ketika tiba waktu Shalat atau yang seperti itu, menyerukan, \"Shalatlah kalian di rumah kalian\", karena turun hujan."},"361":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَعَفَّانُ قَالَا حَدَّثَنَا ثَابِتٌ قَالَ عَفَّانُ بْنُ زَيْدٍ أَبُو زَيْدٍ حَدَّثَنَا هِلَالُ بْنُ خَبَّابٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ قَالَ حَدَّثَنِي عَرِيفٌ مِنْ عُرَفَاءِ قُرَيْشٍ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ مِنْ فَلْقِ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَمَنْ صَامَ رَمَضَانَ وَشَوَّالًا وَالْأَرْبِعَاءَ وَالْخَمِيسَ وَالْجُمُعَةَ دَخَلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Abdusshamad] dan ['Affan] berkata; telah menceritakan kepada kami [Tsabit] berkata; ['Affan] bin Zaid, Abu Zaid telah menceritakan kepada kami [Hilal bin Khabbab] dari ['Ikrimah bin Khalid] berkata telah menceritakan kepadaku [salah seorang pemimpin Quraisy], telah menceritakan kepadaku [Bapakku] dia telah mendengar dari majlis subuh Rasulullah Shallallahu'alaihiwasallam, \"Barangsiapa yang berpuasa Ramadhan, Syawwal, Rabu dan Kamis serta Jum'at maka akan masuk surga.\""},"362":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عِكْرِمَةُ بْنُ خَالِدٍ الْمَخْزُومِيُّ عَنْ أَبِيهِ أَوْ عَنْ عَمِّهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي غَزْوَةِ تَبُوكَ إِذَا وَقَعَ الطَّاعُونُ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا مِنْهَا وَإِذَا وَقَعَ وَلَسْتُمْ بِهَا فَلَا تَقْدَمُوا عَلَيْهِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami ['Ikrimah bin Khalid Al Mahzumi] dari [Bapaknya] atau [pamannya] dari [kakeknya] Rasulullah Shallallahu'alaihiwasallam bersabda pada Perang Tabuk, \"Jika terjadi penyakit Thaun pada suatu tempat, dan kalian sedang bermukim disana, janganlah kalian meninggalkannya, namun jika sedang terjadi suatu tempat dan kalian tidak berdiam disana, janganlah mendatanginya.\""},"363":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ عِكْرِمَةَ يَعْنِي ابْنَ خَالِدٍ عَنْ أَبِيهِ أَوْ عَنْ عَمِّهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي غَزْوَةِ تَبُوكَ إِذَا وَقَعَ الطَّاعُونُ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا مِنْهَا وَإِذَا كَانَ بِأَرْضٍ وَلَسْتُمْ بِهَا فَلَا تَقْرَبُوهَا","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [Hammad] yaitu Ibnu Salamah, dari ['Ikrimah] yaitu Ibnu Khalid dari [Bapaknya] atau [Pamannya] dari [kakeknya] Rasulullah Shallallahu'alaihiwasallam bersabda pada Perang Tabuk: \"Jika terjadi penyakit Thaun pada suatu tempat, dan kalian sedang kalian berdiam disana, janganlah kalian meninggalkannya, namun jika sedang terjadi suatu tempat dan kalian tidak berdiam disana, janganlah mendekatinya.\""},"364":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ الْقَاسِمِ الرَّاسِبِيُّ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَاقَ عَنِ الْوَلِيدِ بْنِ عَبْدِ اللَّهِ بْنِ شُمَيْلَةَ عَنْ أَبِي طَرِيفٍ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ حَاصَرَ الطَّائِفَ وَكَانَ يُصَلِّي بِنَا صَلَاةَ الْعَصْرِ حَتَّى لَوْ أَنَّ رَجُلًا رَمَى لَرَأَى مَوْقِعَ نَبْلِهِ","id":"Telah menceritakan kepada kami [Azhar bin Al Qasim Ar-Rosi] telah menceritakan kepada kami [Zakariya bin Ishaq] dari [Al Walid bin Abdullah bin Syumailah] dari [Abu Tharif] berkata; saya bersama Rasulullah Shallallahu'alaihiwasallam ketika pengepungan Thaif, maka (Rasulullah Shallallahu'alaihiwasallam) Shalat asar bersama kami hingga jikalau orang melempar anak panah maka dia masih bisa melihat tempat anak panahnya (karena keadaan masih terang)."},"365":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ البَجْلِيِّ عَنْ صَخْرٍ الْغَامِدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهِمْ قَالَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ سَرِيَّةً بَعَثَهَا أَوَّلَ النَّهَارِوَكَانَ صَخْرٌ رَجُلًا تَاجِرًا وَكَانَ لَا يَبْعَثُ غِلْمَانَهُ إِلَّا مِنْ أَوَّلِ النَّهَارِ فَكَثُرَ مَالُهُ حَتَّى كَانَ لَا يَدْرِي أَيْنَ يَضَعُ مَالَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atho'] dari ['Umarah bin Hadid Al Bajli] dari [Shakhr Al Ghamidi] dari Nabi Shallallahu'alaihiwasallam beliau bersabda: \"Ya Allah, berilah barakah kepada umatku pada pagi hari mereka.\" (Shakhr Al Ghamidi Radliyallahu'anhu) berkata; Rasulullah Shallallahu'alaihiwasallam jika mengutus suatu pasukan, mengutusnya pada permulaan siang. Shakhr adalah seorang pedagang, dia tidak mengirimkan pekerjanya kecuali pada permulaan siang, maka hartanya menjadi banyak sampai tidak tahu harus dimana meletakkan hartanya."},"366":{"ar":"حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو وَسُرَيْجٌ الْمَعْنَى قَالَا حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ عَنْ أَبِي بَكْرِ بْنِ أَبِي زُهَيْرٍ قَالَ أَبِي كِلَاهُمَا قَالَ عَنْ أَبِي بَكْرِ بْنِ أَبِي زُهَيْرٍ الثَّقَفِيِّ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِالنَّبَاءَةِ أَوْ بِالنِّبَاوَةِ شَكَّ نَافِعٌ مِنْ الطَّائِفِ وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ إِنَّكُمْ تُوشِكُونَ أَنْ تَعْرِفُوا أَهْلَ الْجَنَّةِ مِنْ أَهْلِ النَّارِ أَوْ قَالَ خِيَارَكُمْ مِنْ شِرَارِكُمْ قَالَ فَقَالَ رَجُلٌ مِنْ النَّاسِ بِمَ يَا رَسُولَ اللَّهِ قَالَ بِالثَّنَاءِ السَّيِّئِ وَالثَّنَاءِ الْحَسَنِ وَأَنْتُمْ شُهَدَاءُ اللَّهِ بَعْضُكُمْ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Abdul Malik bin 'Amr] dan [Suraij] secara makna, berkata; telah menceritakan kepada kami [Nafi' bin 'Umar] dari [Umayyah bin Shafwan] dari [Abu Bakr bin Abu Zuhair] Bapakku berkata; keduanya berkata; dari Abu Bakr bin Abu Zuhair Ats-Tsaqafi dari [Bapaknya] berkata; saya mendengar Nabi Shallallahu'alaihiwasallam bersabda di Naba'ah atau Nabawwah, Nafi' ragu tempat yang mana yang di Thaif, \"Wahai para manusia, kalian hampir saja bisa mengenal penduduk surga dari penduduk neraka\" atau bersabda: \"Orang yang baik kalian dari orang yang jelek kalian\" (Abu Zuhair Radliyallahu'anhu) berkata; ada seorang laki-laki yang bertanya, dengan apa wahai Rasulullah? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Dengan pujian yang jelek dan pujian yang baik, dan sebagian dari kalian adalah saksi Allah atas sebagian yang lainnya.\""},"367":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنِ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنِ الْحَارِثِ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ الثَّقَفِيِّ قَالَسَأَلْتُ عُمَرَ بْنَ الْخَطَّابِ عَنْ الْمَرْأَةِ تَطُوفُ بِالْبَيْتِ ثُمَّ تَحِيضُ قَالَ لِيَكُنْ آخِرَ عَهْدِهَا الطَّوَافُ بِالْبَيْتِ فَقَالَ الْحَارِثُ كَذَلِكَ أَفْتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفَقَالَ عُمَرُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ أَدَّيْتَ عَنْ يَدَيْكَ سَأَلْتَنِي عَنْ شَيْءٍ سَأَلْتُ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكِنِّي مَا أُخَالِفُ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Ya'la bin 'Atha'] dari [Al Walid bin Abdurrahman] dari [Al Harits bin Abdullah bin Aus Ats-Tsaqafi] berkata; saya bertanya pada ['Umar bin Khattab] tentang seorang wanita yang thawaf di Ka'bah kemudian dia haid. ('Umar radliyallahu'anhu) berkata; hendaknya (wanita haid itu) menjadikan penutup hajinya dengan thawaf di Ka'bah. Al Harits berkata; begitulah Rasulullah Shallallahu'alaihiwasallam berfatwa kepadaku. 'Umar radliyallahu'anhu berkata; \"Celaka kamu, kamu bertanya sesuatu kepadaku yang saya telah menanyakannya kepada Rasulullah Shallallahu'alaihiwasallam, tapi saya tidak menyelisihinya.\""},"368":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَجَّاجِ وَعَلِيُّ بْنُ إِسْحَاقَ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ عَنْ عَبْدِ الْمَلِكِ بْنِ الْمُغِيرَةِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَمْرِو بْنِ أَوْسٍ عَنِ الْحَارِثِ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلْيَكُنْ آخِرُ عَهْدِهِ بِالْبَيْتِفَبَلَغَ حَدِيثُهُ عُمَرَ رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَقَالَ لَهُ خَرَرْتَ مِنْ يَدِكَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ تُخْبِرْنَا بِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hajjaj] dan ['Ali bin Ishaq] berkata; telah mengabarkan kepada kami [Abdullah] berkata; telah mengabarkan kepada kami [Al Hajjaj bin Arthah] dari [Abdul Malik bin Al Mughirah] dari [Abdurrahman bin Al Bailamani] dari ['Amar bin Aus] dari [Al Harits bin Abdullah bin Aus] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang berhaji menuju Baitullah atau berumrah, maka akhir amalannya yaitu di Ka'bah.\" Hadits itu sampai pada 'Umar radliyallahu'anhu, lalu dia dan berkata kepadanya.\"Celaka kamu, kamu telah mendengarnya dari Rasulullah Shallallahu'alaihiwasallam namun kamu tidak mengabarkannya kepada kami.\""},"369":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ قَالَ أَخْبَرَنَا عَبَّادٌ عَنِ الْحَجَّاجِ بْنِ أَرْطَاةَ عَنْ عَبْدِ الْمَلِكِ بْنِ الْمُغِيرَةِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَمْرِو بْنِ أَوْسٍ عَنِ الْحَارِثِ بْنِ أَوْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَجَّ أَوْ اعْتَمَرَ فَلْيَكُنْ آخِرَ عَهْدِهِ الطَّوَافُ بِالْبَيْتِفَقَالَ لَهُ عُمَرُ بْنُ الْخَطَّابِ خَرَرْتَ مِنْ يَدَيْكَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ لَمْ تُحَدِّثْنِي","id":"Telah menceritakan kepada kami [Suraij bin An-Nu'man] berkata; telah mengabarkan kepada kami ['Abbad] dari [Al Hajjaj bin Arthah] dari [Abdul Malik bin Al Mughirah] dari [Abdurrahman bin Al Bailamani] dari ['Amar bin Aus] dari [Al Harits bin Abdullah bin Aus] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang berhaji atau berUmrah, maka akhir amalannya yaitu thawaf di Ka'bah.\" Lalu 'Umar bin Khattab berkata kepadanya.\"Celaka kamu, kamu telah mendengar hal itu dari Rasulullah Shallallahu'alaihiwasallam namun kamu tidak mengabarkannya kepadaku.\""},"370":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ عَنْ صَخْرٍ الْغَامِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ فَكَانَ إِذَا بَعَثَ سَرِيَّةً أَوْ جَيْشًا بَعَثَهُمْ مِنْ أَوَّلِ النَّهَارِقَالَ فَكَانَ صَخْرٌ رَجُلًا تَاجِرًا وَكَانَ يَبْعَثُ تِجَارَتَهُ مِنْ أَوَّلِ النَّهَارِ قَالَ فَأَثْرَى وَكَثُرَ مَالُهُ","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Ya'la bin 'Atha'] dari ['Umarah bin Hadid] dari [Shakhr Al Ghamidi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ya Allah, berilah barakah kepada umatku pada pagi harinya.\" (Shakhr Al Ghamidi Radliyallahu'anhu) berkata; jika beliau mengutus suatu pasukan atau kelompok tentara, mengutus mereka dari permulaan siang. ('Umarah bin Hadid Radliyallahu'anhu) berkata; Shakhr adalah seorang pedagang, jika dia mengirimkan dagangannya maka pada permulaan siang, maka hal itu hartanya menjadi banyak dan melimpah."},"371":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّ أَبَا الْمِنْهَالِ أَخْبَرَهُ أَنَّ إِيَاسَ بْنَ عَبْدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَا تَبِيعُوا فَضْلَ الْمَاءِ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ الْمَاءِقَالَ وَالنَّاسُ يَبِيعُونَ مَاءَ الْفُرَاتِ فَنَهَاهُمْ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku ['Amr bin Dinar] [Abu Al Minhal] mengabarinya [Iyas bin Abd] salah seorang sahabat Nabi Shallallahu'alaihiwasallam berkata; janganlah kalian menjual air yang lebih, karena Nabi Shallallahu'alaihiwasallam melarang untuk menjual air yang lebih. (Abu Minhal Radliyallahu'anhu) berkata; ketika itu orang-orang menjual air sungai Eufrat, lalu (Iyas bin Abd Radliyallahu'anhu) melarangnya."},"372":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَمْرُو بْنُ كَثِيرٍ الْمَكِّيُّ قَالَ سَأَلْتُ عَبْدَ الرَّحْمَنِ بْنَ كَيْسَانَ مَوْلَى خَالِدِ بْنِ أُسَيْدٍ قُلْتُ أَلَا تُحَدِّثُنِي عَنْ أَبِيكَ فَقَالَ مَا سَأَلْتَنِي فَقَالَ حَدَّثَنِي أَبِي أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْمَطَابِخِ حَتَّى أَتَى الْبِئْرَ وَهُوَ مُتَّزِرٌ بِإِزَارٍ لَيْسَ عَلَيْهِ رِدَاءٌ فَرَأَى عِنْدَ الْبِئْرِ عَبِيدًا يُصَلُّونَ فَحَلَّ الْإِزَارَ وَتَوَشَّحَ بِهِ وَصَلَّى رَكْعَتَيْنِ لَا أَدْرِي الظُّهْرَ أَوْ الْعَصْرَ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah mengabarkan kepada kami ['Amr bin Katsir Al Makki] berkata; saya bertanya kepada [Abdurrahman bin Kaisan] budak Khalid bin Usaid, saya berkata; maukah kamu menceritakan kepadaku dari bapakmu, Dia berkata; apa yang kamu tanyakan? Dia berkata; telah menceritakan kepadaku [bapakku], dia telah melihat Rasulullah Shallallahu'alaihiwasallam keluar dari dapur menuju ke sumur dalam kedaan memakai sarung dengan tidak memakai selendang. ketika di sumur, beliau melihat budak-budak yang sedang Shalat, lalu beliau melepas sarungnya lalu menyandangnya dan Shalat dua rekaat, saya tidak tahu zhuhur atau asar."},"373":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ حَدَّثَنَا عَمْرُو بْنُ كَثِيرِ بْنِ أَفْلَحَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَيْسَانَ قَالَ سَأَلْتُ أَبِي كَيْسَانَمَا أَدْرَكْتَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُهُ يُصَلِّي عِنْدَ الْبِئْرِ الْعُلْيَا بِبِئْرِ بَنِي مُطِيعٍ مُلَبَّبًا فِي ثَوْبٍ الظُّهْرَ أَوْ الْعَصْرَ فَصَلَّاهَا رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Hammad bin Khalid Al Khoyyath] telah menceritakan kepada kami ['Amr bin Katsir bin Aflah] dari [Abdurrahman bin Kaisan] berkata; saya bertanya kepada [Abu Kaisan] apa yang kamu dapatkan dari Nabi Shallallahu'alaihiwasallam?. Dia menjawab, saya melihat beliau Shalat zhuhur atau ashar di samping sumur yang tinggi yang terletak pada Bani Muthi', dengan mengikatkan satu kain dua rekaat."},"374":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلَّبِيُّ عَنْ هِشَامِ بْنِ زِيَادٍ عَنْ عُثْمَانَ بْنِ الْأَرْقَمِ بْنِ أَبِي الْأَرْقَمِ الْمَخْزُومِيِّ عَنْ أَبِيهِ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الَّذِي يَتَخَطَّى رِقَابَ النَّاسِ يَوْمَ الْجُمُعَةِ وَيُفَرِّقُ بَيْنَ الِاثْنَيْنِ بَعْدَ خُرُوجِ الْإِمَامِ كَالْجَارِّ قُصْبَهُ فِي النَّارِ","id":"Telah menceritakan kepada kami ['Abbad bin 'Abbad Al Muhallabi] dari [Hisyam bin Ziyad] dari ['Utsman bin Al Arqam bin Abu Al Arqam Al Mahzumi] dari [Bapaknya], dia adalah salah seorang sahabat Nabi Shallallahu'alaihiwasallam, Nabi Shallallahu'alaihiwasallam bersabda: \"Orang yang melangkahi leher orang-orang pada Hari Jum'at atau, menyela antara dua orang setelah datangnya seorang khatib, seperti orang yang menarik ususnya di neraka.\""},"375":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا أَبُو مُعَاوِيَةَ يَعْنِي شَيْبَانَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ أَنَّ ابْنَ عَابِسٍ الْجُهَنِيَّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا ابْنَ عَابِسٍ أَلَا أُخْبِرُكَ بِأَفْضَلِ مَا تَعَوَّذَ بِهِ الْمُتَعَوِّذُونَ قُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَقُلْ أَعُوذُ بِرَبِّ النَّاسِ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Abu Mu'awiyah] yaitu Syaiban dari [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim], [Ibnu 'Abis Al Juhani] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wahai Ibnu 'Abbas, maukah kamu kuberitahu tentang bacaan yang paling utama, yang dibaca oleh orang yang memohon perlindungan?\" Dia berkata; Ya wahai Rasulullah! (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Bacalah, QUL A'UDZU BIROBBIL FALAQ dan QUL A'UDZU BIROBBIN NAAS \""},"376":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَخْبَرَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ مُبَارَكٍ قَالَ أَخْبَرَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الْمُطَّلِبُ بْنُ حَنْطَبٍ الْمَخْزُومِيُّ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ الْأَنْصَارِيُّ حَدَّثَنِي أَبِي قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَأَصَابَ النَّاسَ مَخْمَصَةٌ فَاسْتَأْذَنَ النَّاسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَحْرِ بَعْضِ ظُهُورِهِمْ وَقَالُوا يُبَلِّغُنَا اللَّهُ بِهِ فَلَمَّا رَأَى عُمَرُ بْنُ الْخَطَّابِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ هَمَّ أَنْ يَأْذَنَ لَهُمْ فِي نَحْرِ بَعْضِ ظَهْرِهِمْ قَالَ يَا رَسُولَ اللَّهِ كَيْفَ بِنَا إِذَا نَحْنُ لَقِينَا الْقَوْمَ غَدًا جِيَاعًا أَرْجَالًا وَلَكِنْ إِنْ رَأَيْتَ يَا رَسُولَ اللَّهِ أَنْ تَدْعُوَ لَنَا بِبَقَايَا أَزْوَادِهِمْ فَتَجْمَعَهَا ثُمَّ تَدْعُوَ اللَّهَ فِيهَا بِالْبَرَكَةِ فَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى سَيُبَلِّغُنَا بِدَعْوَتِكَ أَوْ قَالَ سَيُبَارِكُ لَنَا فِي دَعْوَتِكَ فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَقَايَا أَزْوَادِهِمْ فَجَعَلَ النَّاسُ يُجِيئُونَ بِالْحَثْيَةِ مِنْ الطَّعَامِ وَفَوْقَ ذَلِكَ وَكَانَ أَعْلَاهُمْ مَنْ جَاءَ بِصَاعٍ مِنْ تَمْرٍ فَجَمَعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامَ فَدَعَا مَا شَاءَ اللَّهُ أَنْ يَدْعُوَ ثُمَّ دَعَا الْجَيْشَ بِأَوْعِيَتِهِمْ فَأَمَرَهُمْ أَنْ يَحْتَثُوا فَمَا بَقِيَ فِي الْجَيْشِ وِعَاءٌ إِلَّا مَلَئُوهُ وَبَقِيَ مِثْلُهُ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ لَا يَلْقَى اللَّهَ عَبْدٌ مُؤْمِنٌ بِهِمَا إِلَّا حُجِبَتْ عَنْهُ النَّارُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami ['Ali bin Ishaq] telah mengabarkan kepada kami [Abdullah] yaitu Ibnu Mubarak, berkata; telah mengabarkan kepada kami [Al Auza'i] berkata; telah menceritakan kepadaku [Al Muthalib bin Hanthab Al Mahzumi] berkata; telah menceritakan kepadaku [Abdurrahman bin Abu 'Amrah Al Anshari] telah menceritakan kepadaku [Bapakku] berkata; kami bersama Rasulullah Shallallahu'alaihiwasallam dalam sebuah peperangan, lalu para pasukan tertimpa kelaparan hingga mereka meminta ijin kepada Rasulullah Shallallahu'alaihiwasallam untuk menyembelih sebagian kendaraan mereka, dan mereka berkata; 'Semoga Allah membuat kita cukup dengannya.' Tatkala 'Umar bin Khattab mengetahui Rasulullah Shallallahu'alaihiwasallam hendak mengijinkan mereka untuk menyembelih sebagian kendaraan mereka, ia berkata; 'Wahai Rasulullah bagaimana jika besok kita bertemu dengan musuh dalam keadaan lapar dan berjalan kaki. namun jika anda mau, suruhlah kami untuk mengumpulkan sisa-sisa bekal mereka, lalu anda mengumpulkannya dan berdoa kepada Allah memohon barokah kepada-Nya, niscaya Allah akan mencukupkan kita dengan doa anda. atau berkata; Allah akan memberi barokah kita dengan doa anda.' Nabi Shallallahu'alaihiwasallam menyuruh untuk mengumpulkan perbekalan mereka, hingga orang-orang mengumpulkan perbekalan mereka. Ada yang menyerahkan satu cakupan makanan, ada yang lebih dari itu, dan paling banyak dari mereka adalah yang datang dengan membawa dengan satu sho' kurma. Nabi Shallallahu'alaihiwasallam mengumpulkannya, lalu berdoa dengan do'anya, lalu menyuruh para pasukan untuk membawa tempat makanan dan menyuruh mereka untuk mencakup perbekalan makanan yang telah dikumpulkan, maka tak ada seorang pun yang membawa tempat makanan mereka melainkan mereka telah mengisinya dengan makanan tersebut dan ternyata masih tetap utuh seperti sedia kala. Nabi Shallallahu'alaihiwasallam tersenyum hingga terlihat gerahamnya, lalu bersabda: \"ASYHADU AN LAA ILAAHA ILLA ALLAH WA ANNI ROSULULLOH, tidak seorang hamba yang mukmin yang bertemu Allah dengan kedua kalimat ini melainkan neraka ditutup darinya.\""},"377":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ قَالَ أَخْبَرَنِي عِيسَى بْنُ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ عَنْ عُمَيْرِ بْنِ سَلَمَةَ الضَّمْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِالْعَرْجِ فَإِذَا هُوَ بِحِمَارٍ عَقِيرٍ فَلَمْ يَلْبَثْ أَنْ جَاءَ رَجُلٌ مِنْ بَهْزٍ فَقَالَ يَا رَسُولَ اللَّهِ هَذِهِ رَمْيَتِي فَشَأْنُكُمْ بِهَا فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَسَمَهُ بَيْنَ الرِّفَاقِ ثُمَّ سَارَ حَتَّى أَتَى عَقَبَةَ أُثَايَةَ فَإِذَا هُوَ بِظَبْيٍ فِيهِ سَهْمٌ وَهُوَ حَاقِفٌ فِي ظِلِّ صَخْرَةٍ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ أَصْحَابِهِ فَقَالَ قِفْ هَاهُنَا حَتَّى يَمُرَّ الرِّفَاقُ لَا يَرْمِيهِ أَحَدٌ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] berkata; telah menceritakan kepadaku ['Isa bin Thalhah bin 'Ubaidullah] dari ['Umair bin Salamah Adl Dlamri] Rasulullah Shallallahu'alaihiwasallam melewati 'Aroj (dalam keadaan ihram), lantas ada seekor keledai yang terbunuh dan Rasulullah Shallallahu'alaihiwasallam membiarkannya hingga datang seorang laki-laki dari Bahzi dan berkata 'Wahai Rasulullah ini adalah buruanku, maka terserah apa yang anda perbuat.' Lalu Rasulullah Shallallahu'alaihiwasallam menyuruh Abu Bakar radliyallahu'anhu hingga dia membagikannya kepada para sahabat yang menyertainya. Lalu Rasulullah Shallallahu'alaihiwasallam pergi berjalan hingga ketika sampai di Utsayah maka ada seekor rusa yang terkena anak panah dan terbaring melingkar pada lubang batu besar, Nabi Shallallahu'alaihiwasallam memerintahkan salah seorang dari sahabatnya seraya bersabda: \"Berhentilah disini\", hingga para sahabat yang mengikuti Nabi Shallallahu'alaihiwasallam melewati rusa tersebut begitu saja tanpa ada seorangpun yang melemparnya dengan sesuatu."},"378":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بَلْجٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍ الْجُمَحِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصْلٌ بَيْنَ الْحَلَالِ وَالْحَرَامِ الدُّفُّ وَالصَّوْتُ فِي النِّكَاحِ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Balj] dari [Muhammad bin Hathib Al Jumahi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Yang memisahkan antara halal dan haram adalah rebana dan suara nyanyian dalam acara pernikahan.\""},"379":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ سِمَاكٍ قَالَ قَالَ مُحَمَّدُ بْنُ حَاطِبٍانْصَبَّتْ عَلَى يَدِي مِنْ قِدْرٍ فَذَهَبَتْ بِي أُمِّي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي مَكَانٍ قَالَ فَقَالَ كَلَامًا فِيهِ أَذْهِبْ الْبَاسْ رَبَّ النَّاسْ وَأَحْسِبُهُ قَالَ اشْفِ أَنْتَ الشَّافِي قَالَ وَكَانَ يَتْفُلُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Simak] berkata; [Muhammad bin Hathib] berkata; tanganku tertuang oleh air panas dari sebuah bejana, lalu ibuku membawaku kepada Rasulullah Shallallahu'alaihiwasallam yang berada pada sebuah tempat. (Hathib Radliyallahu'anhu) berkata; beliau mengucapkan sebuah perkataan di dalamnya, ADZHIBIL BA'SA ROBBAN NAS (Hilangkanlah sakitnya wahai Tuhan para manusia) \", saya mengira beliau juga bersabda: \"ISYFI ANTAS SYAAFII\" (Sembuhkanlah karena Engkaulah yang Maha Menyembuhkan). (Hathib Radliyallahu'anhu) berkata; beliau meludah."},"380":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ وَيُونُسُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عُثْمَانَ قَالَ إِبْرَاهِيمُ بْنُ الْعَبَّاسِ فِي حَدِيثِهِ ابْنُ إِبْرَاهِيمَ بْنُ مُحَمَّدِ بْنِ حَاطِبٍ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّهِ مُحَمَّدِ بْنِ حَاطِبٍ عَن�� أُمِّهِ أُمِّ جَمِيلٍ بِنْتِ الْمُجَلِّلِقَالَتْ أَقْبَلْتُ بِكَ مِنْ أَرْضِ الْحَبَشَةِ حَتَّى إِذَا كُنْتُ مِنْ الْمَدِينَةِ عَلَى لَيْلَةٍ أَوْ لَيْلَتَيْنِ طَبَخْتُ لَكَ طَبِيخًا فَفَنِيَ الْحَطَبُ فَخَرَجْتُ أَطْلُبُهُ فَتَنَاوَلْتَ الْقِدْرَ فَانْكَفَأَتْ عَلَى ذِرَاعِكَ فَأَتَيْتُ بِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ هَذَا مُحَمَّدُ بْنُ حَاطِبٍ فَتَفَلَ فِي فِيكَ وَمَسَحَ عَلَى رَأْسِكَ وَدَعَا لَكَ وَجَعَلَ يَتْفُلُ عَلَى يَدَيْكَ وَيَقُولُ أَذْهِبْ الْبَاسْ رَبَّ النَّاسْ وَاشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا فَقَالَتْ فَمَا قُمْتُ بِكَ مِنْ عِنْدِهِ حَتَّى بَرَأَتْ يَدُكَ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu Al 'Abbas] dan [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Abdurrahman bin 'Utsman] berkata; [Ibrahim bin Abu Al 'Abbas] dalam haditsnya [Ibnu Ibrahim bin Muhammad bin Hathib], berkata; telah menceritakan kepadaku [bapakku] dari kakeknya, [Muhammad bin Hathib] dari ibunya, [Ummu Jamil binti Al Mujallil], berkata; saya menemuimu dari Habasyah sampai jika saya di Madinah selama satu atau dua hari, saya memasakkan untukmu, namun kayunya habis, lalu saya keluar untuk memintanya. Kamu memegang bejana, ternyata terbalik dan mengenai tanganmu, lalu saya membawamu menemui Nabi Shallallahu'alaihiwasallam. Saya katakan kepada beliau, demi bapakku dan ibuku Wahai Rasulullah, ini adalah Muhammad bin Hathib, lalu beliau meludah pada mulutmu dan membasuh kepalamu dan mendo'akanmu, lalu beliau meludah pada tanganmu dan membaca: \"Hilangkanlah sakitnya, wahai rabb manusia, Sembuhkanlah karena Engkaulah yang Maha Menyembuhkan. Tidak ada kesembuhan kecuali kesembuhan dari-Mu. Kesembuhan yang tidak menyisakan penyakitpun.\" (Ummu Jamil Radliyallahu'anhuma) berkata; tidaklah saya berdiri denganmu untuk meninggalkan beliau, sehingga tanganmu telah sembuh."},"381":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍقَالَ دَبَبْتُ إِلَى قِدْرٍ وَهِيَ تَغْلِي فَأَدْخَلْتُ يَدِي فِيهَا فَاحْتَرَقَتْ أَوْ قَالَ فَوَرِمَتْ يَدِي فَذَهَبَتْ بِي أُمِّي إِلَى رَجُلٍ كَانَ بِالْبَطْحَاءِ فَقَالَ شَيْئًا وَنَفَثَ فَلَمَّا كَانَ فِي إِمْرَةِ عُثْمَانَ قُلْتُ لِأُمِّي مَنْ كَانَ ذَلِكَ الرَّجُلُ قَالَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu Al 'Abbas] berkata; telah menceritakan kepada kami [Syarik] dari [Simak bin Harb] dari [Muhammad bin Hathib] berkata; saya merangkak ke sebuah bejana, ternyata sedang mendidih, kumasukkan tanganku ke dalamnya dan terbakarlah tanganku, sehingga tanganku melepuh, lalu ibuku membawaku ke seorang laki-laki di Bathha' lalu dia membaca sesuatu dan meniupnya. Tatkala pada masa pemerintahan 'Utsman, saya bertanya kepada ibuku, siapa orang tersebut. Dia menjawab, dia adalah Rasulullah Shallallahu'alaihiwasallam."},"382":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبِي حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ قَالَ حَدَّثَنِي حَكِيمُ بْنُ أَبِي يَزِيدٍ عَنْ أَبِيهِ قَالَ حَدَّثَنِي أَبِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ دَعُوا النَّاسَ يُصِيبُ بَعْضُهُمْ مِنْ بَعْضٍ فَإِذَا اسْتَنْصَحَ أَحَدُكُمْ أَخَاهُ فَلْيَنْصَحْهُ","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami ['Atho' bin As-Sa'ib] berkata; telah menceritakan kepadaku [Hakim bin Abu Yazid] dari [Bapaknya] berkata; telah menceritakan kepadaku [bapakku] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Biarkanlah orang-orang saling membenarkan sebagian dari mereka atas sebagian yang lain, jika salah satu dari kalian memohon nasehat kepada saudaranya maka berilah dia nasehat.\""},"383":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنِي أَبُو الْحُوَيْرِثِ حَفْصٌ مِنْ وَلَدِ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ يَعْلَى بْنِ كَعْبٍ عَنْ مَيْمُونَةَ بِنْتِ كَرْدَمٍ عَنْ أَبِيهَا كَرْدَمِ بْنِ سُفْيَانَأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَذْرٍ نُذِرَ فِي الْجَاهِلِيَّةِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلِوَثَنٍ أَوْ لِنُصُبٍ قَالَ لَا وَلَكِنْ لِلَّهِ تَبَارَكَ وَتَعَالَى قَالَ فَأَوْفِ لِلَّهِ تَبَارَكَ وَتَعَالَى مَا جَعَلْتَ لَهُ انْحَرْ عَلَى بُوَانَةَ وَأَوْفِ بِنَذْرِكَ","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepadaku [Abu Al Huwairits, Hafsh dari anak laki-laki 'Utsman bin Abu Al Ash], berkata; telah menceritakan kepadaku [Abdullah bin Abdurrahman bin Ya'la bin Ka'b] dari dari [Maimunah binti Kardam] dari [Bapaknya, Kardam bin Sufyan] dia telah bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang nadzar yang di ikrarkan di waktu Jahiliyyah. Nabi Shallallahu'alaihiwasallam bersabda kepadanya, apakah untuk berhala atau untuk patung? Dia berkata; tidak, tapi untuk Allah Tabaroka wa ta'ala, (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Tepatilah nadzar kamu untuk Allah Tabaroka wa ta'ala, apa yang telah kamu janjikan pada-Nya, sembelihlah di Buwanah dan tepatilah nadzarmu.\""},"384":{"ar":"حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ فَضَاءٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَنَهَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُكْسَرَ سِكَّةُ الْمُسْلِمِينَ الْجَائِزَةُ بَيْنَهُمْ إِلَّا مِنْ بَأْسٍ","id":"Telah menceritakan kepada kami [Mu'tamir bin Sulaiman] berkata; saya telah mendengar [Muhammad bin Fadlo'] menceritakan dari [Bapaknya] dari [Al Qomah bin Abdullah] dari [Bapaknya] berkata; Nabiyullah Shallallahu'alaihiwasallam melarang memecah (merusak) mata uang kaum muslimin yang berlaku di antara mereka kecuali jika rusak sendiri."},"385":{"ar":"حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ فَحَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ ضَمْرَةَ الْفَزَارِيُّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي سَلِيطٍ عَنْ أَبِيهِ أَبِي سَلِيطٍ قَالَأَتَانَا نَهْيُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ وَالْقُدُورُ تَفُورُ بِهَا فَكَفَأْنَاهَا عَلَى وُجُوهِهَا","id":"Telah menceritakan kepada kami [Ya'qub] berkata; telah menceritakan kepadaku [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Abdullah bin 'Amr bin Dlomroh Al Fazari] dari [Abdullah bin Abu Salith] dari [Bapaknya, Abi Salith] berkata; telah sampai kepada kami larangan Rasulullah Shallallahu'alaihiwasallam tentang memakan keledai yang dipakai untuk kendaraan dan makanan dalam bejana yang masih menyala-nyala (yang masih mendidih) hingga kami menuangkan isinya."},"386":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ عَبْد اللَّهِ وَسَمِعْتُ أَنَا مِنْ ابْنِ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ ضَمُرَةَ الْفَزَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي سَلِيطٍ عَنْ أَبِيهِ أَبِي سَلِيطٍ وَكَانَ بَدْرِيًّا قَالَأَتَانَا نَهْيُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُحُومِ الْحُمُرِ وَنَحْنُ بِخَيْبَرَ فَكَفَأْنَاهَا وَإِنَّا لَجِيَاعٌ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] Abdullah berkata; saya telah mendengar [Ibnu Abu Syaibah] berkata; telah menceritakan kepada kami [Abdullah bin Numair] dari [Muhammad bin Ishaq] dari [Abdullah bin 'Amr bin Dlamrah Al Fazari] dari [Abdullah bin Abu Salith] dari [Bapaknya, Abi Salith] dia adalah termasuk Ahli Badar, berkata; sampai kepada kami larangan Rasulullah Shallallahu'alaihiwasallam tentang daging keledai dan kami sedang di Khaibar, lalu kami menumpahkannya saat kami dalam keadaan lapar."},"387":{"ar":"حَدَّثَنَا سَيَّارُ بْنُ حَاتِمٍ أَبُو سَلَمَةَ الْعَنَزِيُّ قَالَ حَدَّثَنَا جَعْفَرٌ يَعْنِي ابْنَ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو التَّيَّاحِ قَالَ قُلْتُ لِعَبْدِ الرَّحْمَنِ بْنِ خَنْبَشٍ التَّمِيمِيِّ وَكَانَ كَبِيرًاأَدْرَكْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قَالَ قُلْتُ كَيْفَ صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ كَادَتْهُ الشَّيَاطِينُ فَقَالَ إِنَّ الشَّيَاطِينَ تَحَدَّرَتْ تِلْكَ اللَّيْلَةَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَوْدِيَةِ وَالشِّعَابِ وَفِيهِمْ شَيْطَانٌ بِيَدِهِ شُعْلَةُ نَارٍ يُرِيدُ أَنْ يُحْرِقَ بِهَا وَجْهَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَبَطَ إِلَيْهِ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ يَا مُحَمَّدُ قُلْ قَالَ مَا أَقُولُ قَالَ قُلْ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ وَمِنْ شَرِّ مَا يَنْزِلُ مِنْ السَّمَاءِ وَمِنْ شَرِّ مَا يَعْرُجُ فِيهَا وَمِنْ شَرِّ فِتَنِ اللَّيْلِ وَالنَّهَارِ وَمِنْ شَرِّ كُلِّ طَارِقٍ إِلَّا طَارِقًا يَطْرُقُ بِخَيْرٍ يَا رَحْمَنُ قَالَ فَطَفِئَتْ نَارُهُمْ وَهَزَمَهُمْ اللَّهُ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Sayyar bin Hatim Abu Salamah Al 'Anazi] berkata; telah menceritakan kepada kami [Ja'far] yaitu Ibnu Sulaiman berkata; telah menceritakan kepada kami [Abu At Tayah] berkata; saya bertanya kepada [Abdur Rahman bin Khanbasy At Tamimi] yang pada waktu itu sudah tua usia, apakah kamu bertemu Rasulullah Shallallahu'alaihiwasallam? dia berkata; Ya. (Abut At Tayyah Radliyallahu'anhu) berkata; apa yang dilakukan Rasulullah Shallallahu'alaihiwasallam ketika datang setan kepadanya?. dia berkata; \" Setan datang secara bergemuruh kepada Rasulullah Shallallahu'alaihiwasallam pada malam itu dari lembah-lembah dan bukit-bukit dan di antara mereka ada yang membawa obor di tangannya, hendak membakar wajah Rasulullah Shallallahu'alaihiwasallam, lalu Jibril Alaihissalam turun kepada (Rasulullah Shallallahu'alaihiwasallam) dan berkata; wahai Muhammad katakanlah! Beliau bertanya, \"Apa yang saya harus baca?\" (Jibril alaihissalam) berkata; bacalah: A'UDZU BI KALIMATILLAHI TAAMMATI MIN SYARRI MAA KHOLAQ WA DZAROA WA BAROA WA MIN SYARRI MA YANZIL MINAS SAMAAI WA MIN SYARRI MA YA'RUJU FIIHAA WA MIN SYARRI FITANIL LAILI WAN NAHAARI WA MIN SYARRI KULLI THORIQIN ILLAA THOORIQON YATHRUQU BI KHOIRIN YA ROHMAN (aku berlindung dengan kalimat Allah yang sempurna dari kejelekan yang Dia ciptakan, yang Dia buat dan yang Dia adakan dan dari kejelekan apa saja yang turun dari langit dan dari kejelekan apa saja yang naik padaNya, dan dari kejelekan fitnah malam dan siang, dan dari kejelekan yang datang pada malam hari kecuali yang datang dengan kebaikan wahai Rahman (tuhan yang maha pengasih). (Abdur Rahman Radliyallahu'anhu) berkata; lalu api mereka padam dan Allah Tabaaroka wa ta'ala menghancurkan mereka.\""},"388":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو التَّيَّاحِ قَالَ سَأَلَ رَجُلٌ عَبْدَ الرَّحْمَنِ بْنَ خَنْبَشٍكَيْفَ صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ كَادَتْهُ الشَّيَاطِينُ قَالَ جَاءَتْ الشَّيَاطِينُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَوْدِيَةِ وَتَحَدَّرَتْ عَلَيْهِ مِنْ الْجِبَالِ وَفِيهِمْ شَيْطَانٌ مَعَهُ شُعْلَةٌ مِنْ نَارٍ يُرِيدُ أَنْ يُحْرِقَ بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَرُعِبَ قَالَ جَعْفَرٌ أَحْسَبُهُ قَالَ جَعَلَ يَتَأَخَّرُ قَالَ وَجَاءَ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ يَا مُحَمَّدُ قُلْ قَالَ مَا أَقُولُ قَالَ قُلْ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّاتِ الَّتِي لَا يُجَاوِزُهُنَّ بَرٌّ وَلَا فَاجِرٌ مِنْ شَرِّ مَا خَلَقَ وَذَرَأَ وَبَرَأَ وَمِنْ شَرِّ مَا يَنْزِلُ مِنْ السَّمَاءِ وَمِنْ شَرِّ مَا يَعْرُجُ فِيهَا وَمِنْ شَرِّ مَا ذَرَأَ فِي الْأَرْضِ وَمِنْ شَرِّ مَا يَخْرُجُ مِنْهَا وَمِنْ شَرِّ فِتَنِ اللَّيْلِ وَالنَّهَارِ وَمِنْ شَرِّ كُلِّ طَارِقٍ إِلَّا طَارِقًا يَطْرُقُ بِخَيْرٍ يَا رَحْمَنُ فَطَفِئَتْ نَارُ الشَّيَاطِينِ وَهَزَمَهُمْ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Ja'far bin Sulaiman] telah menceritakan kepada kami [Abu At Tayah] berkata; seseorang bertanya kepada [Abdur Rahman bin Khanbasy] apa yang dilakukan Rasulullah Shallallahu'alaihiwasallam ketika datang setan kepadanya?. Lalu dia berkata; \"Setan datang kepada Rasulullah Shallallahu'alaihiwasallam dari bukit-bukit, mereka bergemuruh dari gunung-gunung menuju beliau. Di antara mereka ada setan yang membawa obor, hendak memBakar rasulullah Shallallahu'alaihiwasallam.\" (Rasulullah Shallallahu'alaihiwasallam) takut. Ja'far berkata; saya menaksir (Abdur Rahman bin Khanbasy Radliyallahu'anhu) berkata; (Rasulullah Shallallahu'alaihiwasallam) mundur. (Abdur Rahman bin Khanbasy Radliyallahu'anhu) berkata; lalu Jibril Alaihissalam datang dan berkata; wahai Muhammad bacalah! Beliau bertanya, \"Apa yang saya harus baca?\" (Jibril Alaihissalam) berkata; bacalah: A'UDZU BI KALIMATILLAHI TAAMMATI ALLATI LA YUJAWIZUHUNNA BARRUN WALA FAJIRUN, MIN SYARRI MAA KHOLAQ WA DZAROA WA BAROA WA MIN SYARRI MA YANZIL MINAS SAMAAI WA MIN SYARRI MA YA'RUJU FIIHAA WA MIN SYARRI MA DZAROA FIL ARDLI WA MIN SYARRI MA YAKHRUJU MINHA WAMIN SYARRI FITANIL LAILI WAN NAHAARI WA MIN SYARRI KULLI THORIQIN ILLAA THOORIQON YATHRUQU BI KHOIRIN YA ROHMAN (aku berlindung dengan kalimat Allah yang sempurna yang tidak bisa melewatinya orang yang baik maupun orang yang berdosa, dari kejelekan yang Dia ciptakan, yang Dia buat dan yang Dia adakan dan dari kejelekan apa saja yang turun dari langit dan dari kejelekan apa saja yang naik padanya, dan dari kejelekan apa yang ada di bumi dan dari kejelekan apa yang keluar darinya, dan dari kejelekan fitnah malam dan siang, dan dari kejelekan yang datang pada malam hari kecuali yang datang dengan kebaikan wahai Rahman (tuhan yang maha pengasih). lalu api setan padam dan Allah AzzaWaJalla menghancurkan mereka."},"389":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي زِيَادٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ كَثِيرٍ الدَّارِيُّ عَنْ مُجَاهِدٍ قَالَ حَدَّثَنَا شَيْخٌ أَدْرَكَ الْجَاهِلِيَّةَ وَنَحْنُ فِي غَزْوَةِ رُودِسَ يُقَالُ لَهُ ابْنُ عَبْسٍ قَالَكُنْتُ أَسُوقُ لِآلٍ لَنَا بَقَرَةً قَالَ فَسَمِعْتُ مِنْ جَوْفِهَا آلَ ذَرِيحْ قَوْلٌ فَصِيحْ رَجُلٌ يَصِيحْ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ فَقَدِمْنَا مَكَّةَ فَوَجَدْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami ['Ubaidullah bin Abu Ziyad] berkata; telah menceritakan kepadaku [Abdullah bin Katsir Ad Dari] dari [Mujahid] berkata; telah menceritakan kepada kami seorang tua yang pernah mengalami masa Jahiliyyah ketika kami berada dalam perang Rudisa, namanya adalah [Ibnu Abas], berkata; Saya mengembala sapi milik keluarga kami. Dia berkata; lalu saya mendengar dari perutnya ada suara, 'Wahai keluarga Dzarih ada sebuah perkataan yang fasih, seorang laki-laki yang meneriakkan bahwa tiada ILah selain Allah?. Dia berkata; ketika kami datang di Makkah, ternyata Nabi Shallallahu'alaihiwasallam telah muncul."},"390":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ عَيَّاشِ بْنِ أَبِي رَبِيعَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَخْرُجُ رِيحٌ بَيْنَ يَدَيْ السَّاعَةِ تُقْبَضُ فِيهَا أَرْوَاحُ كُلِّ مُؤْمِنٍ","id":"Telah menceritakan kepada kami [Abdurrazzaq] berkata; telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari ['Ayyasy bin Abu Rab'iah] berkata; saya telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Diantara tanda-tanda Kiamat adalah akan keluar angin yang mencabut ruh setiap mukmin.\""},"391":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي النَّجْمِ وَسَجَدَ النَّاسُ مَعَهُقَالَ الْمُطَّلِبُ وَلَمْ أَسْجُدْ مَعَهُمْ وَهُوَ يَوْمَئِذٍ مُشْرِكٌ فَقَالَ الْمُطَّلِبُ فَلَا أَدَعُ السُّجُودَ فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khalid] dari [Al Muthalib bin Abu Wada'ah] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam sujud karena membaca ayat dalam surat An-Najm, (AN Najm:) lalu orang-orang ikut sujud bersama beliau. Al Muthalib berkata; saya tidak ikut sujud bersama mereka, karena ketika itu dia masih musyrik. Lalu Al Muthalib berkata; namun di kemudian hari saya tidak meninggalkan sujud ketika membacanya selamanya."},"392":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنِ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ جَعْفَرِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيِّ عَنْ أَبِيهِ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ سُورَةَ النَّجْمِ فَسَجَدَ وَسَجَدَ مَنْ عِنْدَهُفَرَفَعْتُ رَأْسِي وَأَبَيْتُ أَنْ أَسْجُدَ وَلَمْ يَكُنْ أَسْلَمَ يَوْمَئِذٍ الْمُطَّلِبُ وَكَانَ بَعْدُ لَا يَسْمَعُ أَحَدًا قَرَأَهَا إِلَّا سَجَدَ","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid] telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Ibnu Thawus] dari ['Ikrimah bin Khalid] dari [Ja'far bin Abu Wada'ah As-Sahmi] dari [Bapaknya] berkata; Rasulullah Shallallahu'alaihiwasallam di Makkah membaca surat An-Najm lalu beliau bersujud, dan orang-orang yang sedang bersama beliau juga bersujud. Lalu saya mengangkat kepalaku dan saya menolak untuk bersujud. Karena ketika itu Al Muthalib belum masuk Islam. Di kemudian hari, tidaklah ia mendengarkan seorang pun yang membacanya kecuali dia bersujud."},"393":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ ثَعْلَبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ سَمِعْتُ مُجَمِّعَ ابْنَ جَارِيَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ الدَّجَّالَ فَقَالَ يَقْتُلُهُ ابْنُ مَرْيَمَ بِبَابِ لُدٍّ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] telah menceritakan kepada kami [Az-Zuhri] dari [Abdullah bin 'Ubaidullah bin Tsa'labah] dari [Abdur Rahman bin Yazid] berkata; saya telah mendengar [Mujammi' bin Jariyah] Nabi Shallallahu'alaihiwasallam menceritakan Dajjal, beliau bersabda: Ibnu Maryam membunuhnya di pintu Ludd."},"394":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا لَيْثٌ يَعْنِي ابْنَ سَعْدٍ قَالَ حَدَّثَنَا ابْنُ شِهَابٍ أَنَّهُ سَمِعَ عُبَيْدِ اللَّهِ بْنَ ثَعْلَبَةَ الْأَنْصَارِيَّ يُحَدِّثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ الْأَنْصَارِيِّ مِنْ بَنِي عَمْرِو بْنِ عَوْفٍ يَقُولُ سَمِعْتُ عَمِّي مُجَمِّعَ ابْنَ جَارِيَةَ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقْتُلُ ابْنُ مَرْيَمَ الْمَسِيحَ الدَّجَّالَ بِبَابِ لُدٍّ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] berkata; telah menceritakan kepada kami [Laits] yaitu Ibnu Sa'd, berkata; telah menceritakan kepada kami [Ibnu Syihab] telah mendengar ['Ubaidullah bin Tsa'labah Al Anshari] menceritakan dari [Abdurrahman bin Yazid Al Anshari] dari Bani 'Amr Bin 'Auf, berkata; saya telah mendengar [pamanku, Mujammi' bin Jariyah] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ibnu Maryam membunuh Al Masih Dajjal di pintu Lud.\""},"395":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ ثَعْلَبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَمِّهِ مُجَمِّعٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقْتُلُ ابْنُ مَرْيَمَ الْمَسِيحَ الدَّجَّالَ بِبَابِ لُدٍّ","id":"Telah menceritakan kepada kami [Muhammad bin Mush'ab] berkata; telah menceritakan kepada kami [Al Auza'i] dari [Az-Zuhri] dari ['Ubaidullah bin Tsa'labah] [Abdurrahman bin Yazid] dari [pamannya, Mujammi'] berkata; saya telah mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Ibnu Maryam membunuh Al Masih Dajjal di pintu Lud.\""},"396":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ ثَعْلَبَةَ الْأَنْصَارِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ مُجَمِّعِ ابْنِ جَارِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقْتُلُ ابْنُ مَرْيَمَ الدَّجَّالَ بِبَابِ لُدٍّ أَوْ إِلَى جَانِبِ لُدٍّ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az-Zuhri] dari [Abdullah bin 'Ubaidullah bin Tsa'labah Al Anshori] dari [Abdurrahman bin Yazid] dari [Mujammi' bin Jariyah] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ibnu Maryam membunuh Al Masih Dajjal di pintu Lud atau ke samping Lud.\""},"397":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى قَالَ حَدَّثَنَا مُجَمِّعُ بْنُ يَعْقُوبَ قَالَ سَمِعْتُ أَبِي يَقُولُ عَنْ عَمِّهِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَمِّهِ مُجَمِّعِ ابْنِ جَارِيَةَ الْأَنْصَارِيِّوَكَانَ أَحَدَ الْقُرَّاءِ الَّذِينَ قَرَءُوا الْقُرْآنَ قَالَ شَهِدْنَا الْحُدَيْبِيَةَ فَلَمَّا انْصَرَفْنَا عَنْهَا إِذَا النَّاسُ يُنْفِرُونَ الْأَبَاعِرَ فَقَالَ النَّاسُ بَعْضُهُمْ لِبَعْضٍ مَا لِلنَّاسِ قَالُوا أُوحِيَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجْنَا مَعَ النَّاسِ نُوجِفُ حَتَّى وَجَدْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَاحِلَتِهِ عِنْدَ كُرَاعِ الْغَمِيمِ وَاجْتَمَعَ النَّاسُ إِلَيْهِ فَقَرَأَ عَلَيْهِمْ إِنَّا فَتَحْنَا لَكَ فَتْحًا مُبِينًا فَقَالَ رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ رَسُولَ اللَّهِ وَفَتْحٌ هُوَ قَالَ أَيْ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ إِنَّهُ لَفَتْحٌ فَقُسِمَتْ خَيْبَرُ عَلَى أَهْلِ الْحُدَيْبِيَةِ لَمْ يُدْخِلْ مَعَهُمْ فِيهَا أَحَدًا إِلَّا مَنْ شَهِدَ الْحُدَيْبِيَةَ فَقَسَمَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى ثَمَانِيَةَ عَشَرَ سَهْمًا وَكَانَ الْجَيْشُ أَلْفًا وَخَمْسَ مِائَةٍ فِيهِمْ ثَلَاثُ مِائَةِ فَارِسٍ فَأَعْطَى الْفَارِسَ سَهْمَيْنِ وَأَعْطَى الرَّاجِلَ سَهْمًا","id":"Telah menceritakan kepada kami [Ishaq bin 'Isa] berkata; telah menceritakan kepada kami [Mujammi' bin Ya'qub] berkata; saya telah mendengar [bapakku] dari [pamannya, Abdurrahman bin Yazid] dari [pamannya, Mujammi' bin Jariyah Al Ashori] dia adalah salah seorang Qurra' yang pandai dalam membaca Al Qur'an, berkata; Kami ikut hadir dalam perdamaian Hudaibiyyah, ketika kami selesai dari sana tiba-tiba orang-orang membawa lari unta-unta mereka. Sebagian mereka berkata kepada yang lainnya, ada apa dengan mereka? Mereka menjawab, sebuah wahyu turun kepada Rasulullah Shallallahu'alaihiwasallam, maka kami keluar bersama mereka dengan cepat hingga kami menemukan Rasulullah Shallallahu'alaihiwasallam di atas kendaraannya di Kura'il Ghamim. Mereka berkumpul kepada (Rasulullah Shallallahu'alaihiwasallam) lalu beliau membacakan: \"kami Telah memberikan kepadamu kemenangan yang nyata.\" Lalu ada seorang sahabat Rasulullah Shallallahu'alaihiwasallam yang berkata; Wahai Rasulullah! apakah itu sebuah kemenangan? (Rasulullah Shallallahu'alaihiwasallam) bersabda: Ya. Demi Dzat yang jiwa Muhammad berada di tangan-Nya, itu adalah kemenangan. Maka (Ghanimah) Khaibar dibagi kepada orang-orang yang mengikuti Hudaibiyyah, tidak ada yang mendapatkan bagian darinya kecuali orang yang ikut dalam peristiwa Hudaibiyyah. Rasulullah Shallallahu'alaihiwasallam membaginya menjadi delapan belas saham, pasukan tersebut jumlahnya yaitu seribu lima ratus, yang diantaranya terdapat tiga ratus kafaleri, (Rasulullah Shallallahu'alaihiwasallam) memberi para kafaleri dengan dua saham dan memberi para infantri dengan satu saham."},"398":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُوَيْسٍ حَدَّثَنَا شُرَحْبِيلٌ عَنْ جَبَّارِ بْنِ صَخْرٍ الْأَنْصَارِيِّ أَحَدِ بَنِي سَلِمَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِطَرِيقِ مَكَّةَ مَنْ يَسْبِقُنَا إِلَى الْأُثَايَةِ قَالَ أَبُو أُوَيْسٍ هُوَ حَيْثُ نَفَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَمْدُرَ حَوْضَهَا وَيَفْرِطَ فِيهِ فَيَمْلَأَهُ حَتَّى نَأْتِيَهُ قَالَ قَالَ جَبَّارٌ فَقُمْتُ فَقُلْتُ أَنَا قَالَ اذْهَبْ فَذَهَبْتُ فَأَتَيْتُ الْأُثَايَةَ فَمَدَرْتُ حَوْضَهَا وَفَرَطْتُ فِيهِ وَمَلَأْتُهُ ثُمَّ غَلَبَتْنِي عَيْنَايَ فَنِمْتُ فَمَا انْتَبَهْتُ إِلَّا بِرَجُلٍ تُنَازِعُهُ رَاحِلَتُهُ إِلَى الْمَاءِ وَيَكُفُّهَا عَنْهُ فَقَالَ يَا صَاحِبَ الْحَوْضِ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ نَعَمْ قَالَ فَأَوْرَدَ رَاحِلَتَهُ ثُمَّ انْصَرَفَ فَأَنَاخَ ثُمَّ قَالَ اتْبَعْنِي بِالْإِدَاوَةِ فَتَبِعْتُهُ بِهَا فَتَوَضَّأَ وَأَحْسَنَ وُضُوءَهُ وَتَوَضَّأْتُ مَعَهُ ثُمَّ قَامَ يُصَلِّي فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَ بِيَدِي فَحَوَّلَنِي عَنْ يَمِينِهِ فَصَلَّيْنَا فَلَمْ يَلْبَثْ يَسِيرًا أَنْ جَاءَ النَّاسُ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Abu Uwais] telah menceritakan kepada kami [Syurahbil] dari [Jabbar bin Shakhr Al Anshari] salah seorang Bani Salamah berkata; ketika Rasulullah Shallallahu'alaihiwasallam berada di sebuah Jalan Makkah, bersabda: \"Siapa yang ingin pergi mendahului kami ke 'Utsayah? - -- Abu Uwais berkata dalam riwayatnya, Rasulullah Shallallahu'alaihiwasallam mendorong kami ke Utsayah- lalu dia membendung telaga Utsayah kemudian mengisi air disana serta memenuhinya hingga kami datang kepadanya.\" Jabbar berkata; saya berdiri dan berkata; saya. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Pergilah\", Lalu saya pergi hingga ketika sampai di 'Utsayah, saya membuat bendungan di telaganya dan mengisinya dengan air hingga penuh, lalu mataku tidak kuat lagi hingga saya tertidur, ketika saya tidak terbangun hingga datang seorang laki-laki yang dihantar oleh kendaraannya menuju air lalu dia menahannya di dalamnya. Dia berkata; \"Wahai penghuni telaga\", dan ternyata orang itu adalah Rasulullah Shallallahu'alaihiwasallam, maka saya berkata; ya. (Jabbar Radliyallahu'anhu) berkata; (Rasulullah Shallallahu'alaihiwasallam) menyuruh minum untanya lalu pergi menuntunnya lalu bersabda: \"Ikutilah saya dengan membawa setimba air\", maka saya mengikutinya dengan membawa setimba air lalu beliau berwudhu dengan sempurna dan saya ikut berwudhu bersamanya, kemudian beliau berdiri shalat, saya ikut berdiri di sisi kirinya hingga beliau mengait tanganku seraya menggeserku ke sisi kanannya lalu kami shalat, kemudian beliau diam sejenak hingga orang-orang datang."},"399":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنِ ابْنِ أَبِي خُزَامَةَ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ وَقَالَ سُفْيَانُ مَرَّةً سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَأَيْتَ دَوَاءً نَتَدَاوَى بِهِ وَرُقًى نَسْتَرْقِي بِهَا وَتُقًى نَتَّقِيهَا أَتَرُدُّ مِنْ قَدَرِ اللَّهِ تَبَارَكَ وَتَعَالَى شَيْئًا قَالَ إِنَّهَا مِنْ قَدَرِ اللَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az-Zuhri] dari [Ibnu Abu Khuzamah] dari [Bapaknya] berkata; saya berkata; wahai Rasulullah Shallallahu'alaihiwasallam, Sufyan berkata dalam riwayatnya, saya telah bertanya kepada Rasulullah Shallallahu'alaihiwasallam, bagaimana menurut anda tentang obat yang kami gunakan untuk mengobati penyakit, ruqyah yang kami praktekkan, dan penjagaan yang kami buat, apakah bisa menolak dari takdir Allah sama sekali? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \" itu semua termasuk takdir Allah Tabaaroka wa Ta'ala.\""},"400":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنِ الزُّبَيْدِيِّ مُحَمَّدِ بْنِ الْوَلِيدِ عَنِ الزُّهْرِيِّ عَنْ ابْنِ أَ��ِي خِزَامَةَ أَحَدِ بَنِي الْحَارِثِ عَنْ أَبِيهِأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ دَوَاءً نَتَدَاوَى بِهِ وَرُقًى نَسْتَرْقِي بِهَا وَتُقًى نَتَّقِيهَا هَلْ تَرُدُّ ذَلِكَ مِنْ قَدَرِ اللَّهِ شَيْئًا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ مِنْ قَدَرِ اللَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami ['Ali bin 'Ayyasy] telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Az-Zubadi, Muhammad bin Al Walid] dari [Az-Zuhri] dari [Ibnu Abu Khuzamah] salah satu Bani Al harits dari [Bapaknya] dia datang kepada Rasulullah Shallallahu'alaihiwasallam lalu berkata; Wahai Rasulullah, Bagaimana menurut anda tentang obat yang kami gunakan untuk mengobati penyakit, ruqyah yang kami praktekkan, dan penjagaan yang kami buat, apakah bisa menolak dari takdir Allah? Rasulullah Shallallahu'alaihiwasallam bersabda: itu semua termasuk takdir Allah Tabaaroka wa Ta'ala."},"401":{"ar":"حَدَّثَنَا هَارُونُ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو عَنِ ابْنِ شِهَابٍ أَنَّ ابْنَ أَبِي خُزَامَةَ أَحَدَ بَنِي الْحَارِثِ بْنِ سَعْدِ بْنِ هُذَيْمٍ حَدَّثَهُ أَنَّ أَبَاهُ حَدَّثَهُأَنَّهُ قَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ دَوَاءً نَتَدَاوَى بِهِ وَرُقًى نَسْتَرْقِيهَا وَتُقًى نَتَّقِيهِ هَلْ تَرُدُّ ذَلِكَ مِنْ قَدَرِ اللَّهِ تَبَارَكَ وَتَعَالَى مِنْ شَيْءٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ مِنْ قَدَرِ اللَّهِ عَزَّ وَجَلَّحَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ وَيَحْيَى بْنِ أَبِي بُكَيْرٍ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ ابْنِ أَبِي خُزَامَةَ عَنْ أَبِيهِ قَالَ أَبِي وَهُوَ الصَّوَابُ كَذَا قَالَ الزُّبَيْدِيُّ","id":"Telah menceritakan kepada kami [Harun] telah menceritakan kepada kami [Ibnu Wahb] berkata; telah mengabarkan kepadaku ['Amr] dari [Ibnu Syihab] [Ibnu Abu Khuzamah] salah satu Bani Al Harits bin Sa'd bin Hudzaim menceritakannya, [Bapaknya] menceritakannya, dia berkata; Wahai Rasulullah, bagaimana menurut anda tentang obat yang kami gunakan untuk mengobati penyakit, ruqyah yang kami praktekkan, dan penjagaan yang kami buat, apakah bisa menolak dari takdir Allah sama sekali? Rasulullah Shallallahu'alaihiwasallam bersabda: \" itu semua termasuk takdir Allah AzzaWaJalla.\" Telah menceritakan kepada kami [Husain bin Muhammad] dan [Yahya bin Abu Bukair] dari [Sufyan bin 'Uyainah] dari [Az-Zuhri] dari [Ibnu Abu Khuzamah] dari [Bapaknya] berkata; dan itulah yang benar, demikian yang dikatakan Az-Zubaidi."},"402":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ سَمِعْتُ يَحْيَى بْنَ أَبِي كَثِيرٍ يَقُولُ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَسْعَدَ بْنِ زُرَارَةَ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَزَارَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَنْزِلِنَا فَقَالَ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ قَالَ فَرَدَّ سَعْدٌ رَدًّا خَفِيًّا فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاتَّبَعَهُ سَعْدٌ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ كُنْتُ أَسْمَعُ تَسْلِيمَكَ وَأَرُدُّ عَلَيْكَ رَدًّا خَفِيًّا لِتُكْثِرَ عَلَيْنَا مِنْ السَّلَامِ قَالَ فَانْصَرَفَ مَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ لَهُ سَعْدٌ بِغُسْلٍ فَوُضِعَ فَاغْتَسَلَ ثُمَّ نَاوَلَهُ أَوْ قَالَ نَاوَلُوهُ مِلْحَفَةً مَصْبُوغَةً بِزَعْفَرَانٍ وَوَرْسٍ فَاشْتَمَلَ بِهَا ثُمَّ رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ وَهُوَ يَقُولُ اللَّهُمَّ اجْعَلْ صَلَوَاتِكَ وَرَحْمَتَكَ عَلَى آلِ سَعْدِ بْنِ عُبَادَةَ قَالَ ثُمَّ أَصَابَ مِنْ الطَّعَامِ فَلَمَّا أَرَادَ الِانْصِرَافَ قَرَّبَ إِلَيْهِ سَعْدٌ حِمَارًا قَدْ وَطَّأَ عَلَيْهِ بِقَطِيفَةٍ فَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَعْدٌ يَا قَيْسُ اصْحَبْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَيْسٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْكَبْ فَأَبَيْتُ ثُمَّ قَالَ إِمَّا أَنْ تَرْكَبَ وَإِمَّا أَنْ تَنْصَرِفَ قَالَ فَانْصَرَفْتُ","id":"Telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] berkata; saya telah mendengar [Yahya bin Abu Katsir] berkata; telah menceritakan kepadaku [Muhammad bin Abdurrahman bin As'ad bin Zurarah] dari [Qais bin Sa'd] berkata; Rasulullah Shallallahu'alaihiwasallam pernah mengunjungi kami di rumah kami, bersabda: \"Assalaamu 'alaikum warohmatullah\" (Qais radliyallahu'ahu) berkata; maka Sa'd menjawabnya dengan suara pelan, lalu Rasulullah Shallallahu'alaihiwasallam mengulangi salamnya dan Sa'd juga menjawabnya dengan suara pelan, lalu dia berkata; Wahai Rasulullah, saya mendengar salam anda, saya menjawabnya dengan pelan supaya anda memperbanyak salam atas kami. (Qais radliyallahu'ahu) berkata; lalu dia pergi bersama Rasulullah Shallallahu'alaihiwasallam dan menyuruh orang untuk menyiapkan pemandian (Rasulullah Shallallahu'alaihiwasallam) hingga beliau mandi. Lalu (Saad radliyallahu'anhu) memberikan atau (Qais radliyallahu'ahu) berkata; lalu mereka memberikan kepada beliau selembar selimut yang telah dilumuri dengan minyak wangi za'faron dan waros, lalu (Rasulullah Shallallahu'alaihiwasallam) memakainya. Lalu (Rasulullah Shallallahu'alaihiwasallam) mengangkat kedua tangannya dengan membaca: \"Ya Allah, jadikan kesejahteraan dan rahmAt Mu atas keluarga Sa'd bin 'Ubadah\" (Qais radliyallahu'ahu) berkata; lalu (Rasulullah Shallallahu'alaihiwasallam) menyantap makanan, tatkala beliau hendak pergi, Sa'd memberikan keledai kepadanya yang telah dilapisi pelana di atasnya, lalu Rasulullah Shallallahu'alaihiwasallam naik. Sa'd berkata; Wahai Qais, temani Rasulullah Shallallahu'alaihiwasallam. Qais berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Naiklah\", namun saya menolaknya. Lalu beliau bersabda: \"Kamu naik atau kamu meninggalkan saya saja\", (Qais radliyallahu'ahu) berkata; lalu saya meninggalkannya."},"403":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنِ الْقَاسِمِ بْنِ مُخَيْمِرَةَ عَنْ أَبِي عَمَّارٍ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَصُومَ عَاشُورَاءَ قَبْلَ أَنْ يَنْزِلَ صِيَامُ رَمَضَانَ فَلَمَّا نَزَلَ صِيَامُ رَمَضَانَ لَمْ يَأْمُرْنَا وَلَمْ يَنْهَنَا وَنَحْنُ نَفْعَلُهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Al Qasim bin mukhoimiroh] dari [Abu 'Ammar] dari [Qais bin Sa'd] berkata; Nabi Shallallahu'alaihiwasallam memerintahkan kami untuk berpuasa 'Asyuro sebelum turun ayat tentang Puasa Ramadlan. Tatkala turun ayat tentang Puasa Ramadlan, beliau tidak menyuruh kami dan tidak juga melarang kami namun kami tetap mengerjakannya."},"404":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنَا حَيْوَةُ قَالَ أَخْبَرَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الْمَلِكِ بْنِ مُلَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي أُمَيَّةَأَنَّ حَبِيبَ بْنَ مَسْلَمَةَ أَتَى قَيْسَ بْنَ سَعْدِ بْنِ عُبَادَةَ فِي الْفِتْنَةِ الْأُولَى وَهُوَ عَلَى فَرَسٍ فَأَخَّرَ عَنْ السَّرْجِ وَقَالَ ارْكَبْ فَأَبَى وَقَالَ لَهُ قَيْسُ بْنُ سَعْدٍ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ صَاحِبُ الدَّابَّةِ أَوْلَى بِصَدْرِهَا فَقَالَ لَهُ حَبِيبٌ إِنِّي لَسْتُ أَجْهَلُ مَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنِّي أَخْشَى عَلَيْكَ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid, Abu Abdurrahman] telah menceritakan kepada kami [Haiwah] berkata; telah mengabarkan kepadaku [Abdul Aziz bin Abdul Malik bin Mulail] dari [Abdur Rahman bin Abu Umayyah] [Habib bin Maslamah] pernah mendatangi [Qais bin Sa'd bin 'Ubadah] pada zaman Fitnah Pertama dengan berkendara atas untanya, lantas dia mundur dari pelananya dan berkata (kepada Qais radliyallahu'ahu) naiklah. (Qais radliyallahu'ahu) menolak dan dia berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Pemilik kendaraan lebih berhak untuk duduk di depan\", Lalu Habib berkata kepadanya, bukannya saya tidak mengerti sabda Rasulullah Shallallahu'alaihiwasallam akan tetapi saya takut akan terjadi apa-apa padamu."},"405":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا إِسْرَائِيلُ عَنْ جَابِرٍ عَنْ عَامِرٍ عَنْ قَيْسِ بْنِ سَعْدِ بْنِ عُبَادَةَ قَالَمَا مِنْ شَيْءٍ كَانَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا وَقَدْ رَأَيْتُهُ إِلَّا شَيْئًا وَاحِدًا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَلَّسُ لَهُ يَوْمَ الْفِطْرِقَالَ جَابِرٌ هُوَ اللَّعِبُ","id":"Telah menceritakan kepada kami [Abu Nadlroh] telah menceritakan kepada kami [Isro'il] dari [Jabir] dari ['Amir] dari [Qais bin Sa'd 'Ubadah] berkata; tidak ada sesuatu yang ada pada masa Rasulullah Shallallahu'alaihiwasallam kecuali saya telah melihatnya, kecuali satu hal. Rasulullah Shallallahu'alaihiwasallam, (pernah dimainkan sebuah permainan pedang dan anak panah di hadapan Rasulullah Shallallahu'alaihiwasallam) pada Hari Idul Fithri. Jabir berkata; itu adalah permainan."},"406":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ مَنْصُورَ بْنَ زَاذَانَ يُحَدِّثُ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ قَيْسِ بْنِ سَعْدِ بْنِ عُبَادَةَأَنَّ أَبَاهُ دَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْدُمُهُ فَأَتَى عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ صَلَّيْتُ رَكْعَتَيْنِ قَالَ فَضَرَبَنِي بِرِجْلِهِ وَقَالَ أَلَا أَدُلُّكَ عَلَى بَابٍ مِنْ أَبْوَابِ الْجَنَّةِ قُلْتُ بَلَى قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [bapakku] berkata; saya telah mendengar [Manshur bin Zadzan] menceritakan dari [Maimun bin Abu Syabib] dari [Qais bin Sa'd bin 'Ubadah] bapaknya menyerahkan (Qais bin Sa'd Radliyallahu'anhu) kepada Nabi Shallallahu'alaihiwasallam sebagai pembantunya. Lalu Nabi Shallallahu'alaihiwasallam datang kepadaku setelah saya shalat dua rekaat. (Qais bin Sa'd Radliyallahu'anhu) berkata; lalu (Rasulullah Shallallahu'alaihiwasallam) menendangku dengan kakinya dan bersabda: maukah kamu saya tunjukkan salah satu pintu dari pintu surga? saya menjawab, Ya. (Rasulullah Shallallahu'alaihiwasallam) bersabda: LAA HAULA WA LAA QUWWATA ILLAA BILLAAH (tidak ada daya dan kekuatan kecuali dengan ijin Allah)."},"407":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ قَيْسِ بْنِ سَعْدِ بْنِ عُبَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ رَبِّي تَبَارَكَ وَتَعَالَى حَرَّمَ عَلَيَّ الْخَمْرَ وَالْكُوبَةَ وَالْقِنِّينَ وَإِيَّاكُمْ وَالْغُبَيْرَاءَ فَإِنَّهَا ثُلُثُ خَمْرِ الْعَالَمِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata; telah mengabarkan kepadaku [Yahya bin Ayyub] dari ['Ubaidullah bin Zahr] dari [Bakr bin Sawadah] dari [Qais bin Sa'dengan bin 'Ubadah] Rasulullah Shallallahu'alaihiwasallam bersabda: Robku Tabaaroka wa Ta'ala mengharamkan padaku arak, gendang dan judi. Jauhilah kalian Al ghubairo' (arak yang terbuat dari jagung) karena itu adalah sepertiga arak di dunia."},"408":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ قَالَ حَدَّثَنِيهِ ابْنُ هُبَيْرَةَ قَالَ سَمِعْتُ شَيْخًا مِنْ حِمْيَرَ يُحَدِّثُ أَبَا تَمِيمٍ الْجَيْشَانِيَّ أَنَّهُ سَمِعَ قَيْسَ بْنَ سَعْدِ بْنِ عُبَادَةَ الْأَنْصَارِيَّ وَهُوَ عَلَى مِصْرٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَذَبَ عَلَيَّ كِذْبَةً مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَضْجَعًا مِنْ النَّارِ أَوْ بَيْتًا فِي جَهَنَّمَ","id":"Telah menceritakan kepada kami [Hasan bin Musa] telah menceritakan kepada kami [Ibnu Lahi'ah] berkata; telah menceritakannya kepadaku [Ibnu Hubairoh] berkata; saya telah mendengar [seseorang dari Himyar] menceritakan kepada [Abu Tamim Al Jaisyani] telah mendengar [Qais bin Sa'd bin 'Ubadah Al Anshori] ketika berada di Mesir berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang berdusta sekali dengan sengaja maka bersiaplah menempati tempat tidurnya di neraka atau rumahnya di Jahannam.\""},"409":{"ar":"سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ شَرِبَ الْخَمْرَ أَتَى عَطْشَانًا يَوْمَ الْقِيَامَةِ أَلَا فَكُلُّ مُسْكِرٍ خَمْرٌ وَإِيَّاكُمْ وَالْغُبَيْرَاءَقَالَ هَذَا الشَّيْخُ ثُمَّ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو بَعْدَ ذَلِكَ يَقُولُ مِثْلَهُ فَلَمْ يَخْتَلِفَا إِلَّا فِي بَيْتٍ أَوْ مَضْجَعٍ","id":"Saya (Qais bin Sa'd bin 'Ubadah Radliyallahu'anhu) telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang meminum arak, maka pada Hari Kiamat dalam keadaan haus. Ketahuilah setiap yang memabukkan adalah arak. Jauhilah Al Ghubaira'.\" Demikian yang dikatakan syaikh tersebut, lalu saya (Qais bin Sa'd bin 'Ubadah Radliyallahu'anhu) telah mendengar [Abdullah bin 'Amr] setelah itu berkata; sama dengan di atas, dan keduanya tidak ada perbedaan kecuali dalam perkataan di rumah atau tempat tidur."},"410":{"ar":"حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى بْنِ عُمَارَةَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ قَالَ حَدَّثَنِي عَمِّي وَاسِعُ بْنُ حَبَّانَ عَنْ وَهْبِ بْنِ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرَّجُلُ أَحَقُّ بِمَجْلِسِهِ وَإِنْ قَامَ مِنْهُ ثُمَّ رَجَعَ أَيْ فَهُوَ أَحَقُّ بِهِ","id":"Telah menceritakan kepada kami [Hisyam bin Sa'id] berkata; telah menceritakan kepada kami [Khalid] yaitu Ibnu Abdullah, berkata; telah menceritakan kepada kami ['Amr bin Yahya bin 'Umarah] dari [Muhammad bin Yahya bin Habban] berkata; telah menceritakan kepadaku [pamanku, Wasi' bin Habban] dari [Wahb bin Hudzaifah] Nabi Shallallahu'alaihiwasallam bersabda: \"Seorang lebih berhak dengan tempat duduknya (yang telah ia tempati), jika dia berdiri kemudian kembali lagi maka juga lebih berhak terhadapnya.\""},"411":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا خَالِدٌ الْوَاسِطِيُّ قَالَ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ وَهْبِ بْنِ حُذَيْفَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَامَ الرَّجُلُ مِنْ مَجْلِسِهِ فَرَجَعَ إِلَيْهِ فَهُوَ أَحَقُّ بِهِ وَإِنْ كَانَتْ لَهُ حَاجَةٌ فَقَامَ إِلَيْهَا ثُمَّ رَجَعَ فَهُوَ أَحَقُّ بِهِ","id":"Telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Khalid Al Wasithi] berkata; telah menceritakan kepada kami ['Amr bin Yahya] dari [Muhammad bin Yahya] dari [pamannya, Wasi' bin Habban] dari [Wahb bin Hudzaifah] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Jika seseorang berdiri dari tempat duduknya (yang telah ia tempati), lalu kembali lagi maka dia lebih berhak terhadapnya, walau dia memiliki keperluan yang dia tinggalkan. Jika dia kembali lagi maka dia lebih berhak.\""},"412":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو أُوَيْسٍ حَدَّثَنَا شُرَحْبِيلٌ عَنْ عُوَيْمِ بْنِ سَاعِدَةَ الْأَنْصَارِيِّ أَنَّهُ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُمْ فِي مَسْجِدِ قُبَاءَ فَقَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قَدْ أَحْسَنَ عَلَيْكُمْ الثَّنَاءَ فِي الطُّهُورِ فِي قِصَّةِ مَسْجِدِكُمْ فَمَا هَذَا الطُّهُورُ الَّذِي تَطَّهَّرُونَ بِهِ قَالُوا وَاللَّهِ يَا رَسُولَ اللَّهِ مَا نَعْلَمُ شَيْئًا إِلَّا أَنَّهُ كَانَ لَنَا جِيرَانٌ مِنْ الْيَهُودِ فَكَانُوا يَغْسِلُونَ أَدْبَارَهُمْ مِنْ الْغَائِطِ فَغَسَلْنَا كَمَا غَسَلُوا","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Abu Uwais] telah menceritakan kepada kami [Syurohbil] dari ['Uwaim bin Sa'idah Al Anshori] dia menceritakannya, Nabi Shallallahu'alaihiwasallam pernah mendatangi mereka di masjid Quba, lalu bersabda: \" Allah telah memperbagus pujian-Nya pada kalian dalam hal bersuci, dalam kisah masjid kalian ini, bagaimana kalian bersuci selama ini?\" Mereka menjawab, Demi Allah, wahai Rasulullah, kami tidak mengetahuinya kecuali kami memiliki tetangga Yahudi, yang mencuci dubur mereka setelah buang air besar lalu kami ikut mencucinya seperti yang mereka kerjakan."},"413":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَخِي الْحَكَمُ بْنُ الْمُطَّلِبِ عَنْ أَبِيهِ عَنْ قُهَيْدِ بْنِ مُطَرِّفٍ الْغِفَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَهُ سَائِلٌ إِنْ عَدَا عَلَيَّ عَادٍ فَأَمَرَهُ أَنْ يَنْهَاهُ ثَلَاثَ مِرَارٍ قَالَ فَإِنْ أَبَى فَأَمَرَهُ بِقِتَالِهِ قَالَ فَكَيْفَ بِنَا قَالَ إِنْ قَتَلَكَ فَأَنْتَ فِي الْجَنَّةِ وَإِنْ قَتَلْتَهُ فَهُوَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Abu 'Amir, Abdul Malik bin 'Amr] telah menceritakan kepada kami [Abdul Aziz bin Al Muthalib bin Abdullah] berkata; telah menceritakan kepadaku [saudaraku, Al Hakam bin Al Muthalib] dari [Bapaknya] dari [Quhaid bin Mutharrif Al Ghifari] Rasulullah Shallallahu'alaihiwasallam pernah ditanya oleh seseorang, bagaimana jika ada orang yang menganiaya diriku? (Rasulullah Shallallahu'alaihiwasallam) menyuruh agar melarangnya tiga kali, (seseorang tersebut) berkata; jika dia enggan? maka beliau menyuruh untuk memeranginya, (dia berkata) lalu bagaimana dengan posisi kami? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Jika dia membunuhmu, kamu berada di surga, jika kamu membunuhnya maka dia berada di neraka.\""},"414":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُطَّلِبِ الْمَخْزُومِيُّ عَنْ أَخِيهِ الْحَكَمِ بْنِ الْمُطَّلِبِ عَنْ أَبِيهِ عَنْ قُهَيْدٍ الْغِفَارِيِّقَالَ سَأَلَ سَائِلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ عَدَا عَلَيَّ عَادٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكِّرْهُ وَأَمَرَهُ بِتَذْكِيرِهِ ثَلَاثَ مَرَّاتٍ فَإِنْ أَبَى فَقَاتِلْهُ فَإِنْ قَتَلَكَ فَإِنَّكَ فِي الْجَنَّةِ وَإِنْ قَتَلْتَهُ فَإِنَّهُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Abdul Aziz bin Al Muthalib Al Makhzumi] dari [saudaranya, Al Hakam bin Al Muthalib] dari [Bapaknya] dari [Quhaid Al Ghifari] berkata; ada seseorang yang bertanya kepada Rasulullah Shallallahu'alaihiwasallam, bagaimana jika ada orang yang menganiaya diriku? Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ingatkanlah dia\" dan beliau menyuruh agar mengingatkannya tiga kali, \"Jika dia menolak, maka perangilah, jika dia membunuhmu, kamu di surga, jika kamu membunuhnya maka dia di neraka.\""},"415":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبْدُ الْمَلِكِ يَعْنِي ابْنَ حَسَنٍ الْحَارِثِيَّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي سَعِيدٍ قَالَ سَمِعْتُ عُمَارَةَ بْنَ حَارِثَةَ الضَّمْرِيَّ يُحَدِّثُ عَنْ عَمْرِو بْنِ يَثْرِبِيٍّ الضَّمْرِيِّ قَالَشَهِدْتُ خُطْبَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى فَكَانَ فِيمَا خَطَبَ بِهِ أَنْ قَالَ وَلَا يَحِلُّ لِامْرِئٍ مِنْ ذَأَفِ أَخِيهِ إِلَّا مَا طَابَتْ بِهِ نَفْسُهُ قَالَ فَلَمَّا سَمِعْتُ ذَلِكَ قُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ لَوْ لَقِيتُ غَنَمَ ابْنِ عَمِّي فَأَخَذْتُ مِنْهَا شَاةً فَاحْتَرَزْتُهَا هَلْ عَلَيَّ فِي ذَلِكَ شَيْءٌ قَالَ إِنْ لَقِيتَهَا نَعْجَةً تَحْمِلُ شَفْرَةً وَزِنَادًا فَلَا تَمَسَّهَا","id":"Telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Abdul Malik] yaitu ibnu Hasan Al Haritsi, telah menceritakan kepada kami [Abdurrahman bin Abu Sa'id] berkata; saya telah mendengar ['Umaroh bin Haristah Ad Dlamri] menceritakan dari ['Amr bin Yatsribi Ad Dlamri] berkata; saya menyaksikan khutbah Rasulullah Shallallahu'alaihiwasallam di Mina maka diantara isi khutbahnya adalah, \"Tidak halal seorang mengambil harta saudaranya kecuali atas kerelaan dirinya\" ('Amr bin Yatsribi Ad Dlamri Radliyallahu'anhu) berkata; tatkala saya mendengar itu, saya berkata 'Wahai Rasulullah, bagaimana menurutmu jika saya menemukan beberapa kambing anak pamanku lalu saya mengambilnya satu lalu saya rawat, apakah berdosa? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Jika kamu menemukan seekor kambing, kamu membawa pisau dan bambu (ingin menyembelihnya) maka janganlah kamu menyentuhnya.\""},"416":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ إِسْحَاقَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ الْمَدَنِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي يَحْيَى عَنْ أَبِيهِ عَنِ ابْنِ أَبِي حَدْرَدٍ الْأَسْلَمِيِّأَنَّهُ كَانَ لِيَهُودِيٍّ عَلَيْهِ أَرْبَعَةُ دَرَاهِمَ فَاسْتَعْدَى عَلَيْهِ فَقَالَ يَا مُحَمَّدُ إِنَّ لِي عَلَى هَذَا أَرْبَعَةَ دَرَاهِمَ وَقَدْ غَلَبَنِي عَلَيْهَا فَقَالَ أَعْطِهِ حَقَّهُ قَالَ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَقْدِرُ عَلَيْهَا قَالَ أَعْطِهِ حَقَّهُ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ مَا أَقْدِرُ عَلَيْهَا قَدْ أَخْبَرْتُهُ أَنَّكَ تَبْعَثُنَا إِلَى خَيْبَرَ فَأَرْجُو أَنْ تُغْنِمَنَا شَيْئًا فَأَرْجِعُ فَأَقْضِيهِ قَالَ أَعْطِهِ حَقَّهُ قَالَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ ثَلَاثًا لَمْ يُرَاجَعْ فَخَرَجَ بِهِ ابْنُ أَبِي حَدْرَدٍ إِلَى السُّوقِ وَعَلَى رَأْسِهِ عِصَابَةٌ وَهُوَ مُتَّزِرٌ بِبُرْدٍ فَنَزَعَ الْعِمَامَةَ عَنْ رَأْسِهِ فَاتَّزَرَ بِهَا وَنَزَعَ الْبُرْدَةَ فَقَالَ اشْتَرِ مِنِّي هَذِهِ الْبُرْدَةَ فَبَاعَهَا مِنْهُ بِأَرْبَعَةِ الدَّرَاهِمِ فَمَرَّتْ عَجُوزٌ فَقَالَتْ مَا لَكَ يَا صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهَا فَقَالَتْ هَا دُونَكَ هَذَا بِبُرْدٍ عَلَيْهَا طَرَحَتْهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Ishaq] telah menceritakan kepada kami [Hatim bin Isma'il Al Madani] berkata; telah menceritakan kepada kami [Abdullah bin Muhammad bin Yahya] dari [Bapaknya] dari [Ibnu Abu Hadrad Al Aslami] dia memiliki hutang pada seorang Yahudi berupa empat dirham, maka dia menagihnya dengan berkata; 'Wahai Muhammad orang ini berhutang kepadaku empat dirham, saya sangat membutuhkannya. Lalu (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Berikan padanya hak dia.\" Dia berkata; demi Dzat yang mengutusmu dengan Al haq, saya tidak mampu membayarnya. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Berikan padanya haknya\" Dia berkata; demi Dzat yang mengutusmu dengan Al haq, saya tidak mampu membayarnya, saya telah mengabarkan kepadanya, dan anda mengutus kami ke Khaibar dengan harapan anda memberi bagian ghanimah pada kami lalu saya pulang untuk melunasinya. (Nabi Shallallahu'alaihiwasallam) bersabda: \"Berikan padanya hak dia.\" Nabi Shallallahu'alaihiwasallam jika telah mengucapkan tiga kali, niscaya tidak akan mengulanginya lagi. Ibnu Abu Hadrod akhirnya keluar bersama orang Yahudi tersebut ke pasar dengan memakai surban di kepalanya dan bersarung dengan mantel, lalu dia (Ibnu Abu Hadrod Radliyallahu'anhu) melepas surban dari kepalanya dan memakainya sebagai sarung, lalu kemudian melepas selimut dan berkata kepada orang-orang, belilah dariku selimut ini, maka dia menjual selimut tersebut dengan empat dirham, lalu ada seorang nenek yang lewat seraya berkata; ada apa denganmu wahai sahabat Rasulullah Shallallahu'alaihiwasallam? Lalu (Ibnu Abu Hadrod Radliyallahu'anhu) memberitahukannya hingga nenek itu berkata; kalau begitu ambillah ini, maka nenek itu memberikan selimut kepadanya."},"417":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا شَيْبَانُ عَنْ عَاصِمٍ عَنْ أَبِي رَزِينٍ عَنْ عَمْرِو بْنِ أُمِّ مَكْتُومٍ قَالَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ كُنْتُ ضَرِيرًا شَاسِعَ الدَّارِ وَلِي قَائِدٌ لَا يُلَائِمُنِي فَهَلْ تَجِدُ لِي رُخْصَةً أَنْ أُصَلِّيَ فِي بَيْتِي قَالَ أَتَسْمَعُ النِّدَاءَ قَالَ قُلْتُ نَعَمْ قَالَ مَا أَجِدُ لَكَ رُخْصَةً","id":"Telah menceritakan kepada kami [Abu Nadlroh] telah menceritakan kepada kami [Syaiban] dari ['Ashim] dari [Abu Razin] dari ['Amr bin Ummi Maktum] berkata; saya datang kepada Rasulullah Shallallahu'alaihiwasallam dan berkata; wahai Rasulullah! saya adalah orang buta yang jauh rumahnya, saya memiliki seorang penuntun yang tidak cocok denganku, apakah ada keringanan bagiku untuk shalat di rumahku? (Rasulullah Shallallahu'alaihiwasallam) bertanya: \"Apakah kamu mendengar adzan?\" ('Amr bin Ummi Maktum Radliyallahu'anhu) berkata; saya menjawab, Ya. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Saya tidak mendapatkan keringanan bagimu.\""},"418":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُسْلِمٍ حَدَّثَنَا الْحُصَيْنُ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادِ بْنِ الْهَادِ عَنِ ابْنِ أُمِّ مَكْتُومٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى الْمَسْجِدَ فَرَأَى فِي الْقَوْمِ رِقَّةً فَقَالَ إِنِّي لَأَهُمُّ أَنْ أَجْعَلَ لِلنَّاسِ إِمَامًا ثُمَّ أَخْرُجُ فَلَا أَقْدِرُ عَلَى إِنْسَانٍ يَتَخَلَّفُ عَنْ الصَّلَاةِ فِي بَيْتِهِ إِلَّا أَحْرَقْتُهُ عَلَيْهِ فَقَالَ ابْنُ أُمِّ مَكْتُومٍ يَا رَسُولَ اللَّهِ إِنَّ بَيْنِي وَبَيْنَ الْمَسْجِدِ نَخْلًا وَشَجَرًا وَلَا أَقْدِرُ عَلَى قَائِدٍ كُلَّ سَاعَةٍ أَيَسَعُنِي أَنْ أُصَلِّيَ فِي بَيْتِي قَالَ أَتَسْمَعُ الْإِقَامَةَ قَالَ نَعَمْ قَالَ فَأْتِهَا","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [Abdul Aziz] yaitu Ibnu Muslim, telah menceritakan kepada kami [Al Hushain] dari [Abdullah bin Syadad bin Al Had] dari [Ibnu Ummi Maktum] Rasulullah Shallallahu'alaihiwasallam mendatangi masjid lalu melihat jamaahnya hanya sedikit. Kontan beliau bersabda: \" Saya berniat untuk mengangkat imam untuk kalian, lalu saya keluar dan menemui orang yang meninggalkan shalat bersamaku dan shalat di rumahnya lalu saya bakar rumahnya.\" Ibnu Ummi Maktum berkata; Wahai Rasulullah, antara saya dengan masjid terdapat banyak pohon kurma dan pohon yang lainnya, dan tidak mungkin bagi penunntunku untuk menuntunku setiap saat, apakah saya boleh shalat di rumahku?. Beliau bertanya, apakah kamu mendengar iqomah?. Dia menjawab, Ya. Beliau bersabda: \"Datangilah.\" "},"419":{"ar":"حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ الْمَكِّيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ الزُّرَقِيِّ عَنْ أَبِيهِ قَالَ وَقَالَ الْفَزَارِيُّ مَرَّةً عَنِ ابْنِ رِفَاعَةَ الزُّرَقِيِّ عَنْ أَبِيهِ قَالَ قَالَ أَبِي وَقَالَ غَيْرُ الْفَزَارِيِّ عُبَيْدِ بْنِ رِفَاعَةَ الزُّرَقِيِّ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ وَانْكَفَأَ الْمُشْرِكُونَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَوُوا حَتَّى أُثْنِيَ عَلَى رَبِّي فَصَارُوا خَلْفَهُ صُفُوفًا فَقَالَ اللَّهُمَّ لَكَ الْحَمْدُ كُلُّهُ اللَّهُمَّ لَا قَابِضَ لِمَا بَسَطْتَ وَلَا بَاسِطَ لِمَا قَبَضْتَ وَلَا هَادِيَ لِمَا أَضْلَلْتَ وَلَا مُضِلَّ لِمَنْ هَدَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُقَرِّبَ لِمَا بَاعَدْتَ وَلَا مُبَاعِدَ لِمَا قَرَّبْتَ اللَّهُمَّ ابْسُطْ عَلَيْنَا مِنْ بَرَكَاتِكَ وَرَحْمَتِكَ وَفَضْلِكَ وَرِزْقِكَ اللَّهُمَّ إِنِّي أَسْأَلُكَ النَّعِيمَ الْمُقِيمَ الَّذِي لَا يَحُولُ وَلَا يَزُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ النَّعِيمَ يَوْمَ الْعَيْلَةِ وَالْأَمْنَ يَوْمَ الْخَوْفِ اللَّهُمَّ إِنِّي عَائِذٌ بِكَ مِنْ شَرِّ مَا أَعْطَيْتَنَا وَشَرِّ مَا مَنَعْتَ اللَّهُمَّ حَبِّبْ إِلَيْنَا الْإِيمَانَ وَزَيِّنْهُ فِي قُلُوبِنَا وَكَرِّهْ إِلَيْنَا الْكُفْرَ وَالْفُسُوقَ وَالْعِصْيَانَ وَاجْعَلْنَا مِنْ الرَّاشِدِينَ اللَّهُمَّ تَوَفَّنَا مُسْلِمِينَ وَأَحْيِنَا مُسْلِمِينَ وَأَلْحِقْنَا بِالصَّالِحِينَ غَيْرَ خَزَايَا وَلَا مَفْتُونِينَ اللَّهُمَّ قَاتِلْ الْكَفَرَةَ الَّذِينَ يُكَذِّبُونَ رُسُلَكَ وَيَصُدُّونَ عَنْ سَبِيلِكَ وَاجْعَلْ عَلَيْهِمْ رِجْزَكَ وَعَذَابَكَ اللَّهُمَّ قَاتِلْ الْكَفَرَةَ الَّذِينَ أُوتُوا الْكِتَابَ إِلَهَ الْحَقِّ","id":"Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] telah menceritakan kepada kami [Abdul Wahid bin Aiman Al Maki] dari ['Ubaidullah bin Abdullah Az-Zuroqi] dari [Bapaknya] berkata. [Al Fazari] berkata juga, dari [Ibnu Rifa'ah Az-Zuraqi] dari [Bapaknya] berkata; Bapakku berkata. Dan selain Al Fazari, ['Ubaid bin Rifa'ah Az-Zuraqi] berkata; pada hari Perang Uhud ketika orang-orang musyrik berlari mundur, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berbarislah kalian hingga saya memuji Rabbku\" lalu mereka membuat barisan di belakang, lalu bersabda: \"Ya Allah, segala puji hanya bagi-Mu, ya Allah tidak ada yang bisa mengenggam apa yang telah Engkau bentangkan dan tidak ada pula yang bisa membentangkan apa yang telah Engkau genggam. Tidak ada yang bisa memberi petunjuk terhadap siapa yang telah Engkau sesatkan, tak ada pula yang bisa menyesatkan siapa yang telah Engkau beri petunjuk. Tidak ada yang bisa memberi terhadap apa yang telah Engkau tahan dan tidak ada pula yang bisa menahan terhadap apa yang telah Engkau beri. Tidak ada yang bisa mendekatkan terhadap apa yang telah Engkau jauhkan dan tidak ada pula yang bisa menjauhkan terhadap apa yang telah Engkau dekatkan. Ya Allah bentangkan pada kami dari barakah-Mu, rahmAt Mu, kelebihan-Mu dan rizki-Mu. Ya Allah, saya memohon kepada-Mu kenikmatan yang kekal yang tidak berlalu dan tidak pula hilang. Ya Allah saya memohon kepada-Mu kenikmatan pada saat kefakiran, dan keamanan pada saat ketakutan. Ya Allah, saya berlindung kepada-Mu dari kejelekan apa saja yang telah Engkau berikan, dan dari kejelekan apa saja yang telah Engkau tahan. Ya Allah, cintakan pada diri kami keimanan dan hiaskanlah pada hati-hati kami. dan bencikan diri kami terhadap kekufuran, kefasikan serta kemaksiatan. Jadikan kami di antara orang-orang yang berpetunjuk. Ya Allah, wafatkan kami dalam keadaan Islam, hidupkan kami dalam keadaan Islam dan sertakan kami bersama dengan orang orang sholeh yang tidak hina dan tidak pula terfitnah. Ya Allah, perangilah orang orang kafir yang mendustakan para Rasul-Mu dan merintangi jalan-Mu, dan berikan mereka siksa-Mu dan adzab-Mu. Ya Allah, perangilah orang orang kafir yang telah diberi kitab (yahudi dan nashroni), ya Allah Tuhan kebenaran.\""},"420":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا الْحَارِثُ بْنُ يَزِيدَ عَنْ أَبِي مُصْعَبٍ قَالَقَدِمَ رَجُلٌ مِنْ أَهْلِ الْمَدِينَةِ شَيْخٌ فَرَأَوْهُ مُوَثِّرًا فِي جَهَازِهِ فَسَأَلُوهُ فَأَخْبَرَهُمْ أَنَّهُ يُرِيدُ الْمَغْرِبَ وَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ سَيَخْرُجُ نَاسٌ إِلَى الْمَغْرِبِ يَأْتُونَ يَوْمَ الْقِيَامَةِ وُجُوهُهُمْ عَلَى ضَوْءِ الشَّمْسِ","id":"Telah menceritakan kepada kami [Husain bin Musa] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Al Harits bin Yazid] dari [Abu Mush'ab] berkata; [ada seorang laki-laki dari penduduk Madinah yang sudah tua], namun mereka melihatnya membawa banyak bekal. Mereka bertanya kepadanya, lalu dia memberitahukan bahwa dia bermaksud pergi ke Maghrib (maroko). Dan berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang-orang akan pergi menuju Maghrib (maroko), mereka datang pada Hari Kiamat dengan wajah bersinar seperti matahari.\""},"421":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنِي عُثْمَانُ بْنُ زُفَرَ الْجُهَنِيُّ قَالَ حَدَّثَنِي أَبُو الْأَشَدِّ السُّلَمِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكُنْتُ سَابِعَ سَبْعَةٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَمَرَنَا نَجْمَعُ لِكُلِّ رَجُلٍ مِنَّا دِرْهَمًا فَاشْتَرَيْنَا أُضْحِيَّةً بِسَبْعِ الدَّرَاهِمِ فَقُلْنَا يَا رَسُولَ اللَّهِ لَقَدْ أَغْلَيْنَا بِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَفْضَلَ الضَّحَايَا أَغْلَاهَا وَأَسْمَنُهَا وَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ رَجُلٌ بِرِجْلٍ وَرَجُلٌ بِرِجْلٍ وَرَجُلٌ بِيَدٍ وَرَجُلٌ بِيَدٍ وَرَجُلٌ بِقَرْنٍ وَرَجُلٌ بِقَرْنٍ وَذَبَحَهَا السَّابِعُ وَكَبَّرْنَا عَلَيْهَا جَمِيعًا","id":"Telah menceritakan kepada kami [Ibrahim bin Abu Al 'Abbas] berkata; telah menceritakan kepada kami [Baqiyyah] berkata; telah menceritakan kepadaku ['Utsman bin Zufar Al Juhani] berkata; telah menceritakan kepadaku [Abu Al Asyad As-Sulami] dari [Bapaknya] dari [kakeknya] berkata; saya adalah satu dari tujuh orang yang bersama Rasulullah Shallallahu'alaihiwasallam. (Abu Al Asyad Radliyallahu'anhu) berkata; lalu (Rasulullah Shallallahu'alaihiwasallam) menyuruh kami untuk mengumpulkan satu dirham setiap orang, lalu kami membeli hewan kurban dengan tujuh dirham tersebut. Kami bertanya, wahai Rasulullah, sungguh kami merasa mahal dengannya. Rasulullah Shallallahu'alaihiwasallam bersabda: \"sebaik-baik hewan kurban adalah yang paling mahal dan paling gemuk.\" Lalu Rasulullah Shallallahu'alaihiwasallam menyuruh seorang untuk memegang kakinya, seorang lagi memegang kakinya yang lain. Seorang lagi memegang kakinya yang lain, seorang lagi memegang kakinya yang lain. Seorang untuk memegang tanduknya dan seorang lagi memegang tanduknya yang lain. Orang ketujuh agar menyembelihnya. Kami pun bertakbir semua."},"422":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يُصَلِّي وَفِي ظَهْرِ قَدَمِهِ لُمْعَةٌ قَدْرُ الدِّرْهَمِ لَمْ يُصِبْهَا الْمَاءُ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُعِيدَ الْوُضُوءَ","id":"Telah menceritakan kepada kami [Ibrahim bin Abu Al 'Abbas] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepada kami [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [salah seorang sahabat Nabi Shallallahu'alaihiwasallam], Rasulullah Shallallahu'alaihiwasallam melihat seorang laki-laki yang sedang shalat dan pada punggung telapak kakinya terdapat petak kulit seukuran satu logam dirham yang tidak tersentuh air, lalu Rasulullah Shallallahu'alaihiwasallam menyuruhnya untuk mengulangi wudhun'ya."},"423":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُبَيْدِ بْنِ خَالِدٍ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ مَوْتُ الْفَجْأَةِ أَخْذَةُ أَسَفٍ وَحَدَّثَ بِهِ مَرَّةً عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] berkata; telah menceritakan kepadaku [Manshur] dari [Tamim bin Salamah] dari ['Ubaid bin Khalid] dia adalah salah seorang sahabat Nabi Shallallahu'alaihiwasallam, berkata; \"Kematian secara tiba-tiba adalah cara pengambilan nyawa yang mengenaskan (yaitu kematiannya orang kafir) \" dan pernah bercerita bahwa hadits ini dari Nabi Shallallahu'alaihiwasallam."},"424":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُبَيْدِ بْنِ خَالِدٍ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ قَالَ فِي مَوْتِ الْفَجْأَةِ أَخْذَةُ أَسَفٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Tamim bin Salamah] dari ['Ubaid bin Khalid] salah seorang sahabat Nabi Shallallahu'alaihiwasallam, dia berkata; \"Kematian secara tiba-tiba adalah cara pengambilan nyawa yang mengenaskan.\""},"425":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو قَالَ حَدَّثَنِي عَبِيدَةُ بْنُ سُفْيَانَ الْحَضْرَمِيُّ عَنْ أَبِي الْجَعْدِ الضَّمْرِيِّ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ ثَلَاثَ جُمَعٍ تَهَاوُنًا مِنْ غَيْرِ عُذْرٍ طَبَعَ اللَّهُ تَبَارَكَ وَتَعَالَى عَلَى قَلْبِهِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin 'Amr] berkata; telah menceritakan kepadaku ['Abidah bin Sufyan Al Hadlrami] dari [Abu Ja'd Ad Dlamri], dia termasuk sahabat Nabi Shallallahu'alaihiwasallam berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang meninggalkan tiga jumat dengan menganggap enteng, tanpa ada udzur (darinya) maka Allah Tabaroka Wa Ta'ala akan menutup hatinya.\""},"426":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ أَخْبَرَنَا مُحَمَّدُ بْنُ مُطَرِّفٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ قَالَاجْتَمَعَ أَرْبَعَةٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُهُمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقْبَلُ تَوْبَةَ الْعَبْدِ قَبْلَ أَنْ يَمُوتَ بِيَوْمٍفَقَالَ الثَّانِي أَأَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قَالَ وَأَنَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقْبَلُ تَوْبَةَ الْعَبْدِ قَبْلَ أَنْ يَمُوتَ بِنِصْفِ يَوْمٍ فَقَالَ الثَّالِثُ أَأَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قَالَ وَأَنَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقْبَلُ تَوْبَةَ الْعَبْدِ قَبْلَ أَنْ يَمُوتَ بِضَحْوَةٍ قَالَ الرَّابِعُ أَأَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَأَنَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يَقْبَلُ تَوْبَةَ الْعَبْدِ مَا لَمْ يُغَرْغِرْ بِنَفَسِهِ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] telah mengabarkan kepada kami [Muhammad bin Muthorrif] dari [Zaid bin Aslam] [Abdurrahman Al Bailamani] berkata; ada empat orang dari sahabat Nabi Shallallahu'alaihiwasallam yang berkumpul, maka [salah satu dari mereka] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah Tabaaroka Wa Ta'ala menerima taubat seorang hamba sehari sebelum kematiannya.\" [Orang yang kedua] berkata; apakah kamu mendengarnya dari Rasulullah Shallallahu'alaihiwasallam? (orang pertama) berkata; Ya. (orang kedua) berkata; sedangkan saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah menerima taubat seorang hamba setengah hari sebelum kematiannya.\" Lalu [orang ketiga] berkata; apakah kamu mendengar ini dari Rasulullah Shallallahu'alaihiwasallam? (orang kedua) berkata; Ya. Orang ketiga berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah menerima tubat seorang hamba sepertiga hari (pada waktu dhuha) sebelum kematiannya.\" Lalu [orang keempat] berkata; apakah kamu mendengar ini dari Rasulullah Shallallahu'alaihiwasallam?. (orang ketiga) berkata; Ya. Orang keempat berkata; sedangkan saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah menerima taubat seorang hamba selagi ia belum sekarat.\""},"427":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ يَعْنِي ابْنَ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنِ السَّائِبِ بْنِ عَبْدِ اللَّهِ قَالَجِيءَ بِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ جَاءَ بِي عُثْمَانُ بْنُ عَفَّانَ وَزُهَيْرٌ فَجَعَلُوا يَثْنُونَ عَلَيْهِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُعْلِمُونِي بِهِ قَدْ كَانَ صَاحِبِي فِي الْجَاهِلِيَّةِ قَالَ قَالَ نَعَمْ يَا رَسُولَ اللَّهِ فَنِعْمَ الصَّاحِبُ كُنْتَ قَالَ فَقَالَ يَا سَائِبُ انْظُرْ أَخْلَاقَكَ الَّتِي كُنْتَ تَصْنَعُهَا فِي الْجَاهِلِيَّةِ فَاجْعَلْهَا فِي الْإِسْلَامِ أَقْرِ الضَّيْفَ وَأَكْرِمْ الْيَتِيمَ وَأَحْسِنْ إِلَى جَارِكَ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Isro'il] dari [Ibrahim] yaitu Ibnu Muhajir, [Mujahid] dari [As-Sa'ib bin Abdullah] berkata; saya dibawa ke hadapan Nabi Shallallahu'alaihiwasallam dan bersamaku 'Utsman bin 'Affan dan Zuhair, maka mereka memuji (Rasulullah Shallallahu'alaihiwasallam) lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepada mereka, kalian tidak usah memberitahu diriku tentang dia (As-Sa'ib), dia adalah sahabatku di Masa Jahiliyyah. (Mujahid Radliyallahu'anhu) berkata; As-Sa'ib berkata; Ya wahai Rasulullah! Sebaik-baik sahabat adalah anda. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Wahai Sa'ib, lihatlah akhlak yang telah kamu perbuat di Masa Jahiliyyah, maka lakukanlah (akhlaq tersebut) dalam Islam; muliakanlah tamu dan hormatilah anak yatim serta berbuatlah baik kepada tetanggamu.\""},"428":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا إِبْرَاهِيمُ يَعْنِي ابْنَ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنْ قَائِدِ السَّائِبِ عَنِ السَّائِبِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْقَاعِدِ عَلَى النِّصْفِ مِنْ صَلَاةِ الْقَائِمِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibrahim] yaitu Ibnu Muhajir, dari [Mujahid] dari [orang yang pernah menuntun As-Sa'ib] dari [As-Sa'ib] dari Nabi Shallallahu'alaihiwasallam bersabda: \"Shalat orang yang duduk seperti separuh shalatnya orang yang berdiri.\""},"429":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ إِبْرَاهِيمَ يَعْنِي ابْنَ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنْ قَائِدِ السَّائِبِ عَنِ السَّائِبِأَنَّهُ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْتَ شَرِيكِي فَكُنْتَ خَيْرَ شَرِيكٍ كُنْتَ لَا تُدَارِي وَلَا تُمَارِي","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Sufyan] dari [Ibrahim] yaitu Ibnu Muhajir, dari [Mujahid] dari [penuntun As-Sa'ib], dari [As-Sa'ib] dia berkata kepada Nabi Shallallahu'alaihiwasallam, \"Anda adalah serikatku, anda adalah sekutu yang paling baik. Anda tidak pernah melakukan madarot dan juga tidak hobi berdebat.\" "},"430":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا سَيْفٌ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُكَانَ السَّائِبُ بْنُ أَبِي السَّائِبِ الْعَابِدِيُّ شَرِيكَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَاهِلِيَّةِ قَالَ فَجَاءَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ فَقَالَ بِأَبِي وَأُمِّي لَا تُدَارِي وَلَا تُمَارِي","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Saif] berkata; saya telah mendengar [Mujahid] berkata; As-Sa'ib bin Abu As-Sa'ib Al 'Abidi sekutu Rasulullah Shallallahu'alaihiwasallam pada Masa Jahiliyah, ketika Nabi Shallallahu'alaihiwasallam datang pada Fath Makkah, berkata; demi bapakku dan ibuku, anda tidak suka melakukan 'madarot' dan tidak suka berjidal."},"431":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا ثَابِتٌ يَعْنِي أَبَا زَيْدٍ حَدَّثَنَا هِلَالٌ يَعْنِي ابْنَ خَبَّابٍ عَنْ مُجَاهِدٍ عَنْ مَوْلَاهُأَنَّهُ حَدَّثَهُ أَنَّهُ كَانَ فِيمَنْ يَبْنِي الْكَعْبَةَ فِي الْجَاهِلِيَّةِ قَالَ وَلِي حَجَرٌ أَنَا نَحَتُّهُ بِيَدَيَّ أَعْبُدُهُ مِنْ دُونِ اللَّهِ تَبَارَكَ وَتَعَالَى فَأَجِيءُ بِاللَّبَنِ الْخَاثِرِ الَّذِي أَنْفَسُهُ عَلَى نَفْسِي فَأَصُبُّهُ عَلَيْهِ فَيَجِيءُ الْكَلْبُ فَيَلْحَسُهُ ثُمَّ يَشْغَرُ فَيَبُولُ فَبَنَيْنَا حَتَّى بَلَغْنَا مَوْضِعَ الْحَجَرِ وَمَا يَرَى الْحَجَرَ أَحَدٌ فَإِذَا هُوَ وَسْطَ حِجَارَتِنَا مِثْلَ رَأْسِ الرَّجُلِ يَكَادُ يَتَرَاءَى مِنْهُ وَجْهُ الرَّجُلِ فَقَالَ بَطْنٌ مِنْ قُرَيْشٍ نَحْنُ نَضَعُهُ وَقَالَ آخَرُونَ نَحْنُ نَضَعُهُ فَقَالُوا اجْعَلُوا بَيْنَكُمْ حَكَمًا قَالُوا أَوَّلَ رَجُلٍ يَطْلُعُ مِنْ الْفَجِّ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا أَتَاكُمْ الْأَمِينُ فَقَالُوا لَهُ فَوَضَعَهُ فِي ثَوْبٍ ثُمَّ دَعَا بُطُونَهُمْ فَأَخَذُوا بِنَوَاحِيهِ مَعَهُ فَوَضَعَهُ هُوَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [Tsabit] yaitu Abu Zaid, telah menceritakan kepada kami [Hilal] yaitu Ibnu Khabbab dari [Mujahid] dari [mantan budaknya], menceritakan kepadanya bahwa dirinya termasuk orang yang membangun Ka'bah di Masa Jahiliyyah. Dia berkata; saya memiliki batu yang saya pahat dengan tanganku dan yang saya sembah selain Allah Tabaaroka Wa Ta'ala, lalu saya membawa susu kental, yang saya hisap sendiri kemudian saya tuangkan di atas batu tersebut hingga datang seekor anjing dan menjilatinya, lalu mengangkat satu kakinya dan mengencinginya. Kami membangun Ka'bah hingga kami sampai pada tempat Hajar Aswad. Tidak ada seorang pun yang melihat Hajar aswad, walau itu ternyata berada pada tengah-tengah batu kami, sebagaimana rambut seseorang, seseolah-olah hampir wajah seorang laki-laki tersebut. Maka ada seorang kepercayaan Quraish berkata 'Kami yang akan menaruhnya.' Yang lainnya berkata 'Kami yang akan menaruhnya.' Mereka berkata 'Bagimana kalau kita mengangkat seorang hakim.' Mereka berkata 'Yang meletakkannya adalah orang yang pertama kali datang dari lorong ka'bah ini'. Kemudian hari datanglah Nabi Shallallahu'alaihiwasallam, mereka berkata; 'Telah datang kepada kalian orang yang dapat dipercaya', lalu beliau meletakkan pada kainnya, lalu memanggil para tokoh mereka, mereka saling memegang ujung-ujungnya dan beliau Shallallahu'alaihiwasallam yang meletakkan di tengahnya."},"432":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ مُجَاهِدٍ عَنِ السَّائِبِ بْنِ أَبِي السَّائِبِأَنَّهُ كَانَ يُشَارِكُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ الْإِسْلَامِ فِي التِّجَارَةِ فَلَمَّا كَانَ يَوْمُ الْفَتْحِ جَاءَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرْحَبًا بِأَخِي وَشَرِيكِي كَانَ لَا يُدَارِي وَلَا يُمَارِي يَا سَائِبُ قَدْ كُنْتَ تَعْمَلُ أَعْمَالًا فِي الْجَاهِلِيَّةِ لَا تُقْبَلُ مِنْكَ وَهِيَ الْيَوْمَ تُقْبَلُ مِنْكَ وَكَانَ ذَا سَلَفٍ وَصِلَةٍ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin 'Utsman bin Khutsaim] dari [Mujahid] dari dari [As-Sa'ib bin Abu As-Sa'ib] dia bersekutu bersama Rasulullah Shallallahu'alaihiwasallam sebelum Islam dalam suatu jual beli. Tatkala Fathu Makkah, dia mendatangi beliau. Lalu Nabi Shallallahu'alaihiwasallam bersabda: \"Selamat datang saudaraku dan sekutuku. Kamu tidak pernah melakukan madarot dan tidak hobi berdebat Wahai Sa'ib, kamu telah melakukan amalan pada Masa Jahiliyyah, yang hal itu adalah tidak diterima, namun hari ini bisa diterima. Amalan itu telah terjadi masa lalu, namun silahkan dilestarikan sekarang. "},"433":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ مَالِكٍ أَنَّ مُحَمَّدَ بْنَ عَمْرِو بْنِ عَطَاءٍ حَدَّثَهُ قَالَرَأَيْتُ السَّائِبَ يَشُمُّ ثَوْبَهُ فَقُلْتُ لَهُ مِمَّ ذَاكَ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا وُضُوءَ إِلَّا مِنْ رِيحٍ أَوْ سَمَاعٍ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Muhammad bin Abdullah bin Malik] [Muhammad bin 'Amr bin Atho'] berkata; saya melihat [As-Sa'ib] mencium bau bajunya, maka saya bertanya, kenapa itu? (As-Sa'ib Radliyallahu'anhu) berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak ada wudlu kecuali karena bau angin atau terdengar suara.\""},"434":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ شَبِيبِ بْنِ غَرْقَدَةَ الْبَارِقِيِّ عَنْ سُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أَبِيهِ قَالَشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ فِي حَجَّةِ الْوَدَاعِ فَقَالَ أَيُّ يَوْمٍ يَوْمُكُمْ فَذَكَرَ خُطْبَتَهُ يَوْمَ النَّحْرِ","id":"Telah menceritakan kepada kami [Yahya bin 'Adam] telah menceritakan kepada kami [Abu Al Awash] dari [Syabib bin ghorqodah Al Bariqi] dari [Sulaiman bin 'Amr bin Al Ahwash] dari [Bapaknya] berkata; saya menyaksikan Rasulullah Shallallahu'alaihiwasallam berkhutbah kepada manusia pada waktu Haji Wada', beliau bersabda: \"Hari apa yang paling mulia?\" lalu (Rasulullah Shallallahu'alaihiwasallam) menyebutkan dalam khutbahnya, hari penyembelihan (Yaitu Hari Idul Adha).\""},"435":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا الْمُشْمَعِلُّ قَالَ حَدَّثَنِي عَمْرُو بْنُ سُلَيْمٍ الْمُزَنِيُّ قَالَ سَمِعْتُ رَافِعَ بْنَ عَمْرٍو الْمُزَنِيَّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا وَصِيفٌ يَقُولُ الْعَجْوَةُ وَالشَّجَرَةُ مِنْ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Al Musyma'il] berkata; telah menceritakan kepadaku ['Amr bin Sulaim Al Muzni] berkata; saya telah mendengar [Rafi' bin 'Amr Al Muzani] berkata; saya telah mendengar Nabi Shallallahu'alaihiwasallam bersabda ketika saya masih bujang, \"Al 'Ajwah (kurma Nabi) beserta pohonnya berasal dari surga.\""},"436":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ حَدَّثَنِي مُعَيْقِيبٌ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْحُ فِي الْمَسْجِدِ يَعْنِي الْحَصَى قَالَ فَقَالَ إِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَوَاحِدَةً","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Hisyam] berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Salamah] berkata; telah menceritakan kepadaku [Al Mu'aiqib] berkata; ditanyakan kepada Nabi Shallallahu'alaihiwasallam tentang mengusap kerikil di masjid (ketika sedang shalat) maka beliau Shallallahu'alaihiwasallam bersabda: \"Jika kamu memang harus melakukannya, cukuplah sekali.\""},"437":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا أَيُّوبُ بْنُ عُتْبَةَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ مُعَيْقِيبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيْلٌ لِلْأَعْقَابِ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Khalaf bin Al Walid] telah menceritakan kepada kami [Ayyub bin 'Utbah] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Al Mu'aiqib] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Celakalah orang-orang yang mata kakinya tak tersentuh air wudhu dari api neraka.\""},"438":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ حَدَّثَنِي مُعَيْقِيبٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الرَّجُلِ يُسَوِّي التُّرَابَ حَيْثُ يَسْجُدُ إِنْ كُنْتَ فَاعِلًا فَوَاحِدَةً","id":"Telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata; telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Abu Salamah] berkata; telah menceritakan kepadaku [Al Mu'aiqib] Rasulullah Shallallahu'alaihiwasallam bersabda kepada seseorang yang meratakan tanahnya ketika hendak bersujud, \"Jika kamu harus melakukannya maka lakukanlah sekali saja.\""},"439":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِسْمَاعِيلَ بْنِ أُمَيَّةَ عَنْ مَوْلًى لَهُمْ مُزَاحِمِ بْنِ أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ خَالِدِ بْنِ أُسَيْدٍ عَنْ رَجُلٍ مِنْ خُزَاعَةَ يُقَالُ لَهُ مُحَرِّشٌ أَوْ مُخَرِّشٌ لَمْ يُثْبِتْ سُفْيَانُ اسْمَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْجِعْرَانَةِ لَيْلًا فَاعْتَمَرَ ثُمَّ رَجَعَ فَأَصْبَحَ كَبَائِتٍ بِهَا فَنَظَرْتُ إِلَى ظَهْرِهِ كَأَنَّهُ سَبِيكَةُ فِضَّةٍ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Isma'il bin 'Umayah] dari budak mereka, [Muzahim bin Abu Muzahim], dari [Abdil Aziz bin Abdullah bin Khalid bin Usaid] dari seorang laki-laki Khuza'ah yang bernama [Muharrisy] atau Mukharrisy (Sufyan bin Uyyainah tidak pasti dalam penyebutan namanya) Nabi Shallallahu'alaihiwasallam pernah keluar dari Ji'ronah pada malam hari, lalu beliau berumrah kemudian kembali hingga beliau bermalam di Ji'ranah lalu saya melihat punggungnya yang terlihat seperti batang perak."},"440":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنِ ابْنِ جُرَيْجٍ حَدَّثَنِي مُزَاحِمُ بْنُ أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ عَنْ مُحَرِّشٍ الْكَعْبِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْجِعْرَانَةِ مُعْتَمِرًا فَدَخَلَ مَكَّةَ لَيْلًا ثُمَّ خَرَجَ مِنْ تَحْتِ لَيْلَتِهِ فَأَصْبَحَ بِالْجِعْرَانَةِ كَبَائِتٍ فَلَمَّا زَالَتْ الشَّمْسُ أَخَذَ فِي بَطْنِ سَرِفَ حَتَّى جَامَعَ الطَّرِيقُ طَرِيقَ الْمَدِينَةِ قَالَ فَلِذَلِكَ خَفِيَتْ عُمْرَتُهُحَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي مُزَاحِمُ بْنُ أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ عَنْ مُحَرِّشٍ الْكَعْبِيِّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] telah menceritakan kepadaku [Muzahim bin Abu Muzahim] dari [Abdul Aziz bin Abdullah] dari [Muharisy Al Ka'bi] Nabi Shallallahu'alaihiwasallam keluar dari Ji'ronah karena umroh lalu memasuki Makkah pada malam hari, lalu kembali dari malam itu dan pagi sudah sampai di Ji'ranah, seperti orang yang menginap. Tatkala matahari condong, beliau menuju ke tengah Sarifa sehingga jalan tersebut bertemu dengan jalan Madinah. Oleh karena itu umrahnya tersembunyi. Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Muzahim bin Abu Muzahim] dari [Abdul Aziz bin Abdullah] dari [Muharisy Al Ka'bi] Nabi Shallallahu'alaihiwasallam keluar, lalu menyebutkan sama dengan di atas."},"441":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنَا قَيْسٌ عَنْ أَبِيهِ قَالَجَاءَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَامَ فِي الشَّمْسِ فَأَمَرَ بِهِ فَحُوِّلَ إِلَى الظِّلِّ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami [Isma'il] berkata; telah menceritakan kepada kami [Qais] dari [Bapaknya] berkata; Pernah seseorang datang ketika Rasulullah Shallallahu'alaihiwasallam berkhutbah, dan (orang itu) berdiri di bawah terik matahari, lalu (Rasulullah Shallallahu'alaihiwasallam) memerintahkannya untuk berpindah ke tempat yang teduh."},"442":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا هُرَيْمٌ عَنْ إِسْمَاعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِيهِأَنَّهُ كَانَ فِي الشَّمْسِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَحَوَّلَ إِلَى الظِّلِّ أَوْ يُجْعَلَ فِي الظِّلِّ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] telah menceritakan kepada kami [Huraim] dari [Isma'il] dari [Qais bin Abu Hazim] dari [Bapaknya] dia berada di bawah matahari lalu Nabi Shallallahu'alaihiwasallam menyuruhnya agar berpindah ke tempat yang teduh atau dipersilahkan pindah ke tempat yang teduh."},"443":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍأَنَّ أَبَاهُ جَاءَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَعَدَ فِي الشَّمْسِ قَالَ فَأَوْمَأَ إِلَيْهِ أَوْ قَالَ فَأَمَرَ بِهِ أَنْ يَتَحَوَّلَ إِلَى الظِّلِّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Isma'il] dari [Qais bin Abu Hazim]. Bapaknya datang dan Rasulullah Shallallahu'alaihiwasallam sedang berkhutbah lalu dia duduk di bawah sinar matahari. (Qais bin Abu Hazim Radliyallahu'anhu) berkata; lalu (Rasulullah Shallallahu'alaihiwasallam) memberi isyarat kepadanya. Atau berkata; lalu (Nabi Shallallahu'alaihiwasallam) menyuruhnya agar berpindah ke tempat yang ada naungannya."},"444":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِيهِقَالَ رَآنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ فَأَمَرَ بِي فَحُوِّلْتُ إِلَى الظِّلِّ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ibnu Abu Khalid] dari [Qais bin Abu Hazim] dari [Bapaknya] berkata; Nabi Shallallahu'alaihiwasallam melihatku ketika sedang berkhutbah, lalu beliau menyuruhku berpindah ke tempat yang teduh."},"445":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي مُزَاحِمُ بْنُ أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ عَنْ مُحَرِّشٍ الْكَعْبِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ لَيْلًا مِنْ الْجِعْرَانَةِ حِينَ أَمْسَى مُعْتَمِرًا فَدَخَلَ مَكَّةَ لَيْلًا فَقَضَى عُمْرَتَهُ ثُمَّ خَرَجَ مِنْ تَحْتِ ل��يْلَتِهِ فَأَصْبَحَ بِالْجِعْرَانَةِ كَبَائِتٍ حَتَّى إِذَا زَالَتْ الشَّمْسُ خَرَجَ مِنْ الْجِعْرَانَةِ فِي بَطْنِ سَرِفَ حَتَّى جَامَعَ الطَّرِيقُ طَرِيقَ الْمَدِينَةِ بِسَرِفَقَالَ مُحَرِّشٌ فَلِذَلِكَ خَفِيَتْ عُمْرَتُهُ عَلَى كَثِيرٍ مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Rauh] dari [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Muzahim bin Abu Muzahim] dari [Abdul Aziz bin Abdullah] dari [Muharisy Al Ka'bi] Nabi Shallallahu'alaihiwasallam keluar dari Ji'ranah pada malam hari, setelah sorenya dalam keadaan umrah, lalu memasuki Makkah pada malam hari. Lalu beliau menyelesaikan umrahnya, kemudian kembali dari malam itu dan pagi sudah sampai di Ji'ranah, seperti orang yang menginap. Tatkala matahari telah condong, beliau keluar dari Ji'ranah menuju ke tengah Sarifa sehingga jalan tersebut bertemu dengan jalan Madinah, masih di daerah Sarifa. Muharrisy berkata; Oleh karena itu umrah beliau tidak diketahui oleh kebanyakan manusia."},"446":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاوِيَةَ عَنْ حَنْظَلَةَ بْنِ قَيْسٍ الزُّرَقِيِّ عَنْ أَبِي الْيَسَرِ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ أَنْ يُظِلَّهُ اللَّهُ عَزَّ وَجَلَّ فِي ظِلِّهِ فَلْيُنْظِرْ الْمُعْسِرَ أَوْ لِيَضَعْ عَنْهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Abdurrahman bin Mu'awiyah] dari [Hanzholah bin Qais Az-Zurroqi] dari [Abu Al Yasar] salah seorang sahabat Rasulullah Shallallahu'alaihiwasallam berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang senang berada dalam naungan Allah AzzaWaJalla (pada hari tiada naungan selain naungan-Nya) maka lihatlah orang yang berada dalam kesulitan atau dia melapaskannya dari (kesulitan) tersebut.\""},"447":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ وَمُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زَائِدَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيٍّ قَالَ حَدَّثَنِي أَبُو الْيَسَرِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَنْظَرَ مُعْسِرًا أَوْ وَضَعَ عَنْهُ أَظَلَّهُ اللَّهُ تَبَارَكَ وَتَعَالَى فِي ظِلِّهِ قَالَ مُعَاوِيَةُ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ","id":"Telah menceritakan kepada kami [Husain bin 'Ali Al Ju'fi] dari [Za'idah] dan [Mu'awiyah bin 'Amr] berkata; telah menceritakan kepada kami [Za'idah] dari [Abdul Malik bin 'Umair] dari [Rib'i] berkata; telah menceritakan kepadaku [Abu Al Yasar] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa mempermudah orang yang kesulitan atau membebaskannya, Allah Tabaroka Wa Ta'ala akan menaunginya dengan naungan-Nya.\" Mu'awiyah berkata; pada hari yang tidak ada naungan kecuali naungan-Nya."},"448":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَسُرَيْجٌ وَمُعَاوِيَةُ بْنُ عَمْرٍو قَالُوا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عُمَرَ بْنِ الْحَكَمِ الْأَنْصَارِيِّ عَنْ أَبِي الْيَسَرِ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْكُمْ مَنْ يُصَلِّي الصَّلَاةَ كَامِلَةً وَمِنْكُمْ مَنْ يُصَلِّي النِّصْفَ وَالثُّلُثَ وَالرُّبُعَ حَتَّى بَلَغَ الْعُشْرَ قَالَ سُرَيْجٌ فِي حَدِيثِهِ حَتَّى بَلَغَ الْعُشْرَ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Suroij] dan [Mu'awiyah bin 'Amr] mereka berkata; telah menceritakan kepada kami [Abdullah bin Wahb] dari ['Amr bin Al Harits] dari [Said bin Abu Hilal] dari ['Umar bin Al Hakam Al Anshor] dari [Abu Al Yasar] salah seorang sahabat Rasulullah Shallallahu'alaihiwasallam Rasulullah bersabda: \"Di antara kalian ada yang mengerjakan shalat dengan mendapatkan (pahala shalat) secara lengkap, ada yang setengahnya, ada pula yang sepertiganya, seperempatnya hingga ada yang sepersepuluhnya.\" Suraij berkata dalam haditsnya, sampai ada yang mendapat sepersepuluhnya."},"449":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ يَعْنِي ابْنَ أَبِي هِنْدٍ عَنْ صَيْفِيٍّ مَوْلَى أَفْلَحَ مَوْلَى أَبِي أَيُّوبَ الْأَنْصَارِيِّ عَنْ أَبِي الْيَسَرِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو بِهَؤُلَاءِ الْكَلِمَاتِ السَّبْعِ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَرَمِ وَأَعُوذُ بِكَ مِنْ التَّرَدِّي وَأَعُوذُ بِكَ مِنْ الْغَمِّ وَالْغَرَقِ وَالْحَرَقِ وَالْهَرَمِ وَأَعُوذُ بِكَ أَنْ يَتَخَبَّطَنِي الشَّيْطَانُ عِنْدَ الْمَوْتِ وَأَعُوذُ بِكَ مِنْ أَنْ أَمُوتَ فِي سَبِيلِكَ مُدْبِرًا وَأَعُوذُ بِكَ أَنْ أَمُوتَ لَدِيغًا","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] berkata; telah menceritakan kepada kami [Abdullah bin Sa'id] yaitu Ibnu Abi Hind dari [Shoifi] budak Aflah, budak Abu Ayub Al Anshori dari [Abu Al Yasar] Rasulullah Shallallahu'alaihiwasallam berdoa dengan tujuh kalimat, berdoa: \"Ya Allah saya berlindung kepada-Mu dari penyakit tua, saya juga berlindung kepada-Mu dari terjatuh dari ketinggian, saya berlindung kepada-Mu dari kesusahan dan dari tenggelam, terbakar serta kepikunan, saya berlindung kepada-Mu dari gangguan setan menjelang kematian, saya berlindung kepada-Mu dari mati dalam berperang di jalan-Mu dalam keadaan melarikan diri dan kabur, dan saya berlindung kepada-Mu dari kematian karena tersengat oleh binatang berbisa.\""},"450":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ قَالَ حَدَّثَنَا أَبُو ضَمْرَةَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ جَدِّهِ أَبِي هِنْدٍ عَنْ صَيْفِيٍّ عَنْ أَبِي الْيَسَرِ السُّلَمِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فَيَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَدْمِ وَالتَّرَدِّي وَالْهَرَمِ وَالْغَرَقِ وَالْحَرِيقِ وَأَعُوذُ بِكَ أَنْ يَتَخَبَّطَنِي الشَّيْطَانُ عِنْدَ الْمَوْتِ وَأَنْ أُقْتَلَ فِي سَبِيلِكَ مُدْبِرًا وَأَنْ أَمُوتَ لَدِيغًا","id":"Telah menceritakan kepada kami ['Ali bin Bahr] berkata; telah menceritakan kepada kami [Abu Dlamrah] berkata; telah menceritakan kepadaku [Abdullah bin Sa'id] dari kakeknya, Abu Hind dari [Shaifi] dari [Abu Al Yasar As-Sulami] Rasulullah Shallallahu'alaihiwasallam berdo'a dengan: \"Ya Allah saya berlindung kepada-Mu dari meninggal karena tertimpa bangunan, terjatuh dari ketinggian, penyakit ketuaan, tenggelam, terbakar, saya berlindung kepada-Mu dari gangguan setan menjelang kematian, saya berlindung kepada-Mu dari mati dalam berperang di jalan-Mu dalam keadaan mundur (lari dan kabur) dan dari kematian tersengat (oleh binatang berbisa).\""},"451":{"ar":"قَالَ قُرِئَ عَلَى يَعْقُوبَ فِي مَغَازِي أَبِيهِ عَنِ ابْنِ إِسْحَاقَ قَالَ ابْنُ إِسْحَاقَ وَحَدَّثَنِي بُرَيْدَةُ بْنُ سُفْيَانَ الْأَسْلَمِيُّ عَنْ بَعْضِ رِجَالِ بَنِي سَلِمَةَ عَنْ أَبِي الْيَسَرِ كَعْبِ بْنِ عَمْرٍو قَالَقَالَ وَاللَّهِ إِنَّا لَمَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَيْبَرَ عَشِيَّةً إِذْ أَقْبَلَتْ غَنَمٌ لِرَجُلٍ مِنْ يَهُودَ تُرِيدُ حِصْنَهُمْ وَنَحْنُ مُحَاصِرُوهُمْ إِذْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَجُلٌ يُطْعِمُنَا مِنْ هَذِهِ الْغَنَمِ قَالَ أَبُو الْيَسَرِ فَقُلْتُ أَنَا يَا رَسُولَ اللَّهِ قَالَ فَافْعَلْ قَالَ فَخَرَجْتُ أَشْتَدُّ مِثْلَ الظَّلِيمِ فَلَمَّا نَظَرَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَلِّيًا قَالَ اللَّهُمَّ أَمْتِعْنَا بِهِ قَالَ فَأَدْرَكْتُ الْغَنَمَ وَقَدْ دَخَلَتْ أَوَائِلُهَا الْحِصْنَ فَأَخَذْتُ شَاتَيْنِ مِنْ أُخْرَاهَا فَاحْتَضَنْتُهُمَا تَحْتَ يَدَيَّ ثُمَّ أَقْبَلْتُ بِهِمَا أَشْتَدُّ كَأَنَّهُ لَيْسَ مَعِي شَيْءٌ حَتَّى أَلْقَيْتُهُمَا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَبَحُوهُمَا فَأَكَلُوهُمَافَكَانَ أَبُو الْيَسَرِ مِنْ آخِرِ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلَاكًا فَكَانَ إِذَا حَدَّثَ بِهَذَا الْحَدِيثِ بَكَى ثُمَّ يَقُولُ أُمْتِعُوا بِي لَعَمْرِي كُنْتُ آخِرَهُمْ","id":"(Ahmad bin Hanbal RH) berkata; dibacakan di hadapan [Ya'qub] pada kitab perang bapaknya, dari [Ibnu Ishaq]. Ibnu Ishaq berkata; dan telah menceritakan kepadaku [Buraidah bin Sufyan Al Aslami] dari [beberapa orang dari Bani Salamah] dari [Abu Al Yasar Ka'b bin 'Amr] berkata; demi Allah kami benar-benar bersama Rasulullah Shallallahu'alaihiwasallam di Khaibar pada sore hari, ketika ada sekumpulan kambing milik seorang dari Yahudi yang sedang menuju benteng mereka, sedang kami sedang mengepung mereka. Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapakah yang akan mengambilkan kami makanan dari kambing tersebut\" Abu Al Yasar berkata; saya Wahai Rasulullah, beliau bersabda: \"Lakukanlah!\" (Abu Al Yasar Radliyallahu'anhu) berkata; lalu saya keluar pada saat gulita malam, tatkala Rasulullah Shallallahu'alaihiwasallam melihatku hendak berangkat, beliau berdo'a, Ya Allah senangkanlah kami dengannya. (Abu Al Yasar Radliyallahu'anhu) berkata; saya mendapatkan kambing ternyata sebagiannya telah masuk dalam benteng, lalu saya mengambil dua kambing yang lain, lalu saya taruh di bawah tanganku, lalu saya membawanya pergi karena rasa khawatirku seolah-olah saya tidak membawa sesuatupun sampai saya membawanya di hadapan Rasulullah Shallallahu'alaihiwasallam. Lalu beliau menyembelih keduanya, lalu mereka memakannya.\" Abu Al Yasar adalah termasuk sahabat Rasulullah Shallallahu'alaihiwasallam yang terakhir meninggal, jika dia menceritakan hadis ini, dia menangis lalu berkata; mereka telah merasa senang denganku dan umurku adalah yang terakhir di antara mereka."},"452":{"ar":"حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ عَمْرٍو عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ أَبِي فَاطِمَةَ الْأَزْدِيِّ أَوْ الْأَسَدِيِّ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا فَاطِمَةَ إِنْ أَرَدْتَ أَنْ تَلْقَانِي فَأَكْثِرْ السُّجُودَ","id":"Telah menceritakan kepada kami [Musa bin Daud] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin 'Amr] dari [Abu Abdurrahman Al Hubuli] dari [Abu Fathimah Al Azdi atau Al Asadi] berkata; Nabi Shallallahu'alaihiwasallam bersabda kepadaku, \"Wahai Abu Fathimah, jika kamu ingin bertemu denganku maka perbanyaklah sujud.\""},"453":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا الْحَارِثُ بْنُ يَزِيدَ عَنْ كَثِيرٍ الْأَعْرَجِ الصَّدَفِيِّ قَالَ سَمِعْتُ أَبَا فَاطِمَةَ وَهُوَ مَعَنَا بِذِي الصَّوَارِي يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا فَاطِمَةَ أَكْثِرْ مِنْ السُّجُودِ فَإِنَّهُ لَيْسَ مِنْ مُسْلِمٍ يَسْجُدُ لِلَّهِ تَبَارَكَ وَتَعَالَى سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ تَبَارَكَ وَتَعَالَى بِهَا دَرَجَةً","id":"Telah menceritakan kepada kami [Husain bin Musa] telah menceritakan kepada kami [Ibnu Lahi'ah] telah menceritakan kepada kami [Al Harits bin Yazid] dari [Katsir Al A'raj As-Shadafi] berkata; saya telah mendengar [Abu Fathimah] dia bersama kami di Dzishawari berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wahai Abu Fathimah, perbanyaklah sujud, sebab tidaklah seorang muslim yang bersujud karena Allah Tabaraka Wa Ta'ala satu kali, melainkan Allah Tabaraka Wa Ta'ala mengangkatnya satu derajat.\""},"454":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ قَالَ أَخْبَرَنِي ابْنُ لَهِيعَةَ عَنِ الْحَارِثِ بْنِ يَزِيدَ عَنْ كَثِيرٍ الْأَعْرَجِ عَنْ أَبِي فَاطِمَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا فَاطِمَةَ أَكْثِرْ مِنْ السُّجُودِ فَإِنَّهُ لَيْسَ مِنْ رَجُلٍ يَسْجُدُ لِلَّهِ تَبَارَكَ وَتَعَالَى سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ تَبَارَكَ وَتَعَالَى بِهَا دَرَجَةً","id":"Telah menceritakan kepada kami [Yahya bin Ishaq] berkata; telah mengabarkan kepadaku [Ibnu Lahi'ah] dari [Al Harits bin Yazid] dari [Katsir Al A'roj] dari [Abu Fathimah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wahai Abu Fathimah, perbanyaklah sujud karena tidak ada orang yang bersujud kepada Allah Tabaroka Wa Ta'ala dengan sekali sujud, melainkan Allah Tabaroka Wa Ta'ala mengangkat dirinya satu derajat.\""},"455":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ هِشَامٍ يَعْنِي الدَّسْتُوَائِيَّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي رَاشِدٍ الْحَبْرَانِيِّ قَالَ قَالَ عَبْدُ الرَّحْمَنِ بْنُ شِبْلٍسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اقْرَءُوا الْقُرْآنَ وَلَا تَغْلُوا فِيهِ وَلَا تَجْفُوا عَنْهُ وَلَا تَأْكُلُوا بِهِ وَلَا تَسْتَكْثِرُوا بِهِ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Hisyam] yaitu Ad Dastiwa'i, berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abu Rasyid Al Habrani] berkata; [Abdur Rahman bin Syibl] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bacalah Al qur'an, janganlah berlebihan di dalamnya, jangan terlalu kaku, janganlah makan dari bacaannya dan jangan pula memperbanyak (harta) dengannya.\""},"456":{"ar":"وَقَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ التُّجَّارَ هُمْ الْفُجَّارُ قَالَ قِيلَ يَا رَسُولَ اللَّهِ أَوَلَيْسَ قَدْ أَحَلَّ اللَّهُ الْبَيْعَ قَالَ بَلَى وَلَكِنَّهُمْ يُحَدِّثُونَ فَيَكْذِبُونَ وَيَحْلِفُونَ وَيَأْثَمُونَ","id":"[Abdur Rahman bin Syibl Radliyallahu'anhu] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \" para pedagang adalah orang-orang yang berbuat fajir\" (Abdur Rahman Radliyallahu'anhu) berkata; ditanyakan, wahai Rasulullah! bukankah Allah telah menghalalkan jual beli? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ya. Tapi mereka berbicara, berdusta, bersumpah dan berbuat dosa.\""},"457":{"ar":"قَالَوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْفُسَّاقَ هُمْ أَهْلُ النَّارِ قِيلَ يَا رَسُولَ اللَّهِ وَمَنْ الْفُسَّاقُ قَالَ النِّسَاءُ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَوَلَسْنَ أُمَّهَاتِنَا وَأَخَوَاتِنَا وَأَزْوَاجَنَا قَالَ بَلَى وَلَكِنَّهُمْ إِذَا أُعْطِينَ لَمْ يَشْكُرْنَ وَإِذَا ابْتُلِينَ لَمْ يَصْبِرْنَ","id":"[Abdur Rahman bin Syibl Radliyallahu'anhuma] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \" orang-orang fasiq adalah para penghuni neraka\", Ditanyakan, wahai Rasulullah siapakah orang orang fasiq itu? Beliau bersabda: \"para wanita\", lalu ada seorang laki-laki yang berkata; bukankah mereka itu adalah ibu-ibu kita, saudara-saudara perempuan kita, dan istri-istri kita? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Ya, tapi mereka jika diberi tidak bersyukur (berterima kasih) dan jika diuji tidak bersabar.\""},"458":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الْحَمِيدِ قَالَ حَدَّثَنِي أَبِي عَنْ تَمِيمِ بْنِ مَحْمُودٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ ثَلَاثٍ عَنْ نَقْرَةِ الْغُرَابِ وَعَنْ افْتِرَاشِ السَّبُعِ وَأَنْ يُوطِنَ الرَّجُلُ الْمَقَامَ كَمَا يُوطِنُ الْبَعِيرُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abdul Hamid] berkata; telah menceritakan kepadaku [Bapakku] dari [Tamim bin Mahmud] dari [Abdurrahman bin Syibl] berkata; saya mendengar Rasulullah Shallallahu'alaihiwasallam melarang tiga hal: dari mematuk (ketika bersujud) seperti burung gagak, dari membentangkan tangan seperti binatang buas (dalam bersujud) dan seseorang turun untuk duduk sebagaimana unta melakukan duduknya."},"459":{"ar":"حَدَّثَنَا الْحَجَّاجُ حَدَّثَنَا اللَّيْثُ يَعْنِي ابْنَ سَعْدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ أَنَّ جَعْفَرَ بْنَ عَبْدِ اللَّهِ بْنِ الْحَكَمِ حَدَّثَهُ عَنْ تَمِيمِ بْنِ مَحْمُودٍ اللَّيْثِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ الْأَنْصَارِيِّ أَنَّهُ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى فِي الصَّلَاةِ عَنْ ثَلَاثٍ نَقْرِ الْغُرَابِ وَافْتِرَاشِ السَّبُعِ وَأَنْ يُوطِنَ الرَّجُلُ الْمَقَامَ الْوَاحِدَ كَإِيطَانِ الْبَعِيرِحَدَّثَنَا هَاشِمٌ قَالَ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ جَعْفَرِ بْنِ الْحَكَمِ عَنْ تَمِيمِ بْنِ مَحْمُودٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ نَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَلَاثَةٍ فَذَكَرَهُ","id":"Telah menceritakan kepada kami [Al Hajjaj] telah menceritakan kepada kami [Laits] yaitu ibnu sa'd, berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] [Ja'far bin Abdullah bin Al Hakam] menceritakannya dari [Tamim bin Mahmud Al Laitsi] dari [Abdurrahman bin Syibl Al Anshori] dia berkata; Rasulullah Shallallahu'alaihiwasallam melarang dalam shalat dari tiga hal: dari mematuk seperti burung gagak, dari membentangkan (tangan) seperti binatang buas (dalam bersujud) dan turun untuk sujud sebagaimana unta. Telah menceritakan kepada kami [Hasyim] berkata; telah menceritakan kepada kami [Laits] dari [Yazid bin Abu Habib] dari [Ja'far bin Al Hakam] dari [Tamim bin Mahmud] dari [Abdurrahman bin Syibl] seorang sahabat Rasulullah Shallallahu'alaihiwasallam dia berkata; Rasulullah Shallallahu'alaihiwasallam melarang dari tiga hal:, lalu menyebutkannya (secara lengkap)."},"460":{"ar":"حَدَّثَنَا وَكِيعٌ عَنِ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي رَاشِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا الْقُرْآنَ وَلَا تَأْكُلُوا بِهِ وَلَا تَسْتَكْثِرُوا بِهِ وَلَا تَجْفُوا عَنْهُ وَلَا تَغْلُوا فِيهِ","id":"Telah menceritakan kepada kami [Waki'] dari [Ad Dastuwa'i] dari [Yahya bin Abu Katsir] dari [Abu Rasyid] dari [Abdurrahman bin Syibl] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bacalah Al qur'an, janganlah kalian makan dengannya, jangan pula memperbanyak (harta) dengannya, jangan terlalu kaku dan janganlah berlebihan di dalamnya.\""},"461":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو سَعِيدٍ يَعْنِي الْمُؤَدِّبَ مُحَمَّدَ بْنَ مُسْلِمِ بْنِ أَبِي الْوَضَّاحِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ وَالْمُجَالِدُ بْنُ سَعِيدٍ عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ عَامِرِ بْنِ شَهْرٍ قَالَسَمِعْتُ كَلِمَتَيْنِ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَةٌ وَمِنْ النَّجَاشِيِّ أُخْرَى سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ انْظُرُوا قُرَيْشًا فَخُذُوا مِنْ قَوْلِهِمْ وَذَرُوا فِعْلَهُمْوَكُنْتُ عِنْدَ النَّجَاشِيِّ جَالِسًا فَجَاءَ ابْنُهُ مِنْ الْكُتَّابِ فَقَرَأَ آيَةً مِنْ الْإِنْجِيلِ فَعَرَفْتُهَا أَوْ فَهِمْتُهَا فَضَحِكْتُ فَقَالَ مِمَّ تَضْحَكُ أَمِنْ كِتَابِ اللَّهِ تَعَالَى فَوَاللَّهِ إِنَّ مِمَّا أَنْزَلَ اللَّهُ تَعَالَى عَلَى عِيسَى ابْنِ مَرْيَمَ أَنَّ اللَّعْنَةَ تَكُونُ فِي الْأَرْضِ إِذَا كَانَ أُمَرَاؤُهَا الصِّبْيَانَ","id":"Telah menceritakan kepada kami [Abu Nadlr] telah menceritakan kepada kami [Abu Sa'id] yaitu Al Muaddib, Muhammad bin Muslim bin Abu Al Wadloh telah menceritakan kepada kami [Isma'il bin Abu Khalid] dan [Al Mujalid bin Sa'id] dari ['Amir As-Sya'bi] dari ['Amir bin Syahr] berkata; saya telah mendengar dua kalimat, satu kalimat dari Nabi Shallallahu'alaihiwasallam dan satu kalimat yang lain dari Najasyi, kalimat yang saya dengar dari Nabi Shallallahu'alaihiwasallam adalah, \"Lihatlah orang-orang Quraisy lalu ambillah perkataan mereka, dan tinggalkanlah perbuatan mereka\" Saya duduk dalam sebuah majlis raja Najasyi, lalu datang seorang anaknya yang pandai Injil, lalu dia membaca satu ayat dari injil hingga saya mengerti dan memahaminya lalu saya tertawa, maka dia bertanya, kenapa kamu tertawa?. Dia bertanya, Apakah kamu tersenyum karena kitab Allah ta'ala? demi Allah di antara apa yang diturunkan oleh Allah terhadap Isa bin Maryam laknat akan terjadi di bumi apabila para pemimpinnya adalah anak-anak."},"462":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا عِمْرَانُ يَعْنِي الْقَطَّانَ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ اللَّيْثِيِّ عَنْ مُعَاوِيَةَ اللَّيْثِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكُونُ النَّاسُ مُجْدِبِينَ فَيُنْزِلُ اللَّهُ تَبَارَكَ وَتَعَالَى عَلَيْهِمْ رِزْقًا مِنْ رِزْقِهِ فَيُصْبِحُونَ مُشْرِكِينَ فَقِيلَ لَهُ وَكَيْفَ ذَاكَ يَا رَسُولَ اللَّهِ قَالَ يَقُولُونَ مُطِرْنَا بِنَوْءِ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Sulaiman bin Daud At Toyalisi] telah menceritakan kepada kami [Imron] yaitu Al Qoththon, dari [Qatadah] dari [Nasr bin 'Ashim Al Laitsi] dari [Mu'awiyah Al Laitsi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Orang-orang berada dalam keadaan kekeringan, lalu Allah Tabaaroka Wa Ta'ala menurunkan satu dari rizqi-Nya, lalu mereka menjadi Musyrik dengannya.\" Lalu ditanyakan, bagaimana itu terjadi wahai Rasulullah? (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Mereka berkata kami diberi hujan karena bintang ini dan itu.\""},"463":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ طَلْحَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ طَلْحَةَ بْنِ عَبْدِ اللَّهِ عَنْ مُعَاوِيَةَ بْنِ جَاهِمَةَجَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَدْتُ الْغَزْوَ وَجِئْتُكَ أَسْتَشِيرُكَ فَقَالَ هَلْ لَكَ مِنْ أُمٍّ قَالَ نَعَمْ فَقَالَ الْزَمْهَا فَإِنَّ الْجَنَّةَ عِنْدَ رِجْلِهَا ثُمَّ الثَّانِيَةَ ثُمَّ الثَّالِثَةَ فِي مَقَاعِدَ شَتَّى كَمِثْلِ هَذَا الْقَوْلِ","id":"Telah menceritakan kepada kami [Rauh] berkata; telah mengabarkan kepada kami [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Muhammad bin Thalhah bin Abdullah bin Abdurrahman] dari [Bapaknya, Thalhah bin Abdullah] dari [Mu'awiyah bin Jahimah] dia telah datang kepada Nabi Shallallahu'alaihiwasallam dan berkata; wahai Rasulullah! saya ingin berperang dan saya datang kepada anda untuk meminta saran!. (Rasulullah Shallallahu'alaihiwasallam) bersabda: \"Apakah kamu masih memiliki seorang ibu?\" Dia berkata; Ya. Lalu beliau bersabda: \"Rawatlah dia, sebab surga itu berada di telapak kakinya\" beliau mengucapkannya dua kali, tiga kali, pada tempat yang berbeda-beda, seperti perkataan tersebut."},"464":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ أَخْبَرَنَا أَيُّوبُ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ عَنْ أَبِي عَزَّةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى إِذَا أَرَادَ قَبْضَ رُوحِ عَبْدٍ بِأَرْضٍ جَعَلَ لَهُ فِيهَا أَوْ قَالَ بِهَا حَاجَةً","id":"Telah menceritakan kepada kami [Isma'il] berkata; telah mengabarkan kepada kami [Ayyub] dari [Abu Al Malih bin Usamah] dari [Abu 'Azzah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \" Allah Tabaroka Wa Ta'ala jika ingin mencabut ruh seorang hamba di sebuah tempat, Allah memunculkan keperluan baginya di tempat tersebut.\""},"465":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْغَسِيلِ قَالَ أَخْبَرَنَا حَمْزَةُ بْنُ أَبِي أُسَيْدٍ وَكَانَ أَبُوهُ بَدْرِيًّا عَنِ الْحَارِثِ بْنِ زِيَادٍ السَّاعِدِيِّ الْأَنْصَارِيِّأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْخَنْدَقِ وَهُوَ يُبَايِعُ النَّاسَ عَلَى الْهِجْرَةِ فَقَالَ يَا رَسُولَ اللَّهِ بَايِعْ هَذَا قَالَ وَمَنْ هَذَا قَالَ ابْنُ عَمِّي حَوْطُ بْنُ يَزِيدَ أَوْ يَزِيدُ بْنُ حَوْطٍ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أُبَايِعُكَ إِنَّ النَّاسَ يُهَاجِرُونَ إِلَيْكُمْ وَلَا تُهَاجِرُونَ إِلَيْهِمْ وَالَّذِي نَفْسُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ لَا يُحِبُّ رَجُلٌ الْأَنْصَارَ حَتَّى يَلْقَى اللَّهَ تَبَارَكَ وَتَعَالَى إِلَّا لَقِيَ اللَّهَ تَبَارَكَ وَتَعَالَى وَهُوَ يُحِبُّهُ وَلَا يَبْغُضُ رَجُلٌ الْأَنْصَارَ حَتَّى يَلْقَى اللَّهَ تَبَارَكَ وَتَعَالَى إِلَّا لَقِيَ اللَّهَ تَبَارَكَ وَتَعَالَى وَهُوَ يَبْغُضُهُ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Abdurrahman bin Al Ghasil] berkata; telah mengabarkan kepada kami [Hamzah bin Abu Usaid], bapaknya adalah Ahli Badar, dari [Al Harits bin Ziyad As-Saidi Al Anshari] dia telah datang kepada Rasulullah Shallallahu'alaihiwasallam pada Perang Khandaq, ketika beliau sedang membaiat orang-orang atas hijrah. (As-Saidi) berkata; Wahai Rasulullah! baiatlah dia! Beliau bertanya, \"Siapa dia?\" Dia berkata; anak pamanku Hauth bin Yazid atau Yazid bin Hauth. Dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saya tidak akan membaiatmu, orang-orang berhijrah kepada kalian namun kalian tidak berhijrah kepada mereka. Demi Dzat yang jiwa Muhammad Shallallahu'alaihiwasallam berada di tangan-Nya, tidak ada seorang yang cinta kepada orang-orang Anshar hingga dia bertemu dengan Allah Tabaaraka Wa Ta'ala melainkan dia bertemu Allah Tabaaroka Wa Ta'ala dan Dia mencintainya. Sebaliknya tidak seorang pun membenci Anshar hingga dia bertemu Allah Tabaaroka Wa Ta'ala melainkan bertemu kepada-Nya sedang Allah memurkainya.\""},"466":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنِي سَعْدُ بْنُ أَوْسٍ عَنْ بِلَالِ بْنِ يَحْيَى شَيْخٌ لَهُمْ عَنْ شُتَيْرِ بْنِ شَكَلٍ عَنْ أَبِيهِقَالَ قُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي دُعَاءً أَنْتَفِعُ بِهِ قَالَ قُلْ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ سَمْعِي وَبَصَرِي وَقَلْبِي وَمَنِيِّيحَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سَعْدُ بْنُ أَوْسٍ عَنْ بِلَالٍ الْعَبْسِيِّ عَنْ شُتَيْرِ بْنِ شَكَلٍ عَنْ أَبِيهِ شَكَلِ بْنِ حُمَيْدٍ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepadaku [Sa'd bin Aus] dari [Bilal bin Yahya] guru mereka, dari [Syutair bin Syakal] dari [Bapaknya] berkata; saya berkata; Wahai Rasulullah! ajarikan kepadaku sebuah doa yang saya bisa mengambil manfaat darinya. Beliau bersabda: \"Bacalah: ALLAHUMMA INNII A'UDZU BIKA MIN SYARRI SAM'I WA BASHORI WA QOLBI WA MANIYYI (Ya Allah, saya berlindung kepada-Mu dari kejelekan pendengaranku, penglihatanku dan hatiku serta angan-anganku).\" Telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sa'd bin Aus] dari [Bilal Al Absi] dari [Syutair bin Syakal] dari [Bapaknya, Syakal bin Humaid] berkata; saya datang kepada Nabi Shallallahu'alaihiwasallam. Lalu menyebutkan hadits seperti yang di atas."},"467":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ يَعِيشَ بْنِ طِخْفَةَ بْنِ قَيْسٍ الْغِفَارِيِّ قَالَكَانَ أَبِي مِنْ أَصْحَابِ الصُّفَّةِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِمْ فَجَعَلَ الرَّجُلُ يَنْقَلِبُ بِالرَّجُلِ وَالرَّجُلُ بِالرَّجُلَيْنِ حَتَّى بَقِيتُ خَامِسَ خَمْسَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقُوا فَانْطَلَقْنَا مَعَهُ إِلَى بَيْتِ عَائِشَةَ فَقَالَ يَا عَائِشَةُ أَطْعِمِينَا فَجَاءَتْ بِحَشِيشَةٍ فَأَكَلْنَا ثُمَّ جَاءَتْ بِحَيْسَةٍ مِثْلَ الْقَطَاةِ فَأَكَلْنَا ثُمَّ قَالَ يَا عَائِشَةُ اسْقِينَا فَجَاءَتْ بِعُسٍّ فَشَرِبْنَا ثُمَّ جَاءَتْ بِقَدَحٍ صَغِيرٍ فِيهِ لَبَنٌ فَشَرِبْنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ شِئْتُمْ بِتُّمْ وَإِنْ شِئْتُمْ انْطَلَقْتُمْ إِلَى الْمَسْجِدِ فَقُلْتُ لَا بَلْ نَنْطَلِقُ إِلَى الْمَسْجِدِ قَالَ فَبَيْنَا أَنَا مِنْ السَّحَرِ مُضْطَجِعٌ عَلَى بَطْنِي إِذَا رَجُلٌ يُحَرِّكُنِي بِرِجْلِهِ فَقَالَ إِنَّ هَذِهِ ضِجْعَةٌ يَبْغُضُهَا اللَّهُ تَبَارَكَ وَتَعَالَى فَنَظَرْتُ فَإِذَا هُوَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا هَاشِمٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ يَعْنِي شَيْبَانَ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ قَالَ أَخْبَرَنِي يَعِيشُ بْنُ طِخْفَةَ بْنِ قَيْسٍ عَنْ أَبِيهِ وَكَانَ أَبُوهُ مِنْ أَهْلِ الصُّفَّةِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا فُلَانُ انْطَلِقْ بِهَذَا مَعَكَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Hisyam Ad Dastuwa'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Yai'sy bin Thikhfah bin Qais Al Ghifari] berkata; ayahku salah satu dari Ahli Shuffah. Rasulullah Shallallahu'alaihiwasallam menyuruh mereka agar seseorang bergabung dengan lainnya (yang masih menyendiri), dan silahkan bergabung dengan mereka yang berdua, sehingga saya menjadi orang kelima dari lima orang, lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Pergilah kalian\", lalu kami pergi bersama beliau ke rumah 'Aisyah. Beliau bersabda: \"Wahai 'Aisyah, berilah makan kami\", lalu ('Aisyah Radliyallahu'anhuma) datang membawa hasyisyah (makanan yang terbuat dari gandum dan daging atau kurma yang telah dimasak) lalu kami memakannya, lalu ('Aisyah Radliyallahu'anha) datang lagi dengan membawa hais (makanan yang terbuat dari kurma dan minyak samin yang dicampur susu) seperti susu yang dikeringkan, lalu kami memakannya. Lalu beliau bersabda: \"Wahai 'Aisyah berilah kami minum\" lalu ('Aisyah Radliyallahu'anhuma) datang dengan membawa bejana berisi air, lalu kami meminumnya. Dia datang lagi membawa segelas susu hingga kami meminumnya. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika mau kalian bisa bermalam di sini, atau kalian ke masjid.\" Maka saya berkata; tidak, kami ke masjid saja. (Bapaknya Thihfah Radliyallahu'anhu) berkata; ketika saya tidur malam dengan tengkurap, tiba-tiba datang seorang laki-laki yang mengerakkan tubuhku dengan kakinya dan berkata; ini adalah posisi tidur yang dibenci Allah Tabaaroka Wa Ta'ala. Saya melihatnya, ternyata dia adalah Rasulullah Shallallahu'alaihiwasallam. Telah menceritakan kepada kami [Hasyim] telah menceritakan kepada kami [Abu Mu'awiyah] yaitu Syaiban, telah menceritakan kepada kami telah [Yahya] yaitu Ibnu Abu Katsir, dari [Abu Salamah] berkata; telah mengabarkan kepadaku [Ya'isy bin Thihfah bin Qais] dari [Bapaknya] dia adalah salah satu dari Ahli Suffah. Dia Berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wahai Fulan, pergilah bersama orang ini.\" Lalu ia sebutkan hadis secara makna."},"468":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ طِخْفَةَ الْغِفَارِيِّ قَالَ أَخْبَرَنِي أَبِيأَنَّهُ ضَافَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ نَفَرٍ قَالَ فَبِتْنَا عِنْدَهُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ اللَّيْلِ يَطَّلِعُ فَرَآهُ مُنْبَطِحًا عَلَى وَجْهِهِ فَرَكَضَهُ بِرِجْلِهِ فَأَيْقَظَهُ فَقَالَ هَذِهِ ضِجْعَةُ أَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Zuhair] yaitu Ibnu Muhammad, dari [Muhammad bin 'Amr bin Al Halhalah] dari [Nu'aim bin Abdullah] dari [Ibnu Thihfah Al Ghifari] berkata; telah mengabarkan kepadaku [bapakku] pernah dia mendatangi Rasulullah Shallallahu'alaihiwasallam bersama beberapa orang. Dia berkata; lalu kami menginap di tempat beliau. Rasulullah Shallallahu'alaihiwasallam keluar pada malam hari, memeriksa tamu-tamunya yang setnagh tidur. Ternyata dia tengkurap pada wajahnya, beliau menyentuhnya dengan kaki beliau, membangunkannya dan bersabda: \"Ini adalah cara berbaring penduduk neraka.\""},"469":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ يَعْنِي ابْنَ عُمَرَ قَالَ أَخْبَرَنِي نَافِعٌ أَنَّهُ سَمِعَ أَبَا لُبَابَةَ يُخْبِرُ ابْنَ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ قَتْلِ الْحَيَّاتِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] yaitu Ibnu 'Umar berkata; telah mengabarkan kepadaku [Nafi'] dia telah mendengar [Abu lubabah] mengabari Ibnu Umar bahwa Rasulullah Shallallahu'alaihiwasallam melarang membunuh ular."},"470":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ قَالَ سَمِعْتُ نَافِعًا قَالَكَانَ ابْنُ عُمَرَ يَأْمُرُ بِقَتْلِ الْحَيَّاتِ كُلِّهِنَّ لَا يَدَعُ مِنْهُنَّ شَيْئًا حَتَّى حَدَّثَهُ أَبُو لُبَابَةَ الْبَدْرِيُّ بْنُ عَبْدِ الْمُنْذِرِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ قَتْلِ جِنَّانِ الْبُيُوتِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Jarir] yaitu Ibnu Hazim, berkata; saya telah mendengar [Nafi'] berkata; Ibnu 'Umar pernah menyuruh membunuh ular semuanya tanpa terkecuali, sampai [Abu Lubabah Al Badari bin Abdulmundzir] menceritakannya bahwa Rasulullah Shallallahu'alaihiwasallam melarang membunuh ular kecil yang berada di rumah."},"471":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو قَالَ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ الْأَنْصَارِيِّ عَنْ أَبِي لُبَابَةَ الْبَدْرِيِّ ابْنِ عَبْدِ الْمُنْذِرِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيِّدُ الْأَيَّامِ يَوْمُ الْجُمُعَةِ وَأَعْظَمُهَا عِنْدَهُ وَأَعْظَمُ عِنْدَ اللَّهِ عَزَّ وَجَلَّ مِنْ يَوْمِ الْفِطْرِ وَيَوْمِ الْأَضْحَى وَفِيهِ خَمْسُ خِلَالٍ خَلَقَ اللَّهُ فِيهِ آدَمَ وَأَهْبَطَ اللَّهُ فِيهِ آدَمَ إِلَى الْأَرْضِ وَفِيهِ تَوَفَّى اللَّهُ آدَمَ وَفِيهِ سَاعَةٌ لَا يَسْأَلُ الْعَبْدُ فِيهَا شَيْئًا إِلَّا آتَاهُ اللَّهُ تَبَارَكَ وَتَعَالَى إِيَّاهُ مَا لَمْ يَسْأَلْ حَرَامًا وَفِيهِ تَقُومُ السَّاعَةُ مَا مِنْ مَلَكٍ مُقَرَّبٍ وَلَا سَمَاءٍ وَلَا أَرْضٍ وَلَا رِيَاحٍ وَلَا جِبَالٍ وَلَا بَحْرٍ إِلَّا هُنَّ يُشْفِقْنَ مِنْ يَوْمِ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Abu 'Amir, Abdul Malik bin 'Amr] berkata; telah menceritakan kepada kami [Zuhair] yaitu Ibnu Muhammad, dari [Abdullah bin Muhammad bin 'Aqil] dari [Abdurrahman bin Yazid Al Anshori] dari [Abu Lubabah Al Badari bin Abu Al Mundzir] Rasulullah Shallallahu'alaihiwasallam bersabda: \"Sayyidul ayyaam (hari yang paling terhormat) adalah Hari Jumat, hari yang paling agung, hari yang paling mulia di sisi Allah AzzaWaJalla dari pada hari Idul Fithri dan Hari Idul Adha. Di hari itu ada lima kejadian besar: Allah menciptakan Adam, Allah menurunkan Adam ke bumi, Allah mewafatkan Adam, Di dalamnya terdapat suatu waktu yang tidaklah seorang hamba meminta suatu permohonan, kecuali Allah Tabaaroka Wa Ta'ala memenuhinya, selama ia tidak memohon yang haram dan hari itu kiamat terjadi, maka tidak ada Malaikat yang selalu bertaqorrub, tidak juga Langit, Bumi, Angin, Gunung serta Lautan melainkan mereka semua merindukan Hari Jum'at.\""},"472":{"ar":"حَدَّثَنَا الْهَيْثَمُ بْنُ خَارِجَةَ قَالَ أَبُو عَبْد الرَّحْمَنِ وَسَمِعْتُهُ أَنَا مِنْ الْهَيْثَمِ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ الْوَلِيدِ عَنْ أَبِي مَنْصُورٍ مَوْلَى الْأَنْصَارِ عَنْ عَمْرِو بْنِ الْجَمُوحِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِقُّ الْعَبْدُ حَقَّ صَرِيحِ الْإِيمَانِ حَتَّى يُحِبَّ لِلَّهِ تَعَالَى وَيُبْغِضَ لِلَّهِ فَإِذَا أَحَبَّ لِلَّهِ تَبَارَكَ وَتَعَالَى وَأَبْغَضَ لِلَّهِ تَبَارَكَ وَتَعَالَى فَقَدْ اسْتَحَقَّ الْوَلَاءَ مِنْ اللَّهِ وَإِنَّ أَوْلِيَائِي مِنْ عِبَادِي وَأَحِبَّائِي مِنْ خَلْقِي الَّذِينَ يُذْكَرُونَ بِذِكْرِي وَأُذْكَرُ بِذِكْرِهِمْ","id":"Telah menceritakan kepada kami [Al Hutsaim bin Khorijah] Abu Abdurrahman berkata; dan saya telah mendengarnya dan [Al Hutsaim], telah menceritakan kepada kami [Risydin bin Sa'd] dari [Abdullah bin Al Walid] dari [Abu Manshur, budak Al Anshor] dari ['Amr bin Al Jamuh] dia mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Seorang hamba tidak berhak dikatakan iman yang nyata hingga dia cinta karena Alalh Ta'ala dan benci karena-Nya. Jika dia telah cinta karena Allah Ta'ala dan benci karena-Nya maka ia berhak mendapatkan pembelaan dari Allah.\" (Allah AzzaWaJalla berfirman) 'Para wali-Ku dari hambaku dan para kekasih-Ku dari mahluk-Ku adalah mereka yang disebut-sebut jika aku disebut, dan Aku disebut jika mereka disebut."},"473":{"ar":"حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صَفْوَانَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْحَجَرِ وَالْبَابِ وَاضِعًا وَجْهَهُ عَلَى الْبَيْتِ","id":"Telah menceritakan kepada kami ['Abidah bin Humaid] berkata; telah menceritakan kepadaku [Yazid bin Abu Ziyad] dari [Mujahid] dari [Abdurrahman bin Shafwan] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam di antara Hajar Aswad dengan pintu, meletakkan wajahnya pada Ka'bah."},"474":{"ar":"حَدَّثَنَا جَرِيرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ قَالَكَانَ رَجُلٌ مِنْ الْمُهَاجِرِينَ يُقَالُ لَهُ عَبْدُ الرَّحْمَنِ بْنُ صَفْوَانَ وَكَانَ لَهُ بَلَاءٌ فِي الْإِسْلَامِ حَسَنٌ وَكَانَ صَدِيقًا لِلْعَبَّاسِ فَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ جَاءَ بِأَبِيهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ بَايِعْهُ عَلَى الْهِجْرَةِ فَأَبَى وَقَالَ إِنَّهَا لَا هِجْرَةَ فَانْطَلَقَ إِلَى الْعَبَّاسِ وَهُوَ فِي السِّقَايَةِ فَقَالَ يَا أَبَا الْفَضْلِ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي يُبَايِعُهُ عَلَى الْهِجْرَةِ فَأَبَى قَالَ فَقَامَ الْعَبَّاسُ مَعَهُ وَمَا عَلَيْهِ رِدَاءٌ فَقَالَ يَا رَسُولَ اللَّهِ قَدْ عَرَفْتَ مَا بَيْنِي وَبَيْنَ فُلَانٍ وَأَتَاكَ بِأَبِيهِ لِتُبَايِعَهُ عَلَى الْهِجْرَةِ فَأَبَيْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَا هِجْرَةَ فَقَالَ الْعَبَّاسُ أَقْسَمْتُ عَلَيْكَ لَتُبَايِعَنَّهُ قَالَ فَبَسَطَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ قَالَ فَقَالَ هَاتِ أَبْرَرْتُ قَسَمَ عَمِّي وَلَا هِجْرَةَ","id":"Telah menceritakan kepada kami [Jarir] dari [Yazid bin Abu Ziyad] dari [Mujahid] berkata; ada seorang lelaki dari Muhajirin yang bernama Abdurrahman bin Safwan yang diuji kebaikan dalam Islam, dia adalah sahabat Abbas. Tatkala Hari Penaklukan Makkah, dia datang dengan bapaknya kepada Rasulullah Shallallahu'alaihiwasallam lalu berkata; Wahai Rasulullah, baiatlah dia atas hijroh. (Rasulullah Shallallahu'alaihiwasallam) menolaknya dan bersabda: \"Tidak ada hijrah (setelah penaklukan makkah).\" Lalu dia pergi kepada Al 'Abbas ketika dia sedang memberi minum, dia berkata; Wahai Abul Fadhol, saya telah menemui Rasulullah Shallallahu'alaihiwasallam bersama bapakku untuk membaiatnya untuk hijrah namun beliau menolaknya. (Mujahid Radliyallahu'anhu) berkata; lalu Al 'Abbas berdiri tanpa memakai selendang lalu berkata; Wahai Rasulullah, sungguh anda telah tahu hubunganku dengan Fulan (dia bercerita bahwa) yang telah datang bersama bapaknya agar anda membaiatnya untuk hijrah namun anda menolaknya. Rasulullah Shallallahu'alaihiwasallam bersabda: sudah tidak ada hijroh\" Al 'Abbas berkata; saya bersumpah pada Allah atas anda, baiatlah dia. (Mujahid Radliyallahu'anhu) berkata; Rasulullah Shallallahu'alaihiwasallam membentangkan tangannya kemudian berkata; \"Berikan (tanganmu), saya telah berbuat baik dengan sumpah pamanku bahwasanya tidak ada hijrah (setelah penaklukan Makkah).\""},"475":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَجَّاجِ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صَفْوَانَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُلْتَزِمًا الْبَابَ مَا بَيْنَ الْحَجَرِ وَالْبَابِ وَرَأَيْتُ النَّاسَ مُلْتَزِمِينَ الْبَيْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hajjaj] telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Abdurrahman bin Shafwan] berkata; saya melihat Rasulullah Shallallahu'alaihiwasallam menetap di pintu, antara Hajar Aswad dan pintu ka'bah. Saya melihat orang-orang menetap pada Ka'bah bersama Rasulullah Shallallahu'alaihiwasallam."},"476":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَجَّاجِ أَخْبَرَنَا جَرِيرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صَفْوَانَقَالَ لَمَّا افْتَتَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قُلْتُ لَأَلْبَسَنَّ ثِيَابِي وَكَانَ دَارِي عَلَى الطَّرِيقِ فَلَأَنْظُرَنَّ مَا يَصْنَعُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ فَوَافَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ مِنْ الْكَعْبَةِ وَأَصْحَابُهُ قَدْ اسْتَلَمُوا الْبَيْت�� مِنْ الْبَابِ إِلَى الْحَطِيمِ وَقَدْ وَضَعُوا خُدُودَهُمْ عَلَى الْبَيْتِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسْطَهُمْ فَقُلْتُ لِعُمَرَ كَيْفَ صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دَخَلَ الْكَعْبَةَ قَالَ صَلَّى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hajjaj] telah mengabarkan kepada kami [Jarir] dari [Yazid bin Abu Ziyad] dari [Mujahid] dari [Abdurrahman bin Shafwan] berkata; tatkala Rasulullah Shallallahu'alaihiwasallam menaklukan Makkah, saya berkata; saya akan memakai pakaianku. Rumahku berada di pinggir jalan, karenanya saya ingin melihat apa yang akan dilakukan Rasulullah Shallallahu'alaihiwasallam. Lalu saya berangkat, saya berhenti, ternyata Rasulullah Shallallahu'alaihiwasallam dan para sahabatnya telah keluar dari Ka'bah. Mereka telah menyentuh Baitullah dari pintunya sampai tembok Ka'bah. Mereka telah meletakkan pipi-pipi mereka pada Ka'bah sedangkan Rasulullah Shallallahu'alaihiwasallam berada di tengah-tengah mereka. Saya bertanya kepada Umar, apa yang dilakukan Rasulullah Shallallahu'alaihiwasallam ketika memasuki Ka'bah? Dia menjawab, beliau Shalat dua rekaat."},"477":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْعُمَرِيُّ حَدَّثَنَا أَبُو سَهْلٍ عَوْفُ بْنُ أَبِي جَمِيلَةَ عَنْ زَيْدٍ أَبِي الْقَمُوصِ عَنْ وَفْدِ عَبْدِ الْقَيْسِأَنَّهُمْ سَمِعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اجْعَلْنَا مِنْ عِبَادِكَ الْمُنْتَخَبِينَ الْغُرِّ الْمُحَجَّلِينَ الْوَفْدِ الْمُتَقَبَّلِينَ قَالَ فَقَالُوا يَا رَسُولَ اللَّهِ مَا عِبَادُ اللَّهِ الْمُنْتَخَبُونَ قَالَ عِبَادُ اللَّهِ الصَّالِحُونَ قَالُوا فَمَا الْغُرُّ الْمُحَجَّلُونَ قَالَ الَّذِينَ يَبْيَضُّ مِنْهُمْ مَوَاضِعُ الطُّهُورِ قَالُوا فَمَا الْوَفْدُ الْمُتَقَبَّلُونَ قَالَ وَفْدٌ يَفِدُونَ مِنْ هَذِهِ الْأُمَّةِ مَعَ نَبِيِّهِمْ إِلَى رَبِّهِمْ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Abu Nadlr] telah menceritakan kepada kami [Muhammad bin Abdullah Al Umari] telah menceritakan kepada kami [Abu Sahl, Auf bin Abu Jamilah] dari [Zaid Abu Al Qamus] dari [utusan Abdul Qais] mereka telah mendengar Rasulullah Shallallahu'alaihiwasallam berdo'a, \"Ya Allah, jadikanlah kami dari hamba-hamba-Mu yang terpilih, yang berseri-seri wajahnya, utusan yang diterima\". Lalu mereka bertanya, Wahai Rasulullah, siapa yang dimaksud hamba Allah yang terpilih?. Beliau menjawab, hamba Allah yang shalih. Mereka bertanya, apakah Al ghur muhajjalin? Beliau menjawab, yaitu orang yang bekas wudlunya berwarna putih. Mereka bertanya, apakah utusan yang diterima?. Beliau menjawab, seorang utusan yang di utus dari kalangan umat ini bersama dengan nabi mereka kepada Rabb mereka Tabaroka Wa Ta'ala."},"478":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي الْهَيْثَمِ بْنِ نَصْرِ بْنِ دَهْرٍ الْأَسْلَمِيِّ عَنْ أَبِيهِ قَالَأَتَى مَاعِزُ بْنُ خَالِدِ بْنِ مَالِكٍ رَجُلٌ مِنَّا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَوْدَى عَلَى نَفْسِهِ بِالزِّنَا فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجْمِهِ فَخَرَجْنَا إِلَى حَرَّةِ بَنِي نِيَارٍ فَرَجَمْنَاهُ فَلَمَّا وَجَدَ مَسَّ الْحِجَارَةِ جَزِعَ جَزَعًا شَدِيدًا فَلَمَّا فَرَغْنَا مِنْهُ وَرَجَعْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْنَا لَهُ جَزَعَهُ فَقَالَ هَلَّا تَرَكْتُمُوهُ","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepadaku [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Al Haitsam bin Nashr bin Dahr Al Aslami] dari [Bapaknya] berkata; Ma'iz bin Khalid bin Malik, salah seorang dari kami kepada Rasulullah Shallallahu'alaihiwasallam, lalu dia mengaku sendiri dia telah berzina, beliau menyuruh kami untuk merajamnya. Lantas kami keluar menuju tempat Bani Niyar, dan kami merajamnya. Tatkala Ma'iz merasakan sentuhan batu dia memberontak dengan keras, tatkala kami sudah selesai dan kami ke Rasulullah Shallallahu'alaihiwasallam, kami sampaikan sikapnya. Lalu beliau bersabda: \"Kenapa tidak kalian biarkan dia?\"."},"479":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي الْهَيْثَمِ بْنِ نَصْرِ بْنِ دَهْرٍ الْأَسْلَمِيِّ أَنَّ أَبَاهُ حَدَّثَهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي مَسِيرِهِ إِلَى خَيْبَرَ لِعَامِرِ بْنِ الْأَكْوَعِ وَهُوَ عَمُّ سَلَمَةَ بْنِ عَمْرِو بْنِ الْأَكْوَعِ وَكَانَ اسْمُ الْأَكْوَعِ سِنَانًا انْزِلْ يَا ابْنَ الْأَكْوَعِ فَاحْدُ لَنَا مِنْ هُنَيَّاتِكَ قَالَ فَنَزَلَ يَرْتَجِزُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ وَاللَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَاإِنَّا إِذَا قَوْمٌ بَغَوْا عَلَيْنَاوَإِنْ أَرَادُوا فِتْنَةً أَبَيْنَافَأَنْزِلَنْ سَكِينَةً عَلَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَا","id":"Telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] berkata; telah menceritakan kepada kami [Muhammad bin Ibrahim bin Al Harits At Taimi] dari [Abu Al Haitsam bin Nashr bin Dahr Al Aslami], [bapaknya] menceritakannya, dia mendengar Rasulullah Shallallahu'alaihiwasallam bersabda pada saat perjalanannya menuju Khaibar kepada 'Amir bin Al Akwa', dia adalah paman Salamah bin 'Amr bin Al Akwa'. Nama Al Akwa' adalah Sinan. \"Turunlah wahai Ibnu Al Akwa', tantanglah dengan syair-syairmu\". (Nashr bin Dahr Al Aslami Radliyallahu'anhu) berkata; lalu dia melantunkan syair kepada Rasulullah Shallallahu'alaihiwasallam 'Demi Allah, seandainya tidak ada Allah, kita tidak akan mendapatkan petunjuk, tidak bersedekah, dan tidak akan Shalat. Jika ada kaum yang berbuat kejahatan kepada kami, dan menghendaki fitnah, kami akan menolaknya. Maka turunkanlah ketenangan kepada kami dan mengokohkan kaki kami jika kami bertemu."},"480":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ عَنْ صَخْرٍ الْغَامِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ وَكَانَ إِذَا بَعَثَ سَرِيَّةً أَوْ جَيْشًا بَعَثَهُمْ مِنْ أَوَّلِ النَّهَارِقَالَ وَكَانَ صَخْرٌ رَجُلًا تَاجِرًا وَكَانَ يَبْعَثُ تِجَارَتَهُ مِنْ أَوَّلِ النَّهَارِ فَأَثْرَى وَكَثُرَ مَالُهُ","id":"Telah menceritakan kepada kami [Husyaim] berkata; telah memberitakan kepada kami [Ya'la bin 'Atho'] dari [Umarah bin Hadid] dari [Shakhr Al Ghamidi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ya berilah berkah pada umatku pada pagi harinya. (Shakhr Al Ghamidi Radliyallahu'anhudliyallahu'anhu) berkata; beliau jika mengutus pasukan perang atau tentara maka pada waktu menjelang siang. (Umarah bin Hadid Radliyallahu'anhu) berkata; Shakhr adalah seorang pedagang, jika dia mengirim dagangannya pada waktu tersebut maka dia menjadi melimpah dan bertambah banyak hartanya."},"481":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ يَعْلَى بْنُ عَطَاءٍ أَنْبَأَنِي قَالَ سَمِعْتُ عُمَارَةَ بْنَ حَدِيدٍ رَجُلٌ مِنْ بَجِيلَةَ قَالَ سَمِعْتُ صَخْرًا الْغَامِدِيَّ رَجُلٌ مِنْ الْأَزْدِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ سَرِيَّةً بَعَثَهُمْ أَوَّلَ النَّهَارِوَكَانَ صَخْرٌ رَجُلًا تَاجِرًا وَكَانَ لَهُ غِلْمَانٌ فَكَانَ يَبْعَثُ غِلْمَانَهُ مِنْ أَوَّلِ النَّهَارِ قَالَ فَكَثُرَ مَالُهُ حَتَّى كَانَ لَا يَدْرِي أَيْنَ يَضَعُهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Syu'bah] berkata; [Ya'la bin 'Atho'] telah memberitakan kepada kami, berkata; saya telah mendengar [Umarah bin Hadid] seorang dari Bajilah, berkata; saya telah mendengar [Shakhr Al Ghamidi] seorang dari Al Azdi, Nabi Shallallahu'alaihi wasallam bersabda: \"Ya berilah berkah pada umatku pada pagi harinya. (Shakhr Al Ghamidi Radliyallahu'anhu) berkata; beliau jika mengutus pasukan perang, beliau lakukan pada waktu pagi hari. Dan Shakhr adalah seorang pedagang, dia memiliki banyak pelayan, dia mengutus para pelayannya, pada awal siang. (Umarah bin Hadid Radliyallahu'anhu) berkata; lalu hartanya bertambah banyak, sampai tidak tahu harus di mana meletakkannya."},"482":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ عَبْدِ الرَّحْمَنِ الْعَصْرِيُّ حَدَّثَنَا شِهَابُ بْنُ عَبَّادٍ أَنَّهُ سَمِعَ بَعْضَ وَفْدِ عَبْدِ الْقَيْسِ وَهُمْ يَقُولُونَقَدِمْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاشْتَدَّ فَرَحُهُمْ بِنَا فَلَمَّا انْتَهَيْنَا إِلَى الْقَوْمِ أَوْسَعُوا لَنَا فَقَعَدْنَا فَرَحَّبَ بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَعَا لَنَا ثُمَّ نَظَرَ إِلَيْنَا فَقَالَ مَنْ سَيِّدُكُمْ وَزَعِيمُكُمْ فَأَشَرْنَا بِأَجْمَعِنَا إِلَى الْمُنْذِرِ بْنِ عَائِذٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهَذَا الْأَشَجُّ وَكَانَ أَوَّلَ يَوْمٍ وُضِعَ عَلَيْهِ هَذَا الِاسْمُ بِضَرْبَةٍ لِوَجْهِهِ بِحَافِرِ حِمَارٍ قُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ فَتَخَلَّفَ بَعْدَ الْقَوْمِ فَعَقَلَ رَوَاحِلَهُمْ وَضَمَّ مَتَاعَهُمْ ثُمَّ أَخْرَجَ عَيْبَتَهُ فَأَلْقَى عَنْهُ ثِيَابَ السَّفَرِ وَلَبِسَ مِنْ صَالِحِ ثِيَابِهِ ثُمَّ أَقْبَلَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ بَسَطَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِجْلَهُ وَاتَّكَأَ فَلَمَّا دَنَا مِنْهُ الْأَشَجُّ أَوْسَعَ الْقَوْمُ لَهُ وَقَالُوا هَاهُنَا يَا أَشَجُّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَوَى قَاعِدًا وَقَبَضَ رِجْلَهُ هَاهُنَا يَا أَشَجُّ فَقَعَدَ عَنْ يَمِينِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَحَّبَ بِهِ وَأَلْطَفَهُ وَسَأَلَهُ عَنْ بِلَادِهِ وَسَمَّى لَهُ قَرْيَةً قَرْيَةً الصَّفَا وَالْمُشَقَّرَ وَغَيْرَ ذَلِكَ مِنْ قُرَى هَجَرَ فَقَالَ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ لَأَنْتَ أَعْلَمُ بِأَسْمَاءِ قُرَانَا مِنَّا فَقَالَ إِنِّي قَدْ وَطِئْتُ بِلَادَكُمْ وَفُسِحَ لِي فِيهَا قَالَ ثُمَّ أَقْبَلَ عَلَى الْأَنْصَارِ فَقَالَ يَا مَعْشَرَ الْأَنْصَارِ أَكْرِمُوا إِخْوَانَكُمْ فَإِنَّهُمْ أَشْبَاهُكُمْ فِي الْإِسْلَامِ أَشْبَهُ شَيْئًا بِكُمْ أَشْعَارًا وَأَبْشَارًا أَسْلَمُوا طَائِعِينَ غَيْرَ مُكْرَهِينَ وَلَا مَوْتُورِينَ إِذْ أَبَى قَوْمٌ أَنْ يُسْلِمُوا حَتَّى قُتِلُوا قَالَ فَلَمَّا أَنْ أَصْبَحُوا قَالَ كَيْفَ رَأَيْتُمْ كَرَامَةَ إِخْوَانِكُمْ لَكُمْ وَضِيَافَتَهُمْ إِيَّاكُمْ قَالُوا خَيْرَ إِخْوَانٍ أَلَانُوا فِرَاشَنَا وَأَطَابُوا مَطْعَمَنَا وَبَاتُوا وَأَصْبَحُوا يُعَلِّمُونَا كِتَابَ رَبِّنَا تَبَارَكَ وَتَعَالَى وَسُنَّةَ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْجَبَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفَرِحَ بِهَا ثُمَّ أَقْبَلَ عَلَيْنَا رَجُلًا رَجُلًا فَعَرَضْنَا عَلَيْهِ مَا تَعَلَّمْنَا وَعَلِمْنَا فَمِنَّا مَنْ عَلِمَ التَّحِيَّاتِ وَأُمَّ الْكِتَابِ وَالسُّورَةَ وَالسُّورَتَيْنِ وَالسُّنَنَ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ هَلْ مَعَكُمْ مِنْ أَزْوَادِكُمْ شَيْءٌ فَفَرِحَ الْ��َوْمُ بِذَلِكَ وَابْتَدَرُوا رِحَالَهُمْ فَأَقْبَلَ كُلُّ رَجُلٍ مِنْهُمْ مَعَهُ صُرَّةٌ مِنْ تَمْرٍ فَوَضَعُوهَا عَلَى نِطْعٍ بَيْنَ يَدَيْهِ فَأَوْمَأَ بِجَرِيدَةٍ فِي يَدِهِ كَانَ يَخْتَصِرُ بِهَا فَوْقَ الذِّرَاعِ وَدُونَ الذِّرَاعَيْنِ فَقَالَ أَتُسَمُّونَ هَذَا التَّعْضُوضَ قُلْنَا نَعَمْ ثُمَّ أَوْمَأَ إِلَى صُرَّةٍ أُخْرَى فَقَالَ أَتُسَمُّونَ هَذَا الصَّرَفَانَ قُلْنَا نَعَمْ ثُمَّ أَوْمَأَ إِلَى صُرَّةٍ فَقَالَ أَتُسَمُّونَ هَذَا الْبَرْنِيَّ قُلْنَا نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ خَيْرُ تَمْرِكُمْ وَأَنْفَعُهُ لَكُمْ قَالَ فَرَجَعْنَا مِنْ وِفَادَتِنَا تِلْكَ فَأَكْثَرْنَا الْغَرْزَ مِنْهُ وَعَظُمَتْ رَغْبَتُنَا فِيهِ حَتَّى صَارَ مُعْظَمَ نَخْلِنَا وَتَمْرِنَا الْبَرْنِيُّ فَقَالَ الْأَشَجُّ يَا رَسُولَ اللَّهِ إِنَّ أَرْضَنَا أَرْضٌ ثَقِيلَةٌ وَخِمَةٌ وَإِنَّا إِذَا لَمْ نَشْرَبْ هَذِهِ الْأَشْرِبَةَ هِيجَتْ أَلْوَانُنَا وَعَظُمَتْ بُطُونُنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَشْرَبُوا فِي الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَلْيَشْرَبْ أَحَدُكُمْ فِي سِقَاءٍ يُلَاثُ عَلَى فِيهِ فَقَالَ لَهُ الْأَشَجُّ بِأَبِي وَأُمِّي يَا رَسُولَ اللَّهِ رَخِّصْ لَنَا فِي مِثْلِ هَذِهِ وَأَوْمَأَ بِكَفَّيْهِ فَقَالَ يَا أَشَجُّ إِنِّي إِنْ رَخَّصْتُ لَكَ فِي مِثْلِ هَذِهِ وَقَالَ بِكَفَّيْهِ هَكَذَا شَرِبْتَهُ فِي مِثْلِ هَذِهِ وَفَرَّجَ يَدَيْهِ وَبَسَطَهَا يَعْنِي أَعْظَمَ مِنْهَا حَتَّى إِذَا ثَمِلَ أَحَدُكُمْ مِنْ شَرَابِهِ قَامَ إِلَى ابْنِ عَمِّهِ فَهَزَرَ سَاقَهُ بِالسَّيْفِ وَكَانَ فِي الْوَفْدِ رَجُلٌ مِنْ بَنِي عَضَلٍ يُقَالُ لَهُ الْحَارِثُ قَدْ هُزِرَتْ سَاقُهُ فِي شَرَابٍ لَهُمْ فِي بَيْتٍ تَمَثَّلَهُ مِنْ الشِّعْرِ فِي امْرَأَةٍ مِنْهُمْ فَقَامَ بَعْضُ أَهْلِ ذَلِكَ الْبَيْتِ فَهَزَرَ سَاقَهُ بِالسَّيْفِفَقَالَ الْحَارِثُ لَمَّا سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلْتُ أَسْدُلُ ثَوْبِي فَأُغَطِّي الضَّرْبَةَ بِسَاقِي وَقَدْ أَبْدَاهَا اللَّهُ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepadaku [Yahya bin Abdurrahman Al 'Ashri] telah menceritakan kepada kami [Syihab bin 'Ubbad] dia telah mendengar [sebagian utusan Abdul Qais], mereka berkata menemui Rasulullah Shallallahu'alaihiwasallam, mereka bertambah gembira dengan kedatangan kami. Tatkala kami sampai pada kaum, lalu kami diberi tempat duduk, lalu Nabi Shallallahu'alaihiwasallam menyambut kami, memanggil kami dan menemui kami. Lalu beliau bertanya, siapakah pemimpin kalian, lalu kami menunjuk dengan sepakat kepada Al Mundzir bin 'Aid. Lalu Nabi Shallallahu'alaihi wasallam bersabda: \"Apakah ini Al Asaj\" dan itulah nama yang pertama kali dipakai karena suatu kali pernah terpukul ke wajahnya dengan kaki keledai. Kami menjawab, ya Wahai Rosulullah. Lalu setelahnya orang-orang meninggalkannya, dia mengikat unta-unta mereka, dan mengumpulkan perbekalan mereka, lalu mengeluarkan pakaiannya, lalu pakaian safarnya di ganti dengan pakaian yang paling bagus. Lalu menemui Nabi Shallallahu'alaihiwasallam, ternyata beliau telah membentangkan kakinya dan bersandar. Tatkala Al Asyaj mendekati beliau, maka anggota kaumnya mempersilahkannya, lalu mereka berkata; sini Wahai Al Asyaj. Nabi Shallallahu'alaihiwasallam meluruskan duduknya dengan menggenggam kakinya, lalu bersabda: \"Sini Wahai Al Asyaj\", lalu dia duduk di sebelah kanan Nabi Shallallahu'alaihiwasallam lalu beliau menyambutnya dengan sambutan yang baik dan menanyakan tentang daerahnya. Lalu (Al Asyaj Radliyallahu'anhu) menyebutkan satu persatu nama-nama desa yang ada. Ada Ash-Shofa, Al Musyaqqor dan yang lainnya. Lalu berkata; demi bapakku dan ibuku Wahai Rosulullah, kenapa anda lebih tahu nama-nama desa kami dari kami? Maka beliau menjawab, saya telah melewati negeri kalian dan saya telah mengilinginya. Lalu beliau menemui orang-orang Anshor dan bersabda: \"Wahai orang-orang Anshor, muliakanlah saudara kalian, mereka adalah orang yang sangat mirip dengan kalian dalam Islam, baik dalam hal syair maupun orangnya. Mereka telah masuk Islam dan taat tanpa rasa terpaksa dan tidak perlu diperangi. Karena jika ada sebuah kaum yang menolak masuk Islam niscaya akan di perangi. (utusan Abdul Qais) berkata; pada pagi harinya, beliau bertanya bagaimana menurut kalian sambutan dari saudara kalian atas kunjungan kalian, mereka menjawab, sambutan yang paling baik. Mereka menyiapkan tempat tidur kami, menyuguh dengan menu yang sangat enak. Pada malam harinya, mereka mengajari kami kitab Alloh Tabaroka Wa Ta'ala dan sunnah Nabi kami shallallahu 'alaihi wasallam, lalu mereka menjadi cinta kepada Nabi Shallallahu'alaihiwasallam dan senang dengan sunnahnya. Lalu beliau menemui kami satu-satu dan kami menyebutkan apa yang telah kami pelajari dan kami mengetahuinya. Di antara kami ada yang mengetahui bacaan tahiyyat, ummul kitab, satu surat, dua surat dan sunah-sunah yang lainnya. Lalu beliau menghadapkan wajahnya kepada kami dan bersabda: \"Apakah kalian membawa makanan untuk bekal safar kalian?\" maka kaum itu menjadi sangat senang, lalu mereka bersegera menuju kendaraan mereka, setiap orang mendapatkan satu kantung kurma, lalu mereka meletakkannya di pelana mereka dan memberi tanda dengan pelepah kurma pada tangannnya. Yang dijadikan gandengan di atas tangannya atau di bawah kedua tangannya. Lalu beliau bertanya, apakah inikah di namakan ta'dludl (jenis kurma)? Kami menjawab, Ya. Lalu beliau menunjuk pada kantong yang lain, apakah ini yang kalian namakan shorfan (salah satu jenis kurma)? Kami menjawabnya, Ya. Lalu beliau menunjuk pada yang lainnya dan bertanya, apakah yang dinamakan Al burni (salah jenis kurma unggulan)? Kami menjawab, ya. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Itu adalah sebaik-baik kuma kalian dan yang paling bermanfaat\". (utusan Abdul Qais) berkata; lalu kami pulang dan kami banyak menanamnya dan kami sangat menyukainya sampai kebanyakan kurma adalah kurma Al burni. Al Asyaj berkata; Wahai Rosulullah, daerah kami adalah daerah yang sangat berat dan tidak cocok hawanya, jika kami jika tidak meminum minuman itu maka akan berubahlah kulit kami dan membesarlah perut kami. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah meminum dalam duba' (tempat minum yang terbuat dari sejenis labu), hantam (bejana yang terbuat dari tanah, rambut dan darah) dan naqir (pohon yang di jadikan bejana), namum minumlah di gelas yang di tempelkan pada mulutnya. Lalu Al Asyaj berkata kepada beliau, demi bapak dan ibuku Wahai Rasulullah, berilah keringanan kepada kami pada hal ini, lalu dia memberi isyarat dengan kedua telapak tangannya, lalu bersabda: \"Wahai Al Asyaj, jika saya memberi keringannan pada hal itu dan memberi isyarat dengan kedua telapak tangannya begini, cara meminummu lalu beliau memperlihatkan kedua tangannya dan membentangkannya, yaitu melebarkannya sampai jika salah seorang kalian telah meminumnya. Lalu beliau berdiri menuju anak pamannya dan memukul dengan keras pada betisnya dengan pedang. Di dalam kelompok utusan terdapat seorang laki-laki dari Bani 'Adlol yang bernama Al Harits telah dipukul betisnya karena ada minuman mereka yang ada pada rumah mereka lalu dia mensifatinya dengan syair, pada seorang wanita dari mereka. Lalu sebagian penghuni rumah dan memukul betisnya dengan pedang. Al Harits berkata; tatkala saya mendengar dari Rasulullah Shallallahu'alaihiwasallam, lalu saya menurunkan pakaianku dan saya menutup bekas pukulan namun Alloh Tabaroka Wa Ta'ala telah menampakkannya."},"483":{"ar":"حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ وَعَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Waki' bin Al Jaroh] dan [Abdurrahman bin Al Mahdi] dari [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berperang satu pagi atau satu sore hari di jalan Allah Azzawajalla itu lebih baik daripada dunia dan segala isinya\"."},"484":{"ar":"قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا ��َبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَرَأَيْتُ الرِّجَالَ تَقِيلُ وَتَتَغَدَّى يَوْمَ الْجُمُعَةِ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; Telah menceritakan kepada kami [Bisyr bin Al Mufadldlol] berkata; telah menceritakan kepada kami [Abu Hazim] dari [Sahl bin Sa'd] berkata; saya telah melihat beberapa orang beristirahat dan makan siang pada Hari Jumat."},"485":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَرَأَيْتُ الرِّجَالَ عَاقِدِي أُزُرِهِمْ فِي أَعْنَاقِهِمْ أَمْثَالَ الصِّبْيَانِ مِنْ ضِيقِ الْأُزُرِ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ فَقَالَ قَائِلٌ يَا مَعْشَرَ النِّسَاءِ لَا تَرْفَعْنَ رُءُوسَكُنَّ حَتَّى يَرْفَعَ الرِّجَالُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd] berkata; saya telah melihat beberapa orang yang mengikatkan sarung mereka pada leher mereka, seperti anak kecil karena sempitnya sarung di belakang Rasulullah Shallallahu'alaihiwasallam pada saat Shalat. Lalu ada seorang yang berkata; Wahai para wanita, janganlah kalian mengangakat kepala kalian sampai kaum laki-laki mengangkatnya."},"486":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ فُضَيْلُ بْنُ حُسَيْنٍ أَمْلَاهُ عَلَيَّ مِنْ كِتَابِهِ الْأَصْلِ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَغَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَلَمَوْضِعُ سَوْطِ أَحَدِكُمْ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Abu Kamil Al Jahdair, Fudlail bin Husain] dia mendiktekannya kepadaku dari kitabnya yang asli. Berkata; telah menceritakan kepada kami [Umar bin 'Ali] berkata; telah menceritakan kepada kami [Abu Hazim] berkata; saya telah mendengar [Sahl bin Sa'd As Sa'idi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berperang satu pagi atau satu sore hari di jalan Allah AzzaWaJalla itu lebih baik daripada dunia dan segala isinya. Sungguh tempat cemeti salah seorang dari kalian di surga itu lebih baik daripada dunia seisinya\""},"487":{"ar":"قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Hazim] dari [Sahl bin Sa'd] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tempat cemeti salah seorang dari kalian di surga itu lebih baik daripada dunia seisinya\""},"488":{"ar":"حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي اللَّيْثُ بْنُ خَالِدٍ الْبَلْخِيُّ أَبُو بَكْرٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَغَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami Abdullah berkata; telah menceritakan kepadaku [Laits bin Khalid Al Balkhi, Abu Bakr] berkata; telah menceritakan kepada kami [Umar bin 'Ali] dari [Abu Hazim] dari [Sahl bin Sa'd] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berperang satu pagi atau satu sore hari di jalan Allah AzzaWaJalla itu lebih baik daripada dunia dan segala isinya\"."},"489":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بِشْرٍ عَاصِمُ بْنُ عُمَرَ بْنِ عَلِيٍّ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا أَبِي عَنْ أَبِي حَازِمٍ الْمَدَنِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَمَوْضِعُ سَوْطِ أَحَدِكُمْ مِنْ الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Bisyr 'Ashim bin Umar bin 'Ali Al Muqaddami] berkata; telah menceritakan kepada kami [bapakku] dari [Abu Hazim Al Madani] dari [Sahl bin Sa'd As Sa'idi] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berperang satu pagi atau satu sore hari di jalan Allah AzzaWaJalla itu lebih baik daripada dunia dan segala isinya. Tempat cemeti salah seorang dari kalian di surga itu lebih baik daripada dunia seisinya\""},"490":{"ar":"عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ قَالَ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ النُّمَيْرِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غَدْوَةٌ أَوْ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Abdullah: telah menceritakan kepadaku [Muhammad bin Abu Bakr Al Muqoddami] berkata; telah menceritakan kepada kami [Fudloil bin Sulaiman an-Numairi] dari [Abu Hazim] dari [Sahl bin Sa'd] dari Nabi Shallallahu'alaihi wasallam bersabda: \"Berperang satu pagi atau satu sore hari di jalan Allah AzzaWaJalla itu lebih baik daripada dunia dan segala isinya.\""},"491":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا الْعَطَّافُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَقُولُ غَدْوَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَرَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَاحَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُطَرِّفٍ وَهُوَ أَبُو غَسَّانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] berkata; telah menceritakan kepada kami [Al 'Atthaf bin Khalid] telah menceritakan kepada kami [Abu Hazim] berkata; saya telah mendengar [Sahl bin Sa'd] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berperang satu pagi hari di jalan Allah Azzawajalla itu lebih baik daripada dunia dan segala isinya. Berperang satu sore hari di jalan Allah Azzawajalla itu lebih baik daripada dunia dan segala isinya. Tempat cemeti salah seorang dari kalian di surga itu lebih baik daripada dunia seisinya\". Telah menceritakan kepada kami [Husain bin Muhammad] berkata; telah menceritakan kepada kami [Muhammad bin Mutharrif, yaitu Abu Ghassan] dari [Abu Hazim] dari [Sahl bin Sa'd] telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berperang satu sore hari di jalan Allah Azzawajalla itu lebih baik daripada dunia dan segala isinya \" lalu menyebutkan secara makna."},"492":{"ar":"قَالَ حَدَّثَنَا عِصَامُ بْنُ خَالِدٍ وَأَبُو النَّضْرِ قَالَا حَدَّثَنَا الْعَطَّافُ بْنُ خَالِدٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ غَزْوَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَرَوْحَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami ['Ishom bin Khalid] dan [Abu Nadlr] berkata; telah menceritakan kepada kami [Al 'Atthaf bin Khalid] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Berperang satu kali di jalan Allah Azzawajalla itu lebih baik daripada dunia dan segala isinya. Berperang satu sore hari di jalan Allah Azzawajalla itu lebih baik daripada dunia dan segala isinya. Tempat cemeti di surga itu lebih baik daripada dunia seisinya\"."},"493":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ يَأْتِينِي الرَّجُلُ يَسْأَلُنِي الْبَيْعَ لَيْسَ عِنْدِي مَا أَبِيعُهُ مِنْهُ ثُمَّ أَبِيعُهُ مِنْ السُّوقِ فَقَالَ لَا تَبِعْ مَا لَيْسَ عِنْدَكَ","id":"telah menceritakan kepada kami [Husyaim] berkata; telah mengabarkan kepada kami [Abu Bisyr] dari [Yusuf bin Mahak] dari [Hakim bin Hizam] berkata; saya berkata; Wahai Rasulullah, ada seorang yang datang kepadaku dan memintaku untuk menjual sesuatu yang bukan milikku, yang saya jualkan, dan saya menjualnya dari pasar. Beliau bersabda: \"Janganlah kamu menjual barang yang bukan milikmu\"."},"494":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الزُّهْرِيِّ سَمِعَ عُرْوَةَ وَسَعِيدَ بْنَ الْمُسَيَّبِ يَقُولَانِ سَمِعْنَا حَكِيمَ بْنَ حِزَامٍ يَقُولُسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ قَالَ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ فَمَنْ أَخَذَهُ بِحَقِّهِ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى","id":"Telah menceritakan kepada kami [Sufyan] dari [Az-Zuhri] telah mendangar ['Urwah] dan [Sa'id bin Musayyab] berkata; kami telah mendengar [Hakim bin Hizam] berkata; Pernah saya meminta Nabi Shallallahu'alaihiwasallam dan beliau memberi. Saya meminta lagi dan beliau memberi. Saya meminta lagi dan beliau memberi. Lalu bersabda: \" Harta ini adalah hijau dan manis, siapa yang mengambil sesuai haknya, maka dia akan diberi berkah, sebaliknya siapa yang mengambilnya dengan berlebihan maka tidak akan diberi berkah. Dia seperti orang yang makan tapi tidak pernah kenyang. Dan tangan di atas lebih baik daripada tangan di bawah\"."},"495":{"ar":"قَالَ قُرِئَ عَلَى سُفْيَانَ سَمِعْتُ هِشَامًا عَنْ أَبِيهِ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَأَعْتَقْتُ فِي الْجَاهِلِيَّةِ أَرْبَعِينَ مُحَرَّرًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمْتَ عَلَى مَا سَبَقَ لَكَ مِنْ خَيْرٍ","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; dibacakan di hadapan [Sufyan] saya telah mendengar [Hisyam] dari [Bapaknya] dari [Hakim bin Hizam] berkata; pada Masa Jahiliyah saya membebaskan empat puluh orang, lalu Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kamu masuk Islam dengan mendapat kebaikan yang kau lakukan di masa lalu\"."},"496":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ الْهَاشِمِيِّ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا فَإِنْ صَدَقَا وَبَيَّنَا رُزِقَا بَرَكَةَ بَيْعِهِمَا وَإِنْ كَذَبَا وَكَتَمَا مُحِقَ بَرَكَةُ بَيْعِهِمَا","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abu Al Khalil] dari [Abdullah bin Al Harits Al Hasyimi] dari [Hakim bin Hizam] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Penjual dan pembeli berhak khiyar (pilihan antara mengambil barang atau mengembalikannya karena adanya cacat) selama keduanya belum berpisah. Jika keduanya jujur dan menjelaskan barangnya maka keduanya dapatkan barakah dalam juAl belinya, sebaliknya jika bohong dan menyembunyikan cacatnya, barokah juAl belinya dihapus\"."},"497":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ سَمِعْتُ مُوسَى بْنَ طَلْحَةَ أَنَّ حَكِيمَ بْنَ حِزَامٍ حَدَّثَهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الصَّدَقَةِ أَوْ أَفْضَلُ الصَّدَقَةِ مَا أَبْقَتْ غِنًى وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami ['Amr bin 'Utsman] berkata; saya telah mendengar [Musa bin Tholhah] [Hakim bin Hizam] menceritakannya berkata; Nabi Shallallahu'alaihi wasallam bersabda: \"Sebaik-baik sedekah\" atau \"Sedekah yang paling utama adalah sisa dari kecukupan. Tangan di atas lebih baik daripada tangan di bawah. Mulailah dari yang kamu tanggung\"."},"498":{"ar":"قَالَ حَدَّثَنَا ابْنُ نُمَيْرٍ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَلْيَبْدَأْ أَحَدُكُمْ بِمَنْ يَعُولُ وَخَيْرُ الصَّدَقَةِ مَا كَانَ عَنْ ظَهْرِ غِنًى وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُ وَمَنْ يَسْتَعْفِفْ يُعِفَّهُ اللَّهُ فَقُلْتُ وَمِنْكَ يَا رَسُولَ اللَّهِ قَالَ وَمِنِّيقَالَ حَكِيمٌ قُلْتُ لَا تَكُونُ يَدِي تَحْتَ يَدِ رَجُلٍ مِنْ الْعَرَبِ أَبَدًا","id":"(Ahmad bin Hanbal Radliyallahu'anhu) berkata; Telah menceritakan kepada kami [Ibnu Numair] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Hakim bin Hizam] berkata; saya telah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tangan di atas lebih baik daripada tangan di bawah. Mulailah dari yang kamu tanggung, sebaik-sebaik sedekah adalah setelah kita mencukupi kebutuhan kita. Barangsiapa yang merasa cukup, maka Allah akan mencukupkannya. Barangsiapa yang menjaga diri maka Allah akan menjaganya\". Maka saya berkata; Wahai Rasulullah, dan juga darimu?. Beliau bersabda: \"Juga dariku\". Hakim berkata; saya berkata dalam hati, saya tidak akan menjadikan tanganku di bawah tangan seseorang dari kalangan Arab selamanya."},"499":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الشُّعَيْثِيُّ عَنِ الْعَبَّاسِ بْنِ عَبْدِ الرَّحْمَنِ الْمَدَنِيِّ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقَامُ الْحُدُودُ فِي الْمَسَاجِدِ وَلَا يُسْتَقَادُ فِيهَا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Muhammad bin Abdullah Asy-Syu'aisyi] dari [Al 'Abbas bin Abdurrahman Al Madani] dari [Hakim bin Hizam] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidak boleh melakukan hudud di masjid dan juga tidak boleh meminta balasan (qishash) di dalamnya\"."},"500":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا الشُّعَيْثِيُّ عَنْ زُفَرَ بْنِ وَثِيمَةَ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَالْمَسَاجِدُ لَا يُنْشَدُ فِيهَا الْأَشْعَارُ وَلَا تُقَامُ فِيهَا الْحُدُودُ وَلَا يُسْتَقَادُ فِيهَاقَالَ أَبِي لَمْ يَرْفَعْهُ يَعْنِي حَجَّاجًا","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Asy-Syu'aisyi] dari [Zufar bin Watsimah] dari [Hakim bin Hizam] berkata; Masjid itu tidak boleh di lantunkan di dalamnya syair-syair, tidak boleh digunakan untuk melaksnakan hukuman (had), juga tidak boleh untuk meminta balasan (qishas) di dalamnya. Bapakku berkata; Hajjaj tidak memarfu'kannya."}};
